import {
  Controller,
  Get,
  Inject,
  Optional,
  ServiceUnavailableException
} from "@nestjs/common";
import { InjectDataSource } from "@nestjs/typeorm";
import type { DataSource } from "typeorm";
import { LoggerService } from "./common/logger/logger.service";
import { RequestContextService } from "./common/request-context/request-context.service";
import { RuntimeSchemaGuardService } from "./database/runtime-schema-guard.service";
import { StorageHealthService } from "./infra/storage/storage-health.service";

@Controller()
export class AppController {
  constructor(
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService,
    @Inject(LoggerService) private readonly loggerService: LoggerService,
    @InjectDataSource() private readonly dataSource: DataSource,
    @Optional() private readonly runtimeSchemaGuardService?: RuntimeSchemaGuardService,
    @Optional() private readonly storageHealthService?: StorageHealthService
  ) {}

  @Get("health")
  async health() {
    this.loggerService.info("health check requested");

    const schemaDegraded = this.runtimeSchemaGuardService?.isDegraded() ?? false;
    const storage = (await this.storageHealthService?.check()) ?? {
      status: "skipped" as const,
      reason: "storage_health_unconfigured"
    };
    const storageDegraded = storage.status === "unavailable";
    const degraded = schemaDegraded || storageDegraded;

    return {
      status: degraded ? "degraded" : "ok",
      requestId: this.requestContextService.getRequestId(),
      dependencies: {
        storage: storage.status,
        ...(storage.bucket ? { storage_bucket: storage.bucket } : {}),
        ...(storage.reason ? { storage_reason: storage.reason } : {})
      },
      ...(schemaDegraded
        ? { degraded_reasons: { missing_columns: this.runtimeSchemaGuardService?.getMissingColumns() ?? [] } }
        : {}),
      ...(storageDegraded ? { degraded_reasons_storage: storage.reason ?? storage.status } : {})
    };
  }

  /** Process is running (no dependency checks). */
  @Get("health/live")
  healthLive() {
    return { status: "live" };
  }

  /** PostgreSQL reachable. */
  @Get("health/ready")
  async healthReady() {
    try {
      await this.requestContextService.runWithoutTenantBinding(
        "health_ready_probe",
        async () => {
          await this.dataSource.query("SELECT 1 AS ok");
        },
      );
      return { status: "ready" };
    } catch {
      throw new ServiceUnavailableException({
        error: {
          code: "DEPENDENCY_TEMPORARY_UNAVAILABLE",
          message: "Service is not ready",
          retryability: "RETRY_WITH_BACKOFF",
          details: {
            reason: "database_unreachable"
          }
        }
      });
    }
  }

  /** Alias for readiness probe naming used by some clients. */
  @Get("health/readiness")
  async healthReadiness() {
    return this.healthReady();
  }
}

import { Inject, Injectable } from "@nestjs/common";

import { AUDIT_CATEGORY } from "./audit-category";
import { AuditService } from "./audit.service";
import type { AuditCategory } from "./audit-category";
import { LoggerService } from "../logger/logger.service";
import { RequestContextService } from "../request-context/request-context.service";

export type AuditLogEventInput = {
  action: string;
  entity: string;
  entityId?: string;
  before?: Record<string, unknown>;
  after?: Record<string, unknown>;
  category?: AuditCategory;
};

/**
 * Structured audit facade (Phase 13) — persists via {@link AuditService} + operational log line.
 */
@Injectable()
export class AuditLogService {
  constructor(
    @Inject(AuditService) private readonly audit: AuditService,
    @Inject(LoggerService) private readonly logger: LoggerService,
    @Inject(RequestContextService) private readonly requestContext: RequestContextService,
  ) {}

  async logEvent(input: AuditLogEventInput): Promise<void> {
    const tenantId = this.requestContext.tryGetTenantId();
    const actorId = this.requestContext.tryGetUserId();

    this.logger.info("AUDIT_EVENT", {
      actor_id: actorId,
      tenant_id: tenantId,
      action: input.action,
      entity: input.entity,
      entity_id: input.entityId,
      before: input.before,
      after: input.after,
      timestamp: new Date().toISOString(),
    });

    const actorDisplay =
      this.requestContext.tryGetUserId() ?? "system";

    await this.audit.recordAuditEvent({
      category: input.category ?? AUDIT_CATEGORY.SECURITY,
      action: input.action,
      actorDisplay,
      actorUserId: actorId,
      resource: { type: input.entity, id: input.entityId ?? null },
      metadata: {
        before: input.before,
        after: input.after,
      },
    });
  }
}

import { Inject, Injectable } from "@nestjs/common";
import { BOOKING_CREATED_EVENT_TYPE, type BookingCreatedPayload } from "../events/booking-created.event";
import type { OutboxDeliveryEnvelope } from "./outbox-delivery.types";
import { LoggerService } from "../logger/logger.service";
import { RequestContextService } from "../request-context/request-context.service";
import { TenantAuditEventsService } from "./tenant-audit-events.service";
import type { RecordAuditEventInput } from "./audit-record.types";

/**
 * Cross-cutting audit pipeline (structured tenant rows + operational logs).
 *
 * **Append-only & integrity (design):** rows are recorded via {@link TenantAuditEventsService.appendOrWarn}
 * — **no** delete / rewrite APIs on this service. Retention windows, export manifests, and integrity
 * envelopes live in `audit-retention-policy.ts`, `audit-integrity-metadata.ts`, `build-audit-export-manifest.ts`.
 *
 * TODO: Audit explorer (search, drill-down, actor/resource facets) — partially covered by web Audit Trail.
 * TODO: Immutable retention jobs + cold archival (policy-driven; **not** destructive of legal holds).
 */
@Injectable()
export class AuditService {
  constructor(
    @Inject(LoggerService) private readonly loggerService: LoggerService,
    @Inject(RequestContextService) private readonly requestContext: RequestContextService,
    @Inject(TenantAuditEventsService) private readonly tenantAudit: TenantAuditEventsService
  ) {}

  /**
   * Delivery path for transactional outbox. Uses `event_id` (outbox row PK) for trace correlation;
   * consumers must treat redelivery as normal and dedupe on `event_id` and/or domain `eventId` in payload.
   */
  deliverFromOutbox(envelope: OutboxDeliveryEnvelope): void {
    if (envelope.event_type === BOOKING_CREATED_EVENT_TYPE) {
      const enc = envelope.payload?.envelope as
        | {
            eventId?: string;
            eventType?: string;
            schemaVersion?: number;
            tenantId?: string;
            correlationId?: string | null;
            payload?: BookingCreatedPayload;
          }
        | undefined;
      const inner = enc?.payload;
      if (enc?.eventId && inner?.registrationId && inner.tourId) {
        this.loggerService.info("domain_event_booking_created_audit", {
          outbox_event_id: envelope.event_id,
          event_id: enc.eventId,
          event_type: enc.eventType ?? envelope.event_type,
          schema_version: enc.schemaVersion,
          tenant_id: enc.tenantId ?? envelope.tenant_id,
          correlation_id: enc.correlationId,
          registration_id: inner.registrationId,
          tour_id: inner.tourId
        });
        return;
      }
    }

    this.loggerService.info("audit.event.delivered", {
      tenant_id: envelope.tenant_id,
      event_id: envelope.event_id,
      event_type: envelope.event_type,
      created_at: envelope.created_at,
      payload: envelope.payload
    });
  }

  /**
   * Records one tenant-scoped audit row with automatic metadata merge.
   * Never throws on persistence failure (delegates to {@link TenantAuditEventsService.appendOrWarn}).
   */
  async recordAuditEvent(input: RecordAuditEventInput): Promise<void> {
    const tenantId = (input.tenantId ?? this.requestContext.tryGetTenantId())?.trim().toLowerCase();
    if (!tenantId) {
      this.loggerService.warn("audit.record.skipped_no_tenant", {
        audit_category: input.category,
        action: input.action
      });
      return;
    }

    const correlationId = this.requestContext.tryGetCorrelationId() ?? this.requestContext.tryGetRequestId() ?? null;
    const actorUserId = input.actorUserId ?? this.requestContext.tryGetUserId() ?? null;
    const clientIp = input.clientIp ?? this.requestContext.tryGetClientIp() ?? "unknown";

    const metadata: Record<string, unknown> = {
      audit_category: input.category,
      correlation_id: correlationId,
      tenant_id: tenantId,
      actor_user_id: actorUserId,
      ...(input.metadata ?? {})
    };

    this.loggerService.info("audit.pipeline.record", {
      audit_category: input.category,
      action: input.action,
      tenant_id: tenantId,
      correlation_id: correlationId,
      actor_user_id: actorUserId
    });

    await this.tenantAudit.appendOrWarn({
      tenantId,
      actorUserId,
      actor: input.actorDisplay,
      userId: null,
      action: input.action,
      resourceType: input.resource?.type ?? "",
      resourceId: input.resource?.id ?? null,
      metadata,
      requestId: correlationId,
      clientIp
    });
  }
}

import { Inject, Injectable } from "@nestjs/common";
import type { EntityManager } from "typeorm";
import { AUDIT_CATEGORY } from "./audit-category";
import { RequestContextService } from "../request-context/request-context.service";
import { TenantAuditEventsService } from "./tenant-audit-events.service";

export type FinancialOutboxAuditInput = {
  tenantId: string;
  eventType: string;
  aggregateType: string;
  aggregateId: string;
  /** Outbox payload (already includes `correlation_id` after enqueue enrichment). */
  payload: Record<string, unknown>;
  /** Explicit correlation id when known (otherwise ALS / payload). */
  correlationId?: string | null;
  /**
   * Optional domain snapshots for traceability (e.g. payment row before/after `save`).
   * When omitted, audit still records `state_after` from payload for outbox-only transitions.
   */
  financialAudit?: {
    stateBefore: Record<string, unknown> | null;
    stateAfter: Record<string, unknown> | null;
  } | null;
};

/**
 * **Transactional financial audit** — append-only `tenant_audit_events` rows that mirror financial outbox
 * writes with actor, tenant, correlation id, and before/after state snapshots.
 *
 * Uses {@link TenantAuditEventsService.append} (not `appendOrWarn`) so audit failure **rolls back** the
 * same DB transaction as the outbox insert when wired through the caller’s `EntityManager`.
 */
@Injectable()
export class FinancialMutationAuditService {
  constructor(
    @Inject(TenantAuditEventsService) private readonly tenantAudit: TenantAuditEventsService,
    @Inject(RequestContextService) private readonly requestContext: RequestContextService
  ) {}

  async recordOutboxFinancialMutation(
    manager: EntityManager,
    input: FinancialOutboxAuditInput
  ): Promise<void> {
    const tenantId = input.tenantId.trim().toLowerCase();
    const actorUserId = this.requestContext.tryGetUserId() ?? null;
    const correlationFromPayload =
      typeof input.payload.correlation_id === "string" ? input.payload.correlation_id.trim() : "";
    const correlation =
      (input.correlationId?.trim() || "") !== ""
        ? input.correlationId!.trim()
        : correlationFromPayload !== ""
          ? correlationFromPayload
          : this.requestContext.tryGetCorrelationId() ??
            this.requestContext.tryGetRequestId() ??
            "unknown";

    const explicit = input.financialAudit;
    const stateBefore = explicit?.stateBefore ?? null;
    const stateAfter = explicit?.stateAfter ?? input.payload;

    const action = `financial.outbox:${input.eventType}`.slice(0, 96);

    await this.tenantAudit.append(
      {
        tenantId,
        actorUserId,
        actor: actorUserId ?? "system",
        userId: null,
        action,
        resourceType: input.aggregateType.trim().slice(0, 96),
        resourceId: input.aggregateId.trim().slice(0, 128),
        metadata: {
          audit_category: AUDIT_CATEGORY.FINANCE,
          correlation_id: correlation,
          event_type: input.eventType,
          aggregate_type: input.aggregateType,
          aggregate_id: input.aggregateId,
          state_before: stateBefore,
          state_after: stateAfter
        },
        clientIp: this.requestContext.tryGetClientIp() ?? "unknown",
        requestId: correlation.slice(0, 128)
      },
      manager
    );
  }
}

import { Inject, Injectable } from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import type { EntityManager } from "typeorm";
import { Brackets, Repository } from "typeorm";
import { TENANT_AUDIT_LIST_MAX_LIMIT } from "./tenant-audit.constants";
import { LoggerService } from "../logger/logger.service";
import { TenantAuditEventEntity } from "./entities/tenant-audit-event.entity";
import type { TenantAuditActionType } from "./tenant-audit-actions";

export type TenantAuditAppendInput = {
  tenantId: string;
  actorUserId?: string | null;
  /** Human-readable actor (e.g. email). */
  actor: string;
  userId?: string | null;
  action: TenantAuditActionType | string;
  resourceType?: string;
  resourceId?: string | null;
  metadata?: Record<string, unknown> | null;
  clientIp?: string;
  requestId?: string | null;
};

export const TENANT_AUDIT_EXPORT_MAX_ROWS = 50_000;
export const TENANT_AUDIT_CONFLICTS_MAX_LIMIT = 200;
export const TENANT_AUDIT_CONFLICTS_DEFAULT_LIMIT = 25;

export type TenantAuditListCursor = { occurredAt: Date; id: string };
export type DraftConflictHotspotRow = {
  resourceType: string;
  resourceId: string;
  conflictCount: number;
  lastOccurredAt: Date;
  sampleRequestId: string | null;
};

export function encodeTenantAuditListCursor(cursor: TenantAuditListCursor): string {
  return Buffer.from(
    JSON.stringify({ at: cursor.occurredAt.toISOString(), id: cursor.id }),
    "utf8"
  ).toString("base64url");
}

export function decodeTenantAuditListCursor(raw: string): TenantAuditListCursor | null {
  try {
    const decoded = Buffer.from(raw.trim(), "base64url").toString("utf8");
    const j = JSON.parse(decoded) as { at?: string; id?: string };
    if (typeof j.at !== "string" || typeof j.id !== "string") {
      return null;
    }
    const occurredAt = new Date(j.at);
    if (Number.isNaN(occurredAt.getTime())) {
      return null;
    }
    const id = j.id.trim();
    if (!id) {
      return null;
    }
    return { occurredAt, id };
  } catch {
    return null;
  }
}

@Injectable()
export class TenantAuditEventsService {
  constructor(
    @InjectRepository(TenantAuditEventEntity)
    private readonly repo: Repository<TenantAuditEventEntity>,
    @Inject(LoggerService) private readonly logger: LoggerService
  ) {}

  async append(
    input: TenantAuditAppendInput,
    manager?: EntityManager
  ): Promise<void> {
    const r = manager?.getRepository(TenantAuditEventEntity) ?? this.repo;
    await r.insert({
      tenantId: input.tenantId.trim().toLowerCase(),
      actorUserId: input.actorUserId ?? null,
      actor: input.actor,
      userId: input.userId ?? null,
      action: input.action,
      resourceType: input.resourceType ?? "",
      resourceId: input.resourceId ?? null,
      metadata:
        input.metadata === undefined || input.metadata === null
          ? null
          : (input.metadata as object),
      clientIp: input.clientIp?.trim() || "unknown",
      requestId: input.requestId?.trim() || null
    });
  }

  async appendMany(
    inputs: TenantAuditAppendInput[],
    manager?: EntityManager
  ): Promise<void> {
    if (inputs.length === 0) {
      return;
    }
    const r = manager?.getRepository(TenantAuditEventEntity) ?? this.repo;
    await r.insert(
      inputs.map((input) => ({
        tenantId: input.tenantId.trim().toLowerCase(),
        actorUserId: input.actorUserId ?? null,
        actor: input.actor,
        userId: input.userId ?? null,
        action: input.action,
        resourceType: input.resourceType ?? "",
        resourceId: input.resourceId ?? null,
        metadata:
          input.metadata === undefined || input.metadata === null
            ? null
            : (input.metadata as object),
        clientIp: input.clientIp?.trim() || "unknown",
        requestId: input.requestId?.trim() || null
      }))
    );
  }

  /** Same as {@link append} but never throws (login/session paths must not fail if audit insert breaks). */
  async appendOrWarn(
    input: TenantAuditAppendInput,
    manager?: EntityManager
  ): Promise<void> {
    try {
      await this.append(input, manager);
    } catch (error: unknown) {
      const msg = error instanceof Error ? error.message : String(error);
      this.logger.warn("tenant_audit.append_failed", {
        tenant_id: input.tenantId,
        action: input.action,
        error: msg
      });
    }
  }

  /**
   * Keyset-paginated tenant audit stream for admin UI (`occurred_at` + `id` descending).
   * Fetches `limit + 1` rows to compute `nextCursor`.
   */
  async listForTenantPaged(params: {
    tenantId: string;
    from?: Date;
    to?: Date;
    action?: string;
    resourceType?: string;
    resourceId?: string;
    actorContains?: string;
    limit: number;
    after?: TenantAuditListCursor | null;
  }): Promise<{ rows: TenantAuditEventEntity[]; nextCursor: string | null }> {
    const tenantId = params.tenantId.trim().toLowerCase();
    const take = Math.min(Math.max(params.limit, 1), TENANT_AUDIT_LIST_MAX_LIMIT);
    const qb = this.repo
      .createQueryBuilder("e")
      .where("e.tenant_id = :tenantId", { tenantId })
      .orderBy("e.occurred_at", "DESC")
      .addOrderBy("e.id", "DESC")
      .take(take + 1);

    if (params.from) {
      qb.andWhere("e.occurred_at >= :from", { from: params.from });
    }
    if (params.to) {
      qb.andWhere("e.occurred_at <= :to", { to: params.to });
    }
    if (params.action?.trim()) {
      qb.andWhere("e.action = :action", { action: params.action.trim() });
    }
    if (params.resourceType?.trim()) {
      qb.andWhere("e.resource_type = :resourceType", { resourceType: params.resourceType.trim() });
    }
    if (params.resourceId?.trim()) {
      qb.andWhere("e.resource_id = :resourceId", { resourceId: params.resourceId.trim() });
    }
    const ac = params.actorContains?.trim();
    if (ac) {
      const stripped = ac.replace(/[%_\\]/g, "");
      if (stripped) {
        qb.andWhere("e.actor ILIKE :actorPat", { actorPat: `%${stripped}%` });
      }
    }
    if (params.after) {
      const cAt = params.after.occurredAt;
      const cId = params.after.id;
      qb.andWhere(
        new Brackets((w) => {
          w.where("e.occurred_at < :cAt", { cAt }).orWhere(
            "(e.occurred_at = :cAt2 AND e.id < :cId)",
            { cAt2: cAt, cId }
          );
        })
      );
    }

    const rows = await qb.getMany();
    const hasMore = rows.length > take;
    const page = hasMore ? rows.slice(0, take) : rows;
    const tail = page.length > 0 ? page[page.length - 1] : undefined;
    const nextCursor =
      hasMore && tail !== undefined
        ? encodeTenantAuditListCursor({ occurredAt: tail.occurredAt, id: tail.id })
        : null;
    return { rows: page, nextCursor };
  }

  async listForTenantExport(params: {
    tenantId: string;
    from?: Date;
    to?: Date;
    limit?: number;
  }): Promise<TenantAuditEventEntity[]> {
    const cap = Math.min(params.limit ?? TENANT_AUDIT_EXPORT_MAX_ROWS, TENANT_AUDIT_EXPORT_MAX_ROWS);
    const tenantId = params.tenantId.trim().toLowerCase();
    const qb = this.repo
      .createQueryBuilder("e")
      .where("e.tenant_id = :tenantId", { tenantId })
      .orderBy("e.occurred_at", "DESC")
      .addOrderBy("e.id", "DESC")
      .take(cap);
    if (params.from) {
      qb.andWhere("e.occurred_at >= :from", { from: params.from });
    }
    if (params.to) {
      qb.andWhere("e.occurred_at <= :to", { to: params.to });
    }
    return qb.getMany();
  }

  async listDraftConflictHotspots(params: {
    tenantId: string;
    from?: Date;
    to?: Date;
    limit?: number;
  }): Promise<DraftConflictHotspotRow[]> {
    const tenantId = params.tenantId.trim().toLowerCase();
    const take = Math.min(
      Math.max(params.limit ?? TENANT_AUDIT_CONFLICTS_DEFAULT_LIMIT, 1),
      TENANT_AUDIT_CONFLICTS_MAX_LIMIT,
    );
    const qb = this.repo
      .createQueryBuilder("e")
      .select("e.resource_type", "resource_type")
      .addSelect("e.resource_id", "resource_id")
      .addSelect("COUNT(*)::int", "conflict_count")
      .addSelect("MAX(e.occurred_at)", "last_occurred_at")
      .addSelect("MAX(e.request_id)", "sample_request_id")
      .where("e.tenant_id = :tenantId", { tenantId })
      .andWhere("e.action = :action", { action: "draft_engine.conflict" })
      .andWhere("e.resource_id IS NOT NULL")
      .groupBy("e.resource_type")
      .addGroupBy("e.resource_id")
      .orderBy("conflict_count", "DESC")
      .addOrderBy("last_occurred_at", "DESC")
      .take(take);

    if (params.from) {
      qb.andWhere("e.occurred_at >= :from", { from: params.from });
    }
    if (params.to) {
      qb.andWhere("e.occurred_at <= :to", { to: params.to });
    }

    const rows = await qb.getRawMany<{
      resource_type: string;
      resource_id: string;
      conflict_count: number | string;
      last_occurred_at: string;
      sample_request_id: string | null;
    }>();
    return rows.map((row) => ({
      resourceType: row.resource_type || "",
      resourceId: row.resource_id,
      conflictCount: Number(row.conflict_count),
      lastOccurredAt: new Date(row.last_occurred_at),
      sampleRequestId: row.sample_request_id,
    }));
  }

  toNdjson(rows: TenantAuditEventEntity[]): string {
    return `${rows.map((row) => JSON.stringify(this.toExportDto(row))).join("\n")}\n`;
  }

  toCsv(rows: TenantAuditEventEntity[]): string {
    const headers = [
      "id",
      "tenant_id",
      "timestamp",
      "user_id",
      "actor_user_id",
      "actor",
      "action",
      "resource_type",
      "resource_id",
      "client_ip",
      "request_id",
      "metadata"
    ];
    const escape = (v: string): string => {
      if (/[",\n\r]/.test(v)) {
        return `"${v.replace(/"/g, '""')}"`;
      }
      return v;
    };
    const lines = [headers.join(",")];
    for (const row of rows) {
      const dto = this.toExportDto(row);
      lines.push(
        [
          dto.id,
          dto.tenant_id,
          dto.timestamp,
          dto.user_id ?? "",
          dto.actor_user_id ?? "",
          dto.actor,
          dto.action,
          dto.resource_type,
          dto.resource_id ?? "",
          dto.client_ip,
          dto.request_id ?? "",
          escape(JSON.stringify(dto.metadata ?? null))
        ].join(",")
      );
    }
    return `${lines.join("\n")}\n`;
  }

  private toExportDto(row: TenantAuditEventEntity): Record<string, unknown> {
    return {
      id: row.id,
      tenant_id: row.tenantId,
      timestamp: row.occurredAt.toISOString(),
      user_id: row.userId,
      actor_user_id: row.actorUserId,
      actor: row.actor,
      action: row.action,
      resource_type: row.resourceType,
      resource_id: row.resourceId,
      client_ip: row.clientIp,
      request_id: row.requestId,
      metadata: row.metadata
    };
  }
}

import { tryParseWorkspaceRole, WorkspaceRole } from "@repo/shared";

export const UserRole = WorkspaceRole;
export type UserRole = WorkspaceRole;

export { tryParseWorkspaceRole as tryParseWorkspaceUserRole };

/**
 * Non-workspace JWT actors (OpenAPI build, workers, CASL placeholders, internal ops).
 */
export enum InternalActorRole {
  System = "SYSTEM",
  None = "none",
  Worker = "worker",
  Api = "api"
}

/** Value stored on {@link RequestContext.role} after auth or synthetic contexts. */
export type RequestActorRole = UserRole | InternalActorRole;

export function isWorkspaceUserRole(role: RequestActorRole | undefined): role is UserRole {
  if (role === undefined) {
    return false;
  }
  return tryParseWorkspaceRole(String(role)) !== undefined;
}

import { HttpException, HttpStatus, Inject, Injectable } from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import type { Request } from "express";
import { Repository } from "typeorm";
import { ConfigService } from "../../config/config.service";
import { LoggerService } from "../logger/logger.service";
import { RequestContextService } from "../request-context/request-context.service";
import {
  getTenantScopeKey,
  isTenantRuntimeApiPath,
  isTenantRuntimeLoginRoute,
  resolveTenantRuntimePath
} from "../tenant/tenant-runtime-policy";
import { TenantUsageDailyEntity } from "./entities/tenant-usage-daily.entity";

type QuotaScope = "api_requests_per_day" | "jobs_per_day";

@Injectable()
export class TenantUsageMeteringService {
  private usageUpdatesTotal = 0;
  private quotaExceededTotal = 0;
  private readonly quotaExceededByScope = new Map<QuotaScope, number>();

  constructor(
    @InjectRepository(TenantUsageDailyEntity)
    private readonly usageRepo: Repository<TenantUsageDailyEntity>,
    @Inject(ConfigService) private readonly configService: ConfigService,
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService,
    @Inject(LoggerService) private readonly loggerService: LoggerService
  ) {}

  private utcDateString(now = new Date()): string {
    return now.toISOString().slice(0, 10);
  }

  private resolveTenantId(req: Request): string | undefined {
    return this.requestContextService.resolveTenantContext(req).tenantId;
  }

  private bumpQuotaExceeded(scope: QuotaScope): void {
    this.quotaExceededTotal += 1;
    this.quotaExceededByScope.set(scope, (this.quotaExceededByScope.get(scope) ?? 0) + 1);
  }

  private async upsertUsage(params: {
    tenantId: string;
    apiRequestsDelta?: number;
    loginAttemptsDelta?: number;
    backgroundJobsDelta?: number;
  }): Promise<void> {
    const date = this.utcDateString();
    const apiDelta = params.apiRequestsDelta ?? 0;
    const loginDelta = params.loginAttemptsDelta ?? 0;
    const jobsDelta = params.backgroundJobsDelta ?? 0;
    await this.usageRepo.query(
      `INSERT INTO tenant_usage_daily
         (tenant_id, date, api_requests, background_jobs, storage_bytes, login_attempts)
       VALUES ($1::uuid, $2::date, $3::bigint, $4::bigint, 0, $5::bigint)
       ON CONFLICT (tenant_id, date)
       DO UPDATE SET
         api_requests = tenant_usage_daily.api_requests + EXCLUDED.api_requests,
         background_jobs = tenant_usage_daily.background_jobs + EXCLUDED.background_jobs,
         login_attempts = tenant_usage_daily.login_attempts + EXCLUDED.login_attempts`,
      [params.tenantId, date, apiDelta, jobsDelta, loginDelta]
    );
    this.usageUpdatesTotal += 1;
  }

  private throwQuotaExceeded(scope: QuotaScope, tenantId: string, req?: Request): never {
    const ip = req
      ? (getTenantScopeKey("ip", req, {
          requestContextService: this.requestContextService,
          configService: this.configService
        }) ?? "")
      : "";
    this.bumpQuotaExceeded(scope);
    this.loggerService.warn("tenant_usage_quota_exceeded", {
      tenant_id: tenantId,
      scope,
      client_ip: ip
    });
    throw new HttpException(
      {
        error: {
          code: "TENANT_QUOTA_EXCEEDED",
          message: "Tenant usage quota exceeded",
          retryability: "RETRY_WITH_BACKOFF",
          details: { quota_scope: scope }
        }
      },
      HttpStatus.TOO_MANY_REQUESTS
    );
  }

  async enforceHttpUsageMetering(req: Request): Promise<void> {
    const path = resolveTenantRuntimePath(req);
    if (!isTenantRuntimeApiPath(path)) {
      return;
    }
    const tenantId = this.resolveTenantId(req);
    if (!tenantId) {
      return;
    }

    const isLogin = isTenantRuntimeLoginRoute(path, req.method);
    await this.upsertUsage({
      tenantId,
      apiRequestsDelta: 1,
      loginAttemptsDelta: isLogin ? 1 : 0
    });

    const [quotaRow] = await this.usageRepo.query(
      `SELECT u.api_requests, l.api_requests_per_day
         FROM tenant_usage_daily u
         LEFT JOIN tenant_plan_limits l ON l.tenant_id = u.tenant_id
        WHERE u.tenant_id = $1::uuid
          AND u.date = $2::date`,
      [tenantId, this.utcDateString()]
    );
    const limit = quotaRow?.api_requests_per_day;
    if (limit !== null && limit !== undefined) {
      const used = Number(quotaRow?.api_requests ?? 0);
      if (used > Number(limit)) {
        this.throwQuotaExceeded("api_requests_per_day", tenantId, req);
      }
    }
  }

  async enforceAndRecordHttpRequest(req: Request): Promise<void> {
    await this.enforceHttpUsageMetering(req);
  }

  /** Returns false when tenant daily background job quota is exhausted. */
  async tryConsumeBackgroundJob(tenantId: string): Promise<boolean> {
    const tid = tenantId.trim().toLowerCase();
    await this.upsertUsage({ tenantId: tid, backgroundJobsDelta: 1 });
    const [quotaRow] = await this.usageRepo.query(
      `SELECT u.background_jobs, l.jobs_per_day
         FROM tenant_usage_daily u
         LEFT JOIN tenant_plan_limits l ON l.tenant_id = u.tenant_id
        WHERE u.tenant_id = $1::uuid
          AND u.date = $2::date`,
      [tid, this.utcDateString()]
    );
    const limit = quotaRow?.jobs_per_day;
    if (limit !== null && limit !== undefined) {
      const used = Number(quotaRow?.background_jobs ?? 0);
      if (used > Number(limit)) {
        this.bumpQuotaExceeded("jobs_per_day");
        this.loggerService.warn("tenant_usage_quota_exceeded_job", {
          tenant_id: tid,
          scope: "jobs_per_day"
        });
        return false;
      }
    }
    return true;
  }

  getPrometheusText(): string {
    const lines: string[] = [
      "# HELP tenant_usage_updates_total Successful tenant usage daily upserts.",
      "# TYPE tenant_usage_updates_total counter",
      `tenant_usage_updates_total ${this.usageUpdatesTotal}`,
      "# HELP tenant_quota_exceeded_total Quota enforcement denials.",
      "# TYPE tenant_quota_exceeded_total counter",
      `tenant_quota_exceeded_total ${this.quotaExceededTotal}`
    ];
    for (const [scope, count] of this.quotaExceededByScope.entries()) {
      lines.push(`tenant_quota_exceeded_total{scope="${scope}"} ${count}`);
    }
    return `${lines.join("\n")}\n`;
  }

  getSnapshot(): {
    tenant_usage_updates_total: number;
    tenant_quota_exceeded_total: number;
    tenant_quota_exceeded_by_scope: Record<string, number>;
  } {
    return {
      tenant_usage_updates_total: this.usageUpdatesTotal,
      tenant_quota_exceeded_total: this.quotaExceededTotal,
      tenant_quota_exceeded_by_scope: Object.fromEntries(this.quotaExceededByScope)
    };
  }
}

import { Injectable, NestMiddleware } from "@nestjs/common";
import type { NextFunction, Request, Response } from "express";
import { Inject } from "@nestjs/common";
import {
  TENANT_RUNTIME_GUARD,
  type TenantRuntimeGuard
} from "../contracts/tenant-runtime.contract";

@Injectable()
export class TenantUsageMiddleware implements NestMiddleware {
  constructor(
    @Inject(TENANT_RUNTIME_GUARD)
    private readonly tenantRuntimeGuardService: TenantRuntimeGuard
  ) {}

  async use(req: Request, _res: Response, next: NextFunction): Promise<void> {
    try {
      await this.tenantRuntimeGuardService.enforceTenantRuntimePolicies(
        req,
        "http_usage_metering"
      );
      next();
    } catch (err) {
      next(err);
    }
  }
}

import { CanActivate, ExecutionContext, Inject, Injectable } from "@nestjs/common";
import { Reflector } from "@nestjs/core";
import { assertCheckAbilitiesForExecutionContext } from "./evaluate-check-abilities";
import { assertRequireCapabilitiesForExecutionContext } from "./evaluate-require-capabilities";
import { LoggerService } from "../logger/logger.service";
import { RequestContextService } from "../request-context/request-context.service";
import { WorkspaceAbilityFactoryService } from "./workspace-ability.factory.service";

/**
 * Enforces {@link CheckAbilities} metadata on a route handler. Intended to run **after**
 * {@link AuthorizationPresenceGuard} / {@link RolesGuard} so JWT + coarse role checks stay canonical.
 *
 * **Defense in depth:** pair with {@link CaslMirrorAbilitiesGuard} on sensitive controllers so CASL rules
 * are evaluated twice per request (mitigates accidental removal of one guard or decorator drift).
 * UI CASL is not a security boundary — this guard (and the mirror) are server-side enforcement.
 */
@Injectable()
export class AbilitiesGuard implements CanActivate {
  constructor(
    @Inject(Reflector) private readonly reflector: Reflector,
    @Inject(WorkspaceAbilityFactoryService)
    private readonly abilityFactory: WorkspaceAbilityFactoryService,
    @Inject(RequestContextService)
    private readonly requestContext: RequestContextService,
    @Inject(LoggerService) private readonly logger: LoggerService,
  ) {}

  canActivate(context: ExecutionContext): boolean {
    const http = context.switchToHttp();
    const req = http.getRequest<{ method?: string; path?: string; url?: string }>();
    const endpoint =
      typeof req.path === "string"
        ? `${req.method ?? "GET"} ${req.path}`
        : typeof req.url === "string"
          ? req.url
          : undefined;
    const logContext = {
      logger: this.logger,
      tenantId: this.requestContext.getTenantId(),
      userId: this.requestContext.getUserId(),
      role: this.requestContext.getRole(),
      endpoint,
    };
    assertCheckAbilitiesForExecutionContext(
      context,
      this.reflector,
      this.abilityFactory,
      logContext,
    );
    assertRequireCapabilitiesForExecutionContext(
      context,
      this.reflector,
      this.requestContext,
      logContext,
    );
    return true;
  }
}

import { CanActivate, ExecutionContext, Inject, Injectable } from "@nestjs/common";
import { Reflector } from "@nestjs/core";
import { assertCheckAbilitiesForExecutionContext } from "./evaluate-check-abilities";
import { assertRequireCapabilitiesForExecutionContext } from "./evaluate-require-capabilities";
import { RequestContextService } from "../request-context/request-context.service";
import { WorkspaceAbilityFactoryService } from "./workspace-ability.factory.service";

/**
 * Re-runs the same {@link CheckAbilities} evaluation as {@link AbilitiesGuard} using shared logic
 * in {@link assertCheckAbilitiesForExecutionContext}. Stack **after** {@link AbilitiesGuard} on controllers
 * where privilege escalation must be blocked even if one guard is misconfigured or removed from a route.
 *
 * UI CASL is not a security boundary — server-side guards enforce permissions.
 */
@Injectable()
export class CaslMirrorAbilitiesGuard implements CanActivate {
  constructor(
    @Inject(Reflector) private readonly reflector: Reflector,
    @Inject(WorkspaceAbilityFactoryService)
    private readonly abilityFactory: WorkspaceAbilityFactoryService,
    @Inject(RequestContextService)
    private readonly requestContext: RequestContextService,
  ) {}

  canActivate(context: ExecutionContext): boolean {
    assertCheckAbilitiesForExecutionContext(context, this.reflector, this.abilityFactory);
    assertRequireCapabilitiesForExecutionContext(context, this.reflector, this.requestContext);
    return true;
  }
}

import { SetMetadata } from "@nestjs/common";
import { subject } from "@casl/ability";
import type { AppAbility } from "@repo/shared";

export const CHECK_ABILITIES_KEY = "casl:check_abilities_handlers";

export type CheckAbilitiesContext = {
  ability: AppAbility;
  /** CASL helper for instance rules / field conditions (e.g. `isWaiverAllowed` on Payment). */
  subject: typeof subject;
};

/**
 * Route-level CASL checks (additive to {@link RolesGuard} when both are applied).
 *
 * @example
 * ```ts
 * @CheckAbilities(({ ability }) => ability.can(AbilityAction.Read, "UserMembership"))
 * @CheckAbilities(({ ability, subject }) =>
 *   ability.can(AbilityAction.Update, subject("Payment", { isWaiverAllowed: true }))
 * )
 * ```
 */
export function CheckAbilities(
  ...handlers: ReadonlyArray<(ctx: CheckAbilitiesContext) => boolean>
): MethodDecorator {
  return SetMetadata(CHECK_ABILITIES_KEY, handlers);
}

import { ExecutionContext, ForbiddenException } from "@nestjs/common";
import { Reflector } from "@nestjs/core";
import { subject } from "@casl/ability";
import { CHECK_ABILITIES_KEY, type CheckAbilitiesContext } from "./check-abilities.decorator";
import { logRbacEvent } from "../logging/rbac-logger";
import type { LoggerService } from "../logger/logger.service";
import type { WorkspaceAbilityFactoryService } from "./workspace-ability.factory.service";

export type CheckAbilitiesLogContext = {
  logger: LoggerService;
  tenantId?: string;
  userId?: string;
  role?: string;
  endpoint?: string;
};

/**
 * Runs merged {@link CheckAbilities} handlers for the active route (handler + class metadata).
 * No-op when no handlers are registered (caller decides fail-open vs fail-closed policy).
 */
export function assertCheckAbilitiesForExecutionContext(
  context: ExecutionContext,
  reflector: Reflector,
  abilityFactory: WorkspaceAbilityFactoryService,
  logContext?: CheckAbilitiesLogContext,
): void {
  const handlers =
    reflector.getAllAndMerge<Array<(ctx: CheckAbilitiesContext) => boolean>>(
      CHECK_ABILITIES_KEY,
      [context.getHandler(), context.getClass()]
    ) ?? [];

  if (handlers.length === 0) {
    return;
  }

  const ability = abilityFactory.createForActiveRequest();
  const checkCtx: CheckAbilitiesContext = { ability, subject };

  for (const handler of handlers) {
    if (!handler(checkCtx)) {
      if (logContext) {
        logRbacEvent(logContext.logger, {
          tenantId: logContext.tenantId,
          userId: logContext.userId,
          role: logContext.role,
          endpoint: logContext.endpoint,
          action: "check_abilities",
          result: "deny",
        });
      }
      throw new ForbiddenException({
        error: {
          code: "AUTH_FORBIDDEN_ABILITY",
          message: "Insufficient permissions for this operation"
        }
      });
    }
  }
}

import { Inject, Injectable } from "@nestjs/common";
import {
  defineAbilityFor,
  type AppAbility,
  type UserAbilityContext,
  type UserAbilityMembershipStatus
} from "@repo/shared";
import { RequestContextService } from "../request-context/request-context.service";

/**
 * Builds a per-request {@link AppAbility} from ALS-backed {@link RequestContextService}.
 * `membership_status` and labels are populated by auth / future loaders.
 */
@Injectable()
export class WorkspaceAbilityFactoryService {
  constructor(@Inject(RequestContextService) private readonly requestContext: RequestContextService) {}

  /**
   * Returns an ability for the authenticated workspace actor.
   * When user id or role is missing, yields a minimal fail-closed ability (read-only workspace shell).
   */
  createForActiveRequest(): AppAbility {
    const id = this.requestContext.tryGetUserId();
    const role = this.requestContext.tryGetRole();
    if (!id || !role) {
      return defineAbilityFor({
        id: "00000000-0000-4000-8000-000000000000",
        role: "none",
        status: "SUSPENDED"
      });
    }

    const status =
      (this.requestContext.tryGetWorkspaceMembershipStatus() as UserAbilityMembershipStatus | undefined) ??
      "ACTIVE";
    const labels = this.requestContext.tryGetAbilityLabels() ?? null;
    const capabilities = this.requestContext.tryGetWorkspaceCapabilities() ?? null;
    const tenantModules = this.requestContext.tryGetTenantEnabledModules() ?? null;
    const membershipMetadata = this.requestContext.tryGetMembershipMetadata();

    const ctx: UserAbilityContext = {
      id,
      role,
      status,
      labels,
      capabilities,
      tenantModules,
      membershipMetadata,
    };
    return defineAbilityFor(ctx);
  }
}

