import { Injectable } from "@nestjs/common";
import { Resend } from "resend";

import { ConfigService } from "../../config/config.service";
import { LoggerService } from "../logger/logger.service";

/** Resend-documented onboarding address for API testing when `RESEND_FROM` is unset. */
const RESEND_ONBOARDING_FROM = "onboarding@resend.dev";

@Injectable()
export class EmailService {
  private readonly resend: Resend | null;

  constructor(
    private readonly configService: ConfigService,
    private readonly loggerService: LoggerService
  ) {
    const apiKey = this.configService.getResendApiKey();
    this.resend = apiKey !== "" ? new Resend(apiKey) : null;
  }

  /** Outbox/worker path: skips quietly without Resend configured; otherwise throws on Hard failures (retryable). */
  async sendVerificationEmailOutboundStrict(to: string, codeOrLink: string): Promise<void> {
    const toTrimmed = to.trim();
    if (toTrimmed === "") {
      throw new Error("Email verification outbound: empty recipient address");
    }

    const apiKey = this.configService.getResendApiKey();
    if (apiKey === "" || this.resend === null) {
      this.loggerService.warn("email_send_skipped_no_resend_api_key", {});
      return;
    }

    const configuredFrom = this.configService.getResendFrom();
    const from = configuredFrom !== "" ? configuredFrom : RESEND_ONBOARDING_FROM;

    const escaped = codeOrLink.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
    const base = this.configService.getFrontendBaseUrl();
    let linkParagraph = "";
    if (base !== "") {
      try {
        /** Fragment keeps the opaque token off the wire to the HTTP server/query logs. */
        const relative = `settings#verify_email_token=${encodeURIComponent(codeOrLink)}`;
        const u = new URL(relative, base.endsWith("/") ? base : `${base}/`);
        if (u.protocol === "http:" || u.protocol === "https:") {
          const href = u.href.replace(/&/g, "&amp;").replace(/"/g, "&quot;");
          linkParagraph = `<p><a href="${href}">Open settings to verify your email</a></p>`;
        }
      } catch {
        /* malformed FRONTEND_BASE_URL — skip link */
      }
    }
    const html = `<p>Verify your email using this token:</p><p><strong>${escaped}</strong></p>${linkParagraph}`;

    const { data, error } = await this.resend.emails.send({
      from,
      to: [toTrimmed],
      subject: "Verify your email",
      html
    });
    if (error) {
      throw new Error(error.message ?? "Resend email send rejected");
    }
    this.loggerService.info("email_send_verification_ok", { to: toTrimmed, id: data?.id });
  }

  async sendVerificationEmail(to: string, codeOrLink: string): Promise<void> {
    const toTrimmed = to.trim();
    if (toTrimmed === "") {
      this.loggerService.warn("email_send_skipped_empty_to", {});
      return;
    }
    try {
      await this.sendVerificationEmailOutboundStrict(toTrimmed, codeOrLink);
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : String(err);
      this.loggerService.error("email_send_verification_failed", { to: toTrimmed, message: msg });
    }
  }
}

import {
  ArgumentsHost,
  Catch,
  ExceptionFilter,
  HttpException,
  HttpStatus
} from "@nestjs/common";
import { randomUUID } from "node:crypto";
import type { Request, Response } from "express";
import { QueryFailedError } from "typeorm";
import { TenantContextMissingError } from "./tenant-context-missing.error";
import { mapValidationPipeErrors } from "./validation-errors.mapper";
import { LoggerService } from "../logger/logger.service";
import type { ObservabilityMetricsService } from "../observability/observability-metrics.service";
import { RequestContextService } from "../request-context/request-context.service";

/** Standard API error JSON (HTTP error responses). */
export type ApiErrorBody = {
  code: string;
  message: string;
  correlationId: string;
  retryability: "NO_RETRY" | "SAFE_RETRY" | "RETRY_WITH_BACKOFF" | "RETRY_AFTER_ACTION";
  details: Record<string, unknown>;
};

type ErrorEnvelope = {
  success: false;
  requestId: string;
  error: ApiErrorBody;
};

type RequestWithRequestId = Request & { requestId?: string };

const RETRYABILITY_VALUES = new Set<ApiErrorBody["retryability"]>([
  "NO_RETRY",
  "SAFE_RETRY",
  "RETRY_WITH_BACKOFF",
  "RETRY_AFTER_ACTION"
]);

import { GlobalErrorTaxonomy } from "@repo/shared";

@Catch()
export class GlobalExceptionFilter implements ExceptionFilter {
  private static readonly CANONICAL_ERROR_CODES = new Set<string>([
    ...Object.values(GlobalErrorTaxonomy.AUTH),
    ...Object.values(GlobalErrorTaxonomy.TENANT),
    ...Object.values(GlobalErrorTaxonomy.RBAC),
    ...Object.values(GlobalErrorTaxonomy.VALIDATION),
    ...Object.values(GlobalErrorTaxonomy.RESOURCE),
    ...Object.values(GlobalErrorTaxonomy.SYSTEM),
    "VALIDATION_UNKNOWN_FIELD",
    "AUTH_NO_ACTIVE_MEMBERSHIP",
    "AUTH_OTP_INVALID",
    "AUTH_OTP_EXPIRED",
    "AUTH_TOKEN_REVOKED",
    "AUTH_TOKEN_STALE",
    "AUTH_FORBIDDEN_ROLE",
    "AUTH_FORBIDDEN_ABILITY",
    "TENANT_HOST_RESERVED",
    "TENANT_HOST_MISMATCH",
    "TENANT_HOST_TOKEN_MISMATCH",
    "TENANT_SCOPE_CONFLICT",
    "REGISTRATION_DUPLICATE_ACTIVE",
    "REGISTRATION_ROW_VERSION_CONFLICT",
    "CAPACITY_FULL",
    "WAITLIST_CONFLICT_ACTIVE_RECORD",
    "PAYMENT_STATUS_TRANSITION_INVALID",
    "PAYMENT_PENDING_EXISTS",
    "PAYMENT_DEBT_AFTER_SETTLEMENT_FORBIDDEN",
    "PAID_TOUR_REQUIRES_AMOUNT",
    "NOT_AUTHORIZED_TO_UPLOAD_RECEIPT_FOR_THIS_PAYMENT",
    "RECEIPT_PENDING_ALREADY_EXISTS_FOR_PAYMENT",
    "INVALID_LIFECYCLE_TRANSITION",
    "TOUR_NOT_PUBLISHABLE",
    "TOUR_NOT_OPEN",
    "TOUR_PATCH_FIELD_FORBIDDEN",
    "EXPORT_SNAPSHOT_INCONSISTENT",
    "PROFILE_ROW_VERSION_CONFLICT",
    "USER_EMAIL_CONFLICT",
    "USER_NATIONAL_ID_CONFLICT",
    "USER_NATIONAL_ID_INVALID",
    "USER_BIRTH_DATE_INVALID",
    "EMAIL_VERIFICATION_INVALID",
    "USER_PHONE_UNCHANGED",
    "USER_PHONE_CONFLICT",
    "MOBILE_OTP_INVALID_PURPOSE",
    "USER_NOT_FOUND",
    "INVITE_NOT_FOUND",
    "INVITE_EMAIL_MISMATCH",
    "INVITE_EXPIRED",
    "WEBHOOK_SIGNATURE_INVALID",
    "WEBHOOK_TIMESTAMP_INVALID",
    "WEBHOOK_TIMESTAMP_EXPIRED",
    "WEBHOOK_IP_NOT_ALLOWED",
    "RBAC_OWNER_ROLE_ASSIGNMENT_FORBIDDEN",
    "RBAC_PROTECTED_ROLE_MODIFICATION_FORBIDDEN",
    "RBAC_UNKNOWN_MEMBERSHIP_ROLE",
    "SCHEMA_DRIFT_MISSING_COLUMN",
    "SCHEMA_DRIFT_MISSING_TABLE",
    "OPS_UNAUTHORIZED",
    "DESTINATION_NOT_IN_WORKSPACE"
  ]);

  constructor(
    private readonly loggerService: LoggerService,
    private readonly requestContextService: RequestContextService,
    private readonly observabilityMetricsService?: ObservabilityMetricsService
  ) {}

  catch(exception: unknown, host: ArgumentsHost): void {
    const ctx = host.switchToHttp();
    const response = ctx.getResponse<Response>();
    const request = ctx.getRequest<Request>();
    const { requestId, correlationId } = this.resolveCorrelationBundle(request);

    if (exception instanceof TenantContextMissingError) {
      const envelope = this.buildEnvelope(
        {
          code: "TENANT_CONTEXT_MISSING",
          message: "Tenant context lost during request processing",
          retryability: "NO_RETRY",
          details: {}
        },
        requestId,
        correlationId
      );
      this.observabilityMetricsService?.recordHttpException({
        errorCode: envelope.error.code,
        path: typeof request.path === "string" ? request.path : "",
        method: typeof request.method === "string" ? request.method : "",
        statusCode: HttpStatus.INTERNAL_SERVER_ERROR
      });
      this.loggerService.error("security anomaly: tenant context lost", {
        status_code: HttpStatus.INTERNAL_SERVER_ERROR,
        route: typeof request.path === "string" ? request.path : request.url,
        error_code: envelope.error.code,
        trace_id: correlationId,
        exception_message: exception.message,
        exception_stack: exception.stack
      });
      response.status(HttpStatus.INTERNAL_SERVER_ERROR).json(envelope);
      return;
    }

    if (exception instanceof HttpException) {
      const status = exception.getStatus();
      const normalized = this.normalizeHttpException(
        exception,
        status,
        requestId,
        correlationId
      );

      this.observabilityMetricsService?.recordHttpException({
        errorCode: normalized.error.code,
        path: typeof request.path === "string" ? request.path : "",
        method: typeof request.method === "string" ? request.method : "",
        statusCode: status
      });

      this.loggerService.error("request failed", {
        status_code: status,
        route: typeof request.path === "string" ? request.path : request.url,
        error_code: normalized.error.code,
        trace_id: correlationId,
        exception_message: exception.message,
        exception_stack: exception.stack
      });

      response.status(status).json(normalized);
      return;
    }

    const fallback = this.normalizeUnknownException(exception, requestId, correlationId);

    this.observabilityMetricsService?.recordHttpException({
      errorCode: fallback.error.code,
      path: typeof request.path === "string" ? request.path : "",
      method: typeof request.method === "string" ? request.method : "",
      statusCode: HttpStatus.INTERNAL_SERVER_ERROR
    });

    this.loggerService.error("unexpected request failure", {
      status_code: HttpStatus.INTERNAL_SERVER_ERROR,
      route: typeof request.path === "string" ? request.path : request.url,
      error_code: fallback.error.code,
      trace_id: correlationId,
      exception_name: exception instanceof Error ? exception.name : undefined,
      exception_message: exception instanceof Error ? exception.message : String(exception),
      exception_stack: exception instanceof Error ? exception.stack : undefined
    });

    response.status(HttpStatus.INTERNAL_SERVER_ERROR).json(fallback);
  }

  private buildEnvelope(
    partial: Pick<ApiErrorBody, "code" | "message"> &
      Partial<Pick<ApiErrorBody, "retryability" | "details">>,
    requestId: string,
    correlationId: string
  ): ErrorEnvelope {
    const retryability = this.normalizeRetryability(partial.retryability);
    const baseDetails =
      partial.details && typeof partial.details === "object" && !Array.isArray(partial.details)
        ? (partial.details as Record<string, unknown>)
        : {};
    let tenantId: string | undefined;
    try {
      tenantId = this.requestContextService.tryGetTenantId();
    } catch {
      tenantId = undefined;
    }
    const details: Record<string, unknown> = {
      ...baseDetails,
      requestId,
      ...(tenantId ? { tenantId } : {}),
      timestamp: new Date().toISOString(),
    };
    return {
      success: false,
      requestId,
      error: {
        code: partial.code,
        message: partial.message,
        correlationId,
        retryability,
        details
      }
    };
  }

  private normalizeRetryability(
    value: ApiErrorBody["retryability"] | undefined
  ): ApiErrorBody["retryability"] {
    if (value && RETRYABILITY_VALUES.has(value)) {
      return value;
    }
    return "NO_RETRY";
  }

  private normalizeUnknownException(
    exception: unknown,
    requestId: string,
    correlationId: string
  ): ErrorEnvelope {
    if (exception instanceof QueryFailedError || this.isTypeOrmQueryFailedError(exception)) {
      const schemaDriftCode = this.resolveSchemaDriftErrorCode(exception);
      return this.buildEnvelope(
        {
          code: schemaDriftCode,
          message: "Database schema is out of sync with application expectations",
          retryability: "NO_RETRY",
          details: {}
        },
        requestId,
        correlationId
      );
    }

    if (
      exception instanceof Error &&
      (exception.message === "TENANT_CONTEXT_INVALID" ||
        exception.message === "TENANT_CONTEXT_MISSING")
    ) {
      return this.buildEnvelope(
        {
          code: exception.message,
          message:
            exception.message === "TENANT_CONTEXT_INVALID"
              ? "Trusted tenant context is invalid"
              : "Trusted tenant context required but absent",
          retryability: "NO_RETRY",
          details: {}
        },
        requestId,
        correlationId
      );
    }

    return this.buildEnvelope(
      {
        code: "INTERNAL_ERROR",
        message: "An unexpected error occurred",
        retryability: "NO_RETRY",
        details: {}
      },
      requestId,
      correlationId
    );
  }

  private isTypeOrmQueryFailedError(exception: unknown): boolean {
    if (!exception || typeof exception !== "object") {
      return false;
    }
    const withName = exception as { name?: unknown };
    return withName.name === "QueryFailedError";
  }

  private resolveSchemaDriftErrorCode(exception: unknown): string {
    const message = exception instanceof Error ? exception.message.toLowerCase() : String(exception).toLowerCase();
    if (message.includes("column") && message.includes("does not exist")) {
      return "SCHEMA_DRIFT_MISSING_COLUMN";
    }
    if (message.includes("relation") && message.includes("does not exist")) {
      return "SCHEMA_DRIFT_MISSING_TABLE";
    }
    return "SCHEMA_DRIFT_QUERY_FAILED";
  }

  private resolveCorrelationBundle(request: Request): { requestId: string; correlationId: string } {
    const headers = request.headers ?? {};
    const headerRequestIdRaw = headers["x-request-id"];
    const headerRequestId =
      typeof headerRequestIdRaw === "string" && headerRequestIdRaw.trim() !== ""
        ? headerRequestIdRaw.trim()
        : Array.isArray(headerRequestIdRaw) &&
            typeof headerRequestIdRaw[0] === "string" &&
            headerRequestIdRaw[0].trim() !== ""
          ? headerRequestIdRaw[0].trim()
          : undefined;

    const headerCorrRaw = headers["x-correlation-id"];
    const headerCorrelationId =
      typeof headerCorrRaw === "string" && headerCorrRaw.trim() !== ""
        ? headerCorrRaw.trim()
        : Array.isArray(headerCorrRaw) &&
            typeof headerCorrRaw[0] === "string" &&
            headerCorrRaw[0].trim() !== ""
          ? headerCorrRaw[0].trim()
          : undefined;

    const fromRequestAug = (request as RequestWithRequestId).requestId;
    const fromRequestAugId =
      typeof fromRequestAug === "string" && fromRequestAug.trim() !== "" ? fromRequestAug.trim() : undefined;

    let ctxRequestId: string | undefined;
    let ctxCorrelationId: string | undefined;
    try {
      ctxRequestId = this.requestContextService.tryGetRequestId();
    } catch {
      ctxRequestId = undefined;
    }
    try {
      ctxCorrelationId = this.requestContextService.tryGetCorrelationId();
    } catch {
      ctxCorrelationId = undefined;
    }

    // Prefer ALS / req.requestId from RequestContextMiddleware over raw headers.
    const requestId =
      ctxRequestId?.trim() ||
      fromRequestAugId ||
      headerRequestId ||
      randomUUID();

    const correlationId =
      ctxCorrelationId?.trim() || headerCorrelationId || requestId;

    return { requestId, correlationId };
  }

  private normalizeHttpException(
    exception: HttpException,
    status: number,
    requestId: string,
    correlationId: string
  ): ErrorEnvelope {
    const body = exception.getResponse();

    if (status === HttpStatus.BAD_REQUEST && this.isValidationPipeErrorBody(body)) {
      const validationErrors = mapValidationPipeErrors(body);
      return this.buildEnvelope(
        {
          code: "VALIDATION_FAILED",
          message: "Request validation failed",
          retryability: "NO_RETRY",
          details: { validationErrors }
        },
        requestId,
        correlationId
      );
    }

    if (this.hasStructuredErrorBody(body)) {
      const raw = body.error;
      const code =
        typeof raw.code === "string" && raw.code.trim() !== ""
          ? this.isCanonicalCode(raw.code)
            ? raw.code
            : raw.code.trim()
          : "INTERNAL_ERROR";
      const message =
        typeof raw.message === "string" && raw.message.trim() !== ""
          ? raw.message.trim()
          : this.resolveFallbackMessage(body, exception);
      const retryability = this.normalizeRetryability(
        typeof raw.retryability === "string" ? (raw.retryability as ApiErrorBody["retryability"]) : undefined
      );
      const details = this.coerceDetails(raw.details);
      return this.buildEnvelope({ code, message, retryability, details }, requestId, correlationId);
    }

    const canonicalFromBody = this.extractCanonicalCodeFromBodyMessage(body);
    const code = canonicalFromBody ?? this.mapStatusToErrorCode(status);
    const fallbackMessage = canonicalFromBody
      ? canonicalFromBody
      : this.resolveFallbackMessage(body, exception);

    return this.buildEnvelope(
      {
        code,
        message: fallbackMessage,
        retryability: this.defaultRetryabilityForHttpStatus(status),
        details: {}
      },
      requestId,
      correlationId
    );
  }

  private defaultRetryabilityForHttpStatus(status: number): ApiErrorBody["retryability"] {
    if (status === HttpStatus.TOO_MANY_REQUESTS || status === HttpStatus.SERVICE_UNAVAILABLE) {
      return "RETRY_WITH_BACKOFF";
    }
    return "NO_RETRY";
  }

  private coerceDetails(value: unknown): Record<string, unknown> {
    if (value && typeof value === "object" && !Array.isArray(value)) {
      return value as Record<string, unknown>;
    }
    return {};
  }

  private mapStatusToErrorCode(status: number): string {
    if (status >= 500) {
      return "INTERNAL_ERROR";
    }
    switch (status) {
      case HttpStatus.UNAUTHORIZED:
        return "AUTH_UNAUTHENTICATED";
      case HttpStatus.FORBIDDEN:
        return "AUTH_FORBIDDEN_ROLE";
      case HttpStatus.NOT_FOUND:
        return "RESOURCE_NOT_FOUND";
      case HttpStatus.CONFLICT:
        return "STATE_TRANSITION_INVALID";
      case HttpStatus.TOO_MANY_REQUESTS:
        return "RATE_LIMITED";
      default:
        return "INTERNAL_ERROR";
    }
  }

  private resolveFallbackMessage(body: unknown, exception: HttpException): string {
    if (typeof body === "string" && body.trim() !== "") {
      return body;
    }
    if (body && typeof body === "object") {
      const candidate = body as { message?: unknown };
      if (typeof candidate.message === "string" && candidate.message.trim() !== "") {
        return candidate.message;
      }
    }
    return exception.message || "Request failed";
  }

  private extractCanonicalCodeFromBodyMessage(body: unknown): string | null {
    if (!body || typeof body !== "object") {
      return null;
    }
    const candidate = body as { message?: unknown };
    if (typeof candidate.message !== "string") {
      return null;
    }
    return this.isCanonicalCode(candidate.message) ? candidate.message : null;
  }

  private isCanonicalCode(value: string): boolean {
    return (
      GlobalExceptionFilter.CANONICAL_ERROR_CODES.has(value) || value.startsWith("WORKSPACE_RULE_")
    );
  }

  private hasStructuredErrorBody(
    body: unknown
  ): body is {
    error: {
      code: string;
      message: string;
      retryability?: unknown;
      details?: unknown;
    };
  } {
    if (!body || typeof body !== "object") {
      return false;
    }

    const candidate = body as {
      error?: { code?: unknown; message?: unknown };
    };

    return (
      typeof candidate.error?.code === "string" &&
      typeof candidate.error?.message === "string"
    );
  }

  private isValidationPipeErrorBody(
    body: unknown
  ): body is { message: unknown[]; error?: string } {
    if (!body || typeof body !== "object") {
      return false;
    }
    const candidate = body as { message?: unknown; error?: unknown };
    return (
      Array.isArray(candidate.message) &&
      candidate.message.length > 0 &&
      (candidate.error === undefined || typeof candidate.error === "string")
    );
  }
}

import { Injectable } from "@nestjs/common";
import { LoggerService } from "../logger/logger.service";
import type { DomainEvent } from "./domain-event.interface";
import type { EventHandler } from "./event-handler.interface";
import { BOOKING_CREATED_EVENT_TYPE, type BookingCreatedPayload } from "./booking-created.event";

/**
 * Sample side-effect handler: structured log only. **Not** wired from controllers — registered on the
 * in-memory bus by {@link EventsModule}.
 *
 * Production: replace or supplement with outbox consumers (audit pipeline, analytics, etc.).
 */
@Injectable()
export class AuditBookingCreatedHandler implements EventHandler {
  readonly handledEventTypes = [BOOKING_CREATED_EVENT_TYPE] as const;

  constructor(private readonly logger: LoggerService) {}

  async handle(event: DomainEvent<unknown>): Promise<void> {
    const payload = event.payload as BookingCreatedPayload;
    this.logger.info("domain_event_booking_created_audit", {
      event_id: event.eventId,
      event_type: event.eventType,
      schema_version: event.schemaVersion,
      tenant_id: event.tenantId,
      correlation_id: event.correlationId,
      registration_id: payload.registrationId,
      tour_id: payload.tourId
    });
  }
}

import type { DomainEvent } from "./domain-event.interface";

/**
 * Subscribes to one or more `eventType` strings from {@link DomainEventEnvelope}.
 * Handlers must be idempotent where possible — at-least-once delivery is typical with brokers/outbox.
 */
export interface EventHandler {
  readonly handledEventTypes: readonly string[];
  handle(event: DomainEvent<unknown>): Promise<void>;
}

import type { DomainEvent } from "./domain-event.interface";

/**
 * Port for publishing domain events. Implementations may be in-memory (dev), outbox-backed (prod), etc.
 * Callers should publish **after** successful persistence (or from within the same transaction when using outbox).
 */
export interface EventPublisher {
  publish<TPayload>(event: DomainEvent<TPayload>): Promise<void>;
}

import { Global, Inject, Injectable, Module, OnModuleInit } from "@nestjs/common";
import { ConfigService } from "../../config/config.service";
import { LoggerModule } from "../logger/logger.module";
import { AuditBookingCreatedHandler } from "./audit-booking-created.handler";
import { InMemoryEventBus } from "./in-memory-event-bus";
import { NoOpEventPublisher } from "./noop-event-publisher";
import { EVENT_PUBLISHER } from "./event-tokens";
import type { EventPublisher } from "./event-publisher.interface";

@Injectable()
class EventsModuleInit implements OnModuleInit {
  constructor(
    @Inject(ConfigService) private readonly config: ConfigService,
    @Inject(InMemoryEventBus) private readonly bus: InMemoryEventBus,
    @Inject(AuditBookingCreatedHandler)
    private readonly auditBookingCreated: AuditBookingCreatedHandler
  ) {}

  onModuleInit(): void {
    if (this.config.getEnableInMemoryDomainEvents()) {
      this.bus.register(this.auditBookingCreated);
    }
  }
}

/**
 * Domain event infrastructure. **Production:** {@link EVENT_PUBLISHER} defaults to {@link NoOpEventPublisher};
 * critical flows emit via {@link OutboxService} in the same DB transaction. Opt-in
 * `ENABLE_IN_MEMORY_DOMAIN_EVENTS=true` wires the in-memory bus for local debugging only.
 */
@Global()
@Module({
  imports: [LoggerModule],
  providers: [
    InMemoryEventBus,
    AuditBookingCreatedHandler,
    NoOpEventPublisher,
    EventsModuleInit,
    {
      provide: EVENT_PUBLISHER,
      useFactory: (
        config: ConfigService,
        inMemory: InMemoryEventBus,
        noop: NoOpEventPublisher
      ): EventPublisher => (config.getEnableInMemoryDomainEvents() ? inMemory : noop),
      inject: [ConfigService, InMemoryEventBus, NoOpEventPublisher]
    }
  ],
  exports: [InMemoryEventBus, AuditBookingCreatedHandler, EVENT_PUBLISHER, NoOpEventPublisher]
})
export class EventsModule {}

import { Injectable } from "@nestjs/common";
import { LoggerService } from "../logger/logger.service";
import type { DomainEvent } from "./domain-event.interface";
import type { EventHandler } from "./event-handler.interface";
import type { EventPublisher } from "./event-publisher.interface";

/**
 * **Development / single-process only** — handlers run in-process after `publish` resolves.
 * Events are **not** persisted: process crash = lost events. No cross-replica fan-out.
 *
 * **Production:** use a **transactional outbox** table written in the same DB transaction as domain
 * mutations, plus a relay worker pushing to Kafka/Rabbit/SNS (or equivalent). Replace this
 * registration with an outbox-backed `EventPublisher` while keeping the same port shape.
 *
 * Error policy: each handler runs in isolation; failures are logged and **never** reject `publish`
 * or throw into the caller (no crash propagation).
 */
@Injectable()
export class InMemoryEventBus implements EventPublisher {
  private readonly handlersByType = new Map<string, Set<EventHandler>>();

  constructor(private readonly logger: LoggerService) {}

  register(handler: EventHandler): void {
    for (const t of handler.handledEventTypes) {
      let set = this.handlersByType.get(t);
      if (!set) {
        set = new Set();
        this.handlersByType.set(t, set);
      }
      set.add(handler);
    }
  }

  async publish<TPayload>(event: DomainEvent<TPayload>): Promise<void> {
    const set = this.handlersByType.get(event.eventType);
    if (!set || set.size === 0) {
      return;
    }
    for (const handler of set) {
      void this.dispatchSafely(handler, event as DomainEvent<unknown>);
    }
  }

  private dispatchSafely(handler: EventHandler, event: DomainEvent<unknown>): void {
    queueMicrotask(() => {
      void (async () => {
        try {
          await handler.handle(event);
        } catch (error: unknown) {
          const name = handler.constructor?.name ?? "EventHandler";
          this.logger.error("domain_event_handler_failed", {
            event_id: event.eventId,
            event_type: event.eventType,
            handler: name,
            error_name: error instanceof Error ? error.name : typeof error,
            error_message: error instanceof Error ? error.message : String(error)
          });
        }
      })();
    });
  }
}

import { Inject, Injectable } from "@nestjs/common";
import pino, { type Logger } from "pino";
import { tryGetActiveTraceLogFields } from "../observability/active-trace-log-fields";
import { RequestContextService } from "../request-context/request-context.service";
import { ConfigService } from "../../config/config.service";

/**
 * Nest-facing **Pino** logger: every line is merged with ALS context (`tenant_id`, `user_id`,
 * `correlation_id`, `request_id`, …) and optional W3C `trace_id` / `span_id` when OTEL is active.
 *
 * **Redaction (call-site discipline — not automatic stripping yet):**
 * - **Tokens:** never log `Authorization`, bearer strings, refresh/access tokens, session cookies, or webhook secrets.
 * - **Medical / PHI:** never log free-text diagnoses, medications, or emergency-contact phone bodies — use opaque ids + severity enums only.
 * - **Secrets:** never log API keys, DB URLs with passwords, private keys, or KMS plaintext.
 *
 * TODO: central `pino.redact` paths + serializers for `req`/`err` once log volume grows.
 */
type LogMeta = Record<string, unknown>;

@Injectable()
export class LoggerService {
  private readonly logger: Logger;

  constructor(
    @Inject(ConfigService) private readonly configService: ConfigService,
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService
  ) {
    this.logger = pino({
      level: this.configService.getLogLevel(),
      timestamp: pino.stdTimeFunctions.isoTime
    });
  }

  debug(message: string, meta: LogMeta = {}): void {
    this.logger.debug(this.withRequestContext(meta), message);
  }

  info(message: string, meta: LogMeta = {}): void {
    this.logger.info(this.withRequestContext(meta), message);
  }

  warn(message: string, meta: LogMeta = {}): void {
    this.logger.warn(this.withRequestContext(meta), message);
  }

  error(message: string, meta: LogMeta = {}): void {
    this.logger.error(this.withRequestContext(meta), message);
  }

  private withRequestContext(meta: LogMeta): LogMeta {
    const traceFields = tryGetActiveTraceLogFields();
    const ctx = this.requestContextService.tryGetStructuredLogContext();
    return {
      ...(traceFields ?? {}),
      ...(ctx ?? {}),
      ...meta
    };
  }
}

import {
  ForbiddenException,
  Inject,
  Injectable,
  NestMiddleware,
  UnauthorizedException
} from "@nestjs/common";
import { InjectDataSource } from "@nestjs/typeorm";
import { jwtVerify } from "jose";
import type { NextFunction, Request, Response } from "express";
import type { DataSource } from "typeorm";
import { loadPublicKey } from "../../auth/jwt-key.util";
import { ConfigService } from "../../config/config.service";
import {
  AUTH_PUBLIC_HOST_PROBE_ROUTES,
  AUTH_SESSION_LOGIN_ROUTES,
  skipsJwtHostTenantAlignment,
} from "../auth/auth-route-policy";
import { authRequiredError } from "../errors/error-response-builders";
import { LoggerService } from "../logger/logger.service";
import { tryParseWorkspaceUserRole } from "../auth/user-role.enum";
import { RequestContextService } from "../request-context/request-context.service";
import { verifyActiveMembershipAndHydrateContext } from "./auth-membership-verification";

type JwtClaims = {
  sub?: string;
  tenant_id?: string;
  role?: string;
  email?: string;
  sess_ver?: unknown;
  /** Comma-separated effective capability snapshot (Phase 8.2). */
  caps?: string;
};

const PUBLIC_ROUTES = [
  "/health",
  "/internal",
  "/api/docs",
  ...AUTH_SESSION_LOGIN_ROUTES,
  ...AUTH_PUBLIC_HOST_PROBE_ROUTES,
];
const JWT_COOKIE_NAME = "jwt";
const PRIMARY_SESSION_TOKEN_COOKIE = "tour_ops_session";
const ALT_SESSION_TOKEN_COOKIE = "session";

function extractCookieToken(cookieHeader: string | undefined, cookieName: string): string | undefined {
  if (!cookieHeader) {
    return undefined;
  }
  const chunks = cookieHeader.split(";");
  for (const chunk of chunks) {
    const [rawName, ...rest] = chunk.trim().split("=");
    if (rawName !== cookieName) {
      continue;
    }
    const rawValue = rest.join("=").trim();
    if (!rawValue) {
      return undefined;
    }
    try {
      return decodeURIComponent(rawValue);
    } catch {
      return rawValue;
    }
  }
  return undefined;
}

@Injectable()
export class AuthMiddleware implements NestMiddleware {
  constructor(
    @Inject(ConfigService) private readonly configService: ConfigService,
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService,
    @InjectDataSource() private readonly dataSource: DataSource,
    @Inject(LoggerService) private readonly loggerService: LoggerService
  ) {}

  /**
   * For public POST `/api/v2/tours/:id/register|waitlist` (and GET mint for keys), authentication is not required.
   * Public mutations require a non-blank `Idempotency-Key` header (enforced in {@link RegistrationsController}).
   * When a valid session token is present anyway, attach JWT context so downstream handlers
   * (e.g. tour policies keyed off profile fields) can resolve `userId`.
   */
  private async tryAttachJwtContextForPublicTourPlacement(req: Request): Promise<void> {
    try {
      const token = this.extractToken(req);
      if (!token) {
        return;
      }

      const publicKey = await loadPublicKey(this.configService.getJwtPublicKey());
      let payload: JwtClaims;
      try {
        const verified = await jwtVerify(token, publicKey, {
          algorithms: ["RS256"],
          issuer: this.configService.getJwtIssuer(),
          audience: this.configService.getJwtAudience(),
          clockTolerance: "5s"
        });
        payload = verified.payload as JwtClaims;
      } catch {
        return;
      }

      if (
        typeof payload.sub !== "string" ||
        typeof payload.tenant_id !== "string" ||
        typeof payload.role !== "string"
      ) {
        return;
      }

      const jwtSessionVersion =
        typeof payload.sess_ver === "number"
          ? payload.sess_ver
          : typeof payload.sess_ver === "string" && payload.sess_ver.trim() !== ""
            ? Number(payload.sess_ver)
            : NaN;
      if (!Number.isInteger(jwtSessionVersion) || jwtSessionVersion < 1) {
        return;
      }

      const userId = payload.sub.trim();
      const tenantId = payload.tenant_id.trim();
      const roleRaw = payload.role.trim();
      const role = tryParseWorkspaceUserRole(roleRaw);
      if (!userId || !tenantId || !role) {
        return;
      }

      const hostTenantEntity = req.tenant;
      if (
        hostTenantEntity?.id &&
        !skipsJwtHostTenantAlignment(req.path, req.method) &&
        hostTenantEntity.id.trim().toLowerCase() !== tenantId.trim().toLowerCase()
      ) {
        return;
      }

      const queryRunner = this.dataSource.createQueryRunner();
      try {
        await queryRunner.connect();

        const result = await verifyActiveMembershipAndHydrateContext({
          userId,
          tenantId,
          jwtRole: role,
          jwtSessionVersion,
          jwtCapsClaim: payload.caps,
          queryRunner,
          requestContextService: this.requestContextService,
          loggerService: this.loggerService,
          silentOnFailure: true
        });
        if (!result.ok) {
          return;
        }
      } finally {
        await queryRunner.release();
      }
    } catch {
      /* anonymous registration — ignore optional auth failures */
    }
  }

  private extractToken(req: Request): string | undefined {
    const cookieHeader = req.header("cookie");
    const jwtCookieToken = extractCookieToken(cookieHeader, JWT_COOKIE_NAME);
    if (jwtCookieToken) {
      this.loggerService.debug("AuthMiddleware: using token from jwt cookie");
      return jwtCookieToken;
    }

    const primaryCookieToken = extractCookieToken(cookieHeader, PRIMARY_SESSION_TOKEN_COOKIE);
    if (primaryCookieToken) {
      this.loggerService.debug("AuthMiddleware: using token from tour_ops_session cookie");
      return primaryCookieToken;
    }

    const altCookieToken = extractCookieToken(cookieHeader, ALT_SESSION_TOKEN_COOKIE);
    if (altCookieToken) {
      this.loggerService.debug("AuthMiddleware: using token from session cookie");
      return altCookieToken;
    }

    const authHeader = req.header("authorization");
    if (typeof authHeader === "string") {
      const [scheme, bearerToken] = authHeader.split(" ");
      if (scheme?.toLowerCase() === "bearer" && typeof bearerToken === "string" && bearerToken.trim() !== "") {
        this.loggerService.debug("AuthMiddleware: using token from Authorization header");
        return bearerToken.trim();
      }
    }

    this.loggerService.debug("AuthMiddleware: no auth token found");
    return undefined;
  }

  /** Fire-and-forget vitality timestamp — must not block request handling. */
  private touchUserLastActiveAtAsync(userId: string): void {
    void this.dataSource
      .query(`UPDATE users SET last_active_at = now() WHERE id = $1 AND deleted_at IS NULL`, [
        userId
      ])
      .catch((err: unknown) => {
        this.loggerService.debug("AuthMiddleware: last_active_at touch skipped", {
          userId,
          error: err instanceof Error ? err.message : String(err)
        });
      });
  }

  async use(req: Request, _res: Response, next: NextFunction): Promise<void> {
    try {
      if (
        (req.method === "POST" &&
          /^\/api\/v2\/tours\/[^/]+\/(register|waitlist)$/.test(req.path)) ||
        (req.method === "GET" &&
          /^\/api\/v2\/tours\/[^/]+\/registration-idempotency-key$/.test(req.path))
      ) {
        await this.tryAttachJwtContextForPublicTourPlacement(req);
        return next();
      }
      if (PUBLIC_ROUTES.some((route) => req.path.startsWith(route))) {
        return next();
      }

      const token = this.extractToken(req);
      if (!token) {
        throw new UnauthorizedException(authRequiredError());
      }

      let payload: JwtClaims;
      try {
        const publicKey = await loadPublicKey(this.configService.getJwtPublicKey());

        const verified = await jwtVerify(token, publicKey, {
          algorithms: ["RS256"],
          issuer: this.configService.getJwtIssuer(),
          audience: this.configService.getJwtAudience(),
          clockTolerance: "5s"
        });
        payload = verified.payload as JwtClaims;
      } catch {
        throw new UnauthorizedException(authRequiredError());
      }

      if (
        typeof payload.sub !== "string" ||
        typeof payload.tenant_id !== "string" ||
        typeof payload.role !== "string"
      ) {
        throw new UnauthorizedException(authRequiredError());
      }

      const jwtSessionVersion =
        typeof payload.sess_ver === "number"
          ? payload.sess_ver
          : typeof payload.sess_ver === "string" && payload.sess_ver.trim() !== ""
            ? Number(payload.sess_ver)
            : NaN;
      if (!Number.isInteger(jwtSessionVersion) || jwtSessionVersion < 1) {
        throw new UnauthorizedException({
          error: {
            code: "AUTH_TOKEN_REVOKED",
            message: "Session token is missing a valid session version"
          }
        });
      }

      const userId = payload.sub.trim();
      const tenantId = payload.tenant_id.trim();
      const roleRaw = payload.role.trim();
      const role = tryParseWorkspaceUserRole(roleRaw);

      if (!userId || !tenantId || !role) {
        throw new UnauthorizedException(
          roleRaw && !role
            ? {
                error: {
                  code: "AUTH_INVALID_ROLE",
                  message: "Unknown workspace role in session token"
                }
              }
            : authRequiredError()
        );
      }

      const hostTenantEntity = req.tenant;
      if (
        hostTenantEntity?.id &&
        !skipsJwtHostTenantAlignment(req.path, req.method) &&
        hostTenantEntity.id.trim().toLowerCase() !== tenantId.trim().toLowerCase()
      ) {
        this.loggerService.warn("JWT tenant does not match resolved Host tenant", {
          path: req.path,
          method: req.method,
          jwtTenantId: tenantId,
          hostTenantId: hostTenantEntity.id
        });
        throw new ForbiddenException({
          error: {
            code: "TENANT_HOST_TOKEN_MISMATCH",
            message: "Session workspace does not match the request host tenant"
          }
        });
      }

      const skipHostJwtAlignment = skipsJwtHostTenantAlignment(req.path, req.method);
      if (skipHostJwtAlignment) {
        this.requestContextService.enableJwtTenantOverrideHost();
      }

      const hostId = hostTenantEntity?.id?.trim().toLowerCase();
      const jwtId = tenantId.trim().toLowerCase();
      if (!this.requestContextService.tryGetTenantId()) {
        this.requestContextService.setTenantId(tenantId);
        this.requestContextService.setUserId(userId);
      } else if (skipHostJwtAlignment && hostId && hostId !== jwtId) {
        this.requestContextService.setTenantId(tenantId);
        this.requestContextService.setUserId(userId);
      }

      const queryRunner = this.dataSource.createQueryRunner();
      try {
        await queryRunner.connect();

        const result = await verifyActiveMembershipAndHydrateContext({
          userId,
          tenantId,
          jwtRole: role,
          jwtSessionVersion,
          jwtCapsClaim: payload.caps,
          queryRunner,
          requestContextService: this.requestContextService,
          loggerService: this.loggerService
        });

        if (!result.ok) {
          if ("error" in result) {
            throw result.error;
          }
          throw new UnauthorizedException(authRequiredError());
        }
      } finally {
        await queryRunner.release();
      }

      this.touchUserLastActiveAtAsync(userId);

      return next();
    } catch (error) {
      return next(error);
    }
  }
}

import { ForbiddenException, Inject, Injectable, NestMiddleware } from "@nestjs/common";
import type { NextFunction, Request, Response } from "express";
import { LoggerService } from "../logger/logger.service";
import { RequestContextService } from "../request-context/request-context.service";

type RequestWithOptionalUserTenant = Request & {
  user?: { tenantId?: string };
};

type RequestWithOptionalContextTenant = Request & {
  context?: { tenantId?: string };
};

/**
 * Paths that must not require a bound workspace tenant (probes, OpenAPI, auth entry,
 * internal webhooks/ops, and public registration flows).
 *
 * **Keep in sync** with {@link TenantMiddleware} bypass rules — a stricter guard here
 * would 403 legitimate anonymous `POST /api/v2/tours/:id/register|waitlist` (or `GET …/registration-idempotency-key`) traffic after
 * express middleware skipped binding tenant until the controller bootstraps scope.
 */
function shouldBypassTenantGuard(req: Request): boolean {
  const { path, method } = req;
  return (
    path.startsWith("/health") ||
    path.startsWith("/api/docs") ||
    path.startsWith("/api/v2/auth/") ||
    path.startsWith("/internal") ||
    (method === "POST" && /^\/api\/v2\/tours\/[^/]+\/(register|waitlist)$/.test(path)) ||
    (method === "GET" &&
      /^\/api\/v2\/tours\/[^/]+\/registration-idempotency-key$/.test(path)) ||
    (method === "GET" && /^\/api\/v2\/registrations\/[^/]+$/.test(path))
  );
}

/**
 * Trusted tenant id: only server-populated {@link RequestContextService} (ALS) or
 * `request.context.tenantId` / `request.user.tenantId` when set by trusted middleware.
 * Never reads body, query, or route params for tenant selection.
 */
function resolveTrustedTenantId(req: Request, requestContextService: RequestContextService): string | undefined {
  const fromAls = requestContextService.tryGetTenantId()?.trim();
  if (fromAls) {
    return fromAls;
  }
  const ctxRaw = (req as RequestWithOptionalContextTenant).context?.tenantId;
  const fromReqContext = typeof ctxRaw === "string" ? ctxRaw.trim() : "";
  if (fromReqContext !== "") {
    return fromReqContext.toLowerCase();
  }
  const raw = (req as RequestWithOptionalUserTenant).user?.tenantId;
  const fromUser = typeof raw === "string" ? raw.trim() : "";
  return fromUser !== "" ? fromUser.toLowerCase() : undefined;
}

@Injectable()
export class TenantGuardMiddleware implements NestMiddleware {
  constructor(
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService,
    @Inject(LoggerService) private readonly loggerService: LoggerService
  ) {}

  use(req: Request, _res: Response, next: NextFunction): void {
    if (shouldBypassTenantGuard(req)) {
      return next();
    }

    const tenantId = resolveTrustedTenantId(req, this.requestContextService);
    if (!tenantId) {
      this.loggerService.warn("tenant_guard: missing tenant for protected route", {
        path: req.path,
        method: req.method,
        request_id: this.requestContextService.tryGetRequestId()
      });
      throw new ForbiddenException({
        error: {
          code: "TENANT_CONTEXT_REQUIRED",
          message: "TENANT_CONTEXT_REQUIRED"
        }
      });
    }

    const userId = this.requestContextService.tryGetUserId()?.trim();
    if (userId) {
      this.loggerService.debug("tenant_guard: authenticated tenant context", {
        path: req.path,
        method: req.method,
        tenant_id: tenantId
      });
    }

    next();
  }
}

import {
  type CallHandler,
  type ExecutionContext,
  Inject,
  Injectable,
  NestInterceptor
} from "@nestjs/common";
import { context as otelContext, trace } from "@opentelemetry/api";
import { ATTR_HTTP_ROUTE } from "@opentelemetry/semantic-conventions";
import type { Request } from "express";
import type { Observable } from "rxjs";
import { tap } from "rxjs/operators";
import { LoggerService } from "../logger/logger.service";
import { RequestContextService } from "../request-context/request-context.service";
import { requestContextStorage } from "../request-context/request-context";

type ExpressRouteRequest = Request & {
  route?: { path?: string };
};

/**
 * Enriches the active HTTP span (OpenTelemetry) with route + tenant context; emits one structured
 * debug log per successful response (errors are logged in {@link GlobalExceptionFilter}).
 */
@Injectable()
export class HttpObservabilityInterceptor implements NestInterceptor {
  constructor(
    @Inject(LoggerService) private readonly loggerService: LoggerService,
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService
  ) {}

  intercept(nestCtx: ExecutionContext, next: CallHandler): Observable<unknown> {
    const started = Date.now();
    const req = nestCtx.switchToHttp().getRequest<ExpressRouteRequest>();

    const span = trace.getSpan(otelContext.active());
    const routeTemplate =
      typeof req.route?.path === "string"
        ? `${req.baseUrl ?? ""}${req.route.path}`.replace(/\/{2,}/g, "/") ||
          (typeof req.path === "string" ? req.path : "")
        : typeof req.path === "string"
          ? req.path
          : "";

    if (span && routeTemplate !== "") {
      span.setAttribute(ATTR_HTTP_ROUTE, routeTemplate);
      span.setAttribute("route", routeTemplate);
    }

    const logCtx = this.requestContextService.tryGetStructuredLogContext();
    if (span && logCtx) {
      if (logCtx.request_id) {
        span.setAttribute("request_id", logCtx.request_id);
      }
      if (logCtx.correlation_id) {
        span.setAttribute("correlation_id", logCtx.correlation_id);
      }
      if (logCtx.route && logCtx.route !== "") {
        span.setAttribute("route", logCtx.route);
      }
      if (logCtx.tenant_id) {
        span.setAttribute("tenant_id", logCtx.tenant_id);
      }
      if (logCtx.user_id) {
        span.setAttribute("user_id", logCtx.user_id);
      }
    }

    return next.handle().pipe(
      tap({
        next: () => {
          const res = nestCtx.switchToHttp().getResponse<{ statusCode?: number; setHeader?: (n: string, v: string) => void }>();
          const durationMs = Date.now() - started;
          if (typeof res.setHeader === "function") {
            res.setHeader("x-api-latency", String(durationMs));
            const dbMs = requestContextStorage.getStore()?.dbDurationMs;
            if (dbMs !== undefined && dbMs > 0) {
              res.setHeader("x-db-latency", String(Math.round(dbMs)));
            }
          }
          const logCtx = this.requestContextService.tryGetStructuredLogContext();
          this.loggerService.debug("http_request_completed", {
            status_code: res.statusCode ?? 0,
            duration_ms: durationMs,
            route: routeTemplate || (typeof req.path === "string" ? req.path : undefined),
            method: typeof req.method === "string" ? req.method : undefined,
            ...(logCtx?.traceparent ? { traceparent: logCtx.traceparent } : {}),
            ...(logCtx?.db_duration_ms ? { db_duration_ms: logCtx.db_duration_ms } : {}),
            ...(logCtx?.db_span_count ? { db_span_count: logCtx.db_span_count } : {})
          });
        }
      })
    );
  }
}

import { Inject, Injectable, NestMiddleware } from "@nestjs/common";
import type { NextFunction, Request, Response } from "express";
import { LoggerService } from "../logger/logger.service";
import { RequestContextService } from "../request-context/request-context.service";

/**
 * Emits one structured `REQUEST_TRACE` line per HTTP request (after response completes).
 * Runs after auth middleware so tenant/user/role/capabilities are populated when present.
 */
@Injectable()
export class RequestTraceMiddleware implements NestMiddleware {
  constructor(
    @Inject(LoggerService) private readonly loggerService: LoggerService,
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService,
  ) {}

  use(req: Request, res: Response, next: NextFunction): void {
    const started = Date.now();
    res.on("finish", () => {
      const ctx = this.requestContextService.tryGetStructuredLogContext();
      const caps = this.requestContextService.tryGetWorkspaceCapabilities();
      this.loggerService.info("REQUEST_TRACE", {
        ...(ctx ?? {}),
        endpoint: typeof req.path === "string" ? req.path : req.url,
        status_code: res.statusCode,
        duration_ms: Date.now() - started,
        capabilities: caps?.length ? caps.join(",") : undefined,
      });
    });
    next();
  }
}

import {
  Column,
  CreateDateColumn,
  Entity,
  Index,
  PrimaryGeneratedColumn
} from "typeorm";

/** Persisted lifecycle for `outbox_events` rows (DB enum `outbox_event_status_enum`). */
export enum OutboxEventStatus {
  PENDING = "PENDING",
  DELIVERED = "DELIVERED",
  FAILED = "FAILED"
}

/** @alias OutboxEventStatus — foundation naming for ports / docs. */
export type OutboxStatus = OutboxEventStatus;

/**
 * Transactional outbox row. **Inserts must use the same `EntityManager` as domain mutations**
 * so the event commits or rolls back atomically with business data.
 *
 * Field mapping (conceptual schema):
 * - `created_at` ≈ **occurred_at** (when the domain event was recorded)
 * - `processed_at` ≈ **published_at** (when relay marked delivered)
 * - `correlation_id` — distributed trace / request correlation
 *
 * **Consumers** (relay, downstream handlers) **must be idempotent** — redelivery is expected.
 */
@Entity("outbox_events")
@Index("idx_outbox_events_status_created_at", ["status", "createdAt"])
@Index("idx_outbox_events_aggregate", ["aggregateType", "aggregateId"])
@Index("idx_outbox_events_tenant_created_at", ["tenantId", "createdAt"])
export class OutboxEventEntity {
  @PrimaryGeneratedColumn("uuid")
  id!: string;

  @Column({ type: "uuid", name: "tenant_id" })
  tenantId!: string;

  @Column({ type: "varchar", name: "aggregate_type", length: 64 })
  aggregateType!: string;

  @Column({ type: "uuid", name: "aggregate_id" })
  aggregateId!: string;

  @Column({ type: "varchar", name: "event_type", length: 128 })
  eventType!: string;

  @Column({ type: "jsonb" })
  payload!: Record<string, unknown>;

  @Column({
    type: "enum",
    enum: OutboxEventStatus,
    enumName: "outbox_event_status_enum",
    default: OutboxEventStatus.PENDING
  })
  status!: OutboxEventStatus;

  @Column({ type: "int", name: "retry_count", default: 0 })
  retryCount!: number;

  @Column({ type: "timestamptz", name: "next_retry_at", nullable: true })
  nextRetryAt!: Date | null;

  @CreateDateColumn({ type: "timestamptz", name: "created_at" })
  createdAt!: Date;

  @Column({ type: "timestamptz", name: "processed_at", nullable: true })
  processedAt!: Date | null;

  @Column({ type: "varchar", name: "correlation_id", length: 128, nullable: true })
  correlationId!: string | null;

  /**
   * Stable id from the domain envelope (e.g. `booking.created:{registrationId}`) for enqueue dedupe.
   * Partial unique index `(tenant_id, domain_event_id)` WHERE NOT NULL — duplicate insert is ignored.
   */
  @Column({ type: "varchar", name: "domain_event_id", length: 128, nullable: true })
  domainEventId!: string | null;
}

/**
 * Future transport port (Kafka/Rabbit/SNS). **Not** wired to real brokers in this slice.
 *
 * Implementations must treat delivery as **at-least-once**; consumers remain **idempotent**.
 */
export interface IOutboxPublisher {
  publish(outboxId: string, eventType: string, payload: Record<string, unknown>): Promise<void>;
}

import {
  Inject,
  Injectable,
  Logger,
  OnModuleDestroy,
  OnModuleInit
} from "@nestjs/common";
import { ConfigService } from "../../config/config.service";
import { SchedulerLockService } from "../../jobs/scheduler-lock.service";
import { SchedulerRuntimeMetricsService } from "../../jobs/scheduler-runtime-metrics.service";
import { OutboxProcessor } from "../../modules/outbox/outbox.processor";

/**
 * Durable second-stage outbox relay: global advisory lock + bounded batch dispatch
 * (same semantics as the historical {@link OutboxProcessor} timer, moved here for a clear
 * **worker** boundary vs enqueue helpers).
 *
 * **Activation:** the interval runs only when {@link ConfigService.shouldRunSchedulers}
 * is true **and** {@link ConfigService.getOutboxProcessorEnabled} is not `false` (env
 * `OUTBOX_PROCESSOR_ENABLED`, default `true`). API-only deployments (`APP_RUNTIME_ROLE=api`)
 * skip schedulers — run a **worker** process or `all` for dispatch.
 *
 * Downstream handlers remain idempotent — redelivery is expected after crashes.
 */
@Injectable()
export class OutboxRelayWorker implements OnModuleInit, OnModuleDestroy {
  private readonly logger = new Logger(OutboxRelayWorker.name);
  private interval?: NodeJS.Timeout;
  private readonly jobName = "outbox_dispatch";
  private readonly lockName = "scheduler:outbox_dispatch";

  constructor(
    @Inject(OutboxProcessor) private readonly outboxProcessor: OutboxProcessor,
    @Inject(ConfigService) private readonly configService: ConfigService,
    @Inject(SchedulerLockService) private readonly schedulerLock: SchedulerLockService,
    @Inject(SchedulerRuntimeMetricsService)
    private readonly schedulerMetrics: SchedulerRuntimeMetricsService
  ) {}

  onModuleInit(): void {
    if (!this.configService.shouldRunSchedulers()) {
      this.logger.log("job_skipped_runtime_role outbox_relay");
      return;
    }
    if (this.configService.getOutboxProcessorEnabled() === false) {
      this.logger.log("job_disabled outbox_relay");
      return;
    }
    const ms = this.configService.getOutboxPollIntervalMs();
    const jitterMs = Math.floor(Math.random() * (this.configService.getSchedulerJitterMs() + 1));
    setTimeout(() => {
      void this.runOnceWithLock();
      this.interval = setInterval(() => {
        void this.runOnceWithLock();
      }, ms);
      this.interval.unref?.();
    }, jitterMs).unref?.();
  }

  onModuleDestroy(): void {
    if (this.interval) {
      clearInterval(this.interval);
    }
  }

  private async runOnceWithLock(): Promise<void> {
    const started = Date.now();
    this.schedulerMetrics.noteStarted(this.jobName);
    this.logger.log("job_started outbox_relay");
    try {
      const lock = await this.schedulerLock.runWithGlobalLock(this.lockName, async () => {
        await this.outboxProcessor.processBatch();
      });
      if (!lock.acquired) {
        this.schedulerMetrics.noteSkippedDueLock(this.jobName);
        this.logger.log("job_skipped_due_lock outbox_relay");
        return;
      }
      this.schedulerMetrics.noteFinished(this.jobName, Date.now() - started);
      this.logger.log("job_finished outbox_relay");
    } catch (error: unknown) {
      this.schedulerMetrics.noteFailed(this.jobName);
      this.logger.warn(`outbox relay batch failed: ${String(error)}`);
    }
  }
}

import { Inject, Injectable, NestMiddleware } from "@nestjs/common";
import { randomUUID } from "node:crypto";
import type { NextFunction, Request, Response } from "express";
import { resolveThrottleClientIp } from "../throttling/public-registration-throttle";
import { ConfigService } from "../../config/config.service";
import { requestContextStorage } from "./request-context";

type RequestWithRequestId = Request & { requestId?: string };

@Injectable()
export class RequestContextMiddleware implements NestMiddleware {
  constructor(@Inject(ConfigService) private readonly configService: ConfigService) {}

  use(req: Request, res: Response, next: NextFunction): void {
    const incomingRequestId = req.header("x-request-id");
    const requestId =
      incomingRequestId && incomingRequestId.trim() !== ""
        ? incomingRequestId.trim()
        : randomUUID();
    const incomingCorrelationId = req.header("x-correlation-id");
    const correlationId =
      incomingCorrelationId && incomingCorrelationId.trim() !== ""
        ? incomingCorrelationId.trim()
        : requestId;

    const incomingTraceparent = req.header("traceparent");
    const traceparent =
      incomingTraceparent && incomingTraceparent.trim() !== ""
        ? incomingTraceparent.trim()
        : `00-${randomUUID().replace(/-/g, "")}-${randomUUID().replace(/-/g, "").substring(0, 16)}-01`;

    (req as RequestWithRequestId).requestId = requestId;
    res.setHeader("x-request-id", requestId);
    res.setHeader("x-correlation-id", correlationId);
    res.setHeader("traceparent", traceparent);

    const trustedProxyCidrs =
      this.configService && typeof this.configService.getTrustedProxyCidrs === "function"
        ? this.configService.getTrustedProxyCidrs()
        : [];
    requestContextStorage.run(
      {
        requestId,
        correlationId,
        traceparent,
        path: req.path,
        method: req.method,
        clientIp: resolveThrottleClientIp(req as unknown as Record<string, unknown>, {
          trustedProxyCidrs
        })
      },
      () => {
        next();
      }
    );
  }
}

import { AsyncLocalStorage } from "node:async_hooks";
import type { RequestActorRole } from "../auth/user-role.enum";

export interface RequestContext {
  requestId: string;
  /**
   * Cross-boundary correlation id (`x-correlation-id` when trusted clients send it; otherwise same as {@link requestId}).
   * Always set with HTTP via {@link RequestContextMiddleware} and for explicit worker ALS contexts.
   */
  correlationId?: string;
  /**
   * Optional low-cardinality fields merged into structured logs (see `attachCorrelationMetadata` in observability/request-tracing).
   * Do not store secrets, tokens, or medical payloads — opaque ids only.
   */
  attachedLogFields?: Record<string, string>;
  path?: string;
  /** HTTP method for path-scoped checks (e.g. tenant session binding). */
  method?: string;
  /** Tenant UUID from Host (`req.tenant`) before/alongside JWT `tenantId`. */
  hostTenantId?: string;
  /** Once true, tenant context cannot be changed to a different tenant within this request/job. */
  tenantContextFrozen?: boolean;
  /**
   * When true, {@link RequestContextService.setTenantId} may replace a host-frozen tenant
   * with the JWT workspace (workspace session exchange, invite accept by URL token).
   */
  allowJwtTenantOverrideHost?: boolean;
  tenantId?: string;
  userId?: string;
  /** Workspace or synthetic actor role (see {@link RequestActorRole}). */
  role?: RequestActorRole;
  /**
   * Controls tenant binding behavior for DB calls in this async context.
   * `normal`: tenant binding is mandatory before tenant-scoped DB access.
   * `suppressed`: no tenant binding, with strict DB query allow-list only.
   */
  tenantBindingMode?: TenantBindingMode;
  /** Explicit suppression flag; must be true only when mode is `suppressed`. */
  tenantBindingSuppressed?: boolean;
  /** Audit string explaining why `tenantBindingMode` is `suppressed`. */
  tenantBindingSuppressionReason?: string;
  /** Client IP (trust-proxy aware), set by {@link RequestContextMiddleware}. */
  clientIp?: string;
  /**
   * Workspace membership lifecycle for CASL (`user_tenants.membership_status`).
   * Set by {@link AuthMiddleware} after ACTIVE membership is verified for JWT requests.
   */
  workspaceMembershipStatus?: string;
  /** Optional marketing / CRM labels for ability rules (future: load from DB). */
  abilityLabels?: readonly string[];
  /** Optional explicit capability grants from membership row (Phase 5 hydration). */
  workspaceCapabilities?: readonly string[];
  /** Parsed `user_tenants.membership_metadata`. */
  membershipMetadata?: Record<string, unknown>;
  /** Parsed `tenants.enabled_modules` for the active tenant. */
  tenantEnabledModules?: readonly string[];
  /** Optional JWT `caps` claim decoded at auth (informational; ALS/DB hydration is authoritative). */
  jwtCapabilitySnapshot?: readonly string[];
  /** W3C traceparent for distributed tracing. */
  traceparent?: string;
  /** Aggregated DB child span time (ms) from OTEL `pg` instrumentation within this request. */
  dbDurationMs?: number;
  /** Count of DB spans aggregated into {@link dbDurationMs}. */
  dbSpanCount?: number;
}

export enum TenantBindingMode {
  Normal = "normal",
  Suppressed = "suppressed"
}

