  TENANT_RUNTIME_GUARD,
  type TenantRuntimeGuard
} from "../contracts/tenant-runtime.contract";

/**
 * Redis sliding-window limits keyed by tenant / user / IP (HTTP).
 * Runs after {@link TenantMiddleware} so JWT tenant context is populated for most `/api/v2` routes.
 */
@Injectable()
export class TenantRateLimitMiddleware implements NestMiddleware {
  constructor(
    @Inject(TENANT_RUNTIME_GUARD)
    private readonly tenantRuntimeGuardService: TenantRuntimeGuard
  ) {}

  async use(req: Request, _res: Response, next: NextFunction): Promise<void> {
    try {
      await this.tenantRuntimeGuardService.enforceTenantRuntimePolicies(req, "http_rate_limit");
      next();
    } catch (err) {
      next(err);
    }
  }
}

import { HttpException, HttpStatus, Inject, Injectable, OnModuleDestroy } from "@nestjs/common";
import { randomUUID } from "node:crypto";
import type { Request } from "express";
import type Redis from "ioredis";
import { ConfigService } from "../../config/config.service";
import { LoggerService } from "../logger/logger.service";
import { RequestContextService } from "../request-context/request-context.service";
import { isAuthTenantHostStrictRoute } from "../auth/auth-route-policy";
import {
  getTenantScopeKey,
  isTenantRuntimeApiPath,
  isTenantRuntimeLoginRoute,
  resolveTenantRuntimePath,
  shouldBypassTenantRuntimePath
} from "../tenant/tenant-runtime-policy";
import { resolveThrottleClientIp } from "../throttling/public-registration-throttle";
import { TENANT_ABUSE_REDIS } from "./tenant-abuse.constants";
import type { TenantRateLimitScope } from "./tenant-abuse.constants";
import { TenantAbuseMetricsService } from "./tenant-abuse-metrics.service";

/**
 * Atomic sliding-window counter using Redis sorted sets (scores = epoch ms).
 */
const SLIDING_WINDOW_LUA = `
redis.call('ZREMRANGEBYSCORE', KEYS[1], '-inf', ARGV[1])
local n = redis.call('ZCARD', KEYS[1])
if tonumber(n) >= tonumber(ARGV[3]) then
  return 0
end
redis.call('ZADD', KEYS[1], ARGV[2], ARGV[4])
redis.call('PEXPIRE', KEYS[1], ARGV[5])
return 1
`;

type InMemoryBucket = {
  tokens: number;
  lastRefillMs: number;
  lastSeenMs: number;
};

@Injectable()
export class TenantRateLimitService implements OnModuleDestroy {
  private readonly inMemoryBuckets = new Map<string, InMemoryBucket>();

  constructor(
    @Inject(TENANT_ABUSE_REDIS) private readonly redis: Redis,
    @Inject(ConfigService) private readonly configService: ConfigService,
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService,
    @Inject(LoggerService) private readonly loggerService: LoggerService,
    @Inject(TenantAbuseMetricsService)
    private readonly abuseMetrics: TenantAbuseMetricsService
  ) {}

  async onModuleDestroy(): Promise<void> {
    await this.redis.quit();
  }

  private async slidingAllow(
    key: string,
    windowMs: number,
    limit: number
  ): Promise<boolean> {
    const now = Date.now();
    const windowStart = now - windowMs;
    const member = `${now}:${randomUUID()}`;
    const ttlMs = windowMs + 5000;
    try {
      const result = (await this.redis.eval(
        SLIDING_WINDOW_LUA,
        1,
        key,
        windowStart.toString(),
        now.toString(),
        limit.toString(),
        member,
        ttlMs.toString()
      )) as number;
      return result === 1;
    } catch (err: unknown) {
      this.abuseMetrics.recordRedisFailure();
      const mode = this.configService.getRateLimitFailMode();
      this.loggerService.warn("tenant_rate_limit_redis_error", {
        message: err instanceof Error ? err.message : String(err),
        redis_key: key,
        fail_mode: mode
      });
      if (mode === "fail_open") {
        return true;
      }
      if (mode === "fail_closed") {
        return false;
      }

      this.abuseMetrics.recordFallbackActivated();
      this.loggerService.warn("tenant_rate_limit_fallback_activated", {
        redis_key: key,
        strategy: "in_memory_token_bucket",
        fail_mode: mode
      });
      return this.allowWithInMemoryTokenBucket(key, windowMs, limit);
    }
  }

  private allowWithInMemoryTokenBucket(
    key: string,
    windowMs: number,
    limit: number
  ): boolean {
    const now = Date.now();
    this.compactInMemoryBuckets(now, windowMs);

    const refillPerMs = limit / windowMs;
    const bucket = this.inMemoryBuckets.get(key);
    if (!bucket) {
      // First hit gets one token consumed immediately.
      this.inMemoryBuckets.set(key, {
        tokens: Math.max(0, limit - 1),
        lastRefillMs: now,
        lastSeenMs: now
      });
      return true;
    }

    const elapsed = Math.max(0, now - bucket.lastRefillMs);
    bucket.tokens = Math.min(limit, bucket.tokens + elapsed * refillPerMs);
    bucket.lastRefillMs = now;
    bucket.lastSeenMs = now;

    if (bucket.tokens < 1) {
      return false;
    }
    bucket.tokens -= 1;
    return true;
  }

  private compactInMemoryBuckets(now: number, windowMs: number): void {
    const staleAfterMs = Math.max(60_000, windowMs * 5);
    for (const [key, bucket] of this.inMemoryBuckets.entries()) {
      if (now - bucket.lastSeenMs > staleAfterMs) {
        this.inMemoryBuckets.delete(key);
      }
    }
  }

  private sanitizeIp(ip: string): string {
    return ip.replace(/:/g, "_").replace(/\s+/g, "");
  }

  private throwLimited(scope: TenantRateLimitScope, req: Request): never {
    const tenantId = getTenantScopeKey("tenant", req, {
      requestContextService: this.requestContextService,
      configService: this.configService
    });
    const userId = getTenantScopeKey("user", req, {
      requestContextService: this.requestContextService,
      configService: this.configService
    });
    const ip =
      getTenantScopeKey("ip", req, {
        requestContextService: this.requestContextService,
        configService: this.configService
      }) ?? "unknown";
    this.abuseMetrics.recordRateLimitExceeded(scope);

    let requestId = "";
    try {
      requestId = this.requestContextService.getRequestId();
    } catch {
      requestId = "";
    }

    this.loggerService.warn("tenant_rate_limit_exceeded", {
      tenant_id: tenantId ?? "",
      user_id: userId ?? "",
      endpoint: typeof req.path === "string" ? req.path : req.url,
      rate_limit: scope,
      client_ip: ip
    });

    throw new HttpException(
      {
        error: {
          code: "RATE_LIMITED",
          message: "Too many requests for this limit scope",
          retryability: "RETRY_WITH_BACKOFF",
          details: { limit_scope: scope, request_id: requestId || undefined }
        }
      },
      HttpStatus.TOO_MANY_REQUESTS
    );
  }

  async enforceHttpRateLimit(req: Request): Promise<void> {
    if (!this.configService.isTenantRateLimitEnabled()) {
      return;
    }

    const path = resolveTenantRuntimePath(req);
    if (shouldBypassTenantRuntimePath(path)) {
      return;
    }

    if (!isTenantRuntimeApiPath(path)) {
      return;
    }

    const ip = this.sanitizeIp(
      resolveThrottleClientIp(req as unknown as Record<string, unknown>, {
        trustedProxyCidrs: this.configService.getTrustedProxyCidrs()
      })
    );

    if (isTenantRuntimeLoginRoute(path, req.method)) {
      await this.enforceLogin(req, ip);
      return;
    }

    await this.enforceApi(req, ip);
  }

  async enforceHttp(req: Request): Promise<void> {
    await this.enforceHttpRateLimit(req);
  }

  /**
   * Throttle hostile workspace host probing on strict auth routes (before 404/400 responses).
   */
  async enforceHostProbeOnAuthRoute(req: Request): Promise<void> {
    if (!this.configService.isTenantRateLimitEnabled()) {
      return;
    }
    const path = resolveTenantRuntimePath(req);
    if (!isAuthTenantHostStrictRoute(path, req.method)) {
      return;
    }
    const ip = this.sanitizeIp(
      resolveThrottleClientIp(req as unknown as Record<string, unknown>, {
        trustedProxyCidrs: this.configService.getTrustedProxyCidrs()
      })
    );
    const cfg = this.configService.getTenantRateLimitHostProbeConfig();
    const ipKey = `trl:v2:host_probe:ip:${ip}`;
    if (!(await this.slidingAllow(ipKey, cfg.windowMs, cfg.perIp))) {
      this.throwLimited("host_probe_ip", req);
    }
  }

  private async enforceLogin(req: Request, ipSan: string): Promise<void> {
    const cfg = this.configService.getTenantRateLimitLoginConfig();
    const tenantId =
      getTenantScopeKey("tenant", req, {
        requestContextService: this.requestContextService,
        configService: this.configService
      }) ?? "_unknown";

    const tenantKey = `trl:v2:login:tenant:${tenantId}`;
    if (!(await this.slidingAllow(tenantKey, cfg.windowMs, cfg.perTenant))) {
      this.throwLimited("login_tenant", req);
    }

    const ipKey = `trl:v2:login:ip:${ipSan}`;
    if (!(await this.slidingAllow(ipKey, cfg.windowMs, cfg.perIp))) {
      this.throwLimited("login_ip", req);
    }
  }

  private async enforceApi(req: Request, ipSan: string): Promise<void> {
    const cfg = this.configService.getTenantRateLimitApiConfig();
    const tenantId =
      getTenantScopeKey("tenant", req, {
        requestContextService: this.requestContextService,
        configService: this.configService
      }) ?? "_public";
    const userId = getTenantScopeKey("user", req, {
      requestContextService: this.requestContextService,
      configService: this.configService
    });

    this.abuseMetrics.recordTenantRequestObserved(
      tenantId === "_public" ? undefined : tenantId
    );

    const tenantKey = `trl:v2:api:tenant:${tenantId}`;
    if (!(await this.slidingAllow(tenantKey, cfg.windowMs, cfg.perTenant))) {
      this.throwLimited("api_tenant", req);
    }

    if (userId && userId.trim() !== "") {
      const userKey = `trl:v2:api:user:${tenantId}:${userId.trim().toLowerCase()}`;
      if (!(await this.slidingAllow(userKey, cfg.windowMs, cfg.perUser))) {
        this.throwLimited("api_user", req);
      }
    }

    const ipKey = `trl:v2:api:ipt:${tenantId}:${ipSan}`;
    if (!(await this.slidingAllow(ipKey, cfg.windowMs, cfg.perIp))) {
      this.throwLimited("api_ip", req);
    }
  }

  /** Background reconciliation / tenant-scoped job budgets. Returns false when limit hit (caller should skip work). */
  async tryConsumeJobForTenant(tenantId: string): Promise<boolean> {
    if (!this.configService.isTenantRateLimitEnabled()) {
      return true;
    }
    const cfg = this.configService.getTenantRateLimitJobConfig();
    const tid = tenantId.trim().toLowerCase();
    const key = `trl:v2:job:tenant:${tid}`;
    const ok = await this.slidingAllow(key, cfg.windowMs, cfg.perTenant);
    if (!ok) {
      this.abuseMetrics.recordRateLimitExceeded("job_tenant");
      this.loggerService.warn("tenant_job_rate_limit_exceeded", {
        tenant_id: tid,
        user_id: "",
        endpoint: "reconciliation_cycle",
        rate_limit: "job_tenant",
        client_ip: ""
      });
    }
    return ok;
  }
}

/// <reference path="../../types/express.d.ts" />
import {
  BadRequestException,
  ForbiddenException,
  Inject,
  Injectable,
  NestMiddleware,
  NotFoundException
} from "@nestjs/common";
import type { NextFunction, Request, Response } from "express";
import { ConfigService } from "../../config/config.service";
import { TenantHostResolverService } from "../../modules/tenant/tenant-host-resolver.service";
import { TenantRateLimitService } from "../tenant-abuse/tenant-rate-limit.service";
import { RequestContextService } from "../request-context/request-context.service";
import { isAuthTenantHostStrictRoute } from "../auth/auth-route-policy";

/**
 * Paths where Host-based tenant lookup must not run (health, docs, public flows).
 * Aligns with {@link TenantMiddleware} bypass list except `/api/v2/auth/*` is NOT skipped here
 * so login routes receive `request.tenant`.
 */
export function shouldBypassTenantResolver(path: string, method: string): boolean {
  return (
    (method === "POST" && /^\/api\/v2\/tours\/[^/]+\/(register|waitlist)$/.test(path)) ||
    (method === "GET" &&
      /^\/api\/v2\/tours\/[^/]+\/registration-idempotency-key$/.test(path)) ||
    (method === "GET" && /^\/api\/v2\/registrations\/[^/]+$/.test(path)) ||
    path.startsWith("/health") ||
    path.startsWith("/internal") ||
    path.startsWith("/api/docs")
  );
}

export function isAuthTenantSessionRoute(path: string, method: string): boolean {
  return isAuthTenantHostStrictRoute(path, method);
}

@Injectable()
export class TenantResolverMiddleware implements NestMiddleware {
  constructor(
    @Inject(TenantHostResolverService)
    private readonly tenantHostResolver: TenantHostResolverService,
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService,
    @Inject(ConfigService) private readonly configService: ConfigService,
    @Inject(TenantRateLimitService)
    private readonly tenantRateLimitService: TenantRateLimitService
  ) {}

  private async guardHostProbeOnAuthRoute(req: Request, authRoute: boolean): Promise<void> {
    if (!authRoute) {
      return;
    }
    await this.tenantRateLimitService.enforceHostProbeOnAuthRoute(req);
  }

  async use(req: Request, _res: Response, next: NextFunction): Promise<void> {
    try {
      if (shouldBypassTenantResolver(req.path, req.method)) {
        return next();
      }

      const root = this.configService.getTenantRootDomain();
      if (!root) {
        return next();
      }

      const authRoute = isAuthTenantSessionRoute(req.path, req.method);
      const inboundHost = TenantHostResolverService.extractInboundHost(
        req,
        this.configService.getTenantHostTrustModel()
      );

      if (authRoute && !inboundHost) {
        await this.guardHostProbeOnAuthRoute(req, authRoute);
        throw new BadRequestException({
          error: {
            code: "TENANT_HOST_INVALID",
            message: "The workspace hostname is missing or invalid"
          }
        });
      }

      if (!inboundHost) {
        return next();
      }

      const outcome = this.tenantHostResolver.parseWorkspaceTenantLabel(inboundHost);

      if (
        outcome.kind === "apex" ||
        outcome.kind === "outside_workspace" ||
        outcome.kind === "no_root_config"
      ) {
        if (authRoute) {
          await this.guardHostProbeOnAuthRoute(req, authRoute);
          throw new BadRequestException({
            error: {
              code: "TENANT_HOST_INVALID",
              message: "The workspace hostname is missing or invalid"
            }
          });
        }
        return next();
      }

      if (outcome.kind === "reserved") {
        if (authRoute) {
          await this.guardHostProbeOnAuthRoute(req, authRoute);
          throw new ForbiddenException({
            error: {
              code: "TENANT_HOST_RESERVED",
              message: "This hostname is reserved and cannot be used as a workspace"
            }
          });
        }
        return next();
      }

      if (outcome.kind === "invalid_label") {
        if (authRoute) {
          await this.guardHostProbeOnAuthRoute(req, authRoute);
          throw new BadRequestException({
            error: {
              code: "TENANT_HOST_INVALID",
              message: "The workspace subdomain in this hostname is not valid"
            }
          });
        }
        return next();
      }

      const tenant = await this.requestContextService.runWithoutTenantBinding(
        "tenant_host_resolution",
        () => this.tenantHostResolver.resolveTenantEntityFromHost(inboundHost)
      );

      if (!tenant) {
        if (authRoute) {
          await this.guardHostProbeOnAuthRoute(req, authRoute);
          throw new NotFoundException({
            error: {
              code: "TENANT_HOST_UNKNOWN",
              message: "No workspace matches this host"
            }
          });
        }
        return next();
      }

      req.tenant = tenant;
      this.requestContextService.setHostTenantId(tenant.id);
      return next();
    } catch (err) {
      return next(err);
    }
  }
}

import { Injectable } from "@nestjs/common";
import type { Request } from "express";
import { Inject } from "@nestjs/common";
import {
  TENANT_RATE_LIMIT_POLICY,
  TENANT_USAGE_METERING_POLICY,
  type TenantRateLimitPolicy,
  type TenantUsageMeteringPolicy
} from "../contracts/tenant-runtime.contract";

export type TenantRuntimeAction = "http_rate_limit" | "http_usage_metering" | "http_all";

@Injectable()
export class TenantRuntimeGuardService {
  constructor(
    @Inject(TENANT_RATE_LIMIT_POLICY)
    private readonly tenantRateLimitService: TenantRateLimitPolicy,
    @Inject(TENANT_USAGE_METERING_POLICY)
    private readonly tenantUsageMeteringService: TenantUsageMeteringPolicy
  ) {}

  async enforceTenantRuntimePolicies(
    req: Request,
    action: TenantRuntimeAction
  ): Promise<void> {
    if (action === "http_rate_limit") {
      await this.tenantRateLimitService.enforceHttpRateLimit(req);
      return;
    }
    if (action === "http_usage_metering") {
      await this.tenantUsageMeteringService.enforceHttpUsageMetering(req);
      return;
    }
    await this.tenantRateLimitService.enforceHttpRateLimit(req);
    await this.tenantUsageMeteringService.enforceHttpUsageMetering(req);
  }
}

import type { Request } from "express";
import type { ConfigService } from "../../config/config.service";
import type { RequestContextService } from "../request-context/request-context.service";
import { resolveThrottleClientIp } from "../throttling/public-registration-throttle";
import { isAuthSessionLoginRoute } from "../auth/auth-route-policy";

export function resolveTenantRuntimePath(req: Pick<Request, "path" | "url">): string {
  return typeof req.path === "string" ? req.path : req.url;
}

export function isTenantRuntimeApiPath(path: string): boolean {
  return path.startsWith("/api/v2");
}

export function isTenantRuntimeLoginRoute(path: string, method: string): boolean {
  return isAuthSessionLoginRoute(path, method);
}

export function shouldBypassTenantRuntimePath(path: string): boolean {
  return (
    path.startsWith("/health") ||
    path.startsWith("/internal") ||
    path.startsWith("/api/docs")
  );
}

export function getTenantScopeKey(
  scope: "tenant" | "user" | "ip",
  req: Request,
  deps: {
    requestContextService: Pick<
      RequestContextService,
      "resolveTenantContext" | "tryGetUserId"
    >;
    configService: Pick<ConfigService, "getTrustedProxyCidrs">;
  }
): string | undefined {
  if (scope === "tenant") {
    return deps.requestContextService.resolveTenantContext(req).tenantId;
  }
  if (scope === "user") {
    const userId = deps.requestContextService.tryGetUserId();
    return userId && userId.trim() !== "" ? userId.trim() : undefined;
  }
  const ip = resolveThrottleClientIp(req as unknown as Record<string, unknown>, {
    trustedProxyCidrs: deps.configService.getTrustedProxyCidrs()
  });
  return ip;
}

export async function enforceBackgroundTenantRuntimePolicies(
  tenantId: string,
  checks: {
    tryConsumeBackgroundJob: (tenantId: string) => Promise<boolean>;
    tryConsumeTenantJobRateLimit: (tenantId: string) => Promise<boolean>;
  }
): Promise<boolean> {
  const quotaAllowed = await checks.tryConsumeBackgroundJob(tenantId);
  if (!quotaAllowed) {
    return false;
  }
  const jobAllowed = await checks.tryConsumeTenantJobRateLimit(tenantId);
  if (!jobAllowed) {
    return false;
  }
  return true;
}

import { ForbiddenException, Inject, Injectable, NestMiddleware } from "@nestjs/common";
import type { NextFunction, Request } from "express";
import { LoggerService } from "../logger/logger.service";
import { RequestContextService } from "../request-context/request-context.service";

@Injectable()
export class TenantMiddleware implements NestMiddleware {
  constructor(
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService,
    @Inject(LoggerService) private readonly loggerService: LoggerService
  ) {}

  use(req: Request, _res: unknown, next: NextFunction): void {
    // Bypass tenant resolution for all health probes (/health, /health/live, /health/ready, ...)
    // Auth v2 entry endpoints skip JWT here; workspace tenant for login comes from Host via TenantResolverMiddleware.
    if (
      (req.method === "POST" &&
        /^\/api\/v2\/tours\/[^/]+\/(register|waitlist)$/.test(req.path)) ||
      (req.method === "GET" &&
        /^\/api\/v2\/tours\/[^/]+\/registration-idempotency-key$/.test(req.path)) ||
      (req.method === "GET" &&
        /^\/api\/v2\/registrations\/[^/]+$/.test(req.path)) ||
      req.path.startsWith("/health") ||
      req.path.startsWith("/internal") ||
      req.path.startsWith("/api/docs") ||
      req.path.startsWith("/api/v2/auth/")
    ) {
      return next();
    }

    const { tenantId } = this.requestContextService.resolveTenantContext(req);

    if (!tenantId) {
      this.loggerService.warn("tenant resolution failed", {
        path: req.path,
        method: req.method,
        requestId: this.requestContextService.getRequestId()
      });
      throw new ForbiddenException({
        error: {
          code: "TENANT_CONTEXT_MISSING",
          message: "Trusted tenant context required but absent"
        }
      });
    }

    this.requestContextService.setTenantId(tenantId);
    next();
  }
}

import { randomUUID } from "node:crypto";
import assert from "node:assert/strict";
import test from "node:test";

test("outbox_events has tenant_id after migration", async (t) => {
  const { Client } = require("pg") as { Client: new (args: unknown) => any };
  const connectionString = process.env.DATABASE_URL;
  if (!connectionString) {
    t.skip("DATABASE_URL is required for integration test");
    return;
  }

  const client = new Client({ connectionString });
  await client.connect();

  try {
    const cols = await client.query(
      `SELECT 1 FROM information_schema.columns
       WHERE table_schema = 'public' AND table_name = 'outbox_events' AND column_name = 'tenant_id'`
    );
    if (cols.rows.length === 0) {
      t.skip("Migration OutboxTenantId1777576100000 not applied — run migrations");
      return;
    }

    const tenantA = randomUUID();
    const tenantB = randomUUID();
    await client.query(
      `INSERT INTO tenants (id, name, created_at, updated_at)
       VALUES ($1, 'outbox-it-a', now(), now()),
              ($2, 'outbox-it-b', now(), now())`,
      [tenantA, tenantB]
    );

    const probe = `outbox_probe_${Date.now().toString(36)}`;
    await client.query(`
      CREATE TABLE ${probe} (
        id uuid PRIMARY KEY,
        tenant_id uuid NOT NULL,
        secret text NOT NULL
      )
    `);
    await client.query(`ALTER TABLE ${probe} ENABLE ROW LEVEL SECURITY`);
    await client.query(`ALTER TABLE ${probe} FORCE ROW LEVEL SECURITY`);
    await client.query(`
      CREATE POLICY tenant_isolation_policy ON ${probe}
      USING (tenant_id = current_setting('app.tenant_id')::uuid)
      WITH CHECK (tenant_id = current_setting('app.tenant_id')::uuid)
    `);

    await client.query(`SELECT set_config('app.tenant_id', $1, false)`, [tenantA]);
    await client.query(`INSERT INTO ${probe} (id, tenant_id, secret) VALUES ($1, $2, $3)`, [
      randomUUID(),
      tenantA,
      "tenant-a-secret"
    ]);

    await client.query("BEGIN");
    await client.query(`SELECT set_config('app.tenant_id', $1, true)`, [tenantB]);
    const wrongCtx = await client.query(`SELECT COUNT(*)::int AS n FROM ${probe}`);
    await client.query("ROLLBACK");
    assert.equal(wrongCtx.rows[0].n, 0, "wrong tenant GUC must not see tenant A rows");

    await client.query("BEGIN");
    await client.query(`SELECT set_config('app.tenant_id', $1, true)`, [tenantA]);
    const rightCtx = await client.query(`SELECT COUNT(*)::int AS n FROM ${probe}`);
    await client.query("ROLLBACK");
    assert.equal(rightCtx.rows[0].n, 1, "correct tenant GUC must see own rows");

    const eventId = randomUUID();
    const aggId = randomUUID();
    await client.query(
      `INSERT INTO outbox_events (
