    await client.query(`DELETE FROM users WHERE id = $1::uuid OR id = $2::uuid`, [userA, userB]);
    await client.query(`DELETE FROM tenants WHERE id = $1::uuid OR id = $2::uuid`, [tenantA, tenantB]);
