import type { WorkspaceSessionDto } from "./dto/workspace-session.dto";
import { OtpService } from "./otp.service";

@Injectable()
export class AuthService {
  constructor(
    @InjectRepository(UserEntity)
    private readonly userRepository: Repository<UserEntity>,
    @InjectRepository(UserTenantEntity)
    private readonly userTenantRepository: Repository<UserTenantEntity>,
    @InjectRepository(WorkspaceInviteEntity)
    private readonly workspaceInviteRepository: Repository<WorkspaceInviteEntity>,
    @Inject(ConfigService) private readonly configService: ConfigService,
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService,
    @Inject(LoggerService) private readonly loggerService: LoggerService,
    @Inject(TenantAuditEventsService)
    private readonly tenantAuditEventsService: TenantAuditEventsService,
    @Inject(OtpService) private readonly otpService: OtpService
  ) {}

  private maskPhoneForLog(value: string | null | undefined): string | null {
    if (typeof value !== "string") {
      return null;
    }
    const digits = value.replace(/\D/g, "");
    if (digits.length === 0) {
      return "***";
    }
    if (digits.length <= 4) {
      return `***${digits}`;
    }
    return `***${digits.slice(-4)}`;
  }

  private isDevStaticOtpEnabled(): boolean {
    const nodeEnv = this.configService.getNodeEnv();
    return (
      (nodeEnv === "development" || nodeEnv === "test") &&
      this.configService.getAuthAllowDevStaticOtp()
    );
  }

  private parseTelegramInitPayload(
    telegramInitPayload: string
  ): { telegramUserId: string } {
    const params = new URLSearchParams(telegramInitPayload);
    const hash = params.get("hash");
    if (!hash) {
      throw new UnauthorizedException("AUTH_TELEGRAM_CONTEXT_REQUIRED");
    }

    const dataEntries: string[] = [];
    for (const [key, value] of params.entries()) {
      if (key !== "hash") {
        dataEntries.push(`${key}=${value}`);
      }
    }
    dataEntries.sort();
    const dataCheckString = dataEntries.join("\n");

    const secretKey = createHash("sha256")
      .update(this.configService.getTelegramBotToken(), "utf8")
      .digest();
    const computedHash = createHmac("sha256", secretKey)
      .update(dataCheckString, "utf8")
      .digest("hex");

    const provided = Buffer.from(hash, "hex");
    const computed = Buffer.from(computedHash, "hex");
    if (provided.length !== computed.length || !timingSafeEqual(provided, computed)) {
      throw new UnauthorizedException("AUTH_TELEGRAM_CONTEXT_REQUIRED");
    }

    const userJson = params.get("user");
    if (!userJson) {
      throw new UnauthorizedException("AUTH_TELEGRAM_CONTEXT_REQUIRED");
    }

    try {
      const user = JSON.parse(userJson) as { id?: unknown };
      if (
        (typeof user.id !== "number" && typeof user.id !== "string") ||
        String(user.id).trim() === ""
      ) {
        throw new Error("invalid");
      }
      return { telegramUserId: String(user.id).trim() };
    } catch {
      throw new UnauthorizedException("AUTH_TELEGRAM_CONTEXT_REQUIRED");
    }
  }

  private async loadActiveMembershipHydrationRow(
    userId: string,
    tenantId: string,
  ): Promise<{
    role: string;
    sessionVersion: number;
    labels: unknown;
    membership_metadata: unknown;
    enabled_modules: unknown;
  } | null> {
    return this.userTenantRepository
      .createQueryBuilder("ut")
      .innerJoin(TenantEntity, "tenant", "tenant.id = ut.tenant_id")
      .select("ut.role", "role")
      .addSelect("ut.session_version", "session_version")
      .addSelect("ut.labels", "labels")
      .addSelect("ut.membership_metadata", "membership_metadata")
      .addSelect("tenant.enabled_modules", "enabled_modules")
      .where("ut.user_id = :userId", { userId })
      .andWhere("ut.tenant_id = :tenantId", { tenantId })
      .andWhere("ut.deleted_at IS NULL")
      .andWhere("ut.membership_status = 'ACTIVE'")
      .getRawOne()
      .then((row) => row ?? null);
  }

  private async signAccessToken(input: {
    userId: string;
    tenantId: string;
    role: string;
    email?: string | null;
    sessionVersion: number;
    capabilitySnapshot?: string;
  }): Promise<string> {
    const privateKey = await loadPrivateKey(this.configService.getJwtPrivateKey());

    const payload: Record<string, string | number> = {
      tenant_id: input.tenantId,
      role: input.role,
      sess_ver: input.sessionVersion
    };
    if (typeof input.email === "string" && input.email.trim() !== "") {
      payload.email = input.email;
    }
    if (input.capabilitySnapshot && input.capabilitySnapshot.trim() !== "") {
      payload.caps = input.capabilitySnapshot;
    }

    return new SignJWT(payload)
      .setProtectedHeader({ alg: "RS256", typ: "JWT" })
      .setSubject(input.userId)
      .setIssuer(this.configService.getJwtIssuer())
      .setAudience(this.configService.getJwtAudience())
      .setIssuedAt()
      .setExpirationTime("1h")
      .sign(privateKey);
  }

  private async signMembershipAccessToken(input: {
    userId: string;
    tenantId: string;
    role: string;
    email?: string | null;
    sessionVersion: number;
  }): Promise<string> {
    const hydration = await this.loadActiveMembershipHydrationRow(
      input.userId,
      this.normalizeUuidString(input.tenantId),
    );
    const capabilitySnapshot = hydration
      ? encodeMembershipJwtCapabilitySnapshot(input.role, hydration)
      : undefined;
    return this.signAccessToken({ ...input, capabilitySnapshot });
  }

  private isPhoneOtpCodeValid(otp: string): boolean {
    return this.isDevStaticOtpEnabled() && otp.trim() === "1234";
  }

  async requestPhoneOtp(
    phone: string
  ): Promise<{ otp_requested: true; delivery: "dev_static"; challenge_id: string }> {
    const normalizedPhone = phone.trim();
    const { challengeId } = await this.otpService.createMobileOtpChallenge(normalizedPhone, "login");
    return {
      otp_requested: true,
      delivery: "dev_static",
      challenge_id: challengeId
    };
  }

  async preflightPhone(dto: PhonePreflightDto): Promise<{
    mode: "existing_user" | "new_user";
    invite_pending: boolean;
    phone: string;
  }> {
    const normalizedPhone = dto.phone.trim();
    const user = await this.findUserByPhone(normalizedPhone);
    const invitePending = await this.hasPendingInviteForPhone(normalizedPhone, dto.invite_token);
    return {
      mode: user ? "existing_user" : "new_user",
      invite_pending: invitePending,
      phone: normalizedPhone
    };
  }

  private async findUserByPhone(phone: string): Promise<UserEntity | null> {
    const trimmed = phone.trim();
    if (!trimmed) {
      return null;
    }
    // tenant-isolation:qb-exempt — pre-auth phone lookup (no tenant context yet).
    const user = await this.userRepository
      .createQueryBuilder("u")
      .where("u.deleted_at IS NULL")
      .andWhere("phone_normalized(u.phone) = phone_normalized(:phone)", { phone: trimmed })
      .getOne();
    if (!user) {
      // tenant-isolation:qb-exempt — diagnostic path for broken phone_normalized() data (same pre-auth scope).
      const userWithBrokenNormalizedPhone = await this.userRepository
        .createQueryBuilder("u")
        .select(["u.id", "u.phone"])
        .where("u.deleted_at IS NULL")
        .andWhere("u.phone = :phone", { phone: trimmed })
        .andWhere("(phone_normalized(u.phone) IS NULL OR phone_normalized(u.phone) = '')")
        .getOne();
      if (userWithBrokenNormalizedPhone) {
        this.loggerService.error("auth_phone_normalization_data_issue", {
          user_id: userWithBrokenNormalizedPhone.id,
          masked_phone: this.maskPhoneForLog(userWithBrokenNormalizedPhone.phone),
          input_masked_phone: this.maskPhoneForLog(trimmed)
        });
      }
    }
    return user;
  }

  private async hasPendingInviteForPhone(
    phone: string,
    inviteToken?: string
  ): Promise<boolean> {
    const normalizedPhone = phone.trim();
    if (!normalizedPhone) return false;
    try {
      // tenant-isolation:qb-exempt — pre-auth invite lookup by phone (workspace_invites.email holds phone).
      const query = this.workspaceInviteRepository
        .createQueryBuilder("wi")
        .select("wi.id", "id")
        .where("wi.status = :status", { status: WorkspaceInviteStatus.PENDING })
        .andWhere("wi.expires_at > now()")
        .andWhere("phone_normalized(wi.email) = phone_normalized(:phone)", { phone: normalizedPhone });
      if (inviteToken && inviteToken.trim() !== "") {
        query.andWhere("wi.invite_token = :inviteToken", { inviteToken: inviteToken.trim() });
      }
      const invite = await query.getRawOne<{ id: string }>();
      return Boolean(invite?.id);
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message.toLowerCase() : "";
      const isQueryFailedError =
        error instanceof QueryFailedError ||
        (typeof error === "object" &&
          error !== null &&
          "name" in error &&
          (error as { name?: unknown }).name === "QueryFailedError");
      const missingColumnMatch =
        error instanceof Error ? error.message.match(/column\s+([a-z_]+\.[a-z_]+)\s+does not exist/i) : null;
      const missingColumnRef = missingColumnMatch?.[1]?.toLowerCase();
      const isMissingInviteColumnError =
        isQueryFailedError &&
        message.includes("does not exist") &&
        (message.includes("workspace_invites") || Boolean(missingColumnRef?.startsWith("wi.")));
      if (isMissingInviteColumnError) {
        this.loggerService.warn("AUTH_INVITE_LOOKUP_MISSING_COLUMN", {
          table: "workspace_invites",
          column: missingColumnRef ?? "unknown",
          masked_phone: this.maskPhoneForLog(normalizedPhone),
          invite_token_present: Boolean(inviteToken && inviteToken.trim() !== "")
        });
        return false;
      }
      throw error;
    }
  }

  private async buildWebRegistrationRequiredResponse(input: {
    phone: string;
    tenantId: string;
    inviteToken?: string;
  }): Promise<WebSessionResponseDto> {
    const onboardingToken = await this.issueOnboardingToken(input);
    return {
      session_token: "",
      user_id: "",
      tenant_id: input.tenantId,
      entry_mode: "web",
      requires_registration: true,
      onboarding_token: onboardingToken
    };
  }

  private async issueOnboardingToken(input: {
    phone: string;
    tenantId: string;
    inviteToken?: string;
  }): Promise<string> {
    const privateKey = await loadPrivateKey(this.configService.getJwtPrivateKey());
    const payload: Record<string, string> = {
      phone: input.phone,
      tenant_id: input.tenantId
    };
    if (input.inviteToken && input.inviteToken.trim() !== "") {
      payload.invite_token = input.inviteToken.trim();
    }
    return new SignJWT(payload)
      .setProtectedHeader({ alg: "RS256", typ: "JWT" })
      .setSubject("onboarding")
      .setIssuer(this.configService.getJwtIssuer())
      .setAudience(this.configService.getJwtAudience())
      .setIssuedAt()
      .setExpirationTime("15m")
      .sign(privateKey);
  }

  private async verifyOnboardingToken(token: string): Promise<{
    phone: string;
    tenantId: string;
    inviteToken?: string;
  }> {
    const publicKey = await loadPublicKey(this.configService.getJwtPublicKey());
    const verified = await jwtVerify(token, publicKey, {
      algorithms: ["RS256"],
      issuer: this.configService.getJwtIssuer(),
      audience: this.configService.getJwtAudience(),
      clockTolerance: "5s"
    });
    const payload = verified.payload as Record<string, unknown>;
    const phone = typeof payload.phone === "string" ? payload.phone.trim() : "";
    const tenantId = typeof payload.tenant_id === "string" ? payload.tenant_id.trim() : "";
    const inviteToken = typeof payload.invite_token === "string" ? payload.invite_token.trim() : undefined;
    if (!phone || !tenantId) {
      throw new UnauthorizedException({
        error: {
          code: "INVALID_INPUT",
          message: "Invalid onboarding token payload"
        }
      });
    }
    return { phone, tenantId, inviteToken };
  }

  async validatePhoneOtp(phone: string, otp: string): Promise<UserEntity | null> {
    if (!this.isDevStaticOtpEnabled()) {
      return null;
    }
    if (!this.isPhoneOtpCodeValid(otp)) {
      return null;
    }
    const trimmed = phone.trim();
    if (!trimmed) {
      return null;
    }
    return this.findUserByPhone(trimmed);
  }

  async createWebSessionOtp(dto: PhoneSessionDto): Promise<WebSessionResponseDto> {
    const resolvedTenantId = this.requestContextService.resolveEffectiveTenantId();
    if (!resolvedTenantId) {
      throw new ForbiddenException({
        error: {
          code: "TENANT_CONTEXT_MISSING",
          message: "Workspace tenant must be resolved from the HTTP Host (tenant subdomain)"
        }
      });
    }
    this.requestContextService.setTenantId(resolvedTenantId);

    const trimmedOtp = dto.otp.trim();
    const challengeId = dto.challenge_id?.trim();

    let user: UserEntity | null;
    let verifiedPhone = normalizeOtpPhoneInput(dto.phone);
    if (challengeId) {
      const verified = await this.otpService.verifyMobileOtp(challengeId, trimmedOtp);
      if (verified.purpose !== "login") {
        throw new UnauthorizedException({
          error: {
            code: "AUTH_OTP_INVALID",
            message: "Invalid OTP challenge for login"
          }
        });
      }
      verifiedPhone = verified.mobile;
      if (verifiedPhone !== normalizeOtpPhoneInput(dto.phone)) {
        throw new UnauthorizedException({
          error: {
            code: "AUTH_OTP_INVALID",
            message: "Phone does not match OTP challenge"
          }
        });
      }
      user = await this.findUserByPhone(verifiedPhone);
    } else {
      const isDevStaticOtpEnabled = this.isDevStaticOtpEnabled();
      if (isDevStaticOtpEnabled && trimmedOtp !== "1234") {
        throw new UnauthorizedException({
          error: {
            code: "AUTH_OTP_INVALID",
            message: "Invalid OTP code"
          }
        });
      }

      user = await this.validatePhoneOtp(dto.phone, dto.otp);
    }
    if (!user) {
      const otpVerified = Boolean(challengeId) || this.isDevStaticOtpEnabled();
      if (!otpVerified) {
        throw new UnauthorizedException({
          error: {
            code: "AUTH_PHONE_INVALID",
            message: "Invalid phone or OTP"
          }
        });
      }
      return this.buildWebRegistrationRequiredResponse({
        phone: verifiedPhone,
        tenantId: resolvedTenantId,
        inviteToken: dto.invite_token
      });
    }

    const membership = await this.userTenantRepository.findOne({
      where: {
        userId: user.id,
        tenantId: resolvedTenantId,
        deletedAt: IsNull(),
        status: MembershipStatus.ACTIVE
      }
    });

    if (!membership) {
      return this.buildWebRegistrationRequiredResponse({
        phone: verifiedPhone,
        tenantId: resolvedTenantId,
        inviteToken: dto.invite_token
      });
    }

    let accessToken: string;
    try {
      accessToken = await this.signMembershipAccessToken({
        userId: user.id,
        tenantId: resolvedTenantId,
        role: membership.role,
        email: user.email ?? null,
        sessionVersion: membership.sessionVersion
      });
    } catch (error: unknown) {
      this.loggerService.error("auth_web_otp_session_issuance_result", {
        success: false,
        error_name: error instanceof Error ? error.name : typeof error,
        error_message: error instanceof Error ? error.message : String(error),
        stack: error instanceof Error ? error.stack : undefined
      });
      throw error;
    }

    void this.tenantAuditEventsService.appendOrWarn({
      tenantId: resolvedTenantId,
      actorUserId: user.id,
      actor: user.email ?? user.id,
      userId: user.id,
      action: TenantAuditAction.AUTH_LOGIN_WEB,
      resourceType: "session",
      resourceId: "web",
      clientIp: this.requestContextService.tryGetClientIp(),
      requestId: this.requestContextService.tryGetRequestId()
    });

    const response: WebSessionResponseDto = {
      session_token: accessToken,
      user_id: user.id,
      tenant_id: resolvedTenantId,
      entry_mode: "web"
    };
    return response;
  }

  private normalizeUuidString(value: string): string {
    return value.trim().toLowerCase();
  }

  /**
   * Ensures `userId` has an active user_tenants row for `tenantId` (non-deleted tenant).
   *
   * @returns `role` from user_tenants when the user belongs to the tenant.
   * @throws {ForbiddenException} HTTP 403 when the user does not belong to `tenantId`.
   */
  private async requireUserTenantMembershipRole(
    userId: string,
    tenantId: string
  ): Promise<{ role: string; sessionVersion: number }> {
    const target = this.normalizeUuidString(tenantId);
    const membership = await this.userTenantRepository.findOne({
      where: {
        userId,
        tenantId: target,
        deletedAt: IsNull(),
        status: MembershipStatus.ACTIVE
      }
    });
    if (!membership) {
      this.loggerService.warn("workspace session denied: user has no membership for tenant", {
        userId,
        tenantId: target
      });
      throw new ForbiddenException({
        error: {
          code: "TENANT_SCOPE_FORBIDDEN",
          message: "User does not belong to the requested tenant"
        }
      });
    }
    return { role: membership.role, sessionVersion: membership.sessionVersion };
  }

  /**
   * Re-issues a JWT for `dto.tenant_id` when the caller (JWT `sub`) has an active membership
   * for that tenant.
   */
  async createWorkspaceSession(
    userId: string,
    dto: WorkspaceSessionDto,
    hostResolvedTenant: Request["tenant"] | undefined,
    jwtTenantIdForAudit: string
  ): Promise<{
    session_token: string;
    user_id: string;
    tenant_id: string;
    entry_mode: "web";
  }> {
    const targetTenantId = dto.tenant_id.trim();
    if (!targetTenantId) {
      throw new BadRequestException({
        error: {
          code: "INVALID_INPUT",
          message: "tenant_id is required"
        }
      });
    }

    if (hostResolvedTenant?.id) {
      const hostId = this.normalizeUuidString(hostResolvedTenant.id);
      const requested = this.normalizeUuidString(targetTenantId);
      if (hostId !== requested) {
        throw new ForbiddenException({
          error: {
            code: "TENANT_HOST_MISMATCH",
            message:
              "Requested workspace must match the tenant subdomain (HTTP Host); open this workspace on its host before exchanging the session."
          }
        });
      }
    }

    const { role, sessionVersion } = await this.requireUserTenantMembershipRole(
      userId,
      targetTenantId
    );

    const user = await this.userRepository.findOne({
      where: { id: userId, deletedAt: IsNull() }
    });
    if (!user) {
      throw new UnauthorizedException({
        error: {
          code: "AUTH_UNAUTHENTICATED",
          message: "User not found"
        }
      });
    }

    const accessToken = await this.signMembershipAccessToken({
      userId: user.id,
      tenantId: this.normalizeUuidString(targetTenantId),
      role,
      email: user.email ?? null,
      sessionVersion
    });

    const fromTenant = this.normalizeUuidString(jwtTenantIdForAudit);
    const toTenant = this.normalizeUuidString(targetTenantId);
    void this.tenantAuditEventsService.appendOrWarn({
      tenantId: fromTenant,
      actorUserId: user.id,
      actor: user.email ?? user.id,
      userId: user.id,
      action: TenantAuditAction.AUTH_WORKSPACE_SWITCH,
      resourceType: "workspace",
      resourceId: toTenant,
      metadata: { from_tenant_id: fromTenant, to_tenant_id: toTenant },
      clientIp: this.requestContextService.tryGetClientIp(),
      requestId: this.requestContextService.tryGetRequestId()
    });

    return {
      session_token: accessToken,
      user_id: user.id,
      tenant_id: this.normalizeUuidString(targetTenantId),
      entry_mode: "web"
    };
  }

  async completeRegistration(dto: CompleteRegistrationDto): Promise<WebSessionResponseDto> {
    const onboarding = await this.verifyOnboardingToken(dto.onboarding_token);
    const fullName = dto.full_name.trim();
    const requestedEmail = dto.email?.trim();
    if (!fullName) {
      throw new BadRequestException({
        error: {
          code: "VALIDATION_ERROR",
          message: "full_name is required"
        }
      });
    }

    const existing = await this.findUserByPhone(onboarding.phone);
    const emailForSave =
      requestedEmail && requestedEmail !== ""
        ? requestedEmail
        : existing?.email?.trim()
          ? existing.email.trim()
          : null;

    const user = existing
      ? await this.userRepository.save({
          ...existing,
          fullName,
          phone: onboarding.phone,
          isPhoneVerified: true,
          email: emailForSave
        })
      : await this.userRepository.save(
          this.userRepository.create({
            email: emailForSave,
            hashedPassword: await argon2.hash(randomUUID()),
            fullName,
            phone: onboarding.phone,
            isPhoneVerified: true
          })
        );

    let membership = await this.userTenantRepository.findOne({
      where: {
        userId: user.id,
        tenantId: onboarding.tenantId,
        deletedAt: IsNull()
      }
    });
    if (!membership) {
      membership = await this.userTenantRepository.save(
        this.userTenantRepository.create({
          userId: user.id,
          tenantId: onboarding.tenantId,
          role: UserRole.Member,
          status: MembershipStatus.ACTIVE,
          invitedAt: null,
          joinedAt: new Date(),
          suspendedAt: null
        })
      );
    } else if (membership.status !== MembershipStatus.ACTIVE) {
      membership.status = MembershipStatus.ACTIVE;
      membership.joinedAt = membership.joinedAt ?? new Date();
      membership.suspendedAt = null;
      membership = await this.userTenantRepository.save(membership);
    }

    const accessToken = await this.signMembershipAccessToken({
      userId: user.id,
      tenantId: onboarding.tenantId,
      role: membership.role,
      email: user.email ?? null,
      sessionVersion: membership.sessionVersion
    });

    void this.tenantAuditEventsService.appendOrWarn({
      tenantId: onboarding.tenantId,
      actorUserId: user.id,
      actor: user.email ?? user.id,
      userId: user.id,
      action: TenantAuditAction.AUTH_LOGIN_WEB,
      resourceType: "registration",
      resourceId: "phone",
      metadata: { registration_completed: true },
      clientIp: this.requestContextService.tryGetClientIp(),
      requestId: this.requestContextService.tryGetRequestId()
    });

    return {
      session_token: accessToken,
      user_id: user.id,
      tenant_id: onboarding.tenantId,
      entry_mode: "web"
    };
  }

  async createTelegramSession(
    req: Request,
    dto: TelegramSessionDto
  ): Promise<{
    session_token: string;
    user_id: string;
    tenant_id: string;
    entry_mode: "telegram";
  }> {
    const { telegramUserId } = this.parseTelegramInitPayload(
      dto.telegram_init_payload
    );

    const tenant = req.tenant;
    if (!tenant) {
      throw new ForbiddenException({
        error: {
          code: "TENANT_CONTEXT_MISSING",
          message: "Workspace tenant must be resolved from the HTTP Host (tenant subdomain)"
        }
      });
    }
    const resolvedTenantId = this.normalizeUuidString(tenant.id);

    let user = await this.userRepository.findOne({
      where: {
        telegramUserId,
        deletedAt: IsNull()
      }
    });

    if (!user) {
      user = await this.userRepository.save(
        this.userRepository.create({
          email: null,
          hashedPassword: await argon2.hash(randomUUID()),
          telegramUserId
        })
      );
    }

    this.requestContextService.setTenantId(resolvedTenantId);

    const membership = await this.userTenantRepository.findOne({
      where: {
        userId: user.id,
        tenantId: resolvedTenantId,
        deletedAt: IsNull(),
        status: MembershipStatus.ACTIVE
      }
    });

    if (!membership) {
      throw new ForbiddenException({
        error: {
          code: "TENANT_SCOPE_FORBIDDEN",
          message: "User does not belong to this workspace tenant"
        }
      });
    }

    const accessToken = await this.signMembershipAccessToken({
      userId: user.id,
      tenantId: resolvedTenantId,
      role: membership.role,
      email: user.email ?? null,
      sessionVersion: membership.sessionVersion
    });

    void this.tenantAuditEventsService.appendOrWarn({
      tenantId: resolvedTenantId,
      actorUserId: user.id,
      actor: user.email ?? user.id,
      userId: user.id,
      action: TenantAuditAction.AUTH_LOGIN_TELEGRAM,
      resourceType: "session",
      resourceId: "telegram",
      clientIp: this.requestContextService.tryGetClientIp(),
      requestId: this.requestContextService.tryGetRequestId()
    });

    return {
      session_token: accessToken,
      user_id: user.id,
      tenant_id: resolvedTenantId,
      entry_mode: "telegram"
    };
  }

  async linkTelegram(
    userId: string,
    sessionTenantId: string,
    dto: LinkTelegramDto
  ): Promise<{
    user_id: string;
    linked_telegram_user_id: string;
    link_status: "Linked";
    linked_at: string;
  }> {
    const { telegramUserId } = this.parseTelegramInitPayload(
      dto.telegram_init_payload
    );

    const resolvedTenantId = this.normalizeUuidString(sessionTenantId);
    this.requestContextService.setTenantId(resolvedTenantId);

    const membership = await this.userTenantRepository.findOne({
      where: {
        userId,
        tenantId: resolvedTenantId,
        deletedAt: IsNull()
      }
    });

    if (!membership) {
      throw new ForbiddenException("TENANT_SCOPE_FORBIDDEN");
    }

    const currentUser = await this.userRepository.findOne({
      where: {
        id: userId,
        deletedAt: IsNull()
      }
    });
    if (!currentUser) {
      throw new UnauthorizedException("AUTH_UNAUTHENTICATED");
    }

    const linkedToAnother = await this.userRepository.findOne({
      where: {
        telegramUserId,
        deletedAt: IsNull()
      }
    });
    if (linkedToAnother && linkedToAnother.id !== userId) {
      throw new BadRequestException("STATE_TRANSITION_INVALID");
    }

    if (
      currentUser.telegramUserId &&
      currentUser.telegramUserId !== telegramUserId
    ) {
      throw new BadRequestException("STATE_TRANSITION_INVALID");
    }

    currentUser.telegramUserId = telegramUserId;
    await this.userRepository.save(currentUser);

    return {
      user_id: userId,
      linked_telegram_user_id: telegramUserId,
      link_status: "Linked",
      linked_at: new Date().toISOString()
    };
  }
}

import { Injectable, UnauthorizedException } from "@nestjs/common";
import { InjectDataSource, InjectRepository } from "@nestjs/typeorm";
import { randomUUID } from "node:crypto";
import { DataSource, Repository } from "typeorm";

import { normalizeOtpPhoneInput } from "../../common/phone/otp-phone-normalize";
import { ConfigService } from "../../config/config.service";
import type { MobileOtpPurpose } from "./entities/mobile-otp-challenge.entity";
import { MobileOtpChallengeEntity } from "./entities/mobile-otp-challenge.entity";

const DEV_STATIC_OTP = "1234";
const CHALLENGE_TTL_MS = 5 * 60 * 1000;

@Injectable()
export class OtpService {
  constructor(
    @InjectRepository(MobileOtpChallengeEntity)
    private readonly challengeRepository: Repository<MobileOtpChallengeEntity>,
    @InjectDataSource()
    private readonly dataSource: DataSource,
    private readonly configService: ConfigService
  ) {}

  private isDevStaticOtpEnabled(): boolean {
    const nodeEnv = this.configService.getNodeEnv();
    return (
      (nodeEnv === "development" || nodeEnv === "test") &&
      this.configService.getAuthAllowDevStaticOtp()
    );
  }

  async createMobileOtpChallenge(
    mobile: string,
    purpose: MobileOtpPurpose
  ): Promise<{ challengeId: string }> {
    const normalized = normalizeOtpPhoneInput(mobile);
    const id = randomUUID();
    const expiresAt = new Date(Date.now() + CHALLENGE_TTL_MS);

    await this.dataSource.query(
      `INSERT INTO mobile_otp_challenges (id, mobile, purpose, expires_at, used)
       VALUES ($1, $2, $3, $4, $5)`,
      [id, normalized, purpose, expiresAt, false]
    );

    return { challengeId: id };
  }

  async verifyMobileOtp(
    challengeId: string,
    code: string
  ): Promise<{ success: true; mobile: string; purpose: MobileOtpPurpose }> {
    if (!this.isDevStaticOtpEnabled()) {
      throw new UnauthorizedException({
        error: {
          code: "AUTH_OTP_INVALID",
          message: "OTP verification is not available"
        }
      });
    }

    const trimmedCode = typeof code === "string" ? code.trim() : "";
    if (trimmedCode !== DEV_STATIC_OTP) {
      throw new UnauthorizedException({
        error: {
          code: "AUTH_OTP_INVALID",
          message: "Invalid OTP code"
        }
      });
    }

    const rows = (await this.dataSource.query(
      `SELECT id, mobile, purpose, expires_at AS "expiresAt", used
       FROM mobile_otp_challenges
       WHERE id = $1
       LIMIT 1`,
      [challengeId.trim()]
    )) as Array<{
      id: string;
      mobile: string;
      purpose: MobileOtpPurpose;
      expiresAt: Date;
      used: boolean;
    }>;
    const row = rows[0];
    if (!row) {
      throw new UnauthorizedException({
        error: {
          code: "AUTH_OTP_INVALID",
          message: "Invalid or expired OTP challenge"
        }
      });
    }
    if (row.used) {
      throw new UnauthorizedException({
        error: {
          code: "AUTH_OTP_INVALID",
          message: "OTP challenge already used"
        }
      });
    }
    if (row.expiresAt.getTime() <= Date.now()) {
      throw new UnauthorizedException({
        error: {
          code: "AUTH_OTP_INVALID",
          message: "OTP challenge expired"
        }
      });
    }

    row.used = true;
    await this.challengeRepository.save(row);

    return { success: true, mobile: row.mobile, purpose: row.purpose };
  }
}

import {
  CanActivate,
  ExecutionContext,
  ForbiddenException,
  Inject,
  Injectable
} from "@nestjs/common";
import { Reflector } from "@nestjs/core";
import { isWorkspaceUserRole, type UserRole } from "../../common/auth/user-role.enum";
import { RequestContextService } from "../../common/request-context/request-context.service";
import { ROLES_METADATA_KEY } from "./roles.decorator";

@Injectable()
export class RolesGuard implements CanActivate {
  constructor(
    @Inject(Reflector) private readonly reflector: Reflector,
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService
  ) {}

  canActivate(context: ExecutionContext): boolean {
    const allowedRoles =
      this.reflector.getAllAndOverride<UserRole[]>(ROLES_METADATA_KEY, [
        context.getHandler(),
        context.getClass()
      ]) ?? [];

    if (allowedRoles.length === 0) {
      return true;
    }

    const role = this.requestContextService.getRole();
    if (!role || !isWorkspaceUserRole(role)) {
      throw new ForbiddenException({
        error: {
          code: "AUTH_FORBIDDEN_ROLE",
          message: "Insufficient role for this operation"
        }
      });
    }

    if (!allowedRoles.includes(role)) {
      throw new ForbiddenException({
        error: {
          code: "AUTH_FORBIDDEN_ROLE",
          message: "Insufficient role for this operation"
        }
      });
    }

    return true;
  }
}

import {
  ConflictException,
  Inject,
  Injectable,
  UnauthorizedException
} from "@nestjs/common";
import { DataSource } from "typeorm";
import { RequestContextService } from "../../common/request-context/request-context.service";
import { TenantEntity } from "../identity/entities/tenant.entity";
import { UserTenantEntity } from "../identity/entities/user-tenant.entity";
import { TenantManagementDbService } from "../tenant/tenant-management-db.service";
import { UserRole } from "../../common/auth/user-role.enum";
import type { AuthWorkspaceItemDto } from "./dto/auth-workspace-item.dto";
import type { CreateWorkspaceDto } from "./dto/create-workspace.dto";

/** Workspace listing reads cross-tenant memberships via TenantManagementDbService. */
@Injectable()
export class WorkspaceService {
  constructor(
    private readonly dataSource: DataSource,
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService,
    @Inject(TenantManagementDbService)
    private readonly tenantManagementDbService: TenantManagementDbService
  ) {}

  /** Lists workspace rows for the JWT subject. */
  async listWorkspaces(): Promise<AuthWorkspaceItemDto[]> {
    const userId = this.requestContextService.getUserId();
    if (!userId) {
      throw new UnauthorizedException({
        error: {
          code: "AUTH_UNAUTHENTICATED",
          message: "Authentication required"
        }
      });
    }

    return this.tenantManagementDbService.listUserWorkspacesForAuth(userId);
  }

  /** Creates a new workspace and attaches current user as owner. */
  async createWorkspace(input: CreateWorkspaceDto): Promise<AuthWorkspaceItemDto> {
    const userId = this.requestContextService.getUserId();
    if (!userId) {
      throw new UnauthorizedException({
        error: {
          code: "AUTH_UNAUTHENTICATED",
          message: "Authentication required"
        }
      });
    }

    const tenantName = input.name.trim();
    const tenantSubdomain = input.subdomain.trim().toLowerCase();
    try {
      return await this.dataSource.transaction(async (manager) => {
        const tenant = await manager.save(
          TenantEntity,
          manager.create(TenantEntity, {
            name: tenantName,
            subdomain: tenantSubdomain
          })
        );
        await manager.save(
          UserTenantEntity,
          manager.create(UserTenantEntity, {
            tenantId: tenant.id,
            userId,
            role: UserRole.Owner
          })
        );
        return {
          tenant_id: tenant.id,
          tenant_name: tenant.name,
          tenant_subdomain: tenant.subdomain ?? "",
          role: UserRole.Owner,
          session_version: 1
        };
      });
    } catch (error) {
      if (this.isSubdomainUniqueViolation(error)) {
        throw new ConflictException({
          error: {
            code: "WORKSPACE_SUBDOMAIN_TAKEN",
            message: "Workspace subdomain is already in use"
          }
        });
      }
      throw error;
    }
  }

  private isSubdomainUniqueViolation(error: unknown): boolean {
    if (!(error instanceof Error)) {
      return false;
    }
    const anyError = error as Error & { code?: string; detail?: string; constraint?: string };
    return (
      anyError.code === "23505" &&
      ((typeof anyError.constraint === "string" &&
        anyError.constraint.includes("uq_tenants_subdomain_active_lower")) ||
        (typeof anyError.detail === "string" &&
          anyError.detail.toLowerCase().includes("uq_tenants_subdomain_active_lower")))
    );
  }
}

import {
  Body,
  Controller,
  Delete,
  Get,
  HttpCode,
  Inject,
  Logger,
  Param,
  Patch,
  UseGuards,
} from "@nestjs/common";
import {
  ApiBearerAuth,
  ApiConflictResponse,
  ApiNoContentResponse,
  ApiNotFoundResponse,
  ApiOkResponse,
  ApiOperation,
  ApiParam,
  ApiTags,
} from "@nestjs/swagger";

import { UserRole } from "../../common/auth/user-role.enum";
import { AuthorizationPresenceGuard } from "../auth/authorization-presence.guard";
import { Roles } from "../auth/roles.decorator";
import { RolesGuard } from "../auth/roles.guard";
import { RequestContextService } from "../../common/request-context/request-context.service";
import { DraftSyncPayloadDto } from "./dto/draft-sync-payload.dto";
import { DraftEngineFacade } from "./draft-engine.facade";
import { DraftEngineAbilitiesGuard } from "./guards/draft-engine-abilities.guard";

@ApiTags("Draft engine")
@Controller("api/v2/workspaces")
@UseGuards(AuthorizationPresenceGuard, RolesGuard, DraftEngineAbilitiesGuard)
@ApiBearerAuth()
export class DraftEngineController {
  private readonly logger = new Logger(DraftEngineController.name);

  constructor(
    @Inject(DraftEngineFacade)
    private readonly draftEngineFacade: DraftEngineFacade,
    @Inject(RequestContextService)
    private readonly requestContext: RequestContextService,
  ) {}

  @Get(":tenantId/draft-engine/:draftKey")
  @Roles(UserRole.Owner, UserRole.Admin, UserRole.Member)
  @ApiOperation({ summary: "Fetch draft snapshot for current member" })
  @ApiParam({ name: "tenantId", format: "uuid" })
  @ApiParam({ name: "draftKey", example: "denali-create" })
  @ApiOkResponse({ type: DraftSyncPayloadDto })
  @ApiNotFoundResponse({ description: "No draft saved for this key" })
  async getDraft(
    @Param("tenantId") tenantId: string,
    @Param("draftKey") draftKey: string,
  ): Promise<DraftSyncPayloadDto | null> {
    this.logger.log(
      `DEBUG-TRACE [A] Input: route workspaceId=${tenantId} draftKey=${draftKey} | ` +
        `session jwtTenantId=${this.requestContext.resolveEffectiveTenantId() ?? "null"} ` +
        `userId=${this.requestContext.getUserId() ?? "null"}`,
    );

    const result = await this.draftEngineFacade.findForMember(tenantId, draftKey);

    this.logger.log(`DEBUG-TRACE [end] GET response payload=${JSON.stringify(result)}`);
    return result;
  }

  @Patch(":tenantId/draft-engine/:draftKey")
  @Roles(UserRole.Owner, UserRole.Admin, UserRole.Member)
  @ApiOperation({ summary: "Upsert draft snapshot with optimistic locking" })
  @ApiParam({ name: "tenantId", format: "uuid" })
  @ApiParam({ name: "draftKey", example: "denali-create" })
  @ApiOkResponse({ type: DraftSyncPayloadDto })
  @ApiConflictResponse({ description: "Version mismatch — server payload included" })
  async upsertDraft(
    @Param("tenantId") tenantId: string,
    @Param("draftKey") draftKey: string,
    @Body() body: DraftSyncPayloadDto,
  ): Promise<DraftSyncPayloadDto> {
    return this.draftEngineFacade.upsertForMember(tenantId, draftKey, body);
  }

  @Delete(":tenantId/draft-engine/:draftKey")
  @HttpCode(204)
  @Roles(UserRole.Owner, UserRole.Admin, UserRole.Member)
  @ApiOperation({ summary: "Delete draft snapshot for current member" })
  @ApiParam({ name: "tenantId", format: "uuid" })
  @ApiParam({ name: "draftKey", example: "denali-create" })
  @ApiNoContentResponse()
  @ApiNotFoundResponse({ description: "Draft not found" })
  async deleteDraft(
    @Param("tenantId") tenantId: string,
    @Param("draftKey") draftKey: string,
  ): Promise<void> {
    await this.draftEngineFacade.deleteForMember(tenantId, draftKey);
  }
}

import { Injectable, Logger, HttpException, Inject } from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import {
  CURRENT_DRAFT_SCHEMA_VERSION,
  draftSnapshotEnvelopeSchema,
  type DraftSnapshot,
} from "@repo/shared-contracts";
import { Repository } from "typeorm";
import { randomUUID } from "node:crypto";

import type { DraftSyncPayloadDto } from "./dto/draft-sync-payload.dto";
import {
  isDraftEngineV2Enabled,
  shouldPersistDraftSchemaMigrationOnRead,
} from "./draft-engine-feature-flags";
import { AUDIT_CATEGORY } from "../../common/audit/audit-category";
import { AuditLogService } from "../../common/audit/audit-log.service";
import { DraftScopeResolver } from "./storage/draft-scope.resolver";
import { PostgresDraftSnapshotStore } from "./storage/postgres-draft-snapshot.store";
import { DraftMigratorRegistry } from "@repo/shared-contracts";
import { DraftConflictException } from "./draft-conflict.exception";
import { DraftForensicException } from "./draft-forensic.exception";
import { DraftEventEntity } from "./entities/draft-event.entity";
import { tryGetActiveTraceLogFields } from "../../common/observability/active-trace-log-fields";
import { RequestContextService } from "../../common/request-context/request-context.service";

export type DraftSyncPayloadResponse = DraftSnapshot;

@Injectable()
export class DraftEngineFacade {
  private readonly logger = new Logger(DraftEngineFacade.name);
  private static readonly DENALI_CREATE_DRAFT_KEY = "denali-create";

  constructor(
    @Inject(PostgresDraftSnapshotStore)
    private readonly store: PostgresDraftSnapshotStore,
    @Inject(DraftScopeResolver)
    private readonly scopeResolver: DraftScopeResolver,
    @Inject(DraftMigratorRegistry)
    private readonly migratorRegistry: DraftMigratorRegistry,
    @Inject(AuditLogService)
    private readonly auditLog: AuditLogService,
    @InjectRepository(DraftEventEntity)
    private readonly draftEventsRepository: Repository<DraftEventEntity>,
    @Inject(RequestContextService)
    private readonly requestContext: RequestContextService,
  ) {}

  private getDebugContextFields(draftKey?: string) {
    let context: any = {};
    try {
      if (this.requestContext && typeof this.requestContext.getContext === "function") {
        context = this.requestContext.getContext() || {};
      }
    } catch {}

    const correlationId = context.correlationId ?? 
      (this.requestContext && typeof this.requestContext.tryGetCorrelationId === "function" ? this.requestContext.tryGetCorrelationId() : undefined) ?? 
      "N/A";
    const tenantId = context.tenantId ?? 
      (this.requestContext && typeof this.requestContext.tryGetTenantId === "function" ? this.requestContext.tryGetTenantId() : undefined) ?? 
      "N/A";
    const hostTenantId = context.hostTenantId ?? 
      (this.requestContext && typeof this.requestContext.tryGetHostTenantId === "function" ? this.requestContext.tryGetHostTenantId() : undefined) ?? 
      "N/A";
    const userId = context.userId ?? 
      (this.requestContext && typeof this.requestContext.tryGetUserId === "function" ? this.requestContext.tryGetUserId() : undefined) ?? 
      "N/A";
    const role = context.role ?? 
      (this.requestContext && typeof this.requestContext.tryGetRole === "function" ? this.requestContext.tryGetRole() : undefined) ?? 
      "N/A";

    return {
      correlationId,
      requestId: context.requestId ?? 
        (this.requestContext && typeof this.requestContext.tryGetRequestId === "function" ? this.requestContext.tryGetRequestId() : undefined) ?? 
        "N/A",
      tenantId,
      hostTenantId,
      userId,
      role,
      tenantContextFrozen: context.tenantContextFrozen,
      tenantBindingMode: context.tenantBindingMode,
      draftKey,
    };
  }

  private ensureCorrelationId(): string {
    let context: any = null;
    try {
      if (this.requestContext && typeof this.requestContext.getContext === "function") {
        context = this.requestContext.getContext();
      }
    } catch {}

    if (context) {
      if (!context.correlationId) {
        context.correlationId = randomUUID();
      }
      return context.correlationId;
    }

    return (this.requestContext && typeof this.requestContext.tryGetCorrelationId === "function" ? this.requestContext.tryGetCorrelationId() : undefined) ?? randomUUID();
  }

  private resolveTraceId(): string | null {
    const otelTraceId = tryGetActiveTraceLogFields()?.trace_id?.trim();
    if (otelTraceId) {
      return otelTraceId;
    }
    const traceId = (this.requestContext && typeof this.requestContext.tryGetCorrelationId === "function" ? this.requestContext.tryGetCorrelationId() : undefined) ?? 
      (this.requestContext && typeof this.requestContext.tryGetRequestId === "function" ? this.requestContext.tryGetRequestId() : undefined);
    if (!traceId || traceId.trim() === "") {
      return null;
    }
    return traceId.trim();
  }

  private async logDraftEvent(input: {
    workspaceId: string;
    userId: string;
    draftKey: string;
    eventType: DraftEventEntity["eventType"];
    baseVersion: number | null;
    nextVersion: number | null;
    payloadSnapshot: Record<string, unknown>;
  }): Promise<void> {
    const correlationId = this.ensureCorrelationId();
    const ctx = this.getDebugContextFields(input.draftKey);
    this.logger.log(
      `[DRAFT-FORENSIC] [correlationId: ${correlationId}] logDraftEvent: entering method. Context: ${JSON.stringify(ctx)}`,
    );

    // Tenant Isolation Check: Verify if active tenantId matches parameter workspaceId
    if (ctx.tenantId !== "N/A" && ctx.tenantId.toLowerCase() !== input.workspaceId.trim().toLowerCase()) {
      const errorMsg = `Tenant isolation mismatch in event logging! Active context tenantId (${ctx.tenantId}) does not match workspaceId (${input.workspaceId})`;
      this.logger.error(`[DRAFT-FORENSIC] [correlationId: ${correlationId}] [CRITICAL] ${errorMsg}`);
      throw new DraftForensicException(errorMsg, null, ctx);
    }

    try {
      this.logger.log(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] logDraftEvent: pre-await draftEventsRepository.insert. Context: ${JSON.stringify(this.getDebugContextFields(input.draftKey))}`,
      );
      await this.draftEventsRepository.insert({
        workspaceId: input.workspaceId,
        userId: input.userId,
        draftKey: input.draftKey,
        eventType: input.eventType,
        traceId: this.resolveTraceId(),
        baseVersion: input.baseVersion,
        nextVersion: input.nextVersion,
        payloadSnapshot: input.payloadSnapshot as never,
      });
      this.logger.log(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] logDraftEvent: post-await draftEventsRepository.insert success.`,
      );
    } catch (err: unknown) {
      this.logger.error(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] logDraftEvent: failed. Context: ${JSON.stringify(this.getDebugContextFields(input.draftKey))}`,
        err instanceof Error ? err.stack : String(err),
      );
      if (err instanceof HttpException) {
        throw err;
      }
      throw new DraftForensicException("Failed to log draft event", err, this.getDebugContextFields(input.draftKey));
    }
  }

  private dtoToSnapshot(body: DraftSyncPayloadDto): DraftSnapshot {
    const schemaVersion = Number(body.schemaVersion);
    return {
      data: body.data,
      version: Number(body.version),
      schemaVersion:
        Number.isFinite(schemaVersion) && schemaVersion >= 1
          ? Math.floor(schemaVersion)
          : CURRENT_DRAFT_SCHEMA_VERSION,
      lastModified: Number(body.lastModified),
    };
  }

  private validateEnvelope(snapshot: DraftSnapshot): DraftSnapshot {
    const parsed = draftSnapshotEnvelopeSchema.safeParse(snapshot);
    if (!parsed.success) {
      this.logger.warn(`draft envelope validation failed: ${parsed.error.message}`);
    }
    return snapshot;
  }

  private readStringPath(record: Record<string, unknown>, path: readonly string[]): string {
    let node: unknown = record;
    for (const segment of path) {
      if (!node || typeof node !== "object" || Array.isArray(node)) {
        return "";
      }
      node = (node as Record<string, unknown>)[segment];
    }
    return typeof node === "string" ? node.trim() : "";
  }

  private hasMeaningfulDenaliFormData(value: unknown): boolean {
    if (!value || typeof value !== "object" || Array.isArray(value)) {
      return false;
    }
    const record = value as Record<string, unknown>;
    const keyPaths: ReadonlyArray<readonly string[]> = [
      ["basicInfo", "title"],
      ["basicInfo", "tourType"],
      ["basicInfo", "destinationId"],
      ["timing", "startDate"],
      ["timing", "endDate"],
    ];
    return keyPaths.some((path) => this.readStringPath(record, path).length > 0);
  }

  private isEffectivelyEmptyDraft(draftKey: string, snapshot: DraftSnapshot): boolean {
    if (draftKey !== DraftEngineFacade.DENALI_CREATE_DRAFT_KEY) {
      return false;
    }
    const data = snapshot.data as { form?: unknown; currentStepIndex?: unknown };
    const stepIndex = typeof data.currentStepIndex === "number" ? data.currentStepIndex : 0;
    const hasMeaningfulForm = this.hasMeaningfulDenaliFormData(data.form);
    return stepIndex <= 0 && !hasMeaningfulForm;
  }

  /** MAP alias: load draft for current member (with optional schema migration). */
  async loadDraft(
    tenantId: string,
    draftKey: string,
  ): Promise<DraftSyncPayloadResponse | null> {
    const correlationId = this.ensureCorrelationId();
    const ctx = this.getDebugContextFields(draftKey);
    this.logger.log(
      `[DRAFT-FORENSIC] [correlationId: ${correlationId}] loadDraft: entering method. Context: ${JSON.stringify(ctx)}`,
    );
    try {
      this.logger.log(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] loadDraft: pre-await findForMember. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
      );
      const res = await this.findForMember(tenantId, draftKey);
      this.logger.log(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] loadDraft: post-await findForMember success.`,
      );
      return res;
    } catch (err: unknown) {
      this.logger.error(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] loadDraft: failed. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
        err instanceof Error ? err.stack : String(err),
      );
      if (err instanceof HttpException) {
        throw err;
      }
      throw new DraftForensicException("Failed to load draft", err, this.getDebugContextFields(draftKey));
    }
  }

  async findForMember(
    tenantId: string,
    draftKey: string,
  ): Promise<DraftSyncPayloadResponse | null> {
    const correlationId = this.ensureCorrelationId();
    const ctx = this.getDebugContextFields(draftKey);
    this.logger.log(
      `[DRAFT-FORENSIC] [correlationId: ${correlationId}] findForMember: entering method with tenantId=${tenantId}, draftKey=${draftKey}. Context: ${JSON.stringify(ctx)}`,
    );

    // Tenant Isolation Check: Verify if active tenantId matches parameter tenantId
    if (ctx.tenantId !== "N/A" && ctx.tenantId.toLowerCase() !== tenantId.trim().toLowerCase()) {
      const errorMsg = `Tenant isolation mismatch! Active context tenantId (${ctx.tenantId}) does not match param tenantId (${tenantId})`;
      this.logger.error(`[DRAFT-FORENSIC] [correlationId: ${correlationId}] [CRITICAL] ${errorMsg}`);
      throw new DraftForensicException(errorMsg, null, ctx);
    }

    try {
      this.logger.log(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] findForMember: pre-await scopeResolver.resolveOrThrow. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
      );
      const scope = this.scopeResolver.resolveOrThrow(tenantId, draftKey);

      this.logger.log(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] findForMember: pre-await store.find. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
      );
      const raw = await this.store.find(scope);
      if (raw == null) {
        this.logger.log(
          `[DRAFT-FORENSIC] [correlationId: ${correlationId}] findForMember: no draft found.`,
        );
        return null;
      }

      if (!isDraftEngineV2Enabled()) {
        const isEmpty = this.isEffectivelyEmptyDraft(draftKey, raw);
        this.logger.log(
          `[DRAFT-FORENSIC] [correlationId: ${correlationId}] findForMember: V2 disabled. isEmpty=${isEmpty}`,
        );
        return isEmpty ? null : raw;
      }

      const { snapshot, upgraded } = this.migratorRegistry.migrateEnvelope(draftKey, raw);
      if (!upgraded) {
        const isEmpty = this.isEffectivelyEmptyDraft(draftKey, snapshot);
        this.logger.log(
          `[DRAFT-FORENSIC] [correlationId: ${correlationId}] findForMember: migrated, not upgraded. isEmpty=${isEmpty}`,
        );
        return isEmpty ? null : snapshot;
      }

      if (shouldPersistDraftSchemaMigrationOnRead()) {
        this.logger.log(
          `[DRAFT-FORENSIC] [correlationId: ${correlationId}] findForMember: pre-await store.upgradeSchemaInPlace. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
        );
        const persisted = await this.store.upgradeSchemaInPlace(scope, {
          data: snapshot.data,
          schemaVersion: snapshot.schemaVersion,
          version: snapshot.version,
        });
        const effective = persisted ?? snapshot;
        const isEmpty = this.isEffectivelyEmptyDraft(draftKey, effective);
        this.logger.log(
          `[DRAFT-FORENSIC] [correlationId: ${correlationId}] findForMember: persisted schema upgrade. isEmpty=${isEmpty}`,
        );
        return isEmpty ? null : effective;
      }

      const isEmpty = this.isEffectivelyEmptyDraft(draftKey, snapshot);
      this.logger.log(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] findForMember: return migrated snapshot. isEmpty=${isEmpty}`,
      );
      return isEmpty ? null : snapshot;
    } catch (err: unknown) {
      this.logger.error(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] findForMember: failed. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
        err instanceof Error ? err.stack : String(err),
      );
      if (err instanceof HttpException) {
        throw err;
      }
      throw new DraftForensicException("Failed to find draft", err, this.getDebugContextFields(draftKey));
    }
  }

  /** MAP alias: upsert draft for current member. */
  async saveDraft(
    tenantId: string,
    draftKey: string,
    body: DraftSyncPayloadDto,
  ): Promise<DraftSyncPayloadResponse> {
    const correlationId = this.ensureCorrelationId();
    const ctx = this.getDebugContextFields(draftKey);
    this.logger.log(
      `[DRAFT-FORENSIC] [correlationId: ${correlationId}] saveDraft: entering method. Context: ${JSON.stringify(ctx)}`,
    );
    try {
      this.logger.log(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] saveDraft: pre-await upsertForMember. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
      );
      const res = await this.upsertForMember(tenantId, draftKey, body);
      this.logger.log(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] saveDraft: post-await upsertForMember success.`,
      );
      return res;
    } catch (err: unknown) {
      this.logger.error(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] saveDraft: failed. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
        err instanceof Error ? err.stack : String(err),
      );
      if (err instanceof HttpException) {
        throw err;
      }
      throw new DraftForensicException("Failed to save draft", err, this.getDebugContextFields(draftKey));
    }
  }

  async upsertForMember(
    tenantId: string,
    draftKey: string,
    body: DraftSyncPayloadDto,
  ): Promise<DraftSyncPayloadResponse> {
    const correlationId = this.ensureCorrelationId();
    const ctx = this.getDebugContextFields(draftKey);
    this.logger.log(
      `[DRAFT-FORENSIC] [correlationId: ${correlationId}] upsertForMember: entering method. Context: ${JSON.stringify(ctx)}`,
    );

    // Tenant Isolation Check: Verify if active tenantId matches parameter tenantId
    if (ctx.tenantId !== "N/A" && ctx.tenantId.toLowerCase() !== tenantId.trim().toLowerCase()) {
      const errorMsg = `Tenant isolation mismatch! Active context tenantId (${ctx.tenantId}) does not match param tenantId (${tenantId})`;
      this.logger.error(`[DRAFT-FORENSIC] [correlationId: ${correlationId}] [CRITICAL] ${errorMsg}`);
      throw new DraftForensicException(errorMsg, null, ctx);
    }

    try {
      this.logger.log(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] upsertForMember: pre-await scopeResolver.resolveOrThrow. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
      );
      const scope = this.scopeResolver.resolveOrThrow(tenantId, draftKey);
      const snapshot = this.validateEnvelope(this.dtoToSnapshot(body));
      const payload = isDraftEngineV2Enabled()
        ? this.migratorRegistry.migrateEnvelope(draftKey, snapshot).snapshot
        : snapshot;
      let saved: DraftSyncPayloadResponse;
      try {
        this.logger.log(
          `[DRAFT-FORENSIC] [correlationId: ${correlationId}] upsertForMember: pre-await store.upsert. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
        );
        saved = await this.store.upsert(scope, payload);
      } catch (error: unknown) {
        if (error instanceof DraftConflictException) {
          const details = (error.getResponse() as { error?: { details?: { server?: DraftSnapshot } } }).error
            ?.details;
          try {
            this.logger.log(
              `[DRAFT-FORENSIC] [correlationId: ${correlationId}] upsertForMember: conflict detected. pre-await logDraftEvent. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
            );
            await this.logDraftEvent({
              workspaceId: scope.workspaceId,
              userId: scope.userId,
              draftKey: scope.draftKey,
              eventType: "draft_conflict",
              baseVersion: payload.version,
              nextVersion: details?.server?.version ?? null,
              payloadSnapshot: payload.data,
            });
          } catch (logErr) {
            this.logger.warn(
              `[DRAFT-FORENSIC] [correlationId: ${correlationId}] draft event log failed for conflict: ${
                logErr instanceof Error ? logErr.message : String(logErr)
              }`,
            );
          }

          this.logger.log(
            `[DRAFT-FORENSIC] [correlationId: ${correlationId}] upsertForMember: pre-await auditLog.logEvent for conflict. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
          );
          await this.auditLog.logEvent({
            action: "draft_engine.conflict",
            entity: "draft_snapshot",
            entityId: `${scope.workspaceId}:${scope.userId}:${scope.draftKey}`,
            category: AUDIT_CATEGORY.DRAFT_ENGINE_EVENT,
            before: {
              incomingVersion: payload.version,
              incomingSchemaVersion: payload.schemaVersion,
              draftKey: scope.draftKey,
            },
            after: {
              serverVersion: details?.server?.version ?? null,
              serverSchemaVersion: details?.server?.schemaVersion ?? null,
            },
          });
        }
        throw error;
      }

      this.logger.log(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] upsertForMember: pre-await auditLog.logEvent for success. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
      );
      await this.auditLog.logEvent({
        action: "draft_engine.upsert",
        entity: "draft_snapshot",
        entityId: `${scope.workspaceId}:${scope.userId}:${scope.draftKey}`,
        category: AUDIT_CATEGORY.DRAFT_ENGINE_EVENT,
        before: {
          incomingVersion: payload.version,
          incomingSchemaVersion: payload.schemaVersion,
        },
        after: {
          savedVersion: saved.version,
          savedSchemaVersion: saved.schemaVersion,
        },
      });

      try {
        this.logger.log(
          `[DRAFT-FORENSIC] [correlationId: ${correlationId}] upsertForMember: pre-await logDraftEvent for success. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
        );
        await this.logDraftEvent({
          workspaceId: scope.workspaceId,
          userId: scope.userId,
          draftKey: scope.draftKey,
          eventType: "draft_saved",
          baseVersion: payload.version,
          nextVersion: saved.version,
          payloadSnapshot: saved.data,
        });
      } catch (logErr) {
        this.logger.warn(
          `[DRAFT-FORENSIC] [correlationId: ${correlationId}] draft event log failed for save: ${
            logErr instanceof Error ? logErr.message : String(logErr)
          }`,
        );
      }
      return saved;
    } catch (err: unknown) {
      this.logger.error(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] upsertForMember: failed. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
        err instanceof Error ? err.stack : String(err),
      );
      if (err instanceof HttpException) {
        throw err;
      }
      throw new DraftForensicException("Failed to upsert draft", err, this.getDebugContextFields(draftKey));
    }
  }

  /** MAP alias: delete draft for current member. */
  async deleteDraft(tenantId: string, draftKey: string): Promise<void> {
    const correlationId = this.ensureCorrelationId();
    const ctx = this.getDebugContextFields(draftKey);
    this.logger.log(
      `[DRAFT-FORENSIC] [correlationId: ${correlationId}] deleteDraft: entering method. Context: ${JSON.stringify(ctx)}`,
    );
    try {
      this.logger.log(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] deleteDraft: pre-await deleteForMember. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
      );
      await this.deleteForMember(tenantId, draftKey);
      this.logger.log(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] deleteDraft: post-await deleteForMember success.`,
      );
    } catch (err: unknown) {
      this.logger.error(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] deleteDraft: failed. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
        err instanceof Error ? err.stack : String(err),
      );
      if (err instanceof HttpException) {
        throw err;
      }
      throw new DraftForensicException("Failed to delete draft", err, this.getDebugContextFields(draftKey));
    }
  }

  async deleteForMember(tenantId: string, draftKey: string): Promise<void> {
    const correlationId = this.ensureCorrelationId();
    const ctx = this.getDebugContextFields(draftKey);
    this.logger.log(
      `[DRAFT-FORENSIC] [correlationId: ${correlationId}] deleteForMember: entering method. Context: ${JSON.stringify(ctx)}`,
    );

    // Tenant Isolation Check: Verify if active tenantId matches parameter tenantId
    if (ctx.tenantId !== "N/A" && ctx.tenantId.toLowerCase() !== tenantId.trim().toLowerCase()) {
      const errorMsg = `Tenant isolation mismatch! Active context tenantId (${ctx.tenantId}) does not match param tenantId (${tenantId})`;
      this.logger.error(`[DRAFT-FORENSIC] [correlationId: ${correlationId}] [CRITICAL] ${errorMsg}`);
      throw new DraftForensicException(errorMsg, null, ctx);
    }

    try {
      this.logger.log(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] deleteForMember: pre-await scopeResolver.resolveOrThrow. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
      );
      const scope = this.scopeResolver.resolveOrThrow(tenantId, draftKey);

      this.logger.log(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] deleteForMember: pre-await store.delete. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
      );
      await this.store.delete(scope);

      this.logger.log(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] deleteForMember: pre-await auditLog.logEvent. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
      );
      await this.auditLog.logEvent({
        action: "draft_engine.delete",
        entity: "draft_snapshot",
        entityId: `${scope.workspaceId}:${scope.userId}:${scope.draftKey}`,
        category: AUDIT_CATEGORY.DRAFT_ENGINE_EVENT,
        after: { deleted: true },
      });

      try {
        this.logger.log(
          `[DRAFT-FORENSIC] [correlationId: ${correlationId}] deleteForMember: pre-await logDraftEvent. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
        );
        await this.logDraftEvent({
          workspaceId: scope.workspaceId,
          userId: scope.userId,
          draftKey: scope.draftKey,
          eventType: "draft_deleted",
          baseVersion: null,
          nextVersion: null,
          payloadSnapshot: {},
        });
      } catch (logErr) {
        this.logger.warn(
          `[DRAFT-FORENSIC] [correlationId: ${correlationId}] draft event log failed for delete: ${
            logErr instanceof Error ? logErr.message : String(logErr)
          }`,
        );
      }
    } catch (err: unknown) {
      this.logger.error(
        `[DRAFT-FORENSIC] [correlationId: ${correlationId}] deleteForMember: failed. Context: ${JSON.stringify(this.getDebugContextFields(draftKey))}`,
        err instanceof Error ? err.stack : String(err),
      );
      if (err instanceof HttpException) {
        throw err;
      }
      throw new DraftForensicException("Failed to delete draft", err, this.getDebugContextFields(draftKey));
    }
  }
}

