import assert from "node:assert/strict";
import test from "node:test";

import { NotFoundException } from "@nestjs/common";
import { CURRENT_DRAFT_SCHEMA_VERSION } from "@repo/shared-contracts";

import { DraftConflictException } from "./draft-conflict.exception";
import { PostgresDraftSnapshotStore } from "./storage/postgres-draft-snapshot.store";
import type { DraftSnapshotEntity } from "./entities/draft-snapshot.entity";

function mockRow(overrides: Partial<DraftSnapshotEntity> = {}): DraftSnapshotEntity {
  return {
    id: "row-1",
    workspaceId: "ws-1",
    userId: "user-1",
    draftKey: "denali-create",
    data: { value: "stored" },
    version: 2,
    schemaVersion: CURRENT_DRAFT_SCHEMA_VERSION,
    lastModified: "1000",
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  } as DraftSnapshotEntity;
}

function createStore(input: {
  existing: DraftSnapshotEntity | null;
  updateAffected?: number;
  deleteResult?: { affected?: number };
  upgradeAffected?: number;
  traceId?: string;
  onCreate?: (partial: Partial<DraftSnapshotEntity>) => void;
  onUpdate?: (partial: Record<string, unknown>) => void;
}): PostgresDraftSnapshotStore {
  const findOne = async () => input.existing;
  const save = async (entity: DraftSnapshotEntity) => entity;
  const create = (_entity: unknown, partial: Partial<DraftSnapshotEntity>) => {
    input.onCreate?.(partial);
    return { ...partial, version: partial.version ?? 1 } as DraftSnapshotEntity;
  };
  const update = async (...args: unknown[]) => {
    const partial = (args[2] ?? args[1]) as Record<string, unknown> | undefined;
    if (partial) {
      input.onUpdate?.(partial);
    }
    return { affected: input.updateAffected ?? input.upgradeAffected ?? 1 };
  };
  const manager = { findOne, create, save, update };

  const draftsRepository = {
    findOne,
    create,
    save,
    update,
    manager: {
      transaction: async <T>(fn: (em: typeof manager) => Promise<T>) => fn(manager),
    },
    delete: async () => input.deleteResult ?? { affected: 1 },
    createQueryBuilder: () => ({
      where: () => ({
        andWhere: () => ({
          getSql: () => "SELECT",
          getParameters: () => ({}),
        }),
      }),
    }),
  };

  const requestContext = {
    tryGetCorrelationId: () => input.traceId,
    tryGetRequestId: () => input.traceId,
  };
  return new PostgresDraftSnapshotStore(draftsRepository as never, requestContext as never);
}

const scope = { workspaceId: "ws-1", userId: "user-1", draftKey: "denali-create" };

test("upsert creates version 1 when no row exists", async () => {
  const store = createStore({ existing: null });
  const result = await store.upsert(scope, {
    data: { value: "new" },
    version: 0,
    schemaVersion: CURRENT_DRAFT_SCHEMA_VERSION,
    lastModified: 2000,
  });

  assert.equal(result.version, 1);
  assert.deepEqual(result.data, { value: "new" });
});

test("upsert rejects first insert when client version is not zero", async () => {
  const store = createStore({ existing: null });

  await assert.rejects(
    () =>
      store.upsert(scope, {
        data: { value: "new" },
        version: 1,
        schemaVersion: CURRENT_DRAFT_SCHEMA_VERSION,
        lastModified: 2000,
      }),
    (err: unknown) => err instanceof DraftConflictException,
  );
});

test("upsert increments version when incoming version matches", async () => {
  const existing = mockRow({ version: 2 });
  const store = createStore({ existing, updateAffected: 1 });

  const result = await store.upsert(scope, {
    data: { value: "updated" },
    version: 2,
    schemaVersion: 2,
    lastModified: 3000,
  });

  assert.equal(result.version, 3);
  assert.equal(result.schemaVersion, 2);
});

test("upsert attaches trace id into persisted row", async () => {
  let createdPayload: Partial<DraftSnapshotEntity> | undefined;
  const store = createStore({
    existing: null,
    traceId: "trace-123",
    onCreate: (partial) => {
      createdPayload = partial;
    },
  });

  await store.upsert(scope, {
    data: { value: "new" },
    version: 0,
    schemaVersion: 2,
    lastModified: 3000,
  });

  assert.equal(createdPayload?.traceId, "trace-123");
});

test("upsert update writes trace id", async () => {
  let updatedPayload: Record<string, unknown> | undefined;
  const store = createStore({
    existing: mockRow({ version: 2 }),
    traceId: "trace-456",
    onUpdate: (partial) => {
      updatedPayload = partial;
    },
  });

  await store.upsert(scope, {
    data: { value: "updated" },
    version: 2,
    schemaVersion: 2,
    lastModified: 3000,
  });

  assert.equal(updatedPayload?.traceId, "trace-456");
});

test("upsert throws DraftConflictException when version is stale", async () => {
  const existing = mockRow({ version: 3 });
  const store = createStore({ existing });

  await assert.rejects(
    () =>
      store.upsert(scope, {
        data: { value: "client" },
        version: 2,
        schemaVersion: CURRENT_DRAFT_SCHEMA_VERSION,
        lastModified: 4000,
      }),
    (err: unknown) => err instanceof DraftConflictException,
  );
});

test("delete throws when delete affects zero rows", async () => {
  const store = createStore({ existing: null, deleteResult: { affected: 0 } });

  await assert.rejects(
    () => store.delete(scope),
    (err: unknown) => err instanceof NotFoundException,
  );
});

test("concurrent upserts with same version: exactly one succeeds", async () => {
  let row = mockRow({ version: 2, data: { value: "stored" } });

  const manager = {
    findOne: async () => ({ ...row }),
    create: (_entity: unknown, partial: Partial<DraftSnapshotEntity>) =>
      ({ ...partial, version: partial.version ?? 1 } as DraftSnapshotEntity),
    save: async (entity: DraftSnapshotEntity) => {
      row = entity;
      return entity;
    },
    update: async (...args: unknown[]) => {
      const criteria = (args[1] ?? args[0]) as { id?: string; version?: number };
      const partial = (args[2] ?? args[1]) as Record<string, unknown>;
      const storedVersion = criteria.version;
      if (storedVersion == null || row.version !== storedVersion) {
        return { affected: 0 };
      }
      row = {
        ...row,
        data: (partial.data as Record<string, unknown>) ?? row.data,
        version: Number(partial.version),
        schemaVersion: Number(partial.schemaVersion ?? row.schemaVersion),
        lastModified: String(partial.lastModified ?? row.lastModified),
        traceId: (partial.traceId as string | null | undefined) ?? row.traceId ?? null,
      };
      return { affected: 1 };
    },
  };

  const draftsRepository = {
    findOne: manager.findOne,
    create: manager.create,
    save: manager.save,
    update: manager.update,
    manager: {
      transaction: async <T>(fn: (em: typeof manager) => Promise<T>) => fn(manager),
    },
    delete: async () => ({ affected: 1 }),
    createQueryBuilder: () => ({
      where: () => ({
        andWhere: () => ({
          getSql: () => "SELECT",
          getParameters: () => ({}),
        }),
      }),
    }),
  };

  const store = new PostgresDraftSnapshotStore(draftsRepository as never, undefined);
  const payloadBase = {
    version: 2,
    schemaVersion: CURRENT_DRAFT_SCHEMA_VERSION,
    lastModified: Date.now(),
  };

  const results = await Promise.allSettled([
    store.upsert(scope, { data: { value: "race-a" }, ...payloadBase }),
    store.upsert(scope, { data: { value: "race-b" }, ...payloadBase }),
  ]);

  const fulfilled = results.filter((r) => r.status === "fulfilled");
  const rejected = results.filter((r) => r.status === "rejected");
  assert.equal(fulfilled.length, 1);
  assert.equal(rejected.length, 1);
  const failure = rejected[0];
  assert.equal(failure?.status, "rejected");
  assert.ok(
    failure.status === "rejected" && failure.reason instanceof DraftConflictException,
  );
  assert.equal(row.version, 3);
});

import { ForbiddenException, Inject, Injectable } from "@nestjs/common";

import { authRequiredError } from "../../../common/errors/error-response-builders";
import { RequestContextService } from "../../../common/request-context/request-context.service";
import { toDraftScope, type DraftScope } from "@repo/shared-contracts";

@Injectable()
export class DraftScopeResolver {
  constructor(
    @Inject(RequestContextService)
    private readonly requestContext: RequestContextService,
  ) {}

  resolveOrThrow(paramTenantId: string, draftKey: string): DraftScope {
    const jwtTenantId = this.requestContext.resolveEffectiveTenantId()?.trim().toLowerCase();
    const normalized = paramTenantId.trim().toLowerCase();
    if (!jwtTenantId || jwtTenantId !== normalized) {
      throw new ForbiddenException({
        error: {
          code: "TENANT_SCOPE_FORBIDDEN",
          message: "Draft access requires a token scoped to this workspace",
        },
      });
    }

    const userId = this.requestContext.getUserId();
    if (!userId) {
      throw new ForbiddenException(authRequiredError());
    }

    return toDraftScope(normalized, userId, draftKey);
  }
}

import { Injectable, Logger, NotFoundException, Optional } from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import {
  CURRENT_DRAFT_SCHEMA_VERSION,
  type DraftScope,
  type DraftSnapshot,
  type DraftStoragePort,
} from "@repo/shared-contracts";
import { Repository } from "typeorm";

import { tryGetActiveTraceLogFields } from "../../../common/observability/active-trace-log-fields";
import { RequestContextService } from "../../../common/request-context/request-context.service";
import { DraftConflictException } from "../draft-conflict.exception";
import { DraftSnapshotEntity } from "../entities/draft-snapshot.entity";

@Injectable()
export class PostgresDraftSnapshotStore implements DraftStoragePort {
  private readonly logger = new Logger(PostgresDraftSnapshotStore.name);

  constructor(
    @InjectRepository(DraftSnapshotEntity)
    private readonly draftsRepository: Repository<DraftSnapshotEntity>,
    @Optional()
    private readonly requestContext?: RequestContextService,
  ) {}

  private resolveTraceId(): string | null {
    const otelTraceId = tryGetActiveTraceLogFields()?.trace_id?.trim();
    if (otelTraceId) {
      return otelTraceId;
    }
    const traceId =
      this.requestContext?.tryGetCorrelationId() ?? this.requestContext?.tryGetRequestId();
    if (!traceId || traceId.trim() === "") {
      return null;
    }
    return traceId.trim();
  }

  private toSnapshot(row: DraftSnapshotEntity): DraftSnapshot {
    return {
      data: row.data,
      version: Number(row.version),
      schemaVersion: Number(row.schemaVersion ?? CURRENT_DRAFT_SCHEMA_VERSION),
      lastModified: Number(row.lastModified),
    };
  }

  async find(scope: DraftScope): Promise<DraftSnapshot | null> {
    const where = {
      workspaceId: scope.workspaceId,
      userId: scope.userId,
      draftKey: scope.draftKey,
    };

    const queryTrace = this.draftsRepository
      .createQueryBuilder("draft_snapshots")
      .where("draft_snapshots.workspace_id = :workspaceId", { workspaceId: scope.workspaceId })
      .andWhere("draft_snapshots.user_id = :userId", { userId: scope.userId })
      .andWhere("draft_snapshots.draft_key = :draftKey", { draftKey: scope.draftKey });

    this.logger.log(
      `DEBUG-TRACE [B] DB: DraftSnapshotEntity.findOne | ` +
        `filters=${JSON.stringify(where)} | ` +
        `sql=${queryTrace.getSql()} | ` +
        `params=${JSON.stringify(queryTrace.getParameters())}`,
    );

    const row = await this.draftsRepository.findOne({ where });

    if (!row) {
      this.logger.warn(
        `DEBUG-TRACE: No record found matching [${scope.workspaceId}, ${scope.userId}, ${scope.draftKey}]`,
      );
      return null;
    }

    this.logger.log(
      `DEBUG-TRACE [C] raw DB row (pre-serialize): ${JSON.stringify({
        id: row.id,
        workspaceId: row.workspaceId,
        userId: row.userId,
        draftKey: row.draftKey,
        version: row.version,
        schemaVersion: row.schemaVersion,
        lastModified: row.lastModified,
      })}`,
    );

    return this.toSnapshot(row);
  }

  async upsert(scope: DraftScope, snapshot: DraftSnapshot): Promise<DraftSnapshot> {
    const clientVersion = Number(snapshot.version);
    const schemaVersion = Number(snapshot.schemaVersion) || CURRENT_DRAFT_SCHEMA_VERSION;

    if (!Number.isFinite(clientVersion) || clientVersion < 0) {
      throw new DraftConflictException({
        data: snapshot.data,
        version: 0,
        schemaVersion,
        lastModified: Number(snapshot.lastModified) || Date.now(),
      });
    }

    return this.draftsRepository.manager.transaction(async (manager) => {
      const existing = await manager.findOne(DraftSnapshotEntity, {
        where: {
          workspaceId: scope.workspaceId,
          userId: scope.userId,
          draftKey: scope.draftKey,
        },
      });

      if (!existing) {
        if (clientVersion !== 0) {
          throw new DraftConflictException({
            data: snapshot.data,
            version: 0,
            schemaVersion,
            lastModified: Number(snapshot.lastModified) || Date.now(),
          });
        }

        const saved = await manager.save(
          manager.create(DraftSnapshotEntity, {
            workspaceId: scope.workspaceId,
            userId: scope.userId,
            draftKey: scope.draftKey,
            data: snapshot.data,
            version: 1,
            schemaVersion,
            lastModified: String(snapshot.lastModified),
            traceId: this.resolveTraceId(),
          }),
        );
        return this.toSnapshot(saved);
      }

      const storedVersion = Number(existing.version);
      if (!Number.isFinite(storedVersion) || storedVersion !== clientVersion) {
        throw new DraftConflictException(this.toSnapshot(existing));
      }

      const nextVersion = storedVersion + 1;
      const lastModified = Date.now();
      const updateResult = await manager.update(
        DraftSnapshotEntity,
        { id: existing.id, version: storedVersion },
        {
          data: snapshot.data,
          version: nextVersion,
          schemaVersion,
          lastModified: String(lastModified),
          traceId: this.resolveTraceId(),
        } as Parameters<Repository<DraftSnapshotEntity>["update"]>[1],
      );

      if (updateResult.affected !== 1) {
        const fresh = await manager.findOne(DraftSnapshotEntity, {
          where: {
            workspaceId: scope.workspaceId,
            userId: scope.userId,
            draftKey: scope.draftKey,
          },
        });
        throw new DraftConflictException(this.toSnapshot(fresh ?? existing));
      }

      return {
        data: snapshot.data,
        version: nextVersion,
        schemaVersion,
        lastModified,
      };
    });
  }

  async upgradeSchemaInPlace(
    scope: DraftScope,
    input: Pick<DraftSnapshot, "data" | "schemaVersion" | "version">,
  ): Promise<DraftSnapshot | null> {
    const updateResult = await this.draftsRepository.update(
      {
        workspaceId: scope.workspaceId,
        userId: scope.userId,
        draftKey: scope.draftKey,
        version: input.version,
      },
      {
        data: input.data,
        schemaVersion: input.schemaVersion,
        traceId: this.resolveTraceId(),
      } as Parameters<Repository<DraftSnapshotEntity>["update"]>[1],
    );

    if ((updateResult.affected ?? 0) !== 1) {
      return null;
    }

    return this.find(scope);
  }

  async delete(scope: DraftScope): Promise<void> {
    const result = await this.draftsRepository.delete({
      workspaceId: scope.workspaceId,
      userId: scope.userId,
      draftKey: scope.draftKey,
    });
    if ((result.affected ?? 0) === 0) {
      throw new NotFoundException({
        error: {
          code: "DRAFT_NOT_FOUND",
          message: "Draft not found",
        },
      });
    }
  }
}

