} from "./contracts/leader-registration-payment-ledger.contracts";
import { emitFinanceLedgerDoubleEntryAppliedOutbox } from "./emit-finance-ledger-journal-outbox";
import { REGISTRATION_LEADER_PAYMENT_CLEARING_ACCOUNT } from "./ledger-accounts";
import type { LedgerJournalLine } from "./ledger-journal-line";
import { postAndPersistDoubleEntryJournal } from "./post-double-entry-journal";

/** Wallet id for booking / registration monetary projection (not a persisted wallet row yet). */
export function bookingWalletId(registrationId: string): string {
  return `booking:${registrationId}`;
}

/** Leader PATCH paid amount — positive integer only; no float coercion. */
export function positiveIntegerMinorStringFromLeaderAmount(amount: number): string {
  if (!Number.isFinite(amount) || !Number.isInteger(amount) || amount <= 0) {
    throw new Error("LEDGER_LEADER_PAID_AMOUNT: must be a positive integer minor amount");
  }
  return BigInt(amount).toString();
}

function paidAmountPayloadPositiveMinor(
  paidAmount: number | string | undefined
): string | null {
  if (paidAmount === undefined) {
    return null;
  }
  if (typeof paidAmount === "string") {
    const t = paidAmount.trim();
    if (!/^\d+$/.test(t)) {
      return null;
    }
    const n = BigInt(t);
    return n > 0n ? t : null;
  }
  if (!Number.isFinite(paidAmount) || !Number.isInteger(paidAmount) || paidAmount <= 0) {
    return null;
  }
  return BigInt(paidAmount).toString();
}

function isPaidAmountCleared(paidAmount: number | string | undefined): boolean {
  if (paidAmount === undefined) {
    return false;
  }
  if (typeof paidAmount === "string") {
    const t = paidAmount.trim();
    if (t === "" || t === "0") {
      return true;
    }
    if (!/^\d+$/.test(t)) {
      return false;
    }
    return BigInt(t) <= 0n;
  }
  return paidAmount <= 0;
}

function parsePreviousPaidMinor(previous: string | undefined): bigint {
  if (previous === undefined || previous.trim() === "") {
    return 0n;
  }
  const t = previous.trim();
  if (!/^\d+$/.test(t)) {
    return 0n;
  }
  return BigInt(t);
}

function projectPaidAmountString(
  registrationId: string,
  payload: LeaderRegistrationPaymentPatchPayload,
  lines: LedgerJournalLine[],
  previousPaidAmount: string | undefined
): string | undefined {
  const bookingAcct = bookingWalletId(registrationId);
  if (lines.length > 0) {
    const onBooking = lines.filter((l) => l.account === bookingAcct).sort((a, b) => {
      const c = a.createdAt.localeCompare(b.createdAt);
      return c !== 0 ? c : a.id.localeCompare(b.id);
    });
    const last = onBooking[onBooking.length - 1];
    if (last?.side === "credit") {
      return last.amount_minor;
    }
    if (last?.side === "debit") {
      return undefined;
    }
  }
  const clearing =
    payload.paymentStatus === "NotPaid" || isPaidAmountCleared(payload.paidAmount);
  if (clearing && parsePreviousPaidMinor(previousPaidAmount) === 0n) {
    return undefined;
  }
  const minor = paidAmountPayloadPositiveMinor(payload.paidAmount);
  if (minor !== null) {
    return minor;
  }
  return previousPaidAmount;
}

/**
 * **System of record (money):** append-only {@link postDoubleEntryJournal} journals (two lines each).
 * **`registrations.paid_amount`** is a **projection** derived from those facts in-process until a
 * durable `ledger_journal_lines` rows and `account_balances` snapshots on the same `EntityManager`.
 *
 * Every journal batch is also written to the **transactional outbox** on the same `EntityManager`
 * as the caller’s domain transaction (`finance.ledger.double_entry_applied`).
 *
 * No other service should assign `registration.paidAmount` — CI enforces this (`check-ledger-only-money.mjs`).
 *
 * **Strict ledger (Phase 2.6):** {@link postAndPersistDoubleEntryJournal} rejects invalid journals with
 * `LEDGER_CONTRACT_VALIDATION_FAILED` before any `ledger_journal_lines` insert — leader PATCH and
 * payment flows must treat this as a hard failure (transaction rollback).
 */
@Injectable()
export class BookingLedgerAuthorityService {
  constructor(private readonly outboxService: OutboxService) {}

  /**
   * Derives `registrations.paid_amount` from ledger lines (shared by leader PATCH and payment capture).
   */
  projectPaidAmountFromLedgerLines(
    registrationId: string,
    payload: LeaderRegistrationPaymentPatchPayload,
    lines: readonly LedgerJournalLine[],
    previousPaidAmount?: string | null
  ): string | undefined {
    return projectPaidAmountString(
      registrationId,
      payload,
      [...lines],
      previousPaidAmount ?? undefined
    );
  }

  /** Assigns `paidAmount` on a registration row from ledger facts (payment capture / receipt approve). */
  applyPaidAmountProjectionToRegistration(
    registration: BookingLedgerLeaderRegistrationRow,
    payload: LeaderRegistrationPaymentPatchPayload,
    lines: readonly LedgerJournalLine[]
  ): void {
    registration.paidAmount = projectPaidAmountString(
      registration.id,
      payload,
      [...lines],
      registration.paidAmount
    );
  }

  /**
   * Mutates `registration.paymentStatus` and `registration.paidAmount` **only** after emitting
   * balanced ledger journals and enqueueing the finance outbox event on `manager`.
   */
  async applyLeaderRegistrationPaymentMutation(
    manager: EntityManager,
    registration: BookingLedgerLeaderRegistrationRow,
    payload: LeaderRegistrationPaymentPatchPayload,
    idempotencyKey: string
  ): Promise<{ ledgerFacts: LedgerJournalLine[]; ledgerCorrelationId: string }> {
    const bookingAccount = bookingWalletId(registration.id);
    const correlationBase = `registration:${registration.id}:leader_payment`;
    const currency = registration.quotedCurrencyCode?.trim() || "UNK";
    const previousPaid = registration.paidAmount;
    const ledgerFacts: LedgerJournalLine[] = [];

    const receiveMinor = paidAmountPayloadPositiveMinor(payload.paidAmount);
    if (receiveMinor !== null) {
      const { lines } = await postAndPersistDoubleEntryJournal(manager, {
        tenantId: registration.tenantId,
        debitAccount: REGISTRATION_LEADER_PAYMENT_CLEARING_ACCOUNT,
        creditAccount: bookingAccount,
        amount_minor: receiveMinor,
        currency,
        correlationId: `${correlationBase}:${idempotencyKey}`,
        idempotencyKey: `${idempotencyKey}:receive`,
        metadata: {
          source: "leader_patch_registration_payment",
          paymentStatus: payload.paymentStatus,
          kind: "registration_prepayment_received"
        }
      });
      ledgerFacts.push(...lines);
    } else if (payload.paymentStatus === "NotPaid" || isPaidAmountCleared(payload.paidAmount)) {
      const prevMinor = parsePreviousPaidMinor(previousPaid);
      if (prevMinor > 0n) {
        const { lines } = await postAndPersistDoubleEntryJournal(manager, {
          tenantId: registration.tenantId,
          debitAccount: bookingAccount,
          creditAccount: REGISTRATION_LEADER_PAYMENT_CLEARING_ACCOUNT,
          amount_minor: prevMinor.toString(),
          currency,
          correlationId: `${correlationBase}:clear:${idempotencyKey}`,
          idempotencyKey: `${idempotencyKey}:clear`,
          metadata: {
            source: "leader_patch_registration_payment",
            paymentStatus: payload.paymentStatus,
            kind: "registration_prepayment_cleared"
          }
        });
        ledgerFacts.push(...lines);
      }
    }

    await emitFinanceLedgerDoubleEntryAppliedOutbox({
      manager,
      outboxService: this.outboxService,
      tenantId: registration.tenantId,
      registrationId: registration.id,
      lines: ledgerFacts
    });

    registration.paymentStatus = payload.paymentStatus;
    registration.paidAmount = projectPaidAmountString(
      registration.id,
      payload,
      ledgerFacts,
      previousPaid
    );

    return { ledgerFacts, ledgerCorrelationId: correlationBase };
  }
}

import { Inject, Injectable } from "@nestjs/common";
import type { EntityManager } from "typeorm";
import { OutboxService } from "../../outbox/outbox.service";
import type { PaymentEntity } from "../../payments/entities/payment.entity";
import { bookingWalletId } from "./booking-ledger-authority.service";
import { emitFinanceLedgerDoubleEntryAppliedOutbox } from "./emit-finance-ledger-journal-outbox";
import { REGISTRATION_LEADER_PAYMENT_CLEARING_ACCOUNT } from "./ledger-accounts";
import { paymentAmountToLedgerMinorString } from "./payment-amount-to-ledger-minor";
import type { LedgerJournalLine } from "./ledger-journal-line";
import { postAndPersistDoubleEntryJournal } from "./post-double-entry-journal";
import { stablePaymentCaptureLedgerIdentifiers } from "./stable-payment-capture-ledger-ids";

export type PaymentCaptureLedgerSource = "manual_receipt_approve" | "online_webhook_paid";

/**
 * Emits the canonical payment-capture journal when a {@link PaymentEntity} reaches `Paid`.
 * Uses the same stable ids / `domainEventId` as refund reversal anchors (idempotent via outbox).
 *
 * **Strict mode (Phase 2.6):** {@link postAndPersistDoubleEntryJournal} → {@link persistLedgerJournal}
 * enforces the ledger contract before SQL. On failure throws `BadRequestException` with
 * `LEDGER_CONTRACT_VALIDATION_FAILED`, aborting the caller transaction (e.g. webhook paid transition).
 */
@Injectable()
export class PaymentCaptureLedgerAuthorityService {
  constructor(@Inject(OutboxService) private readonly outboxService: OutboxService) {}

  async emitPaymentCaptureAtPaid(
    manager: EntityManager,
    payment: Pick<PaymentEntity, "id" | "tenantId" | "registrationId" | "amount" | "currency" | "paidAt">,
    source: PaymentCaptureLedgerSource
  ): Promise<{ journalId: string; lines: [LedgerJournalLine, LedgerJournalLine] }> {
    const tenantId = payment.tenantId.trim();
    const amountMinor = paymentAmountToLedgerMinorString(String(payment.amount));
    const paidAtIso = payment.paidAt ? payment.paidAt.toISOString() : new Date().toISOString();
    const stableIds = stablePaymentCaptureLedgerIdentifiers(payment.id);

    const { journalId, lines } = await postAndPersistDoubleEntryJournal(manager, {
      tenantId,
      debitAccount: REGISTRATION_LEADER_PAYMENT_CLEARING_ACCOUNT,
      creditAccount: bookingWalletId(payment.registrationId),
      amount_minor: amountMinor,
      currency: payment.currency.trim().toUpperCase(),
      correlationId: `payment:${payment.id}:capture`,
      idempotencyKey: `payment:${payment.id}:capture-anchor`,
      stableJournalAndLineIds: stableIds,
      journalLinesCreatedAtIso: paidAtIso,
      metadata: {
        kind: "payment_capture_at_paid",
        source,
        paymentId: payment.id,
        registrationId: payment.registrationId
      }
    });

    await emitFinanceLedgerDoubleEntryAppliedOutbox({
      manager,
      outboxService: this.outboxService,
      tenantId,
      registrationId: payment.registrationId,
      lines,
      domainEventIdOverride: `payment:${payment.id}:ledger-capture-anchor`
    });
    return { journalId, lines };
  }
}

import { Injectable } from "@nestjs/common";
import type { EntityManager } from "typeorm";
import { OutboxService } from "../../outbox/outbox.service";
import type { PaymentEntity } from "../../payments/entities/payment.entity";
import { bookingWalletId } from "./booking-ledger-authority.service";
import { emitFinanceLedgerDoubleEntryAppliedOutbox } from "./emit-finance-ledger-journal-outbox";
import { REGISTRATION_LEADER_PAYMENT_CLEARING_ACCOUNT } from "./ledger-accounts";
import { paymentAmountToLedgerMinorString } from "./payment-amount-to-ledger-minor";
import { LedgerJournalLineEntity } from "./entities/ledger-journal-line.entity";
import { ledgerJournalLineEntityToDomain } from "./ledger-journal-line.mapper";
import type { LedgerJournalLine } from "./ledger-journal-line";
import {
  postAndPersistDoubleEntryJournal,
  postAndPersistDoubleEntryReversalJournal
} from "./post-double-entry-journal";
import { stablePaymentCaptureLedgerIdentifiers } from "./stable-payment-capture-ledger-ids";

/**
 * **Refund money path:** emits a new balanced journal that **reverses** the synthetic payment-capture
 * anchor (clearing ↔ booking wallet), with `reversesLineId` on each reversal leg pointing at the
 * original capture line. Never mutates historical `payments.amount` / `paid_at` / `provider_payment_id`.
 *
 * The synthetic anchor reproduces the same account mapping as checkout capture and leader prepayment
 * (`REGISTRATION_LEADER_PAYMENT_CLEARING_ACCOUNT` × `booking:{registrationId}`) so wallet projections net to zero after refund.
 *
 * **Two outbox rows:** (1) deterministic synthetic capture anchor (`domainEventIdOverride` per payment),
 * (2) reversal journal. When capture-at-`Paid` ledger rows exist in production, replace the synthetic
 * anchor with persisted originals so anchors are not double-posted.
 */
@Injectable()
export class PaymentRefundLedgerAuthorityService {
  constructor(private readonly outboxService: OutboxService) {}

  async emitPaymentRefundLedgerReversal(
    manager: EntityManager,
    payment: Pick<
      PaymentEntity,
      "id" | "tenantId" | "registrationId" | "amount" | "currency" | "paidAt" | "ledgerJournalId"
    >,
    _idempotencyKey?: string
  ): Promise<void> {
    const tenantId = payment.tenantId.trim();
    /** Stable anchor — idempotent replay neutralizes double-refund / double-click. */
    const reversalIdempotencyKey = `payment:${payment.id}:refund-reversal-anchor`;
    const stableIds = stablePaymentCaptureLedgerIdentifiers(payment.id);
    const amountMinor = paymentAmountToLedgerMinorString(String(payment.amount));
    const paidAtIso = payment.paidAt ? payment.paidAt.toISOString() : new Date().toISOString();

    let captureAnchor: [LedgerJournalLine, LedgerJournalLine];

    const persistedJournalId = payment.ledgerJournalId?.trim();
    if (persistedJournalId) {
      const rows = await manager.find(LedgerJournalLineEntity, {
        where: { tenantId, journalId: persistedJournalId },
        order: { side: "ASC", id: "ASC" }
      });
      const debit = rows.find((r) => r.side === "debit");
      const credit = rows.find((r) => r.side === "credit");
      if (!debit || !credit) {
        throw new Error(
          `PAYMENT_REFUND_LEDGER_ANCHOR_MISSING: journal ${persistedJournalId} has no debit/credit pair`
        );
      }
      captureAnchor = [
        ledgerJournalLineEntityToDomain(debit),
        ledgerJournalLineEntityToDomain(credit)
      ];
    } else {
      const { lines } = await postAndPersistDoubleEntryJournal(manager, {
        tenantId,
        debitAccount: REGISTRATION_LEADER_PAYMENT_CLEARING_ACCOUNT,
        creditAccount: bookingWalletId(payment.registrationId),
        amount_minor: amountMinor,
        currency: payment.currency.trim().toUpperCase(),
        correlationId: `payment:${payment.id}:capture-anchor`,
        idempotencyKey: `payment:${payment.id}:capture-anchor`,
        stableJournalAndLineIds: stableIds,
        journalLinesCreatedAtIso: paidAtIso,
        metadata: {
          kind: "payment_capture_synthetic_anchor",
          paymentId: payment.id,
          registrationId: payment.registrationId
        }
      });
      captureAnchor = lines;

      await emitFinanceLedgerDoubleEntryAppliedOutbox({
        manager,
        outboxService: this.outboxService,
        tenantId,
        registrationId: payment.registrationId,
        lines: captureAnchor,
        domainEventIdOverride: `payment:${payment.id}:ledger-capture-anchor`
      });
    }

    const { lines: reversal } = await postAndPersistDoubleEntryReversalJournal(manager, {
      tenantId,
      originalLines: captureAnchor,
      correlationId: `payment:${payment.id}:refund`,
      idempotencyKey: reversalIdempotencyKey,
      metadata: {
        kind: "payment_refund_reversal",
        paymentId: payment.id,
        registrationId: payment.registrationId
      }
    });

    await emitFinanceLedgerDoubleEntryAppliedOutbox({
      manager,
      outboxService: this.outboxService,
      tenantId,
      registrationId: payment.registrationId,
      lines: reversal
    });
  }
}

import assert from "node:assert/strict";
import test from "node:test";
import { postDoubleEntryJournal } from "./post-double-entry-journal";

test("postDoubleEntryJournal rejects blank idempotency key", () => {
  assert.throws(
    () =>
      postDoubleEntryJournal({
        tenantId: "t1",
        debitAccount: "a",
        creditAccount: "b",
        amount_minor: "1",
        currency: "USD",
        correlationId: "c1",
        idempotencyKey: "   "
      }),
    /LEDGER_IDEMPOTENCY_KEY_REQUIRED/
  );
});

test("postDoubleEntryJournal rejects same debit and credit account", () => {
  assert.throws(
    () =>
      postDoubleEntryJournal({
        tenantId: "t1",
        debitAccount: "same",
        creditAccount: "same",
        amount_minor: "10",
        currency: "USD",
        correlationId: "c1",
        idempotencyKey: "j1"
      }),
    /LEDGER_ACCOUNTS_DISTINCT/
  );
});

test("postDoubleEntryJournal rejects non-positive amount", () => {
  assert.throws(
    () =>
      postDoubleEntryJournal({
        tenantId: "t1",
        debitAccount: "a",
        creditAccount: "b",
        amount_minor: "0",
        currency: "USD",
        correlationId: "c1",
        idempotencyKey: "j1"
      }),
    /LEDGER_AMOUNT_POSITIVE/
  );
});

test("postDoubleEntryJournal returns balanced two-line journal with shared journalId", () => {
  const { journalId, lines } = postDoubleEntryJournal({
    tenantId: "t1",
    debitAccount: "gl:clearing",
    creditAccount: "booking:r1",
    amount_minor: "500",
    currency: "IRR",
    correlationId: "corr",
    idempotencyKey: "pay-1"
  });
  assert.equal(lines.length, 2);
  assert.equal(lines[0]!.journalId, journalId);
  assert.equal(lines[1]!.journalId, journalId);
  assert.equal(lines[0]!.side, "debit");
  assert.equal(lines[1]!.side, "credit");
  assert.equal(lines[0]!.account, "gl:clearing");
  assert.equal(lines[1]!.account, "booking:r1");
  assert.equal(lines[0]!.amount_minor, "500");
  assert.equal(lines[1]!.amount_minor, "500");
  assert.match(lines[0]!.idempotencyKey, /:debit$/);
  assert.match(lines[1]!.idempotencyKey, /:credit$/);
});

test("postDoubleEntryJournal returns frozen lines (append-only in-memory contract)", () => {
  const full = postDoubleEntryJournal({
    tenantId: "t1",
    debitAccount: "gl:clearing",
    creditAccount: "booking:r1",
    amount_minor: "500",
    currency: "IRR",
    correlationId: "corr",
    idempotencyKey: "pay-freeze"
  });
  assert.ok(Object.isFrozen(full));
  const { lines } = full;
  assert.ok(Object.isFrozen(lines));
  assert.ok(Object.isFrozen(lines[0]));
  assert.ok(Object.isFrozen(lines[1]));
  assert.throws(() => {
    (lines[0] as { amount_minor: string }).amount_minor = "999";
  }, /Cannot assign|read only|read-only/i);
  assert.throws(() => {
    (lines as unknown as { push: (x: unknown) => void }).push({});
  }, /Cannot|read only|read-only|not extensible/i);
});

test("postDoubleEntryJournal accepts stableJournalAndLineIds and journalLinesCreatedAtIso", () => {
  const stable = {
    journalId: "11111111-1111-4111-8111-111111111111",
    debitLineId: "22222222-2222-4222-8222-222222222222",
    creditLineId: "33333333-3333-4333-8333-333333333333"
  };
  const { journalId, lines } = postDoubleEntryJournal({
    tenantId: "t1",
    debitAccount: "gl:clearing",
    creditAccount: "booking:r1",
    amount_minor: "1",
    currency: "IRR",
    correlationId: "corr",
    idempotencyKey: "pay-stable",
    stableJournalAndLineIds: stable,
    journalLinesCreatedAtIso: "2026-02-01T00:00:00.000Z"
  });
  assert.equal(journalId, stable.journalId);
  assert.equal(lines[0]!.id, stable.debitLineId);
  assert.equal(lines[1]!.id, stable.creditLineId);
  assert.equal(lines[0]!.createdAt, "2026-02-01T00:00:00.000Z");
  assert.equal(lines[1]!.createdAt, "2026-02-01T00:00:00.000Z");
});

import type { PaymentIntent } from "./payment-intent";
import type { PaymentResult, RefundRequest, RefundResult } from "./payment-result";

/**
 * Vendor-neutral payment gateway port (finance bounded context).
 *
 * TODO: `StripePaymentGateway` adapter — real API calls + idempotent client usage.
 * TODO: `ZibalPaymentGateway` adapter — IRR settlement + local compliance hooks.
 * TODO: `reconciliation worker` — compare PSP settlement files vs `payments` / ledger projections.
 *
 * **Do not** bind real credentials in this repository; adapters load secrets from env/KMS at runtime.
 */
export interface IPaymentGateway {
  readonly providerId: string;

  createPaymentIntent(intent: PaymentIntent): Promise<PaymentResult>;

  /** Optional — not all PSPs expose synchronous refund on same port. */
  refundPayment?(request: RefundRequest): Promise<RefundResult>;
}

/**
 * Scope for idempotent payment mutations (create intent, refund, capture).
 * Composite key should be enforced in durable storage before hitting a PSP.
 */
export type PaymentIdempotencyScope = {
  tenantId: string;
  /** Logical operation, e.g. `fake:create_payment_intent`. */
  operation: string;
  idempotencyKey: string;
};

/**
 * **Placeholder** — duplicate prevention must be backed by the same durability guarantees
 * as HTTP idempotency (`IdempotencyService` / DB) before any real PSP.
 *
 * - First call: runs `fn`, stores outcome fingerprint.
 * - Duplicate: returns cached outcome, `duplicate: true`.
 *
 * TODO: Wire to shared idempotency store + reconciliation worker for drift detection.
 */
export interface IPaymentIdempotencyPlaceholder {
  executeOnce<T>(
    scope: PaymentIdempotencyScope,
    fn: () => Promise<T>
  ): Promise<{ value: T; duplicate: boolean }>;
}

/**
 * Normalized webhook payload after provider-specific verification + parsing.
 * **No raw card / PAN data** — adapters must redact before logging.
 */
export type ParsedWebhookEvent = {
  /** Provider event id for deduplication (Stripe `evt_*`, Zibal reference, …). */
  providerEventId: string;
  /** Normalized event type, e.g. `payment.succeeded`. */
  type: string;
  /** Optional tenant resolution hint (metadata / path) — binding still server-authoritative. */
  tenantHint?: string;
  /** Links to internal payment / booking row when present. */
  providerPaymentId?: string;
  bookingId?: string;
  /** Fingerprint of raw body for replay / audit (not the body itself). */
  rawPayloadHash?: string;
};

/**
 * Verifies webhook authenticity (HMAC, mTLS, signed payload) and parses a neutral event.
 *
 * TODO: `StripeWebhookVerifier` — construct with webhook signing secret from KMS (never in repo).
 * TODO: `ZibalWebhookVerifier` — merchant key + documented signature scheme.
 */
export interface IWebhookVerifier {
  /**
   * @param headers Normalized lower-case keys optional; adapters may read `stripe-signature` etc.
   */
  verifySignature(
    headers: Record<string, string | string[] | undefined>,
    rawBody: Buffer | string
  ): Promise<boolean>;

  parseEvent(rawBody: unknown): Promise<ParsedWebhookEvent>;
}

/**
 * Outcome of **eligibility-only** validation — does **not** compute monetary deltas (pricing engine owns totals).
 */
export type DiscountEligibility = {
  readonly eligible: boolean;
  readonly reasons: readonly DiscountIneligibilityReason[];
  /** Populated when `eligible` — caller may attach to quote metadata / audit only. */
  readonly appliedDiscountRuleId?: string;
};

export enum DiscountIneligibilityReason {
  NO_CODE_OR_RULE = "no_code_or_rule",
  CODE_INACTIVE = "code_inactive",
  RULE_NOT_LOADED = "rule_not_loaded",
  TENANT_SCOPE_MISMATCH = "tenant_scope_mismatch",
  EXPIRED = "expired",
  NOT_YET_VALID = "not_yet_valid",
  INVALID_AS_OF = "invalid_as_of",
  USAGE_LIMIT_TOTAL = "usage_limit_total",
  USAGE_LIMIT_USER = "usage_limit_user",
  STACKING_CONFLICT = "stacking_conflict"
}

