  tourId: string;
  departureId: string;
  userRole: string;
  discountCode: string | null;
  lineItems: PricingLineItem[];
  total: string;
}): string {
  const h = createHash("sha256")
    .update(
      JSON.stringify({
        rules: FINANCE_PRICING_RULES_ID,
        tenantId: input.tenantId,
        tourId: input.tourId,
        departureId: input.departureId,
        userRole: input.userRole,
        discountCode: input.discountCode,
        lines: input.lineItems.map((l) => ({
          id: l.line_id,
          k: l.kind,
          a: l.amount_minor,
          c: l.currency_code
        })),
        total: input.total
      })
    )
    .digest("hex")
    .slice(0, 16);
  return `${FINANCE_PRICING_RULES_ID}:${h}`;
}

/**
 * Finance bounded-context pricing engine. Evaluates {@link PricingRule} instances in fixed stage order:
 * **tenant → catalog → role → discount**.
 *
 * **Determinism guarantee:** For the same {@link PricingContext} and {@link CatalogPricingSnapshot},
 * {@link PricingEngine.evaluate} returns the same {@link PricingQuote} (including `pricing_rule_version`).
 * There is no I/O, wall clock, randomness, or network. Evaluation uses only `bigint` arithmetic and a
 * SHA-256 digest over a JSON payload with a fixed key layout; `catalog.prices` order is part of the input.
 */
export class PricingEngine {
  constructor(private readonly rules: PricingRule[]) {}

  evaluate(context: PricingContext, catalog: CatalogPricingSnapshot): PricingQuote {
    assertDepartureBelongsToTourSnapshot(catalog.tour, catalog.departure);

    const discountCode = normalizeDiscountCode(context.discountCode);

    const state: FinanceEvaluationState = {
      context,
      catalog,
      baseMinor: 0n,
      currency: "",
      discountCode,
      lineItems: []
    };

    for (const stage of PRICING_RULE_STAGE_ORDER) {
      const stageRules = this.rules.filter((r) => r.stage === stage);
      for (const rule of stageRules) {
        rule.apply(state);
      }
    }

    assertSingleCurrency(state.lineItems, state.currency);

    const totalMinor = sumLineMinor(state.lineItems);
    if (totalMinor < 0n) {
      throw new BadRequestException({
        error: {
          code: "PRICING_TOTAL_NEGATIVE",
          message: "Discounts exceed list price"
        }
      });
    }

    const total = totalMinor.toString();
    const pricing_rule_version = buildFinancePricingVersion({
      tenantId: context.tenantId,
      tourId: context.tourId,
      departureId: context.departureId,
      userRole: context.userRole,
      discountCode,
      lineItems: state.lineItems,
      total
    });

    return {
      line_items: state.lineItems,
      total_minor: total,
      currency_code: state.currency,
      pricing_rule_version
    };
  }
}

/** Default finance rule bundle (order fixed in {@link PRICING_RULE_STAGE_ORDER}). */
export function createDefaultFinancePricingEngine(): PricingEngine {
  return new PricingEngine([
    new TenantNoopRule(),
    new CatalogListPriceRule(),
    new RoleWorkspaceStaffRule(),
    new DiscountPromoAndCatalogRule()
  ]);
}

import type { PricingLineItem } from "../../pricing/pricing.types";
import type { CatalogPricingSnapshot } from "./contracts/catalog-pricing-snapshot.dto";
import type { PricingContext } from "./pricing-context";

/** Ordered evaluation stages: tenant → catalog → role → discount. */
export type PricingRuleStage = "tenant" | "catalog" | "role" | "discount";

export const PRICING_RULE_STAGE_ORDER: PricingRuleStage[] = [
  "tenant",
  "catalog",
  "role",
  "discount"
];

/**
 * One step in the finance pricing pipeline. Rules are pure functions over {@link FinanceEvaluationState}
 * (append-only line items); the engine passes a fixed {@link CatalogPricingSnapshot} before the first rule runs.
 */
export interface PricingRule {
  readonly stage: PricingRuleStage;
  /** Stable id for logs / diagnostics (e.g. `tenant:noop`). */
  readonly ruleId: string;
  apply(state: FinanceEvaluationState): void;
}

/** Mutable accumulator while rules run (append-only line pushes). */
export type FinanceEvaluationState = {
  context: PricingContext;
  catalog: CatalogPricingSnapshot;
  /** List reference in minor units (set during catalog stage). */
  baseMinor: bigint;
  currency: string;
  discountCode: string | null;
  lineItems: PricingLineItem[];
};

import { BadRequestException, Inject, Injectable, NotFoundException } from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import { Repository } from "typeorm";
import { TenantDbContextService } from "../../../database/tenant-db-context.service";
import { FILE_STORAGE_PORT, FileStoragePort } from "../../../infra/storage/file-storage.port";
import { PaymentReceiptEntity, ReceiptStatus } from "../../payments/entities/payment-receipt.entity";
import { PaymentEntity, PaymentStatus, PaymentMethod } from "../../payments/entities/payment.entity";
import { randomUUID } from "node:crypto";
import {
  REGISTRATION_PAYMENT_PORT,
  IRegistrationPaymentPort
} from "../../registrations/ports/registration-payment.port";
import {
  RegistrationEntity,
  RegistrationPaymentStatus,
  RegistrationStatus
} from "../../registrations/registration.entity";
import { lockRegistrationByTenantAndId } from "../../registrations/utils/lock-registration-for-financial-mutation";
import { validatePaymentTransition } from "../../registrations/registrations-policy";
import { BookingLedgerAuthorityService } from "../ledger/booking-ledger-authority.service";
import { PaymentCaptureLedgerAuthorityService } from "../ledger/payment-capture-ledger-authority.service";
import { FinanceReportsService } from "../reports/finance-reports.service";
import { assertActorMayUploadReceiptForRegistration } from "./receipt-upload-authorization";
import { assertNoPendingReceiptForPayment } from "./receipt-pending.policy";
import { UserEntity } from "../../identity/entities/user.entity";

@Injectable()
export class ReceiptService {
  constructor(
    @InjectRepository(PaymentReceiptEntity)
    private readonly receiptRepository: Repository<PaymentReceiptEntity>,
    @Inject(TenantDbContextService)
    private readonly tenantDbContext: TenantDbContextService,
    @Inject(FILE_STORAGE_PORT)
    private readonly storage: FileStoragePort,
    @Inject(REGISTRATION_PAYMENT_PORT)
    private readonly registrationPaymentPort: IRegistrationPaymentPort,
    @Inject(FinanceReportsService)
    private readonly financeReportsService: FinanceReportsService,
    @Inject(PaymentCaptureLedgerAuthorityService)
    private readonly paymentCaptureLedgerAuthority: PaymentCaptureLedgerAuthorityService,
    @Inject(BookingLedgerAuthorityService)
    private readonly bookingLedgerAuthority: BookingLedgerAuthorityService
  ) {}

  async submitReceipt(params: {
    tenantId: string;
    paymentId: string;
    actorUserId: string;
    actorRole: string;
    file: Buffer;
    contentType: string;
    note?: string;
  }): Promise<PaymentReceiptEntity> {
    return this.tenantDbContext.runInTenantScope(params.tenantId, async (manager) => {
      const payment = await manager.findOne(PaymentEntity, {
        where: { id: params.paymentId, tenantId: params.tenantId }
      });

      if (!payment) {
        throw new NotFoundException("Payment not found");
      }

      if (payment.method !== PaymentMethod.MANUAL) {
        throw new BadRequestException("Receipts can only be submitted for manual payments");
      }

      if (payment.status !== PaymentStatus.PENDING) {
        throw new BadRequestException(
          `Cannot submit receipt for payment with status ${payment.status}`
        );
      }

      const registration = await manager.findOne(RegistrationEntity, {
        where: { id: payment.registrationId, tenantId: params.tenantId }
      });
      if (!registration) {
        throw new NotFoundException("Registration not found for payment");
      }

      const actor = await manager.findOne(UserEntity, {
        where: { id: params.actorUserId }
      });
      assertActorMayUploadReceiptForRegistration({
        actorRole: params.actorRole,
        actorPhone: actor?.phone ?? null,
        participantContactPhone: registration.participantContactPhone
      });

      const existingReceipts = await manager.find(PaymentReceiptEntity, {
        where: { paymentId: payment.id, tenantId: params.tenantId },
        select: { status: true }
      });
      assertNoPendingReceiptForPayment(existingReceipts);

      const fileExtension = params.contentType.split("/")[1] || "bin";
      const relativePath = `receipts/${params.paymentId}/${randomUUID()}.${fileExtension}`;

      let objectKey: string | null = null;
      try {
        const uploaded = await this.storage.upload({
          workspaceId: params.tenantId,
          relativePath,
          body: params.file,
          contentType: params.contentType
        });
        objectKey = uploaded.key;

        const receipt = manager.create(PaymentReceiptEntity, {
          tenantId: params.tenantId,
          paymentId: payment.id,
          fileKey: objectKey,
          status: ReceiptStatus.PENDING,
          note: params.note ?? null
        });

        return await manager.save(PaymentReceiptEntity, receipt);
      } catch (err) {
        if (objectKey) {
          await this.storage.deleteObject(objectKey);
        }
        throw err;
      }
    });
  }

  async approveReceipt(params: {
    tenantId: string;
    receiptId: string;
    actorId: string;
    reviewNote?: string;
  }): Promise<PaymentReceiptEntity> {
    return this.tenantDbContext.runInTenantScope(params.tenantId, async (manager) => {
      const receipt = await manager.findOne(PaymentReceiptEntity, {
        where: { id: params.receiptId, tenantId: params.tenantId },
        relations: ["payment"]
      });

      if (!receipt) {
        throw new NotFoundException("Receipt not found");
      }

      if (receipt.status !== ReceiptStatus.PENDING) {
        throw new BadRequestException(`Receipt already ${receipt.status}`);
      }

      const payment = receipt.payment;
      if (!payment) {
        throw new NotFoundException("Payment not found for receipt");
      }

      const regPeek = await manager.findOne(RegistrationEntity, {
        where: { id: payment.registrationId, tenantId: params.tenantId },
        select: { id: true, tourId: true, tenantId: true }
      });
      if (!regPeek) {
        throw new NotFoundException("Registration not found for receipt payment");
      }
      await this.registrationPaymentPort.lockTourRowForUpdate(
        manager,
        regPeek.tourId,
        regPeek.tenantId
      );
      const registration = await lockRegistrationByTenantAndId(
        manager,
        params.tenantId,
        payment.registrationId
      );

      if (payment.status !== PaymentStatus.PENDING) {
        throw new BadRequestException(
          `Cannot approve receipt for payment with status ${payment.status}`
        );
      }

      receipt.status = ReceiptStatus.APPROVED;
      receipt.reviewedByUserId = params.actorId;
      receipt.reviewedAt = new Date();
      receipt.reviewNote = params.reviewNote ?? null;

      const savedReceipt = await manager.save(PaymentReceiptEntity, receipt);

      payment.status = PaymentStatus.PAID;
      payment.paidAt = new Date();
      await manager.save(PaymentEntity, payment);

      const { journalId, lines } = await this.paymentCaptureLedgerAuthority.emitPaymentCaptureAtPaid(
        manager,
        payment,
        "manual_receipt_approve"
      );

      payment.ledgerJournalId = journalId;
      await manager.save(PaymentEntity, payment);
      savedReceipt.ledgerJournalId = journalId;
      await manager.save(PaymentReceiptEntity, savedReceipt);

      const updatedRegistration = await this.registrationPaymentPort.transitionRegistrationForPayment(
        manager,
        registration,
        RegistrationStatus.ACCEPTED_PAID,
        params.actorId
      );
      validatePaymentTransition(
        updatedRegistration.status,
        updatedRegistration.paymentStatus,
        RegistrationPaymentStatus.PAID
      );
      updatedRegistration.paymentStatus = RegistrationPaymentStatus.PAID;
      this.bookingLedgerAuthority.applyPaidAmountProjectionToRegistration(
        updatedRegistration,
        { paymentStatus: RegistrationPaymentStatus.PAID },
        lines
      );
      await manager.save(RegistrationEntity, updatedRegistration);

      await this.financeReportsService.invalidateSummaryCache(params.tenantId);
      return savedReceipt;
    });
  }

  async rejectReceipt(params: {
    tenantId: string;
    receiptId: string;
    actorId: string;
    reviewNote?: string;
  }): Promise<PaymentReceiptEntity> {
    return this.tenantDbContext.runInTenantScope(params.tenantId, async (manager) => {
      const receipt = await manager.findOne(PaymentReceiptEntity, {
        where: { id: params.receiptId, tenantId: params.tenantId }
      });

      if (!receipt) {
        throw new NotFoundException("Receipt not found");
      }

      if (receipt.status !== ReceiptStatus.PENDING) {
        throw new BadRequestException(`Receipt already ${receipt.status}`);
      }

      receipt.status = ReceiptStatus.REJECTED;
      receipt.reviewedByUserId = params.actorId;
      receipt.reviewedAt = new Date();
      receipt.reviewNote = params.reviewNote ?? null;

      const saved = await manager.save(PaymentReceiptEntity, receipt);
      await this.financeReportsService.invalidateSummaryCache(params.tenantId);
      return saved;
    });
  }

  async getReceiptSignedUrl(params: {
    tenantId: string;
    receiptId: string;
  }): Promise<string> {
    const receipt = await this.receiptRepository.findOne({
      where: { id: params.receiptId, tenantId: params.tenantId }
    });

    if (!receipt) {
      throw new NotFoundException("Receipt not found");
    }

    return this.storage.getSignedUrl(receipt.fileKey, 3600);
  }

  async listPendingReceipts(tenantId: string): Promise<PaymentReceiptEntity[]> {
    return this.receiptRepository.find({
      where: { tenantId, status: ReceiptStatus.PENDING },
      relations: ["payment"],
      order: { createdAt: "ASC" },
      take: 100
    });
  }
}

