import { Inject, Injectable, Optional } from "@nestjs/common";
import type { Redis } from "ioredis";
import { Like } from "typeorm";
import { OutboxEventEntity } from "../../../common/outbox/entities/outbox-event.entity";
import { ConfigService } from "../../../config/config.service";
import { TenantDbContextService } from "../../../database/tenant-db-context.service";
import { REDIS_CLIENT } from "../../../infra/redis/redis.constants";
import { ledgerLinesFromFinanceOutboxRows } from "../reconciliation/payment-finance-reconciliation.loader";
import { PaymentEntity, PaymentMethod, PaymentStatus } from "../../payments/entities/payment.entity";
import { PaymentReceiptEntity, ReceiptStatus } from "../../payments/entities/payment-receipt.entity";
import type { FinanceLedgerEventRow } from "./finance-ledger-event.dto";

export type FinanceReportsSummary = {
  pendingManualPayments: number;
  pendingReceiptReviews: number;
  paidPayments: number;
  failedPayments: number;
};

export type FinanceOpenPaymentRow = {
  id: string;
  registrationId: string;
  amount: string;
  currency: string;
  method: PaymentMethod;
  status: PaymentStatus;
  createdAt: Date;
};

const SUMMARY_CACHE_TTL_SEC = 30;
const SUMMARY_CACHE_PREFIX = "finance:reports:summary:";

function isRecord(x: unknown): x is Record<string, unknown> {
  return typeof x === "object" && x !== null;
}

function mapOutboxRowToLedgerEvent(row: OutboxEventEntity, tenantId: string): FinanceLedgerEventRow | null {
  if (!row.eventType.startsWith("finance.ledger.")) {
    return null;
  }
  const payload = row.payload;
  const journalId =
    (typeof payload.journalId === "string" && payload.journalId.trim()) ||
    row.aggregateId ||
    "";
  const registrationId =
    typeof payload.registrationId === "string" && payload.registrationId.trim() !== ""
      ? payload.registrationId.trim()
      : null;
  const lines = ledgerLinesFromFinanceOutboxRows([row], tenantId);
  if (!journalId) {
    return null;
  }
  return {
    outboxEventId: row.id,
    eventType: row.eventType,
    journalId,
    registrationId,
    domainEventId: row.domainEventId,
    lineCount: lines.length,
    createdAt: row.createdAt,
    lines
  };
}

@Injectable()
export class FinanceReportsService {
  constructor(
    @Inject(TenantDbContextService) private readonly tenantDbContext: TenantDbContextService,
    @Inject(ConfigService) private readonly configService: ConfigService,
    @Optional() @Inject(REDIS_CLIENT) private readonly redis: Redis | null
  ) {}

  private summaryCacheKey(tenantId: string): string {
    return `${SUMMARY_CACHE_PREFIX}${tenantId}`;
  }

  async invalidateSummaryCache(tenantId: string): Promise<void> {
    if (!this.redis || this.configService.getNodeEnv() === "test") {
      return;
    }
    try {
      await this.redis.del(this.summaryCacheKey(tenantId));
    } catch {
      /* non-fatal */
    }
  }

  async getSummary(tenantId: string): Promise<FinanceReportsSummary> {
    if (this.redis && this.configService.getNodeEnv() !== "test") {
      try {
        const cached = await this.redis.get(this.summaryCacheKey(tenantId));
        if (cached) {
          const parsed: unknown = JSON.parse(cached);
          if (isRecord(parsed)) {
            return {
              pendingManualPayments: Number(parsed.pendingManualPayments) || 0,
              pendingReceiptReviews: Number(parsed.pendingReceiptReviews) || 0,
              paidPayments: Number(parsed.paidPayments) || 0,
              failedPayments: Number(parsed.failedPayments) || 0
            };
          }
        }
      } catch {
        /* cache miss or parse failure — fall through to DB */
      }
    }

    const summary = await this.loadSummaryFromDb(tenantId);

    if (this.redis && this.configService.getNodeEnv() !== "test") {
      try {
        await this.redis.set(
          this.summaryCacheKey(tenantId),
          JSON.stringify(summary),
          "EX",
          SUMMARY_CACHE_TTL_SEC
        );
      } catch {
        /* non-fatal */
      }
    }

    return summary;
  }

  private async loadSummaryFromDb(tenantId: string): Promise<FinanceReportsSummary> {
    return this.tenantDbContext.runInTenantScope(tenantId, async (manager) => {
      const [pendingManualPayments, pendingReceiptReviews, paidPayments, failedPayments] =
        await Promise.all([
          manager.count(PaymentEntity, {
            where: {
              tenantId,
              method: PaymentMethod.MANUAL,
              status: PaymentStatus.PENDING
            }
          }),
          manager.count(PaymentReceiptEntity, {
            where: { tenantId, status: ReceiptStatus.PENDING }
          }),
          manager.count(PaymentEntity, {
            where: { tenantId, status: PaymentStatus.PAID }
          }),
          manager.count(PaymentEntity, {
            where: { tenantId, status: PaymentStatus.FAILED }
          })
        ]);

      return {
        pendingManualPayments,
        pendingReceiptReviews,
        paidPayments,
        failedPayments
      };
    });
  }

  async listLedgerEvents(tenantId: string, limit = 50): Promise<FinanceLedgerEventRow[]> {
    const capped = Math.min(Math.max(limit, 1), 200);
    return this.tenantDbContext.runInTenantScope(tenantId, async (manager) => {
      const rows = await manager.find(OutboxEventEntity, {
        where: {
          tenantId,
          eventType: Like("finance.ledger.%")
        },
        order: { createdAt: "DESC" },
        take: capped,
        select: {
          id: true,
          eventType: true,
          payload: true,
          createdAt: true,
          domainEventId: true,
          aggregateId: true
        }
      });
      const events: FinanceLedgerEventRow[] = [];
      for (const row of rows) {
        const mapped = mapOutboxRowToLedgerEvent(row, tenantId);
        if (mapped) {
          events.push(mapped);
        }
      }
      return events;
    });
  }

  async listOpenPayments(tenantId: string, limit = 100): Promise<FinanceOpenPaymentRow[]> {
    return this.tenantDbContext.runInTenantScope(tenantId, async (manager) => {
      const rows = await manager.find(PaymentEntity, {
        where: { tenantId, status: PaymentStatus.PENDING },
        order: { createdAt: "ASC" },
        take: limit,
        select: {
          id: true,
          registrationId: true,
          amount: true,
          currency: true,
          method: true,
          status: true,
          createdAt: true
        }
      });
      return rows.map((row) => ({
        id: row.id,
        registrationId: row.registrationId,
        amount: row.amount,
        currency: row.currency,
        method: row.method,
        status: row.status,
        createdAt: row.createdAt
      }));
    });
  }
}

import {
  BadRequestException,
  CallHandler,
  ExecutionContext,
  Inject,
  Injectable,
  NestInterceptor
} from "@nestjs/common";
import { Reflector } from "@nestjs/core";
import { firstValueFrom, from, Observable } from "rxjs";
import { RequestContextService } from "../../common/request-context/request-context.service";
import { runWithIdempotentEntityManager } from "./idempotent-transaction.context";
import { IdempotencyService } from "./idempotency.service";
import { IDEMPOTENCY_POLICY_KEY, type IdempotencyPolicy } from "./idempotent.decorator";
import { assertHttpIdempotencyKeyFormat } from "./http-idempotency-key";

@Injectable()
export class IdempotencyInterceptor implements NestInterceptor {
  constructor(
    @Inject(Reflector) private readonly reflector: Reflector,
    @Inject(IdempotencyService) private readonly idempotencyService: IdempotencyService,
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService
  ) {}

  intercept(context: ExecutionContext, next: CallHandler): Observable<unknown> {
    const policy = this.reflector.getAllAndOverride<IdempotencyPolicy>(
      IDEMPOTENCY_POLICY_KEY,
      [context.getHandler(), context.getClass()]
    );
    if (!policy) {
      return next.handle();
    }

    const request = context.switchToHttp().getRequest<{
      method: string;
      originalUrl?: string;
      body?: Record<string, unknown>;
      headers: Record<string, string | string[] | undefined>;
    }>();
    const idempotencyKeyRaw = request.headers["idempotency-key"];
    const idempotencyKey = Array.isArray(idempotencyKeyRaw)
      ? idempotencyKeyRaw[0]
      : idempotencyKeyRaw;

    if (idempotencyKey) {
      assertHttpIdempotencyKeyFormat(idempotencyKey);
    }

    if (!idempotencyKey) {
      if (policy.required) {
        throw new BadRequestException({
          error: {
            code: "VALIDATION_REQUIRED_FIELD_MISSING",
            message: "Idempotency-Key header is required"
          }
        });
      }
      return next.handle();
    }

    const tenantId = this.resolveTenantId(policy, request.body);
    const requestHash = this.idempotencyService.createRequestHash({
      method: request.method,
      path: request.originalUrl ?? policy.endpoint,
      body: request.body ?? null
    });

    return from(
      this.idempotencyService
        .executeWithIdempotency(
          {
            tenantId,
            key: idempotencyKey,
            endpoint: policy.endpoint,
            requestHash,
            statusCode: policy.statusCode
          },
          async (manager) =>
            runWithIdempotentEntityManager(
              manager,
              async () => (await firstValueFrom(next.handle())) as Record<string, unknown>,
              { idempotencyKey }
            )
        )
        .then((result) => result.responseBody)
    );
  }

  private resolveTenantId(policy: IdempotencyPolicy, body?: Record<string, unknown>): string {
    if (policy.tenantSource === "context") {
      const trustedTenantId = this.requestContextService.resolveEffectiveTenantId();
      if (!trustedTenantId) {
        throw new BadRequestException({
          error: {
            code: "TENANT_CONTEXT_MISSING",
            message: "Trusted tenant context required for idempotent operation"
          }
        });
      }
      return trustedTenantId;
    }

    const field = policy.tenantBodyField ?? "tenantId";
    const tenantId = body?.[field];
    if (typeof tenantId === "string" && tenantId.length > 0) {
      return tenantId;
    }
    throw new BadRequestException({
      error: {
        code: "VALIDATION_REQUIRED_FIELD_MISSING",
        message: `${field} is required for idempotent operation`
      }
    });
  }
}

import { ConflictException, Injectable } from "@nestjs/common";
import { InjectDataSource, InjectRepository } from "@nestjs/typeorm";
import { createHash } from "node:crypto";
import { QueryFailedError } from "typeorm";
import { DataSource, LessThan, Repository } from "typeorm";
import { IdempotencyKeyEntity } from "./entities/idempotency-key.entity";

const DEFAULT_IDEMPOTENCY_TTL_MS = 24 * 60 * 60 * 1000;
const parsedTtlFromEnv = Number(process.env.IDEMPOTENCY_TTL_MS ?? "");
const IDEMPOTENCY_TTL_MS =
  Number.isFinite(parsedTtlFromEnv) && parsedTtlFromEnv > 0
    ? parsedTtlFromEnv
    : DEFAULT_IDEMPOTENCY_TTL_MS;

@Injectable()
export class IdempotencyService {
  constructor(
    @InjectRepository(IdempotencyKeyEntity)
    private readonly idempotencyRepository: Repository<IdempotencyKeyEntity>,
    @InjectDataSource()
    private readonly dataSource: DataSource
  ) {}

  async findByKey(tenantId: string, key: string): Promise<IdempotencyKeyEntity | null> {
    return this.idempotencyRepository.findOne({ where: { tenantId, key } });
  }

  isExpired(record: Pick<IdempotencyKeyEntity, "expiresAt">): boolean {
    return record.expiresAt.getTime() <= Date.now();
  }

  async deleteExpired(): Promise<number> {
    const result = await this.idempotencyRepository.delete({
      expiresAt: LessThan(new Date())
    });
    return result.affected ?? 0;
  }

  async storeResponse(
    manager: DataSource["manager"],
    params: {
      tenantId: string;
      key: string;
      endpoint: string;
      requestHash: string;
      response: Record<string, unknown>;
      statusCode: number;
      ttlMs?: number;
    }
  ): Promise<IdempotencyKeyEntity> {
    const row = manager.create(IdempotencyKeyEntity, {
      tenantId: params.tenantId,
      key: params.key,
      endpoint: params.endpoint,
      requestHash: params.requestHash,
      responseBody: params.response,
      statusCode: params.statusCode,
      expiresAt: new Date(Date.now() + (params.ttlMs ?? IDEMPOTENCY_TTL_MS))
    });
    return manager.save(row);
  }

  createRequestHash(input: {
    method: string;
    path: string;
    body: unknown;
  }): string {
    const stable = JSON.stringify({
      method: input.method.toUpperCase(),
      path: input.path,
      body: input.body
    });
    return createHash("sha256").update(stable).digest("hex");
  }

  async executeWithIdempotency<TResponse>(
    params: {
      tenantId: string;
      key: string;
      endpoint: string;
      requestHash: string;
      statusCode?: number;
    },
    handler: (manager: DataSource["manager"]) => Promise<TResponse>
  ): Promise<{ statusCode: number; responseBody: TResponse; replayed: boolean }> {
    return this.dataSource.transaction(async (manager) => {
      const existing = await this.findRecord(manager, params.tenantId, params.key);

      const replayResult = this.resolveExistingRecord<TResponse>(existing, params);
      if (replayResult) return replayResult;

      if (existing && this.isExpired(existing)) {
        await manager.delete(IdempotencyKeyEntity, { id: existing.id });
      }

      const placeholder = manager.create(IdempotencyKeyEntity, {
        tenantId: params.tenantId,
        key: params.key,
        endpoint: params.endpoint,
        requestHash: params.requestHash,
        responseBody: null,
        statusCode: null,
        expiresAt: new Date(Date.now() + IDEMPOTENCY_TTL_MS)
      });
      const reservation = await this.reservePlaceholder(manager, placeholder, params);
      if ("replayResult" in reservation) {
        return reservation.replayResult as {
          statusCode: number;
          responseBody: TResponse;
          replayed: boolean;
        };
      }
      const reserved = reservation.reserved;
      const responseBody = await handler(manager);
      reserved.responseBody = responseBody as Record<string, unknown>;
      reserved.statusCode = params.statusCode ?? 201;
      await manager.save(reserved);
      return {
        statusCode: reserved.statusCode,
        responseBody,
        replayed: false
      };
    });
  }

  private async findRecord(
    manager: DataSource["manager"],
    tenantId: string,
    key: string
  ): Promise<IdempotencyKeyEntity | null> {
    return manager.findOne(IdempotencyKeyEntity, {
      where: { tenantId, key }
    });
  }

  private resolveExistingRecord<TResponse>(
    existing: IdempotencyKeyEntity | null,
    params: {
      endpoint: string;
      requestHash: string;
    }
  ): { statusCode: number; responseBody: TResponse; replayed: boolean } | null {
    if (!existing || this.isExpired(existing)) {
      return null;
    }
    if (existing.endpoint !== params.endpoint) {
      throw new ConflictException({
        error: {
          code: "IDEMPOTENCY_KEY_ENDPOINT_MISMATCH",
          message: "Idempotency key already used by a different endpoint"
        }
      });
    }
    if (existing.requestHash !== params.requestHash) {
      throw new ConflictException({
        error: {
          code: "IDEMPOTENCY_KEY_REPLAY_MISMATCH",
          message: "Idempotency key already used with a different payload"
        }
      });
    }
    if (existing.responseBody && existing.statusCode) {
      return {
        statusCode: existing.statusCode,
          responseBody: existing.responseBody as TResponse,
        replayed: true
      };
    }
    throw new ConflictException({
      error: {
        code: "IDEMPOTENCY_REQUEST_IN_PROGRESS",
        message: "Another request is in progress for this key"
      }
    });
  }

  private async reservePlaceholder(
    manager: DataSource["manager"],
    placeholder: IdempotencyKeyEntity,
    params: {
      tenantId: string;
      key: string;
      endpoint: string;
      requestHash: string;
    }
  ): Promise<
    | { reserved: IdempotencyKeyEntity }
    | {
        replayResult: {
          statusCode: number;
          responseBody: unknown;
          replayed: boolean;
        };
      }
  > {
    try {
      return { reserved: await manager.save(placeholder) };
    } catch (error: unknown) {
      if (!this.isUniqueViolation(error)) {
        throw error;
      }
      const existing = await this.findRecord(manager, params.tenantId, params.key);
      const replayResult = this.resolveExistingRecord(existing, params);
      if (replayResult) {
        return { replayResult };
      }
      throw error;
    }
  }

  private isUniqueViolation(error: unknown): boolean {
    return (
      error instanceof QueryFailedError &&
      typeof (error as { driverError?: { code?: string } }).driverError?.code === "string" &&
      (error as { driverError?: { code?: string } }).driverError?.code === "23505"
    );
  }
}

import {
