@Injectable()
export class UsersInviteService {
  constructor(
    @Inject(UsersAccessService) private readonly access: UsersAccessService,
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService,
    @Inject(TenantAuditEventsService)
    private readonly tenantAuditEventsService: TenantAuditEventsService,
    @InjectRepository(WorkspaceInviteEntity)
    private readonly workspaceInviteRepository: Repository<WorkspaceInviteEntity>,
    @InjectRepository(UserEntity)
    private readonly userRepository: Repository<UserEntity>,
    @InjectRepository(UserTenantEntity)
    private readonly membershipRepository: Repository<UserTenantEntity>
  ) {}

  async inviteUser(phone: string, role: string): Promise<InviteUserResult> {
    const tenantId = this.access.resolveTenantIdOrThrow();
    const { actorUserId, actorRole } = this.access.resolveActorContextOrThrow();
    await this.access.ensureActorMembershipOrThrow(tenantId, actorUserId);

    const normalizedPhone = normalizeOtpPhoneInput(phone);
    const normalizedRole = normalizeWorkspaceMembershipRole(role);
    if (!normalizedPhone) {
      throw new BadRequestException({
        error: { code: "VALIDATION_ERROR", message: "phone is required" }
      });
    }
    if (!normalizedRole) {
      throw new BadRequestException({
        error: { code: "VALIDATION_ERROR", message: "role is invalid" }
      });
    }

    const inviteDecision = evaluateWorkspaceInviteRole({
      inviterRole: actorRole,
      invitedRole: normalizedRole
    });
    if (!inviteDecision.ok) {
      throw new ForbiddenException({
        error: { code: inviteDecision.code, message: inviteDecision.message }
      });
    }

    // tenant-isolation:qb-exempt — resolve user by phone across tenants; invite still tenant-scoped.
    const targetUser = await this.userRepository
      .createQueryBuilder("u")
      .where("u.deleted_at IS NULL")
      .andWhere("phone_normalized(COALESCE(u.phone, '')) = phone_normalized(:phone)", {
        phone: normalizedPhone
      })
      .getOne();

    if (targetUser) {
      const existingActiveMembership = await this.membershipRepository.findOne({
        where: {
          tenantId,
          userId: targetUser.id,
          deletedAt: IsNull(),
          status: MembershipStatus.ACTIVE
        }
      });
      if (existingActiveMembership) {
        throw new BadRequestException({
          error: {
            code: "INVITE_ALREADY_ACTIVE_MEMBER",
            message: "User is already an active workspace member"
          }
        });
      }
    }

    const inviteToken = randomBytes(24).toString("hex");
    const now = new Date();
    const expiresAt = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);

    const saved = await this.membershipRepository.manager.transaction(async (manager) => {
      const invite = await manager.save(
        manager.create(WorkspaceInviteEntity, {
          tenantId,
          email: normalizedPhone,
          role: normalizedRole,
          invitedByUserId: actorUserId,
          inviteToken,
          status: WorkspaceInviteStatus.PENDING,
          expiresAt,
          invitedAt: now
        })
      );

      let savedMembership: UserTenantEntity | null = null;
      if (targetUser) {
        const membershipRepo = manager.getRepository(UserTenantEntity);
        let membership = await membershipRepo.findOne({
          where: {
            tenantId,
            userId: targetUser.id,
            deletedAt: IsNull()
          }
        });

        if (!membership) {
          membership = membershipRepo.create({
            tenantId,
            userId: targetUser.id,
            role: normalizedRole,
            status: MembershipStatus.INVITED,
            invitedAt: now,
            joinedAt: null,
            suspendedAt: null
          });
        } else {
          membership.role = normalizedRole;
          membership.status = MembershipStatus.INVITED;
          membership.invitedAt = now;
          membership.joinedAt = null;
          membership.suspendedAt = null;
        }
        savedMembership = await membershipRepo.save(membership);
      }

      const actorLabelRecord = await manager.getRepository(UserEntity).findOne({
        where: { id: actorUserId, deletedAt: IsNull() }
      });
      const actorLabel = actorLabelRecord?.email ?? actorUserId;
      await this.tenantAuditEventsService.append(
        {
          tenantId,
          actorUserId,
          actor: actorLabel,
          userId: targetUser?.id ?? null,
          action: TenantAuditAction.USER_INVITED,
          resourceType: "workspace_invite",
          resourceId: invite.id,
          metadata: {
            actorUserId,
            targetUserId: targetUser?.id ?? null,
            tenantId,
            timestamp: now.toISOString(),
            details: {
              role: normalizedRole,
              inviteStatus: WorkspaceInviteStatus.PENDING,
              membershipStatus: savedMembership?.status ?? null,
              expiresAt: expiresAt.toISOString()
            }
          },
          clientIp: this.requestContextService.tryGetClientIp(),
          requestId: this.requestContextService.tryGetRequestId()
        },
        manager
      );

      return { invite, membership: savedMembership };
    });

    return {
      inviteId: saved.invite.id,
      tenantId: saved.invite.tenantId,
      phone: saved.invite.email,
      role: saved.invite.role,
      inviteToken: saved.invite.inviteToken,
      status: saved.invite.status,
      expiresAt: saved.invite.expiresAt.toISOString(),
      membershipStatus: saved.membership?.status ?? null
    };
  }

  async acceptInvite(
    dto: AcceptInviteDto,
    actorContext?: { actorUserId: string; clientIp?: string; requestId?: string }
  ): Promise<AcceptInviteResult> {
    const inviteToken = dto.inviteToken.trim();
    if (!inviteToken) {
      throw new BadRequestException({
        error: { code: "VALIDATION_ERROR", message: "invite token is required" }
      });
    }

    const invite = await this.workspaceInviteRepository.findOne({
      where: { inviteToken }
    });
    if (!invite) {
      throw new NotFoundException({
        error: { code: "INVITE_NOT_FOUND", message: "Invite not found" }
      });
    }

    if (invite.status !== WorkspaceInviteStatus.PENDING) {
      throw new BadRequestException({
        error: { code: "INVITE_NOT_PENDING", message: "Invite is not pending" }
      });
    }

    const now = new Date();
    if (invite.expiresAt.getTime() <= now.getTime()) {
      await this.workspaceInviteRepository.update(
        { id: invite.id },
        { status: WorkspaceInviteStatus.EXPIRED }
      );
      throw new BadRequestException({
        error: { code: "INVITE_EXPIRED", message: "Invite has expired" }
      });
    }

    const normalizedRole = normalizeWorkspaceMembershipRole(invite.role);
    if (!normalizedRole) {
      throw new BadRequestException({
        error: { code: "INVITE_ROLE_INVALID", message: "Invite role is invalid" }
      });
    }

    const tenantAuditEvents = this.tenantAuditEventsService;
    const actorUserId = actorContext?.actorUserId?.trim() ?? this.requestContextService.getUserId();
    if (!actorUserId) {
      throw new ForbiddenException({
        error: { code: "AUTH_UNAUTHENTICATED", message: "Authentication required" }
      });
    }
    const auditClientIp = actorContext?.clientIp ?? this.requestContextService.tryGetClientIp();
    const auditRequestId = actorContext?.requestId ?? this.requestContextService.tryGetRequestId();

    const accepted = await this.membershipRepository.manager.transaction(async (manager) => {
      const userRepo = manager.getRepository(UserEntity);
      const inviteRepo = manager.getRepository(WorkspaceInviteEntity);
      const membershipRepo = manager.getRepository(UserTenantEntity);
      const user = await userRepo.findOne({
        where: { id: actorUserId, deletedAt: IsNull() }
      });
      if (!user) {
        throw new ForbiddenException({
          error: { code: "AUTH_UNAUTHENTICATED", message: "Authentication required" }
        });
      }
      assertInviteTargetMatchesUser(invite, user);

      let membership = await membershipRepo.findOne({
        where: {
          tenantId: invite.tenantId,
          userId: user.id,
          deletedAt: IsNull()
        }
      });

      if (!membership) {
        membership = membershipRepo.create({
          tenantId: invite.tenantId,
          userId: user.id,
          role: normalizedRole,
          status: MembershipStatus.ACTIVE,
          invitedAt: invite.invitedAt ?? invite.createdAt,
          joinedAt: now,
          suspendedAt: null
        });
      } else {
        membership.role = normalizedRole;
        membership.status = MembershipStatus.ACTIVE;
        membership.joinedAt = now;
        membership.suspendedAt = null;
        if (!membership.invitedAt) {
          membership.invitedAt = invite.invitedAt ?? invite.createdAt;
        }
      }
      const savedMembership = await membershipRepo.save(membership);

      invite.status = WorkspaceInviteStatus.ACCEPTED;
      await inviteRepo.remove(invite);

      const actorLabel = user.email ?? user.id;
      await tenantAuditEvents.append(
        {
          tenantId: invite.tenantId,
          actorUserId: user.id,
          actor: actorLabel,
          userId: user.id,
          action: TenantAuditAction.USER_JOINED,
          resourceType: "workspace_invite",
          resourceId: invite.id,
          metadata: {
            actorUserId: user.id,
            targetUserId: user.id,
            tenantId: invite.tenantId,
            timestamp: now.toISOString(),
            details: {
              role: normalizedRole,
              inviteStatus: WorkspaceInviteStatus.ACCEPTED,
              membershipStatus: MembershipStatus.ACTIVE,
              joinedAt: now.toISOString()
            }
          },
          clientIp: auditClientIp,
          requestId: auditRequestId
        },
        manager
      );

      return {
        user,
        membership: savedMembership,
        inviteStatus: WorkspaceInviteStatus.ACCEPTED,
        tenantId: invite.tenantId
      };
    });

    return {
      tenantId: accepted.tenantId,
      userId: accepted.user.id,
      role: accepted.membership.role,
      membershipStatus: accepted.membership.status,
      joinedAt: accepted.membership.joinedAt?.toISOString() ?? now.toISOString(),
      inviteStatus: accepted.inviteStatus
    };
  }

  async resendInvite(userId: string): Promise<ResendInviteResult> {
    const tenantId = this.access.resolveTenantIdOrThrow();
    const { actorUserId } = this.access.resolveActorContextOrThrow();
    await this.access.ensureActorMembershipOrThrow(tenantId, actorUserId);

    const membership = await this.membershipRepository.findOne({
      where: {
        tenantId,
        userId,
        deletedAt: IsNull()
      }
    });
    if (!membership) {
      throw new NotFoundException({
        error: { code: "MEMBERSHIP_NOT_FOUND", message: "Membership not found" }
      });
    }
    if (membership.status !== MembershipStatus.INVITED) {
      throw new BadRequestException({
        error: {
          code: "INVITE_RESEND_NOT_ALLOWED",
          message: "Invite can only be resent for invited memberships"
        }
      });
    }

    const user = await this.userRepository.findOne({
      where: { id: userId, deletedAt: IsNull() }
    });
    if (!user) {
      throw new NotFoundException({
        error: { code: "USER_NOT_FOUND", message: "User not found" }
      });
    }

    const normalizedPhone = normalizeOtpPhoneInput(user.phone ?? "");
    if (!normalizedPhone) {
      throw new BadRequestException({
        error: { code: "INVITE_PHONE_REQUIRED", message: "User must have a phone number to resend invite" }
      });
    }

    const now = new Date();
    const expiresAt = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);
    const inviteToken = randomBytes(24).toString("hex");

    const invite = await this.workspaceInviteRepository.save(
      this.workspaceInviteRepository.create({
        tenantId,
        email: normalizedPhone,
        role: membership.role,
        invitedByUserId: actorUserId,
        inviteToken,
        status: WorkspaceInviteStatus.PENDING,
        expiresAt,
        invitedAt: now
      })
    );

    membership.invitedAt = now;
    await this.membershipRepository.save(membership);

    const actorLabelRecord = await this.userRepository.findOne({
      where: { id: actorUserId, deletedAt: IsNull() }
    });
    const actorLabel = actorLabelRecord?.email ?? actorUserId;
    await this.tenantAuditEventsService.append({
      tenantId,
      actorUserId,
      actor: actorLabel,
      userId: membership.userId,
      action: TenantAuditAction.USER_INVITE_RESENT,
      resourceType: "workspace_invite",
      resourceId: invite.id,
      metadata: {
        actorUserId,
        targetUserId: membership.userId,
        tenantId,
        timestamp: now.toISOString(),
        details: {
          role: membership.role,
          inviteStatus: WorkspaceInviteStatus.PENDING,
          membershipStatus: membership.status,
          expiresAt: expiresAt.toISOString()
        }
      },
      clientIp: this.requestContextService.tryGetClientIp(),
      requestId: this.requestContextService.tryGetRequestId()
    });

    return {
      inviteId: invite.id,
      tenantId: invite.tenantId,
      userId: membership.userId,
      phone: invite.email,
      role: invite.role,
      inviteToken: invite.inviteToken,
      status: invite.status,
      expiresAt: invite.expiresAt.toISOString(),
      membershipStatus: membership.status
    };
  }

  private async resolveUserIdForInvitePhone(
    tenantId: string,
    phone: string
  ): Promise<string | null> {
    const normalizedPhone = normalizeOtpPhoneInput(phone);
    if (!normalizedPhone) {
      return null;
    }
    const user = await this.userRepository
      .createQueryBuilder("u")
      .select(["u.id"])
      .where("u.deleted_at IS NULL")
      .andWhere("phone_normalized(COALESCE(u.phone, '')) = phone_normalized(:phone)", {
        phone: normalizedPhone
      })
      .getOne();
    if (!user) {
      return null;
    }
    const membership = await this.membershipRepository.findOne({
      where: {
        tenantId,
        userId: user.id,
        deletedAt: IsNull(),
        status: MembershipStatus.INVITED
      },
      select: ["id", "userId"]
    });
    return membership?.userId ?? null;
  }

  async listPendingInvites(): Promise<PendingWorkspaceInviteRow[]> {
    const tenantId = this.access.resolveTenantIdOrThrow();
    const { actorUserId } = this.access.resolveActorContextOrThrow();
    await this.access.ensureActorMembershipOrThrow(tenantId, actorUserId);

    const now = new Date();
    const invites = await this.workspaceInviteRepository.find({
      where: {
        tenantId,
        status: WorkspaceInviteStatus.PENDING,
        expiresAt: MoreThan(now)
      },
      order: { expiresAt: "ASC" }
    });

    const rows: PendingWorkspaceInviteRow[] = [];
    for (const invite of invites) {
      const userId = await this.resolveUserIdForInvitePhone(tenantId, invite.email);
      rows.push({
        inviteId: invite.id,
        phone: invite.email,
        role: invite.role,
        status: invite.status,
        expiresAt: invite.expiresAt.toISOString(),
        invitedAt: invite.invitedAt?.toISOString() ?? invite.createdAt.toISOString(),
        userId
      });
    }
    return rows;
  }

  async cancelInvite(inviteId: string): Promise<CancelInviteResult> {
    const tenantId = this.access.resolveTenantIdOrThrow();
    const { actorUserId } = this.access.resolveActorContextOrThrow();
    await this.access.ensureActorMembershipOrThrow(tenantId, actorUserId);

    const invite = await this.workspaceInviteRepository.findOne({
      where: { id: inviteId, tenantId }
    });
    if (!invite || invite.status !== WorkspaceInviteStatus.PENDING) {
      throw new NotFoundException({
        error: { code: "INVITE_NOT_FOUND", message: "Pending invite not found" }
      });
    }

    const userId = await this.resolveUserIdForInvitePhone(tenantId, invite.email);
    const now = new Date();

    await this.workspaceInviteRepository.manager.transaction(async (manager) => {
      await manager.getRepository(WorkspaceInviteEntity).update(
        { id: invite.id, tenantId },
        { status: WorkspaceInviteStatus.EXPIRED }
      );
      if (userId) {
        const membership = await manager.getRepository(UserTenantEntity).findOne({
          where: {
            tenantId,
            userId,
            deletedAt: IsNull(),
            status: MembershipStatus.INVITED
          }
        });
        if (membership) {
          await manager.getRepository(UserTenantEntity).delete({ id: membership.id });
        }
      }

      const actorLabelRecord = await manager.getRepository(UserEntity).findOne({
        where: { id: actorUserId, deletedAt: IsNull() }
      });
      const actorLabel = actorLabelRecord?.email ?? actorUserId;
      await this.tenantAuditEventsService.append(
        {
          tenantId,
          actorUserId,
          actor: actorLabel,
          userId,
          action: TenantAuditAction.USER_INVITED,
          resourceType: "workspace_invite",
          resourceId: invite.id,
          metadata: {
            cancelled: true,
            inviteStatus: WorkspaceInviteStatus.EXPIRED,
            timestamp: now.toISOString()
          },
          clientIp: this.requestContextService.tryGetClientIp(),
          requestId: this.requestContextService.tryGetRequestId()
        },
        manager
      );
    });

    return { inviteId: invite.id, status: WorkspaceInviteStatus.EXPIRED };
  }

  async resendInviteByInviteId(inviteId: string): Promise<ResendInviteResult> {
    const tenantId = this.access.resolveTenantIdOrThrow();
    const { actorUserId } = this.access.resolveActorContextOrThrow();
    await this.access.ensureActorMembershipOrThrow(tenantId, actorUserId);

    const invite = await this.workspaceInviteRepository.findOne({
      where: { id: inviteId, tenantId, status: WorkspaceInviteStatus.PENDING }
    });
    if (!invite) {
      throw new NotFoundException({
        error: { code: "INVITE_NOT_FOUND", message: "Pending invite not found" }
      });
    }

    const now = new Date();
    if (invite.expiresAt.getTime() <= now.getTime()) {
      await this.workspaceInviteRepository.update(
        { id: invite.id },
        { status: WorkspaceInviteStatus.EXPIRED }
      );
      throw new BadRequestException({
        error: { code: "INVITE_EXPIRED", message: "Invite has expired" }
      });
    }

    const userId = await this.resolveUserIdForInvitePhone(tenantId, invite.email);
    const inviteToken = randomBytes(24).toString("hex");
    const expiresAt = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);

    invite.inviteToken = inviteToken;
    invite.expiresAt = expiresAt;
    invite.invitedAt = now;
    await this.workspaceInviteRepository.save(invite);

    if (userId) {
      const membership = await this.membershipRepository.findOne({
        where: { tenantId, userId, deletedAt: IsNull() }
      });
      if (membership && membership.status === MembershipStatus.INVITED) {
        membership.invitedAt = now;
        await this.membershipRepository.save(membership);
      }
    }

    const actorLabelRecord = await this.userRepository.findOne({
      where: { id: actorUserId, deletedAt: IsNull() }
    });
    const actorLabel = actorLabelRecord?.email ?? actorUserId;
    await this.tenantAuditEventsService.append({
      tenantId,
      actorUserId,
      actor: actorLabel,
      userId,
      action: TenantAuditAction.USER_INVITE_RESENT,
      resourceType: "workspace_invite",
      resourceId: invite.id,
      metadata: {
        actorUserId,
        targetUserId: userId,
        tenantId,
        timestamp: now.toISOString(),
        details: {
          role: invite.role,
          inviteStatus: WorkspaceInviteStatus.PENDING,
          expiresAt: expiresAt.toISOString()
        }
      },
      clientIp: this.requestContextService.tryGetClientIp(),
      requestId: this.requestContextService.tryGetRequestId()
    });

    return {
      inviteId: invite.id,
      tenantId: invite.tenantId,
      userId: userId ?? "",
      phone: invite.email,
      role: invite.role,
      inviteToken: invite.inviteToken,
      status: invite.status,
      expiresAt: invite.expiresAt.toISOString(),
      membershipStatus: MembershipStatus.INVITED
    };
  }
}

import {
  BadRequestException,
  Controller,
  ForbiddenException,
  Get,
  Inject,
  Param,
  ParseUUIDPipe,
  Query,
  Res,
  UnauthorizedException,
  UseGuards
} from "@nestjs/common";
import {
  ApiBearerAuth,
  ApiForbiddenResponse,
  ApiOkResponse,
  ApiOperation,
  ApiTags,
  ApiUnauthorizedResponse
} from "@nestjs/swagger";
import { InjectRepository } from "@nestjs/typeorm";
import type { Response } from "express";
import { IsNull, Repository } from "typeorm";
import { TenantAuditAction } from "../../common/audit/tenant-audit-actions";
import { TENANT_AUDIT_LIST_DEFAULT_LIMIT } from "../../common/audit/tenant-audit.constants";
import {
  decodeTenantAuditListCursor,
  TenantAuditEventsService
} from "../../common/audit/tenant-audit-events.service";
import { RequestContextService } from "../../common/request-context/request-context.service";
import { AuthorizationPresenceGuard } from "../auth/authorization-presence.guard";
import { Roles } from "../auth/roles.decorator";
import { UserRole } from "../../common/auth/user-role.enum";
import { RolesGuard } from "../auth/roles.guard";
import { AbilitiesGuard } from "../../common/casl/abilities.guard";
import { CaslMirrorAbilitiesGuard } from "../../common/casl/casl-mirror-abilities.guard";
import { AbilityAction } from "../../common/casl/ability-actions";
import { CheckAbilities } from "../../common/casl/check-abilities.decorator";
import { ExportTenantAuditQueryDto } from "./dto/export-tenant-audit-query.dto";
import { ListDraftConflictsQueryDto } from "./dto/list-draft-conflicts-query.dto";
import { ListTenantAuditQueryDto } from "./dto/list-tenant-audit-query.dto";
import { UserEntity } from "./entities/user.entity";

@ApiTags("Compliance")
@Controller("api/v2/workspaces")
@UseGuards(AuthorizationPresenceGuard, RolesGuard, AbilitiesGuard, CaslMirrorAbilitiesGuard)
@ApiBearerAuth()
@Roles(UserRole.Owner, UserRole.Admin, UserRole.Leader)
export class TenantAuditEventsController {
  constructor(
    @Inject(TenantAuditEventsService)
    private readonly tenantAuditEventsService: TenantAuditEventsService,
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService,
    @InjectRepository(UserEntity)
    private readonly userRepository: Repository<UserEntity>
  ) {}

  /**
   * Ensures the JWT workspace tenant matches `:tenantId` (defense in depth vs CASL).
   */
  private requireWorkspaceTenantMatch(paramTenantId: string): string {
    const jwtTenantId = this.requestContextService.resolveEffectiveTenantId()?.trim().toLowerCase();
    const normalized = paramTenantId.trim().toLowerCase();
    if (!jwtTenantId || jwtTenantId !== normalized) {
      throw new ForbiddenException({
        error: {
          code: "TENANT_SCOPE_FORBIDDEN",
          message: "Workspace audit requires a token scoped to this tenant"
        }
      });
    }
    return normalized;
  }

  @Get(":tenantId/audit-events/export")
  @CheckAbilities(({ ability }) => ability.can(AbilityAction.Read, "Audit"))
  @ApiOperation({
    summary: "Export tenant-scoped audit event stream",
    description:
      "Append-only compliance audit (`tenant_audit_events`) for the workspace. " +
      "Requires JWT tenant to match `:tenantId`. Owner, admin, or leader (read Audit)."
  })
  @ApiOkResponse({
    description: "CSV, NDJSON, or JSON array depending on `format`",
    schema: { type: "string", format: "binary" }
  })
  @ApiUnauthorizedResponse({ description: "Authentication required" })
  @ApiForbiddenResponse({ description: "Tenant mismatch or insufficient role" })
  async exportTenantAudit(
    @Param("tenantId", ParseUUIDPipe) tenantId: string,
    @Query() query: ExportTenantAuditQueryDto,
    @Res({ passthrough: true }) res: Response
  ): Promise<string | Record<string, unknown>[]> {
    const paramTenantId = this.requireWorkspaceTenantMatch(tenantId);

    const exporterUserId = this.requestContextService.getUserId();
    if (!exporterUserId) {
      throw new UnauthorizedException({
        error: {
          code: "AUTH_UNAUTHENTICATED",
          message: "Authentication required"
        }
      });
    }

    const exporter = await this.userRepository.findOne({
      where: { id: exporterUserId, deletedAt: IsNull() }
    });
    const actorLabel = exporter?.email ?? exporterUserId;

    const from = query.from ? new Date(query.from) : undefined;
    const to = query.to ? new Date(query.to) : undefined;

    const rows = await this.tenantAuditEventsService.listForTenantExport({
      tenantId: paramTenantId,
      from,
      to,
      limit: query.limit
    });

    await this.tenantAuditEventsService.appendOrWarn({
      tenantId: paramTenantId,
      actorUserId: exporterUserId,
      actor: actorLabel,
      userId: exporterUserId,
      action: TenantAuditAction.DATA_EXPORT_AUDIT,
      resourceType: "audit_trail",
      resourceId: paramTenantId,
      metadata: {
        format: query.format ?? "csv",
        row_count: rows.length,
        filters: { from: query.from ?? null, to: query.to ?? null }
      },
      clientIp: this.requestContextService.tryGetClientIp(),
      requestId: this.requestContextService.tryGetRequestId()
    });

    const fmt = query.format ?? "csv";
    if (fmt === "csv") {
      res.setHeader("Content-Type", "text/csv; charset=utf-8");
      res.setHeader(
        "Content-Disposition",
        `attachment; filename="tenant-audit-${paramTenantId}.csv"`
      );
      return this.tenantAuditEventsService.toCsv(rows);
    }
    if (fmt === "ndjson") {
      res.setHeader("Content-Type", "application/x-ndjson; charset=utf-8");
      res.setHeader(
        "Content-Disposition",
        `attachment; filename="tenant-audit-${paramTenantId}.ndjson"`
      );
      return this.tenantAuditEventsService.toNdjson(rows);
    }
    res.setHeader("Content-Type", "application/json; charset=utf-8");
    return rows.map((row) => ({
      id: row.id,
      tenant_id: row.tenantId,
      timestamp: row.occurredAt.toISOString(),
      user_id: row.userId,
      actor_user_id: row.actorUserId,
      actor: row.actor,
