      from,
      to,
      action: query.action,
      resourceType: query.resourceType,
      resourceId: query.resourceId,
      actorContains: query.actorContains,
      limit,
      after
    });

    return {
      data: rows.map((row) => ({
        id: row.id,
        occurredAt: row.occurredAt.toISOString(),
        actor: row.actor,
        actorUserId: row.actorUserId,
        userId: row.userId,
