import { ForbiddenException, Inject, Injectable, Logger, NotFoundException } from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import { Repository } from "typeorm";
import {
  UserRole,
  tryParseWorkspaceUserRole,
  type RequestActorRole
} from "../../common/auth/user-role.enum";
import { FALLBACK_OPERATING_CURRENCY_CODE } from "./users-member-wallet-balances.service";
import {
  authRequiredError,
  tenantContextMissingError,
  tenantScopedResourceNotFoundError
} from "../../common/errors/error-response-builders";
import { normalizeMembershipLabels } from "../../common/rbac/normalize-membership-labels";
import { membershipHasSelectableLeader, parseMembershipMetadata } from "@repo/shared";
import { RequestContextService } from "../../common/request-context/request-context.service";
import type { UserResponseDto } from "./dto/user-response.dto";
import { PROFILE_GENDER_VALUES, type ProfileGenderValue } from "./constants/profile-gender";
import { UserTenantEntity } from "./entities/user-tenant.entity";
import { UserEntity } from "./entities/user.entity";
import type { TenantScopedUserRow } from "./users/users-tenant-scope.types";
import { UsersTenantScopeRepository } from "./users/repositories/users-tenant-scope.repository";
import type { MemberWalletBalanceSnapshot } from "./users-member-wallet-balances.service";
import type { UserBookingSummarySnapshot } from "./workspace-user-booking-summary.service";

export type { TenantScopedUserRow } from "./users/users-tenant-scope.types";

export type UserResponseMappingContext = {
  wallet?: MemberWalletBalanceSnapshot;
  bookingSummary?: UserBookingSummarySnapshot;
};

/**
 * **Services = orchestration + policy** (tenant resolution, guards, DTO mapping).
 * Tenant-scoped row loads delegate to repositories (**persistence only**).
 */
@Injectable()
export class UsersAccessService {
  private readonly logger = new Logger(UsersAccessService.name);

  constructor(
    @InjectRepository(UserEntity)
    private readonly userRepository: Repository<UserEntity>,
    @InjectRepository(UserTenantEntity)
    private readonly userTenantRepository: Repository<UserTenantEntity>,
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService,
    @Inject(UsersTenantScopeRepository)
    private readonly tenantScopeRepository: UsersTenantScopeRepository
  ) {}

  get users(): Repository<UserEntity> {
    return this.userRepository;
  }

  get memberships(): Repository<UserTenantEntity> {
    return this.userTenantRepository;
  }

  resolveTenantIdOrThrow(): string {
    const tenantId = this.requestContextService.resolveEffectiveTenantId();
    if (!tenantId) {
      throw new ForbiddenException(tenantContextMissingError());
    }
    return tenantId;
  }

  resolveActorContextOrThrow(): { actorUserId: string; actorRole: RequestActorRole | undefined } {
    const actorUserId = this.requestContextService.getUserId();
    const actorRole = this.requestContextService.getRole();
    if (!actorUserId) {
      throw new ForbiddenException(authRequiredError());
    }
    return { actorUserId, actorRole };
  }

  async ensureActorMembershipOrThrow(tenantId: string, actorUserId: string): Promise<void> {
    const actorMembership = await this.tenantScopeRepository.findActiveMembership(tenantId, actorUserId);
    if (!actorMembership) {
      throw new ForbiddenException({
        error: {
          code: "TENANT_SCOPE_FORBIDDEN",
          message: "Access to tenant denied"
        }
      });
    }
  }

  async findTenantScopedUserOrThrow(tenantId: string, userId: string): Promise<TenantScopedUserRow> {
    const row = await this.tenantScopeRepository.findTenantScopedUserRow(tenantId, userId);
    if (!row) {
      throw new NotFoundException(tenantScopedResourceNotFoundError());
    }
    return row;
  }

  toUserResponseDto(row: TenantScopedUserRow, ctx?: UserResponseMappingContext): UserResponseDto {
    let membershipRole = tryParseWorkspaceUserRole(row.role);
    if (!membershipRole) {
      this.logger.warn(
        `Unknown membership role "${String(row.role ?? "")}" for user ${row.id}; falling back to ${UserRole.Member}`
      );
      membershipRole = UserRole.Member;
    }
    const meta = parseMembershipMetadata(row.membership_metadata);
    const wallet = ctx?.wallet;
    const booking = ctx?.bookingSummary;

    return {
      id: row.id,
      name:
        row.full_name?.trim() ||
        row.email?.split("@")[0]?.trim() ||
        row.phone?.trim() ||
        "User",
      email: row.email ?? null,
      phone: row.phone,
      isPhoneVerified: row.is_phone_verified,
      role: membershipRole,
      status: row.membership_status,
      gender: normalizeProfileGender(row.gender),
      profileImageUrl: normalizeProfileImageUrl(row.profile_image_url),
      lastLoginAt: row.last_login_at ?? null,
      lastActiveAt: row.last_active_at ?? null,
      invitedAt: row.invited_at ?? null,
      joinedAt: row.joined_at ?? null,
      suspendedAt: row.suspended_at ?? null,
      labels: normalizeMembershipLabels(row.labels),
      permanentDiscountPercentage: meta.permanentDiscountPercentage,
      rewardBadges: meta.badges ?? [],
      isSelectableLeader: membershipHasSelectableLeader(meta),
      telegramLinked: coerceTelegramLinked(row.telegram_linked),
      walletBalanceMinor: wallet?.balanceMinor ?? "0",
      walletCurrency: wallet?.currency ?? FALLBACK_OPERATING_CURRENCY_CODE,
      totalTrips: booking?.totalTrips ?? 0,
      completedTrips: booking?.completedTrips ?? 0,
      cancelledTrips: booking?.cancelledTrips ?? 0,
      profileRowVersion:
        row.profile_row_version !== undefined && row.profile_row_version !== null
          ? Number(row.profile_row_version)
          : undefined
    };
  }
}

function normalizeProfileGender(value: string | null | undefined): ProfileGenderValue | null {
  if (!value || typeof value !== "string") {
    return null;
  }
  const trimmed = value.trim().toLowerCase();
  if ((PROFILE_GENDER_VALUES as readonly string[]).includes(trimmed)) {
    return trimmed as ProfileGenderValue;
  }
  return null;
}

function normalizeProfileImageUrl(value: string | null | undefined): string | null {
  if (!value || typeof value !== "string") {
    return null;
  }
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
}

function coerceTelegramLinked(value: boolean | string | null | undefined): boolean {
  if (value === true || value === "t" || value === "true" || value === "1") {
    return true;
  }
  return false;
}

import { Injectable, NotFoundException } from "@nestjs/common";
import { IsNull } from "typeorm";
import type { UserRoleHistoryItemDto } from "./dto/user-role-history-item.dto";
import { UserEntity } from "./entities/user.entity";
import { UserRoleAuditEntity } from "./entities/user-role-audit.entity";
import { tenantScopedResourceNotFoundError } from "../../common/errors/error-response-builders";
import { UsersAccessService } from "./users-access.service";

@Injectable()
export class UsersAuditService {
  constructor(private readonly access: UsersAccessService) {}

  async getUserRoleHistory(userId: string): Promise<UserRoleHistoryItemDto[]> {
    const tenantId = this.access.resolveTenantIdOrThrow();

    const membership = await this.access.memberships.findOne({
      where: { tenantId, userId, deletedAt: IsNull() }
    });
    if (!membership) {
      throw new NotFoundException(tenantScopedResourceNotFoundError());
    }

    const rows = await this.access.memberships.manager
      .getRepository(UserRoleAuditEntity)
      .createQueryBuilder("audit")
      .innerJoin(UserEntity, "actor", "actor.id = audit.actor_user_id AND actor.deleted_at IS NULL")
      .where("audit.tenant_id = :tenantId", { tenantId })
      .andWhere("audit.target_user_id = :userId", { userId })
      .select([
        "audit.actor_user_id AS actor_user_id",
        "actor.email AS actor_email",
        "audit.old_role AS old_role",
        "audit.new_role AS new_role",
        "audit.created_at AS created_at"
      ])
      .orderBy("audit.created_at", "DESC")
      .limit(50)
      .getRawMany<{
        actor_user_id: string;
        actor_email: string;
        old_role: string;
        new_role: string;
        created_at: Date;
      }>();

    return rows.map((row) => ({
      actorUserId: row.actor_user_id,
      actorEmail: row.actor_email,
      oldRole: row.old_role,
      newRole: row.new_role,
      createdAt: row.created_at.toISOString()
    }));
  }
}

import { Injectable } from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import { In, IsNull, Repository } from "typeorm";
import { memberWalletId } from "../finance/ledger/member-wallet-id";
import { normalizeFinanceTenantId } from "../finance/ledger/ledger-tenant-scope";
import { AccountBalanceEntity } from "../finance/ledger/entities/account-balance.entity";
import { TenantEntity } from "./entities/tenant.entity";

export type MemberWalletBalanceSnapshot = {
  balanceMinor: string;
  currency: string;
};

export const FALLBACK_OPERATING_CURRENCY_CODE = "IRR";

const CURRENCY_CODE_PATTERN = /^[A-Z]{3}$/;

export function normalizeOperatingCurrencyCode(value: string | null | undefined): string {
  const raw = (value ?? "").trim().toUpperCase();
  if (raw.length === 0 || !CURRENCY_CODE_PATTERN.test(raw)) {
    return FALLBACK_OPERATING_CURRENCY_CODE;
  }
  return raw;
}

@Injectable()
export class UsersMemberWalletBalancesService {
  constructor(
    @InjectRepository(AccountBalanceEntity)
    private readonly accountBalances: Repository<AccountBalanceEntity>,
    @InjectRepository(TenantEntity)
    private readonly tenants: Repository<TenantEntity>
  ) {}

  async resolveOperatingCurrencyCode(tenantId: string): Promise<string> {
    const row = await this.tenants.findOne({
      where: { id: tenantId, deletedAt: IsNull() },
      select: ["id", "operatingCurrencyCode"]
    });
    return normalizeOperatingCurrencyCode(row?.operatingCurrencyCode);
  }

  /**
   * Single batched query (`account IN (...)` + tenant operating currency). Never call per user row.
   */
  async loadBalancesForUserIds(
    tenantId: string,
    userIds: readonly string[]
  ): Promise<Map<string, MemberWalletBalanceSnapshot>> {
    const out = new Map<string, MemberWalletBalanceSnapshot>();
    if (userIds.length === 0) {
      return out;
    }
    const currency = await this.resolveOperatingCurrencyCode(tenantId);
    const tenantNorm = normalizeFinanceTenantId(tenantId);
    const accounts = userIds.map((id) => memberWalletId(id));
    const rows = await this.accountBalances.find({
      where: {
        tenantId: tenantNorm,
        account: In(accounts),
        currency
      }
    });
    for (const row of rows) {
      const prefix = "member:";
      if (!row.account.startsWith(prefix)) {
        continue;
      }
      const userId = row.account.slice(prefix.length);
      if (!userId) {
        continue;
      }
      out.set(userId, {
        balanceMinor: row.balanceMinor?.trim() || "0",
        currency
      });
    }
    for (const userId of userIds) {
      if (!out.has(userId)) {
        out.set(userId, { balanceMinor: "0", currency });
      }
    }
    return out;
  }
}

import { Inject, Injectable } from "@nestjs/common";
import type { ListUsersQueryDto } from "./dto/list-users-query.dto";
import type { ListUsersResponseDto } from "./dto/list-users-response.dto";
import type { UserResponseDto } from "./dto/user-response.dto";
import { UsersListRepository } from "./users/repositories/users-list.repository";
import { UsersAccessService } from "./users-access.service";
import { UsersMemberWalletBalancesService } from "./users-member-wallet-balances.service";
import { WorkspaceUserBookingSummaryService } from "./workspace-user-booking-summary.service";

/**
 * **Services = orchestration + policy** (cursors, list shaping). Listing queries delegate to repositories (**persistence only**).
 */
@Injectable()
export class UsersReadService {
  constructor(
    @Inject(UsersAccessService) private readonly access: UsersAccessService,
    @Inject(UsersListRepository) private readonly usersListRepository: UsersListRepository,
    @Inject(UsersMemberWalletBalancesService)
    private readonly memberWalletBalances: UsersMemberWalletBalancesService,
    @Inject(WorkspaceUserBookingSummaryService)
    private readonly bookingSummaries: WorkspaceUserBookingSummaryService
  ) {}

  async listUsers(query: ListUsersQueryDto): Promise<ListUsersResponseDto> {
    const tenantId = this.access.resolveTenantIdOrThrow();

    const limit = query.limit ?? 50;
    const normalizedSearch = query.search?.trim().toLowerCase() ?? "";
    const roleFilter = query.role?.trim().toLowerCase();
    const statusFilter = query.status?.trim().toUpperCase();
    const lastLoginFrom = query.lastLoginFrom?.trim();
    const lastLoginTo = query.lastLoginTo?.trim();
    const decodedCursor = this.decodeUsersCursor(query.cursor, tenantId);

    const rows = await this.usersListRepository.listTenantUsers({
      tenantId,
      limit,
      normalizedSearch,
      roleFilter: roleFilter || undefined,
      statusFilter: statusFilter || undefined,
      lastLoginFrom: lastLoginFrom || undefined,
      lastLoginTo: lastLoginTo || undefined,
      cursor: decodedCursor
    });

    const hasNext = rows.length > limit;
    const pageRows = hasNext ? rows.slice(0, limit) : rows;

    const pageUserIds = pageRows.map((row) => row.id);
    const [walletByUserId, bookingByUserId] = await Promise.all([
      this.memberWalletBalances.loadBalancesForUserIds(tenantId, pageUserIds),
      this.bookingSummaries.loadBookingSummariesForUserIds(tenantId, pageUserIds)
    ]);

    const data: UserResponseDto[] = pageRows.map((row) =>
      this.access.toUserResponseDto(
        {
          id: row.id,
          full_name: row.full_name,
          email: row.email,
          phone: row.phone,
          gender: row.gender,
          profile_image_url: row.profile_image_url,
          last_login_at: row.last_login_at,
          last_active_at: row.last_active_at,
          is_email_verified: row.is_email_verified,
          is_phone_verified: row.is_phone_verified,
          role: row.role,
          membership_status: row.membership_status,
          invited_at: row.invited_at,
          joined_at: row.joined_at,
          suspended_at: row.suspended_at,
          labels: row.labels,
          membership_metadata: row.membership_metadata,
          telegram_linked: row.telegram_linked,
          profile_row_version: row.profile_row_version ?? undefined
        },
        {
          wallet: walletByUserId.get(row.id),
          bookingSummary: bookingByUserId.get(row.id)
        }
      )
    );

    const last = pageRows.at(-1);
    const nextCursor =
      hasNext && last
        ? this.encodeUsersCursor({
            tenantId,
            createdAt: new Date(last.membership_created_at).toISOString(),
            id: last.membership_id
          })
        : null;

    return { data, nextCursor };
  }

  async getUserById(userId: string): Promise<UserResponseDto> {
    const tenantId = this.access.resolveTenantIdOrThrow();
    const { actorUserId } = this.access.resolveActorContextOrThrow();
    await this.access.ensureActorMembershipOrThrow(tenantId, actorUserId);
    const user = await this.access.findTenantScopedUserOrThrow(tenantId, userId);
    const [walletMap, bookingMap] = await Promise.all([
      this.memberWalletBalances.loadBalancesForUserIds(tenantId, [userId]),
      this.bookingSummaries.loadBookingSummariesForUserIds(tenantId, [userId])
    ]);
    return this.access.toUserResponseDto(user, {
      wallet: walletMap.get(userId),
      bookingSummary: bookingMap.get(userId)
    });
  }

  private encodeUsersCursor(input: { tenantId: string; createdAt: string; id: string }): string {
    return Buffer.from(
      JSON.stringify({ v: 1, t: input.tenantId, c: input.createdAt, i: input.id })
    ).toString("base64url");
  }

  private decodeUsersCursor(
    rawCursor: string | undefined,
    tenantId: string
  ): { createdAt: string; id: string } | null {
    if (!rawCursor || rawCursor.trim() === "") {
      return null;
    }
    try {
      const decoded = JSON.parse(Buffer.from(rawCursor, "base64url").toString("utf8")) as {
        v?: unknown;
        t?: unknown;
        c?: unknown;
        i?: unknown;
        createdAt?: unknown;
        id?: unknown;
      };
      if (decoded.v === 1 && typeof decoded.t === "string" && typeof decoded.c === "string" && typeof decoded.i === "string") {
        if (decoded.t !== tenantId) {
          return null;
        }
        const createdAt = decoded.c.trim();
        const id = decoded.i.trim();
        if (!createdAt || !id || Number.isNaN(Date.parse(createdAt))) {
          return null;
        }
        return { createdAt, id };
      }
      /** Legacy cursors lacked tenant binding — reject to avoid ambiguous pagination across workspaces. */
      if (typeof decoded.createdAt === "string" && typeof decoded.id === "string") {
        return null;
      }
      return null;
    } catch {
      return null;
    }
  }
}

