        role: this.configService.getRuntimeRole(),
        jobs: this.schedulerRuntimeMetrics.getSnapshot()
      }
    };
  }
}

import {
  Column,
  CreateDateColumn,
  Entity,
  Index,
  PrimaryGeneratedColumn
} from "typeorm";

export enum OutboxEventStatus {
  PENDING = "PENDING",
  DELIVERED = "DELIVERED",
  FAILED = "FAILED"
}

@Entity("outbox_events")
@Index("idx_outbox_events_status_created_at", ["status", "createdAt"])
@Index("idx_outbox_events_aggregate", ["aggregateType", "aggregateId"])
@Index("idx_outbox_events_tenant_created_at", ["tenantId", "createdAt"])
export class OutboxEventEntity {
  @PrimaryGeneratedColumn("uuid")
  id!: string;

  @Column({ type: "uuid", name: "tenant_id" })
  tenantId!: string;

  @Column({ type: "varchar", name: "aggregate_type", length: 64 })
  aggregateType!: string;

  @Column({ type: "uuid", name: "aggregate_id" })
  aggregateId!: string;

  @Column({ type: "varchar", name: "event_type", length: 128 })
  eventType!: string;

  @Column({ type: "jsonb" })
  payload!: Record<string, unknown>;

  @Column({
    type: "enum",
    enum: OutboxEventStatus,
    enumName: "outbox_event_status_enum",
    default: OutboxEventStatus.PENDING
  })
  status!: OutboxEventStatus;

  @Column({ type: "int", name: "retry_count", default: 0 })
  retryCount!: number;

  @Column({ type: "timestamptz", name: "next_retry_at", nullable: true })
  nextRetryAt!: Date | null;

  @CreateDateColumn({ type: "timestamptz", name: "created_at" })
  createdAt!: Date;

  @Column({ type: "timestamptz", name: "processed_at", nullable: true })
  processedAt!: Date | null;
}

import { Inject, Injectable, Logger } from "@nestjs/common";
import { DataSource } from "typeorm";
import { ConfigService } from "../../config/config.service";
import { AuditService } from "../../common/audit/audit.service";
import {
  OutboxEventEntity,
  OutboxEventStatus
} from "./entities/outbox-event.entity";
import { OutboxMetricsService } from "./outbox-metrics.service";
import { TenantDbContextService } from "../../database/tenant-db-context.service";
import { EmailService } from "../../common/email/email.service";
import { OUTBOX_EVENT_TYPE_IDENTITY_EMAIL_VERIFICATION_SEND } from "./identity-email-outbox.constants";
import {
  dispatchRegistrationAcceptedSmsGateIfEligible,
  REGISTRATION_ACCEPTED_OUTBOX_EVENT_TYPE
} from "./registration-accepted-sms-outbox.handler";

/**
 * Transactional outbox dispatcher.
 *
 * **Enqueue:** domain-critical events must be inserted via {@link enqueueOutboxEvent} in the same
 * transaction as aggregate writes. Optional `domainEventId` enables DB-level dedupe (unique per tenant).
 *
 * **Publish / retry:** failed deliveries increment `retry_count` and set `next_retry_at` with exponential
 * backoff until `OUTBOX_MAX_RETRY`, then `FAILED`.
 *
 * **Idempotency:** at-least-once delivery — the same row may be processed again after a crash before
 * `DELIVERED`. Downstream handlers MUST dedupe on `event_id` (outbox PK) and/or stable domain ids in payload.
 */
@Injectable()
export class OutboxProcessor {
  private readonly logger = new Logger(OutboxProcessor.name);

  constructor(
    @Inject(DataSource) private readonly dataSource: DataSource,
    @Inject(AuditService) private readonly auditService: AuditService,
    @Inject(EmailService) private readonly emailService: EmailService,
    @Inject(ConfigService) private readonly configService: ConfigService,
    @Inject(OutboxMetricsService) private readonly metrics: OutboxMetricsService,
    @Inject(TenantDbContextService)
    private readonly tenantDbContext: TenantDbContextService
  ) {}

  async processBatch(): Promise<void> {
    const started = Date.now();
    const maxRetry = this.configService.getOutboxMaxRetry();
    const batchSize = this.configService.getOutboxBatchSize();

    const rows = await this.dataSource.transaction(async (manager) => {
      const pendingTotal = await manager.count(OutboxEventEntity, {
        where: { status: OutboxEventStatus.PENDING }
      });
      this.metrics.setPendingTotal(pendingTotal);

      // tenant-isolation:qb-exempt — pending queue is global; each row dispatched under runInTenantScope.
      return manager
        .createQueryBuilder(OutboxEventEntity, "o")
        .where("o.status = :status", { status: OutboxEventStatus.PENDING })
        .andWhere("(o.nextRetryAt IS NULL OR o.nextRetryAt <= :now)", {
          now: new Date()
        })
        .orderBy("o.createdAt", "ASC")
        .take(batchSize)
        .setLock("pessimistic_write")
        .setOnLocked("skip_locked")
        .getMany();
    });

    for (const row of rows) {
      try {
        const tenantId = row.tenantId.trim().toLowerCase();
        await this.tenantDbContext.runInTenantScope(tenantId, async (manager) => {
          const payload = row.payload as Record<string, unknown>;
          if (row.eventType === OUTBOX_EVENT_TYPE_IDENTITY_EMAIL_VERIFICATION_SEND) {
            const to = typeof payload.to === "string" ? payload.to : "";
            const tok = typeof payload.token === "string" ? payload.token : "";
            await this.emailService.sendVerificationEmailOutboundStrict(to, tok);
          } else {
            if (row.eventType === REGISTRATION_ACCEPTED_OUTBOX_EVENT_TYPE) {
              await dispatchRegistrationAcceptedSmsGateIfEligible({
                manager,
                metrics: this.metrics,
                logger: this.logger,
                tenantId,
                outboxEventId: row.id,
                payload
              });
            }
            this.auditService.deliverFromOutbox({
              tenant_id: tenantId,
              event_id: row.id,
              event_type: row.eventType,
              payload,
              created_at: row.createdAt instanceof Date
                ? row.createdAt.toISOString()
                : String(row.createdAt)
            });
          }
          row.status = OutboxEventStatus.DELIVERED;
          row.processedAt = new Date();
          await manager.save(row);
        });
      } catch (error: unknown) {
        const errMsg = error instanceof Error ? error.message : String(error);
        this.logger.warn(
          `outbox_delivery_failed eventType=${row.eventType} id=${row.id}: ${errMsg}`
        );
        await this.dataSource.transaction(async (manager) => {
          const fresh = await manager.findOne(OutboxEventEntity, { where: { id: row.id } });
          if (!fresh) {
            return;
          }
          fresh.retryCount += 1;
          if (fresh.retryCount >= maxRetry) {
            fresh.status = OutboxEventStatus.FAILED;
            fresh.nextRetryAt = null;
            this.metrics.incrementFailed();
            this.logger.warn(`Outbox event ${fresh.id} reached max retry attempts`);
          } else {
            fresh.nextRetryAt = new Date(
              Date.now() + 2 ** fresh.retryCount * 60 * 1000
            );
          }
          await manager.save(fresh);
        });
      }
    }

    this.metrics.setProcessingLatencyMs(Date.now() - started);
    this.metrics.setLastBatchProcessedAt(new Date().toISOString());
  }
}

import { randomUUID } from "node:crypto";
import { Inject, Injectable } from "@nestjs/common";
import type { EntityManager } from "typeorm";
import { FinancialMutationAuditService } from "../../common/audit/financial-mutation-audit.service";
import { isFinancialOutboxEventType } from "../../common/audit/financial-outbox-event-types";
import { enqueueOutboxEvent } from "../../common/outbox/enqueue-outbox-event";
import { OutboxMetricsService } from "./outbox-metrics.service";

export type OutboxEventInput = {
  /** Workspace tenant for worker dispatch and RLS alignment during processing. */
  tenantId: string;
  aggregateType: string;
  aggregateId: string;
  eventType: string;
  payload: Record<string, unknown>;
  correlationId?: string;
  /** Stable domain id for enqueue dedupe (optional). */
  domainEventId?: string | null;
  /**
   * Optional domain row snapshots for `tenant_audit_events` when {@link eventType} is financial
   * (see `isFinancialOutboxEventType`). Omitted callers still get an audit row with `state_after`
   * defaulting to the outbox payload.
   */
  financialAudit?: {
    stateBefore: Record<string, unknown> | null;
    stateAfter: Record<string, unknown> | null;
  } | null;
};

@Injectable()
export class OutboxService {
  constructor(
    @Inject(OutboxMetricsService) private readonly metrics: OutboxMetricsService,
    @Inject(FinancialMutationAuditService)
    private readonly financialMutationAudit: FinancialMutationAuditService
  ) {}

  /**
   * Inserts an outbox row using the caller's EntityManager so the write commits
   * or rolls back with the same transaction as domain mutations (AUDIT-RULE-004).
   *
   * Financial `eventType` values also append `tenant_audit_events` in the same transaction when
   * the outbox row is newly inserted (skipped duplicate `domainEventId` → no second audit row).
   */
  async addEvent(manager: EntityManager, event: OutboxEventInput): Promise<void> {
    const correlationId = (event.correlationId?.trim() || randomUUID()) as string;
    const inserted = await enqueueOutboxEvent(
      manager,
      {
        tenantId: event.tenantId,
        eventType: event.eventType,
        payload: event.payload,
        aggregateType: event.aggregateType,
        aggregateId: event.aggregateId,
        correlationId,
        domainEventId: event.domainEventId
      },
      { onEnqueued: () => this.metrics.noteEnqueued() }
    );
    if (inserted && isFinancialOutboxEventType(event.eventType)) {
      await this.financialMutationAudit.recordOutboxFinancialMutation(manager, {
        tenantId: event.tenantId,
        eventType: event.eventType,
        aggregateType: event.aggregateType,
        aggregateId: event.aggregateId,
        correlationId,
        payload: { ...event.payload, correlation_id: correlationId },
        financialAudit: event.financialAudit
      });
    }
  }
}

import {
  BadRequestException,
  ForbiddenException,
  Inject,
  Injectable,
  NotFoundException
} from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import type { EntityManager } from "typeorm";
import { IsNull, Repository, type FindOptionsWhere } from "typeorm";
import { capabilitiesForTenantModules } from "@repo/shared";
import { registrationWhereForActor } from "../../../common/security/ownership-scope";
import { RequestContextService } from "../../../common/request-context/request-context.service";
import {
  actorHasTrustedTenantOrPlatformAdminBypass,
  registrationTenantMatchesActorScope,
} from "../../../common/rbac/workspace-access.helper";
import { RegistrationEntity } from "../../registrations/registration.entity";
import { TourEntity } from "../../tours/entities/tour.entity";
import { UserEntity } from "../../identity/entities/user.entity";
import type { CreatePaymentIntentDto } from "../dto/create-payment-intent.dto";
import { tenantContextMissingError } from "../../../common/errors/error-response-builders";

/**
 * Application slice: **resolve registration** for payment-intent creation (tenant + ownership scope).
 * Pure payment amount / gateway rules stay on {@link PaymentsService}.
 */
@Injectable()
export class PaymentIntentRegistrationResolverApplicationService {
  constructor(
    @Inject(RequestContextService) private readonly requestContextService: RequestContextService,
    @InjectRepository(UserEntity)
    private readonly userRepository: Repository<UserEntity>
  ) {}

  async resolveRegistrationForCreateIntent(
    manager: EntityManager,
    dto: CreatePaymentIntentDto
  ): Promise<RegistrationEntity> {
    const trustedTenantId = this.requestContextService.resolveEffectiveTenantId();
    const actorRoleRaw = this.requestContextService.getRole();
    const actorUserIdRaw = this.requestContextService.getUserId();
    if (!actorHasTrustedTenantOrPlatformAdminBypass(actorRoleRaw, trustedTenantId)) {
      throw new ForbiddenException(tenantContextMissingError());
    }

    const isPublicTenantBootstrapActor =
      typeof trustedTenantId === "string" &&
      trustedTenantId.trim() !== "" &&
      (!actorUserIdRaw || actorUserIdRaw.trim() === "") &&
      (!actorRoleRaw || actorRoleRaw.trim() === "");

    let registrationScope: FindOptionsWhere<RegistrationEntity> | FindOptionsWhere<RegistrationEntity>[];

    if (isPublicTenantBootstrapActor) {
      registrationScope = {
        id: dto.registrationId,
        tenantId: trustedTenantId,
        deletedAt: IsNull()
      };
    } else {
      registrationScope = await registrationWhereForActor(
        manager,
        this.userRepository,
        this.requestContextService,
        dto.registrationId
      );
    }

    const registration = await manager.findOne(RegistrationEntity, {
      where: registrationScope
    });
    if (!registration) {
      throw new NotFoundException({
        error: {
          code: "RESOURCE_NOT_FOUND",
          message: "Registration not found"
        }
      });
    }
    if (!registrationTenantMatchesActorScope(actorRoleRaw, trustedTenantId, registration.tenantId)) {
      throw new NotFoundException({
        error: {
          code: "RESOURCE_NOT_FOUND",
          message: "Registration not found"
        }
      });
    }

    const tenantModules = this.requestContextService.tryGetTenantEnabledModules() ?? [];
    const financeCaps = capabilitiesForTenantModules(tenantModules);
    if (!financeCaps.includes("module.finance")) {
      throw new BadRequestException({
        error: {
          code: "FINANCE_MODULE_REQUIRED",
          message: "Online payment intents require the finance module for this workspace."
        }
      });
    }

    const tour = await manager.findOne(TourEntity, {
      where: { id: registration.tourId, tenantId: registration.tenantId },
      select: { id: true, tenantId: true, costContext: true }
    });
    if (!tour) {
      throw new NotFoundException({
        error: {
          code: "RESOURCE_NOT_FOUND",
          message: "Tour not found for registration"
        }
      });
    }

    const costContext = tour.costContext;
    const requiresPayment =
      costContext != null &&
      typeof costContext === "object" &&
      Boolean(
        (costContext as { requiresPayment?: boolean }).requiresPayment ??
          (costContext as { requires_payment?: boolean }).requires_payment
      );
    if (!requiresPayment) {
      throw new BadRequestException({
        error: {
          code: "PAYMENT_NOT_REQUIRED",
          message: "This tour does not require payment; payment intents are not allowed."
        }
      });
    }

    return registration;
  }
}

