import { Inject, Injectable } from "@nestjs/common";
import type { IPaymentGateway } from "./payment-gateway.interface";
import type { CreatePaymentIntentGatewayInput, PaymentIntentGatewayResult } from "./payment-gateway.types";
import type { IdempotencyKeyStore } from "./payment-idempotency-key.store";
import { PAYMENT_GATEWAY_IDEMPOTENCY_STORE } from "./payment-idempotency-key.store";

@Injectable()
export class MockPaymentGateway implements IPaymentGateway {
  readonly providerId = "mock";

  constructor(
    @Inject(PAYMENT_GATEWAY_IDEMPOTENCY_STORE) private readonly idempotencyStore: IdempotencyKeyStore
  ) {}

  async createPaymentIntent(input: CreatePaymentIntentGatewayInput): Promise<PaymentIntentGatewayResult> {
    const { value } = await this.idempotencyStore.runOnce(
      {
        tenantId: input.tenantId,
        operation: `${this.providerId}:create_payment_intent`,
        idempotencyKey: input.idempotencyKey
      },
      async () => {
        const suffix = input.registrationId.replace(/-/g, "").slice(0, 12);
        return {
          provider: this.providerId,
          providerPaymentId: `mock_pi_${suffix}`,
          clientSecret: `mock_cs_${suffix}`,
          status: "requires_payment_method" as const
        } satisfies PaymentIntentGatewayResult;
      }
    );
    return value;
  }
}

import { BadRequestException, Injectable } from "@nestjs/common";
import { ConfigService } from "../../../config/config.service";
import type { IPaymentGateway } from "./payment-gateway.interface";
import { MockPaymentGateway } from "./mock-payment-gateway";
import { StripeLikePaymentGatewayPlaceholder } from "./stripe-like-payment-gateway.placeholder";
import { StripePaymentGateway } from "./stripe-payment-gateway";
import { ZibalPaymentGateway } from "./zibal-payment-gateway";

/**
 * Resolves a gateway implementation by provider slug (`mock`, `stripe`, `zibal`, …).
 */
@Injectable()
export class PaymentGatewayFactory {
  constructor(
    private readonly mockGateway: MockPaymentGateway,
    private readonly stripePlaceholder: StripeLikePaymentGatewayPlaceholder,
    private readonly stripeLive: StripePaymentGateway,
    private readonly zibalGateway: ZibalPaymentGateway,
    private readonly config: ConfigService
  ) {}

  forProvider(paymentProvider: string): IPaymentGateway {
    const p = paymentProvider.trim().toLowerCase();
    if (
      this.config.getNodeEnv() === "production" &&
      (p === "mock_provider" || p === "mock" || p === "")
    ) {
      throw new BadRequestException({
        error: {
          code: "PAYMENT_PROVIDER_NOT_ALLOWED",
          message: "Mock payment provider is disabled in production"
        }
      });
    }
    if (p === "stripe") {
      return this.config.getStripeSecretKey().length > 0 ? this.stripeLive : this.stripePlaceholder;
    }
    if (p === "zibal") {
      if (!this.config.getZibalMerchant() || !this.config.getZibalCallbackUrl()) {
        throw new BadRequestException({
          error: {
            code: "PAYMENT_PROVIDER_NOT_CONFIGURED",
            message: "Zibal requires ZIBAL_MERCHANT and ZIBAL_CALLBACK_URL"
          }
        });
      }
      return this.zibalGateway;
    }
    return this.mockGateway;
  }
}

import type { CreatePaymentIntentGatewayInput, PaymentIntentGatewayResult } from "./payment-gateway.types";

/**
 * Vendor-neutral payment port. Implementations must require `CreatePaymentIntentGatewayInput.idempotencyKey`
 * and delegate dedupe to `IdempotencyKeyStore` (or equivalent persistence).
 */
export interface IPaymentGateway {
  readonly providerId: string;

  createPaymentIntent(input: CreatePaymentIntentGatewayInput): Promise<PaymentIntentGatewayResult>;
}

import { Injectable } from "@nestjs/common";

export type PaymentIdempotencyScope = {
  tenantId: string;
  /** Logical operation, e.g. `stripe:create_payment_intent`. */
  operation: string;
  idempotencyKey: string;
};

export type IdempotentRunResult<T> = {
  value: T;
  /** True when a prior completed or in-flight execution satisfied this call. */
  replayed: boolean;
};

/**
 * Payment-layer idempotency (distinct from HTTP `IdempotencyService` on routes).
 * Same composite key must yield the same successful result; failures are not cached.
 */
export interface IdempotencyKeyStore {
  runOnce<T>(scope: PaymentIdempotencyScope, fn: () => Promise<T>): Promise<IdempotentRunResult<T>>;
}

/** Nest DI token for {@link IdempotencyKeyStore} (memory vs Redis implementation). */
export const PAYMENT_GATEWAY_IDEMPOTENCY_STORE = Symbol("PAYMENT_GATEWAY_IDEMPOTENCY_STORE");

/** Dedicated Redis client for payment-gateway idempotency (avoid coupling to tenant-abuse Redis). */
export const PAYMENTS_GATEWAY_IDEMPOTENCY_REDIS = Symbol("PAYMENTS_GATEWAY_IDEMPOTENCY_REDIS");

export function paymentGatewayIdempotencyCompositeKey(scope: PaymentIdempotencyScope): string {
  return `${scope.tenantId}\n${scope.operation}\n${scope.idempotencyKey}`;
}

function jsonClone<T>(value: T): T {
  return JSON.parse(JSON.stringify(value)) as T;
}

function compositeKey(scope: PaymentIdempotencyScope): string {
  return paymentGatewayIdempotencyCompositeKey(scope);
}

/**
 * In-process {@link IdempotencyKeyStore} (single Node instance). **Not** cross-replica or crash-safe.
 * Use {@link PostgresPaymentIdempotencyKeyStore} (default outside tests) or {@link RedisPaymentIdempotencyKeyStore}.
 */
@Injectable()
export class InMemoryIdempotencyKeyStore implements IdempotencyKeyStore {
  private readonly cache = new Map<string, unknown>();
  private readonly chainTail = new Map<string, Promise<unknown>>();

  async runOnce<T>(scope: PaymentIdempotencyScope, fn: () => Promise<T>): Promise<IdempotentRunResult<T>> {
    const key = compositeKey(scope);
    const prev = this.chainTail.get(key) ?? Promise.resolve();

    const next = (prev as Promise<unknown>)
      .catch(() => {
        /* keep chain alive after a failed attempt */
      })
      .then(async () => {
        const hit = this.cache.get(key);
        if (hit !== undefined) {
          return { value: jsonClone(hit) as T, replayed: true as const };
        }
        const value = await fn();
        const frozen = jsonClone(value);
        this.cache.set(key, frozen);
        return { value: jsonClone(frozen) as T, replayed: false as const };
      }) as Promise<IdempotentRunResult<T>>;

    this.chainTail.set(key, next);
    return next;
  }
}

import { createHash } from "node:crypto";
import { Injectable, InternalServerErrorException } from "@nestjs/common";
import { InjectDataSource } from "@nestjs/typeorm";
import { DataSource, QueryFailedError } from "typeorm";
import { PaymentGatewayIdempotencyEntity } from "../entities/payment-gateway-idempotency.entity";
import type { IdempotencyKeyStore, IdempotentRunResult, PaymentIdempotencyScope } from "./payment-idempotency-key.store";
import { paymentGatewayIdempotencyCompositeKey } from "./payment-idempotency-key.store";

const PENDING_TTL_MS = 90_000;
const RESULT_TTL_MS = 86400_000 * 7;
const WAIT_DEADLINE_MS = 35_000;

function jsonClone<T>(value: T): T {
  return JSON.parse(JSON.stringify(value)) as T;
}

function digestOf(scope: PaymentIdempotencyScope): string {
  return createHash("sha256").update(paymentGatewayIdempotencyCompositeKey(scope)).digest("hex");
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function isUniqueViolation(error: unknown): boolean {
  if (!(error instanceof QueryFailedError)) {
    return false;
  }
  const driverCode = (error as { driverError?: { code?: string } }).driverError?.code;
  const topCode = (error as { code?: string }).code;
  return driverCode === "23505" || topCode === "23505";
}

type ClaimPhase =
  | { kind: "acquired" }
  | { kind: "replay"; payload: Record<string, unknown> }
  | { kind: "wait" }
  | { kind: "retry" };

/**
 * PostgreSQL-backed {@link IdempotencyKeyStore} for payment gateways.
 *
 * - **Cross-replica safe:** single canonical row per digest (PK); followers block on `SELECT … FOR UPDATE`
 *   until the leader commits `completed` or the pending row expires.
 * - **Crash-safe:** pending rows expire; followers delete stale `pending` and retry acquisition.
 *   Successful results persist until `expires_at` (TTL) for replay; failures delete the pending row so `fn` can retry.
 *
 * Complements PSP-native keys (e.g. Stripe `Idempotency-Key` on `paymentIntents.create`) by deduplicating
 * our process before hitting the network.
 */
@Injectable()
export class PostgresPaymentIdempotencyKeyStore implements IdempotencyKeyStore {
  constructor(@InjectDataSource() private readonly dataSource: DataSource) {}

  async runOnce<T>(scope: PaymentIdempotencyScope, fn: () => Promise<T>): Promise<IdempotentRunResult<T>> {
    const digest = digestOf(scope);
    const deadline = Date.now() + WAIT_DEADLINE_MS;
    let delayMs = 12;
    let acquired = false;

    while (Date.now() < deadline) {
      const phase = await this.dataSource.transaction(async (em) => {
        await em.query(`DELETE FROM payment_gateway_idempotency WHERE digest = $1 AND expires_at < NOW()`, [
          digest
        ]);

        try {
          const row = em.create(PaymentGatewayIdempotencyEntity, {
            digest,
            tenantId: scope.tenantId.trim(),
            operation: scope.operation.trim().slice(0, 191),
            idempotencyKey: scope.idempotencyKey.trim().slice(0, 255),
            status: "pending",
            resultPayload: null,
            expiresAt: new Date(Date.now() + PENDING_TTL_MS)
          });
          await em.save(row);
          return { kind: "acquired" } satisfies ClaimPhase;
        } catch (error: unknown) {
          if (!isUniqueViolation(error)) {
            throw error;
          }
        }

        const row = await em.findOne(PaymentGatewayIdempotencyEntity, {
          where: { digest },
          lock: { mode: "pessimistic_write" }
        });

        if (!row) {
          return { kind: "retry" } satisfies ClaimPhase;
        }

        if (row.status === "completed" && row.resultPayload != null) {
          return { kind: "replay", payload: row.resultPayload } satisfies ClaimPhase;
        }

        if (row.expiresAt.getTime() <= Date.now()) {
          await em.delete(PaymentGatewayIdempotencyEntity, { digest });
          return { kind: "retry" } satisfies ClaimPhase;
        }

        return { kind: "wait" } satisfies ClaimPhase;
      });

      if (phase.kind === "replay") {
        return { value: jsonClone(phase.payload) as T, replayed: true };
      }

      if (phase.kind === "acquired") {
        acquired = true;
        break;
      }

      await sleep(delayMs);
      delayMs = Math.min(delayMs * 2, 220);
    }

    if (!acquired) {
      throw new InternalServerErrorException({
        error: {
          code: "PAYMENT_IDEMPOTENCY_LOCK_TIMEOUT",
          message: "Timed out waiting for payment gateway idempotency row (Postgres)"
        }
      });
    }

    try {
      const value = await fn();
      const frozen = JSON.parse(JSON.stringify(value)) as Record<string, unknown>;
      const result = await this.dataSource.transaction(async (em) => {
        const res = await em
          .createQueryBuilder()
          .update(PaymentGatewayIdempotencyEntity)
          .set({
            status: "completed",
            resultPayload: frozen,
            expiresAt: new Date(Date.now() + RESULT_TTL_MS)
          })
          .where("digest = :digest AND status = :status", { digest, status: "pending" })
          .execute();
        return res.affected ?? 0;
      });
      if (result === 0) {
        throw new InternalServerErrorException({
          error: {
            code: "PAYMENT_IDEMPOTENCY_ROW_LOST",
            message: "Payment gateway idempotency pending row was missing at commit time"
          }
        });
      }
      return { value: jsonClone(value) as T, replayed: false };
    } catch (error: unknown) {
      await this.dataSource.transaction(async (em) => {
        await em.delete(PaymentGatewayIdempotencyEntity, { digest });
      });
      throw error;
    }
  }
}

import { createHash } from "node:crypto";
import {
  Inject,
  Injectable,
  InternalServerErrorException,
  OnModuleDestroy
} from "@nestjs/common";
import type Redis from "ioredis";
import type { IdempotencyKeyStore, IdempotentRunResult, PaymentIdempotencyScope } from "./payment-idempotency-key.store";
import {
  PAYMENTS_GATEWAY_IDEMPOTENCY_REDIS,
  paymentGatewayIdempotencyCompositeKey
} from "./payment-idempotency-key.store";

const PENDING_SENTINEL = "__payment_gateway_idempotency_pending__";
const REDIS_KEY_PREFIX = "paygw:idemp:v1:";

function jsonClone<T>(value: T): T {
  return JSON.parse(JSON.stringify(value)) as T;
}

function redisKey(scope: PaymentIdempotencyScope): string {
  const digest = createHash("sha256")
    .update(paymentGatewayIdempotencyCompositeKey(scope))
    .digest("hex");
  return `${REDIS_KEY_PREFIX}${digest}`;
}

/**
 * Redis-backed {@link IdempotencyKeyStore} for payment gateways (multi-instance safe).
 * Uses `SET … NX` + a pending sentinel so concurrent callers wait for the winner’s result.
 */
@Injectable()
export class RedisPaymentIdempotencyKeyStore implements IdempotencyKeyStore, OnModuleDestroy {
  private readonly pendingTtlSec = 90;
  private readonly resultTtlSec = 86400 * 7;
  private readonly waitDeadlineMs = 35_000;

  constructor(
    @Inject(PAYMENTS_GATEWAY_IDEMPOTENCY_REDIS) private readonly redis: Redis
  ) {}

  async onModuleDestroy(): Promise<void> {
    await this.redis.quit();
  }

  async runOnce<T>(
    scope: PaymentIdempotencyScope,
    fn: () => Promise<T>
  ): Promise<IdempotentRunResult<T>> {
    const key = redisKey(scope);
    const deadline = Date.now() + this.waitDeadlineMs;

    while (Date.now() < deadline) {
      const raw = await this.redis.get(key);
      if (raw && raw !== PENDING_SENTINEL) {
        return { value: jsonClone(JSON.parse(raw) as T), replayed: true };
      }
      if (raw === PENDING_SENTINEL) {
        await this.sleepWhilePending(key, deadline);
        continue;
      }

      const acquired = await this.redis.set(key, PENDING_SENTINEL, "EX", this.pendingTtlSec, "NX");
      if (acquired === "OK") {
        try {
          const value = await fn();
          const frozen = jsonClone(value);
          await this.redis.set(key, JSON.stringify(frozen), "EX", this.resultTtlSec);
          return { value: jsonClone(frozen) as T, replayed: false };
        } catch (error: unknown) {
          await this.redis.del(key);
          throw error;
        }
      }

      await this.sleepWhilePending(key, deadline);
    }

    throw new InternalServerErrorException({
      error: {
        code: "PAYMENT_IDEMPOTENCY_LOCK_TIMEOUT",
        message: "Timed out waiting for payment gateway idempotency lock"
      }
    });
  }

  private async sleepWhilePending(key: string, deadline: number): Promise<void> {
    let delayMs = 12;
    while (Date.now() < deadline) {
      const raw = await this.redis.get(key);
      if (raw === null || raw !== PENDING_SENTINEL) {
        return;
      }
      await new Promise<void>((resolve) => setTimeout(resolve, delayMs));
      delayMs = Math.min(delayMs * 2, 220);
    }
  }
}

import { UnauthorizedException } from "@nestjs/common";
import type { Redis } from "ioredis";
import { PAYMENTS_WEBHOOK_REPLAY_TTL_MS } from "./webhook-signature.verify";

const KEY_PREFIX = "payments:webhook:replay:";

/**
 * Cross-instance webhook replay protection (SET NX + TTL).
 * Used by {@link PaymentWebhookSignatureGuard} when Redis is available.
 */
export class RedisWebhookReplayCache {
  constructor(private readonly redis: Redis) {}

  async assertNotReplayed(timestampNorm: string, signatureHex: string, nowMs: number): Promise<void> {
    const replayKey = `${KEY_PREFIX}${timestampNorm}:${signatureHex}`;
    const ttlSec = Math.ceil(PAYMENTS_WEBHOOK_REPLAY_TTL_MS / 1000);
    const inserted = await this.redis.set(replayKey, String(nowMs), "EX", ttlSec, "NX");
    if (inserted !== "OK") {
      throw new UnauthorizedException({
        error: {
          code: "WEBHOOK_REPLAY_DETECTED",
          message: "Replay webhook detected"
        }
      });
    }
  }
}

