import { Inject, Injectable, InternalServerErrorException } from "@nestjs/common";
import Stripe from "stripe";
import { ConfigService } from "../../../config/config.service";
import type { IPaymentGateway } from "./payment-gateway.interface";
import type { CreatePaymentIntentGatewayInput, PaymentIntentGatewayResult } from "./payment-gateway.types";
import type { IdempotencyKeyStore } from "./payment-idempotency-key.store";
import { PAYMENT_GATEWAY_IDEMPOTENCY_STORE } from "./payment-idempotency-key.store";

function mapStripePaymentIntentStatus(status: string): PaymentIntentGatewayResult["status"] {
  switch (status) {
    case "requires_payment_method":
    case "requires_confirmation":
    case "requires_action":
    case "requires_capture":
      return "requires_payment_method";
    case "processing":
      return "processing";
    case "succeeded":
      return "succeeded";
    case "canceled":
      return "canceled";
    default:
      return "requires_payment_method";
  }
}

/**
 * Live Stripe {@link IPaymentGateway} using the official Node SDK.
 * Enabled when {@link ConfigService.getStripeSecretKey} is non-empty; otherwise use the placeholder adapter.
 */
@Injectable()
export class StripePaymentGateway implements IPaymentGateway {
  readonly providerId = "stripe";

  constructor(
    @Inject(PAYMENT_GATEWAY_IDEMPOTENCY_STORE) private readonly idempotencyStore: IdempotencyKeyStore,
    private readonly config: ConfigService
  ) {}

  async createPaymentIntent(input: CreatePaymentIntentGatewayInput): Promise<PaymentIntentGatewayResult> {
    const secret = this.config.getStripeSecretKey();
    if (!secret) {
      throw new InternalServerErrorException({
        error: {
          code: "STRIPE_NOT_CONFIGURED",
          message: "Stripe secret key is not configured"
        }
      });
    }

    const { value } = await this.idempotencyStore.runOnce(
      {
        tenantId: input.tenantId,
        operation: `${this.providerId}:create_payment_intent`,
        idempotencyKey: input.idempotencyKey
      },
      async () => {
        const stripe = new Stripe(secret);
        const metadata: Record<string, string> = {
          tenantId: input.tenantId,
          registrationId: input.registrationId,
          ...(input.metadata ?? {})
        };
        const pi = await stripe.paymentIntents.create(
          {
            amount: input.amount,
            currency: input.currency.trim().toLowerCase(),
            metadata,
            automatic_payment_methods: { enabled: true }
          },
          // PSP-native idempotency (Stripe); Postgres/Redis store above dedupes before this network call.
          { idempotencyKey: input.idempotencyKey.slice(0, 255) }
        );
        return {
          provider: this.providerId,
          providerPaymentId: pi.id,
          clientSecret: pi.client_secret ?? undefined,
          status: mapStripePaymentIntentStatus(pi.status)
        } satisfies PaymentIntentGatewayResult;
      }
    );
    return value;
  }
}

import { createHmac, timingSafeEqual } from "node:crypto";
import { ForbiddenException, UnauthorizedException } from "@nestjs/common";
import type { Request } from "express";
import { resolveThrottleClientIp } from "../../../common/throttling/public-registration-throttle";

export const PAYMENTS_WEBHOOK_TIMESTAMP_HEADER = "x-payments-webhook-timestamp";
export const PAYMENTS_WEBHOOK_SIGNATURE_HEADER = "x-payments-webhook-signature";
export const PAYMENTS_WEBHOOK_MAX_SKEW_SEC = 300;
export const PAYMENTS_WEBHOOK_REPLAY_TTL_MS = (PAYMENTS_WEBHOOK_MAX_SKEW_SEC + 60) * 1000;

export type RequestWithRawBody = Request & { rawBody?: Buffer };

export type PaymentWebhookVerifySecrets = {
  primarySecret: string;
  previousSecret: string;
};

export type PaymentWebhookVerifyOptions = {
  allowedIps: string[];
  trustedProxyCidrs: string[];
  secrets: PaymentWebhookVerifySecrets;
  nowMs: number;
  nowSec: number;
};

/** HMAC verification only (timestamp freshness must be checked separately). */
export function assertPaymentWebhookHmacValid(
  rawBody: Buffer,
  timestampHeader: string,
  signatureHeader: string,
  secrets: PaymentWebhookVerifySecrets
): void {
  const tsNorm = timestampHeader.trim();

  const signedMaterial = Buffer.concat([Buffer.from(`${tsNorm}.`, "utf8"), rawBody]);
  const expectedHex = (secret: string) =>
    createHmac("sha256", secret).update(signedMaterial).digest("hex");
  const expectedPrimary = expectedHex(secrets.primarySecret);
  const candidates =
    secrets.previousSecret.length >= 16
      ? [expectedPrimary, expectedHex(secrets.previousSecret)]
      : [expectedPrimary];

  const provided = signatureHeader.trim().toLowerCase().replace(/^v1=/, "");
  const hexBuf = (hex: string): Buffer | null => {
    if (!/^[0-9a-f]{64}$/i.test(hex)) {
      return null;
    }
    return Buffer.from(hex, "hex");
  };
  const providedBuf = hexBuf(provided);
  if (!providedBuf) {
    throw new UnauthorizedException({
      error: {
        code: "WEBHOOK_SIGNATURE_INVALID",
        message: "Invalid webhook signature format"
      }
    });
  }
  const ok = candidates.some((hex) => {
    const h = hexBuf(hex);
    return h !== null && h.length === providedBuf.length && timingSafeEqual(h, providedBuf);
  });

  if (!ok) {
    throw new UnauthorizedException({
      error: {
        code: "WEBHOOK_SIGNATURE_INVALID",
        message: "Invalid webhook signature"
      }
    });
  }
}

export function assertPaymentWebhookTimestampFresh(
  timestampHeader: string,
  nowSec: number,
  maxSkewSec: number
): void {
  const tsNorm = timestampHeader.trim();
  const ts = Number(tsNorm);
  if (!Number.isFinite(ts) || ts <= 0) {
    throw new UnauthorizedException({
      error: {
        code: "WEBHOOK_TIMESTAMP_INVALID",
        message: "Invalid webhook timestamp"
      }
    });
  }
  if (Math.abs(nowSec - ts) > maxSkewSec) {
    throw new UnauthorizedException({
      error: {
        code: "WEBHOOK_TIMESTAMP_EXPIRED",
        message: "Webhook timestamp outside allowed window"
      }
    });
  }
}

export function assertPaymentWebhookIpAllowed(
  req: Request,
  allowedIps: string[],
  trustedProxyCidrs: string[]
): void {
  if (allowedIps.length === 0) {
    return;
  }
  const ip = resolveThrottleClientIp(req as unknown as Record<string, unknown>, {
    trustedProxyCidrs
  });
  if (!allowedIps.includes(ip)) {
    throw new ForbiddenException({
      error: {
        code: "WEBHOOK_IP_NOT_ALLOWED",
        message: "Caller IP is not allowlisted for payment webhooks"
      }
    });
  }
}

export function assertPaymentWebhookRawBodyPresent(raw: Buffer | undefined): asserts raw is Buffer {
  if (!raw || !Buffer.isBuffer(raw)) {
    throw new UnauthorizedException({
      error: {
        code: "WEBHOOK_SIGNATURE_INVALID",
        message: "Signed webhook body required"
      }
    });
  }
}

export type WebhookReplayCache = {
  get(key: string): number | undefined;
  set(key: string, seenAtMs: number): void;
  deleteExpired(nowMs: number, ttlMs: number): void;
};

export function assertPaymentWebhookNotReplayed(
  replayCache: WebhookReplayCache,
  timestampNorm: string,
  signatureHex: string,
  nowMs: number,
  ttlMs: number
): void {
  replayCache.deleteExpired(nowMs, ttlMs);
  const replayKey = `${timestampNorm}:${signatureHex}`;
  const seenAt = replayCache.get(replayKey);
  if (typeof seenAt === "number" && nowMs - seenAt <= ttlMs) {
    throw new UnauthorizedException({
      error: {
        code: "WEBHOOK_REPLAY_DETECTED",
        message: "Replay webhook detected"
      }
    });
  }
  replayCache.set(replayKey, nowMs);
}

/**
 * Full verification pipeline used by {@link PaymentWebhookSignatureGuard}.
 */
export function verifyPaymentWebhookRequest(
  req: RequestWithRawBody,
  opts: PaymentWebhookVerifyOptions,
  replayCache: WebhookReplayCache
): void {
  assertPaymentWebhookIpAllowed(req, opts.allowedIps, opts.trustedProxyCidrs);
  assertPaymentWebhookRawBodyPresent(req.rawBody);

  const tsHeader =
    req.header(PAYMENTS_WEBHOOK_TIMESTAMP_HEADER) ??
    req.header(PAYMENTS_WEBHOOK_TIMESTAMP_HEADER.toUpperCase());
  const sigHeader =
    req.header(PAYMENTS_WEBHOOK_SIGNATURE_HEADER) ??
    req.header(PAYMENTS_WEBHOOK_SIGNATURE_HEADER.toUpperCase());
  if (!tsHeader?.trim() || !sigHeader?.trim()) {
    throw new UnauthorizedException({
      error: {
        code: "WEBHOOK_SIGNATURE_INVALID",
        message: "Missing webhook timestamp or signature headers"
      }
    });
  }

  assertPaymentWebhookTimestampFresh(tsHeader, opts.nowSec, PAYMENTS_WEBHOOK_MAX_SKEW_SEC);
  assertPaymentWebhookHmacValid(req.rawBody, tsHeader, sigHeader, opts.secrets);

  const provided = sigHeader.trim().toLowerCase().replace(/^v1=/, "");
  assertPaymentWebhookNotReplayed(
    replayCache,
    tsHeader.trim(),
    provided,
    opts.nowMs,
    PAYMENTS_WEBHOOK_REPLAY_TTL_MS
  );
}

/** HMAC + IP checks without replay dedupe (caller handles replay via Redis or memory). */
export function verifyPaymentWebhookRequestWithoutReplay(
  req: RequestWithRawBody,
  opts: PaymentWebhookVerifyOptions
): { timestampNorm: string; signatureHex: string } {
  assertPaymentWebhookIpAllowed(req, opts.allowedIps, opts.trustedProxyCidrs);
  assertPaymentWebhookRawBodyPresent(req.rawBody);

  const tsHeader =
    req.header(PAYMENTS_WEBHOOK_TIMESTAMP_HEADER) ??
    req.header(PAYMENTS_WEBHOOK_TIMESTAMP_HEADER.toUpperCase());
  const sigHeader =
    req.header(PAYMENTS_WEBHOOK_SIGNATURE_HEADER) ??
    req.header(PAYMENTS_WEBHOOK_SIGNATURE_HEADER.toUpperCase());
  if (!tsHeader?.trim() || !sigHeader?.trim()) {
    throw new UnauthorizedException({
      error: {
        code: "WEBHOOK_SIGNATURE_INVALID",
        message: "Missing webhook timestamp or signature headers"
      }
    });
  }

  assertPaymentWebhookTimestampFresh(tsHeader, opts.nowSec, PAYMENTS_WEBHOOK_MAX_SKEW_SEC);
  assertPaymentWebhookHmacValid(req.rawBody, tsHeader, sigHeader, opts.secrets);

  const provided = sigHeader.trim().toLowerCase().replace(/^v1=/, "");
  return { timestampNorm: tsHeader.trim(), signatureHex: provided };
}

import {
  BadRequestException,
  Inject,
  Injectable,
  InternalServerErrorException
} from "@nestjs/common";
import { ConfigService } from "../../../config/config.service";
import type { IPaymentGateway } from "./payment-gateway.interface";
import type { CreatePaymentIntentGatewayInput, PaymentIntentGatewayResult } from "./payment-gateway.types";
import type { IdempotencyKeyStore } from "./payment-idempotency-key.store";
import { PAYMENT_GATEWAY_IDEMPOTENCY_STORE } from "./payment-idempotency-key.store";

type ZibalRequestResponse = {
  message: string;
  result: number;
  trackId?: number;
};

const ZIBAL_REQUEST_URL = "https://gateway.zibal.ir/v1/request";

/**
 * Zibal (Iran) payment request → returns a hosted checkout URL.
 * Amount must be in **IRR** (Rials) as an integer, per Zibal API.
 */
@Injectable()
export class ZibalPaymentGateway implements IPaymentGateway {
  readonly providerId = "zibal";

  constructor(
    @Inject(PAYMENT_GATEWAY_IDEMPOTENCY_STORE) private readonly idempotencyStore: IdempotencyKeyStore,
    private readonly config: ConfigService
  ) {}

  async createPaymentIntent(input: CreatePaymentIntentGatewayInput): Promise<PaymentIntentGatewayResult> {
    const merchant = this.config.getZibalMerchant();
    const callbackUrl = this.config.getZibalCallbackUrl();
    if (!merchant) {
      throw new InternalServerErrorException({
        error: {
          code: "ZIBAL_NOT_CONFIGURED",
          message: "Zibal merchant id is not configured"
        }
      });
    }
    if (!callbackUrl) {
      throw new InternalServerErrorException({
        error: {
          code: "ZIBAL_CALLBACK_NOT_CONFIGURED",
          message: "ZIBAL_CALLBACK_URL is not configured"
        }
      });
    }
    if (input.currency.trim().toUpperCase() !== "IRR") {
      throw new BadRequestException({
        error: {
          code: "PAYMENT_GATEWAY_CURRENCY_UNSUPPORTED",
          message: "Zibal only supports IRR"
        }
      });
    }

    const { value } = await this.idempotencyStore.runOnce(
      {
        tenantId: input.tenantId,
        operation: `${this.providerId}:create_payment_intent`,
        idempotencyKey: input.idempotencyKey
      },
      async () => {
        const amount = Math.round(Number(input.amount));
        if (!Number.isFinite(amount) || amount < 1) {
          throw new BadRequestException({
            error: {
              code: "VALIDATION_FIELD_FORMAT_INVALID",
              message: "Amount must be a positive integer for Zibal"
            }
          });
        }
        const res = await fetch(ZIBAL_REQUEST_URL, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            merchant,
            amount,
            callbackUrl,
            description: `Booking ${input.registrationId}`,
            orderId: input.registrationId.replace(/-/g, "").slice(0, 32),
            mobile: undefined
          })
        });
        if (!res.ok) {
          throw new InternalServerErrorException({
            error: {
              code: "ZIBAL_HTTP_ERROR",
              message: `Zibal request failed with HTTP ${res.status}`
            }
          });
        }
        const body = (await res.json()) as ZibalRequestResponse;
        if (body.result !== 100 || body.trackId === undefined) {
          throw new InternalServerErrorException({
            error: {
              code: "ZIBAL_REQUEST_REJECTED",
              message: body.message || `Zibal result code ${body.result}`
            }
          });
        }
        const trackId = String(body.trackId);
        const checkoutUrl = `https://gateway.zibal.ir/start/${trackId}`;
        return {
          provider: this.providerId,
          providerPaymentId: trackId,
          checkoutUrl,
          status: "requires_payment_method" as const
        } satisfies PaymentIntentGatewayResult;
      }
    );
    return value;
  }
}

import { Inject, Injectable, NotFoundException } from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import { Repository } from "typeorm";
import { TenantDbContextService } from "../../database/tenant-db-context.service";
import { PaymentEntity, PaymentMethod, PaymentStatus } from "./entities/payment.entity";
import { RegistrationEntity } from "../registrations/registration.entity";
import { FinanceReportsService } from "../finance/reports/finance-reports.service";
import { assertManualPaymentDebtAllowed } from "./domain/manual-payment-debt.policy";
import { enforcePaymentIntentFinanceContract } from "./enforce-payment-intent-finance-contract";

@Injectable()
export class ManualPaymentService {
  constructor(
    @Inject(TenantDbContextService) private readonly tenantDbContext: TenantDbContextService,
    @InjectRepository(PaymentEntity)
    private readonly paymentRepository: Repository<PaymentEntity>,
    @Inject(FinanceReportsService) private readonly financeReportsService: FinanceReportsService
  ) {}

  async createManualPayment(params: {
    tenantId: string;
    registrationId: string;
    amount: string;
    currency: string;
  }): Promise<PaymentEntity> {
    return this.tenantDbContext.runInTenantScope(params.tenantId, async (manager) => {
      const registration = await manager.findOne(RegistrationEntity, {
        where: { id: params.registrationId, tenantId: params.tenantId }
      });

      if (!registration) {
        throw new NotFoundException("Registration not found");
      }

      const existingPayments = await manager.find(PaymentEntity, {
        where: {
          registrationId: registration.id,
          tenantId: params.tenantId
        },
        select: { status: true }
      });
      assertManualPaymentDebtAllowed(existingPayments.map((p) => p.status));

      enforcePaymentIntentFinanceContract(
        {
          tenantId: params.tenantId,
          registrationId: registration.id,
          amount: params.amount,
          currency: params.currency,
          method: PaymentMethod.MANUAL,
          provider: "manual",
          providerPaymentId: null,
          status: PaymentStatus.PENDING,
          paidAt: null,
          failedAt: null,
          refundedAt: null,
          ledgerJournalId: null,
        },
        "createManualPayment",
      );

      const payment = manager.create(PaymentEntity, {
        tenantId: params.tenantId,
        registrationId: registration.id,
        amount: params.amount,
        currency: params.currency,
        method: PaymentMethod.MANUAL,
        status: PaymentStatus.PENDING,
        provider: "manual"
      });

      const saved = await manager.save(PaymentEntity, payment);
      await this.financeReportsService.invalidateSummaryCache(params.tenantId);
      return saved;
    });
  }

  async listManualPayments(tenantId: string): Promise<PaymentEntity[]> {
    return this.paymentRepository.find({
      where: { tenantId, method: PaymentMethod.MANUAL },
      order: { createdAt: "DESC" },
      take: 100
    });
  }
}

import { CanActivate, ExecutionContext, Inject, Injectable, Optional } from "@nestjs/common";
import { ConfigService } from "../../config/config.service";
import { REDIS_CLIENT } from "../../infra/redis/redis.constants";
import type { Redis } from "ioredis";
import { InMemoryWebhookReplayCache } from "./gateway/in-memory-webhook-replay.cache";
import { RedisWebhookReplayCache } from "./gateway/redis-webhook-replay.cache";
import {
  verifyPaymentWebhookRequest,
  verifyPaymentWebhookRequestWithoutReplay,
  type RequestWithRawBody
} from "./gateway/webhook-signature.verify";

@Injectable()
export class PaymentWebhookSignatureGuard implements CanActivate {
  private readonly memoryReplay = new InMemoryWebhookReplayCache();
  private readonly redisReplay: RedisWebhookReplayCache | null;

  constructor(
    @Inject(ConfigService) private readonly configService: ConfigService,
    @Optional() @Inject(REDIS_CLIENT) redis: Redis | null
  ) {
    this.redisReplay = redis ? new RedisWebhookReplayCache(redis) : null;
  }

  async canActivate(context: ExecutionContext): Promise<boolean> {
    const req = context.switchToHttp().getRequest<RequestWithRawBody>();
    const nowMs = Date.now();
    const opts = {
      allowedIps: this.configService.getPaymentsWebhookAllowedIps(),
      trustedProxyCidrs: this.configService.getTrustedProxyCidrs(),
      secrets: {
        primarySecret: this.configService.getPaymentsWebhookSigningSecret(),
        previousSecret: this.configService.getPaymentsWebhookSigningSecretPrevious()
      },
      nowMs,
      nowSec: Math.floor(nowMs / 1000)
    };

    const useRedisReplay =
      this.redisReplay !== null && this.configService.getNodeEnv() !== "test";

    if (useRedisReplay) {
      const { timestampNorm, signatureHex } = verifyPaymentWebhookRequestWithoutReplay(req, opts);
      await this.redisReplay!.assertNotReplayed(timestampNorm, signatureHex, nowMs);
      return true;
    }

    verifyPaymentWebhookRequest(req, opts, this.memoryReplay);
    return true;
  }
}

