@ApiTags("Payments")
@Controller("api/v2")
@RequireCapability("module.finance")
export class PaymentsController {
  constructor(
    @Inject(PaymentsService) private readonly paymentsService: PaymentsService,
    @Inject(RequestContextService) private readonly requestContextService: RequestContextService
  ) {}

  @Post("payments/intent")
  @UseGuards(AuthorizationPresenceGuard, RolesGuard, AbilitiesGuard, CaslMirrorAbilitiesGuard)
  /** Members (participants) create intents for registrations in their tenant; leaders/admins retain access. */
  @Roles(UserRole.Owner, UserRole.Admin, UserRole.Member, UserRole.Leader)
  @CheckAbilities(({ ability }) => ability.can(AbilityAction.Create, "Payment"))
  @ApiBearerAuth()
  @ApiHeader({
    name: "Idempotency-Key",
    required: true,
    description: "Required idempotency key for create mutation."
  })
  @ApiOperation({ summary: "Create payment intent for registration" })
  @ApiBody({ type: CreatePaymentIntentDto })
  @ApiCreatedResponse({ type: PaymentResponseDto })
  @UseInterceptors(IdempotencyInterceptor)
  @Idempotent({
    endpoint: "/api/v2/payments/intent",
    statusCode: 201,
    required: true,
    tenantSource: "context"
  })
  async createPaymentIntent(
    @Body() payload: CreatePaymentIntentDto
  ): Promise<PaymentResponseDto> {
    return this.paymentsService.createPaymentIntent(payload);
  }

  @Get("admin/payments")
  @UseGuards(AuthorizationPresenceGuard, RolesGuard, AbilitiesGuard, CaslMirrorAbilitiesGuard)
  @Roles(UserRole.Admin)
  @CheckAbilities(({ ability }) => ability.can(AbilityAction.Read, "Payment"))
  @ApiBearerAuth()
  @ApiOperation({ summary: "Admin list of recent payments" })
  @ApiOkResponse({ type: PaymentResponseDto, isArray: true })
  async listPayments(): Promise<PaymentResponseDto[]> {
    const tenantContext = this.requestContextService.assertTenantContext();
    return this.paymentsService.listPayments(tenantContext.tenantId);
  }

  @Get("admin/payments/:id")
  @UseGuards(AuthorizationPresenceGuard, RolesGuard, AbilitiesGuard, CaslMirrorAbilitiesGuard)
  @Roles(UserRole.Admin)
  @CheckAbilities(({ ability }) => ability.can(AbilityAction.Read, "Payment"))
  @ApiBearerAuth()
  @ApiOperation({ summary: "Admin get payment by id" })
  @ApiOkResponse({ type: PaymentResponseDto })
  async getPayment(
    @Param("id", new ParseUUIDPipe()) id: string
  ): Promise<PaymentResponseDto> {
    return this.paymentsService.getPaymentById(id);
  }

  @Post("admin/payments/:id/refund")
  @UseGuards(AuthorizationPresenceGuard, RolesGuard, AbilitiesGuard, CaslMirrorAbilitiesGuard)
  @Roles(UserRole.Admin)
  @CheckAbilities(({ ability }) => ability.can(AbilityAction.Update, "Payment"))
  @ApiBearerAuth()
  @ApiHeader({
    name: "Idempotency-Key",
    required: true,
    description: "Required idempotency key for refund mutation."
  })
  @ApiOperation({ summary: "Admin refund payment and reconcile registration" })
  @ApiOkResponse({ type: PaymentResponseDto })
  @UseInterceptors(IdempotencyInterceptor)
  @Idempotent({
    endpoint: "/api/v2/admin/payments/:id/refund",
    statusCode: 200,
    required: true,
    tenantSource: "context"
  })
  async refundPayment(
    @Param("id", new ParseUUIDPipe()) id: string,
    @Body() body: RefundPaymentDto,
    @Headers("idempotency-key") idempotencyKey: string
  ): Promise<PaymentResponseDto> {
    return this.paymentsService.refundPayment(id, body.reason, idempotencyKey);
  }
}

@ApiTags("Payments")
/** Webhook uses only `payments-webhook` bucket; do not consume `public-registration` (shared IP limit). */
@SkipThrottle({ "public-registration": true })
@Controller("internal/payments")
@UseGuards(ThrottlerGuard, PaymentWebhookSignatureGuard)
export class PaymentsWebhookController {
  constructor(
    @Inject(PaymentsService) private readonly paymentsService: PaymentsService,
    @Inject(LoggerService) private readonly loggerService: LoggerService,
    @Inject(RequestContextService) private readonly requestContextService: RequestContextService
  ) {}

  @Post("webhook")
  @HttpCode(200)
  @Throttle({
    "payments-webhook": { limit: 500, ttl: 60_000, blockDuration: 1 }
  })
  @ApiHeader({
    name: "X-Payments-Webhook-Timestamp",
    required: true,
    description: "Unix timestamp (seconds) used in HMAC; must be within ±5 minutes."
  })
  @ApiHeader({
    name: "X-Payments-Webhook-Signature",
    required: true,
    description: "Lowercase hex HMAC-SHA256 of `${timestamp}.${rawBody}` using PAYMENTS_WEBHOOK_SIGNING_SECRET."
  })
  @ApiOperation({
    summary:
      "Internal payment provider webhook (200 on processed/unknown payment; non-200 on binding or processing failure)"
  })
  @ApiBody({ type: PaymentWebhookDto })
  @ApiOkResponse({
    schema: {
      example: { ok: true }
    },
    description: "Returns 200 for processed/deduplicated/unknown payment events."
  })
  @ApiBadRequestResponse({
    description: "Tenant binding failed for webhook payload/payment scope."
  })
  @ApiInternalServerErrorResponse({
    description: "Webhook processing failed."
  })
  async webhook(@Body() payload: PaymentWebhookDto): Promise<{ ok: true }> {
    const requestId = this.safeRequestId();
    this.loggerService.info("webhook_received", {
      request_id: requestId,
      event_type: "payment.webhook",
      provider: "internal_provider",
      provider_event_id: payload.providerEventId ?? null,
      provider_payment_id: payload.providerPaymentId,
      tenant_id: payload.tenant_id,
      status: payload.status
    });
    try {
      const result = await this.paymentsService.processWebhook(payload);
      if (!result.processed) {
        this.loggerService.warn("webhook_unknown_payment", {
          request_id: result.requestId,
          event_type: "payment.webhook",
          provider: "internal_provider",
          provider_event_id: result.providerEventId,
          provider_payment_id: payload.providerPaymentId,
          tenant_id: payload.tenant_id,
          status: payload.status,
          error_message: "PAYMENT_NOT_FOUND"
        });
      } else if (result.deduplicated) {
        this.loggerService.info("webhook_deduplicated", {
          request_id: result.requestId,
          event_type: "payment.webhook",
          provider: result.provider ?? "internal_provider",
          provider_event_id: result.providerEventId,
          provider_payment_id: result.providerPaymentId,
          tenant_id: result.tenantId,
          status: result.status
        });
      } else {
        this.loggerService.info("webhook_processed", {
          request_id: result.requestId,
          event_type: "payment.webhook",
          provider: result.provider ?? "internal_provider",
          provider_event_id: result.providerEventId,
          provider_payment_id: result.providerPaymentId,
          tenant_id: result.tenantId,
          status: result.status
        });
      }
    } catch (error: unknown) {
      const asBadRequest = error instanceof BadRequestException ? error : null;
      const err = error instanceof Error ? error : new Error(String(error));
      if (asBadRequest) {
        this.loggerService.warn("webhook_binding_failed", {
          request_id: requestId,
          event_type: "payment.webhook",
          provider: "internal_provider",
          provider_event_id: payload.providerEventId ?? null,
          provider_payment_id: payload.providerPaymentId,
          tenant_id: payload.tenant_id,
          status: payload.status,
          error_message: err.message
        });
      } else {
        this.loggerService.error("webhook_failed", {
          request_id: requestId,
          event_type: "payment.webhook",
          provider: "internal_provider",
          provider_event_id: payload.providerEventId ?? null,
          provider_payment_id: payload.providerPaymentId,
          tenant_id: payload.tenant_id,
          status: payload.status,
          error_message: err.message,
          stack: err.stack ?? null
        });
      }
      throw error;
    }
    return { ok: true };
  }

  private safeRequestId(): string {
    try {
      return this.requestContextService.getRequestId();
    } catch {
      return "unknown";
    }
  }
}

import {
  Inject,
  Injectable,
  Logger,
  OnModuleDestroy,
  OnModuleInit
} from "@nestjs/common";
import { ConfigService } from "../../config/config.service";
import { SchedulerLockService } from "../../jobs/scheduler-lock.service";
import { SchedulerRuntimeMetricsService } from "../../jobs/scheduler-runtime-metrics.service";
import { PaymentsService } from "./payments.service";

@Injectable()
export class PaymentsProcessor implements OnModuleInit, OnModuleDestroy {
  private readonly logger = new Logger(PaymentsProcessor.name);
  private interval?: NodeJS.Timeout;
  private readonly jobName = "payments_timeout";
  private readonly lockName = "scheduler:payments_timeout";

  constructor(
    @Inject(ConfigService) private readonly configService: ConfigService,
    @Inject(PaymentsService) private readonly paymentsService: PaymentsService,
    @Inject(SchedulerLockService) private readonly schedulerLock: SchedulerLockService,
    @Inject(SchedulerRuntimeMetricsService)
    private readonly schedulerMetrics: SchedulerRuntimeMetricsService
  ) {}

  onModuleInit(): void {
    if (!this.configService.shouldRunSchedulers()) {
      this.logger.log("job_skipped_runtime_role payments_timeout");
      return;
    }
    if (!this.configService.getPaymentsTimeoutEnabled()) {
      this.logger.log("job_disabled payments_timeout");
      return;
    }
    const ms = this.configService.getPaymentsTimeoutIntervalMs();
    const jitterMs = Math.floor(Math.random() * (this.configService.getSchedulerJitterMs() + 1));
    setTimeout(() => {
      void this.runOnceWithLock();
      this.interval = setInterval(() => {
        void this.runOnceWithLock();
      }, ms);
      this.interval.unref?.();
    }, jitterMs).unref?.();
  }

  onModuleDestroy(): void {
    if (this.interval) {
      clearInterval(this.interval);
    }
  }

  private async runOnceWithLock(): Promise<void> {
    const started = Date.now();
    this.schedulerMetrics.noteStarted(this.jobName);
    this.logger.log("job_started payments_timeout");
    try {
      const lock = await this.schedulerLock.runWithGlobalLock(this.lockName, async () => {
        await this.paymentsService.failTimedOutPendingPayments();
      });
      if (!lock.acquired) {
        this.schedulerMetrics.noteSkippedDueLock(this.jobName);
        this.logger.log("job_skipped_due_lock payments_timeout");
        return;
      }
      this.schedulerMetrics.noteFinished(this.jobName, Date.now() - started);
      this.logger.log("job_finished payments_timeout");
    } catch (error: unknown) {
      this.schedulerMetrics.noteFailed(this.jobName);
      this.logger.warn(`payments timeout run failed: ${String(error)}`);
    }
  }
}

