export type PaymentFinanceReconciliationSnapshot = {
  lastRunAt: string | null;
  lastCriticalFindings: number;
};

function safeErrorMessage(error: unknown, max = 4000): string {
  const raw = error instanceof Error ? error.message : String(error);
  return raw.length > max ? `${raw.slice(0, max)}…` : raw;
}

function errorCode(error: unknown): string {
  if (error && typeof error === "object" && "name" in error && typeof (error as Error).name === "string") {
    return (error as Error).name;
  }
  return "UNKNOWN";
}

/**
 * Periodic job: compares **PSP capture path** (`payment.succeeded` outbox + `payments`),
 * **ledger** (`finance.ledger.double_entry_applied` outbox lines), and **booking price snapshots**
 * via {@link generatePaymentReconciliationReport}.
 *
 * Each tenant run is persisted in `reconciliation_jobs` with tenant-scoped updates and alerting hooks.
 */
@Injectable()
export class PaymentFinanceReconciliationService {
  private readonly logger = new Logger(PaymentFinanceReconciliationService.name);
  private lastRunAt: string | null = null;
  private lastCriticalFindings = 0;

  constructor(
    @InjectRepository(TenantEntity)
    private readonly tenantRepository: Repository<TenantEntity>,
    @Inject(TenantDbContextService) private readonly tenantDbContext: TenantDbContextService,
    @Inject(TenantUsageMeteringService)
    private readonly tenantUsageMeteringService: TenantUsageMeteringService,
    @Inject(TenantRateLimitService) private readonly tenantRateLimitService: TenantRateLimitService,
    @Inject(ConfigService) private readonly configService: ConfigService,
    @Inject(ReconciliationFindingsService)
    private readonly reconciliationFindings: ReconciliationFindingsService,
    @Inject(RECONCILIATION_JOB_ALERT_HOOKS)
    private readonly alertHooks: ReconciliationJobAlertHooks
  ) {}

  getSnapshot(): PaymentFinanceReconciliationSnapshot {
    return {
      lastRunAt: this.lastRunAt,
      lastCriticalFindings: this.lastCriticalFindings
    };
  }

  async runPaymentFinanceReconciliationCycle(options?: { cycleBatchId?: string }): Promise<void> {
    const lookbackDays = this.configService.getPaymentFinanceReconciliationLookbackDays();
    const tenants = await this.tenantRepository.find({
      select: { id: true },
      where: { deletedAt: IsNull() }
    });

    let maxCritical = 0;
    const cycleBatchId = (options?.cycleBatchId?.trim() || randomUUID()).trim();

    for (const { id: tenantId } of tenants) {
      const runtimeAllowed = await enforceBackgroundTenantRuntimePolicies(tenantId, {
        tryConsumeBackgroundJob: async (currentTenantId) =>
          this.tenantUsageMeteringService.tryConsumeBackgroundJob(currentTenantId),
        tryConsumeTenantJobRateLimit: async (currentTenantId) =>
          this.tenantRateLimitService.tryConsumeJobForTenant(currentTenantId)
      });
      if (!runtimeAllowed) {
        continue;
      }

      const envelopeTenant = tenantId.trim().toLowerCase();

      let jobId: string;
      try {
        jobId = await this.tenantDbContext.runInTenantScope(envelopeTenant, async (manager) => {
          const row = manager.create(ReconciliationJobEntity, {
            tenantId: envelopeTenant,
            jobKind: ReconciliationJobKind.PAYMENT_FINANCE,
            status: ReconciliationStatus.IN_PROGRESS,
            startedAt: new Date(),
            metadata: {
              lookbackDays,
              cycleBatchId
            },
            mismatchCount: 0,
            criticalCount: 0
          });
          const saved = await manager.save(ReconciliationJobEntity, row);
          return saved.id;
        });
      } catch (error: unknown) {
        this.logger.warn(
          `payment_finance_reconciliation job_create_failed tenant=${envelopeTenant} err=${String(error)}`
        );
        continue;
      }

      const startedAt = new Date().toISOString();
      await Promise.resolve(
        this.alertHooks.onJobStarted({
          tenant_id: envelopeTenant,
          job_id: jobId,
          job_kind: ReconciliationJobKind.PAYMENT_FINANCE,
          cycle_batch_id: cycleBatchId,
          at: startedAt
        })
      );

      try {
        const finish = await this.tenantDbContext.runInTenantScope(envelopeTenant, async (manager) => {
          const input = await loadPaymentReconciliationReportInputForTenant(manager, envelopeTenant, {
            lookbackDays
          });
          const report = generatePaymentReconciliationReport({
            ...input,
            reportId: jobId
          });
          maxCritical = Math.max(maxCritical, report.summary.criticalCount);

          await this.reconciliationFindings.persistForJob(manager, envelopeTenant, jobId, report.findings);

          for (const f of report.findings) {
            if (f.triadMismatch) {
              logPaymentReconciliationMismatch(this.logger, f.triadMismatch, jobId);
            }
          }

          if (report.summary.findingCount === 0) {
            this.logger.debug(
              `payment_finance_reconciliation ok tenant=${envelopeTenant} bookings=${report.summary.bookingIdsExamined} job=${jobId}`
            );
          } else {
            const payload = formatPaymentReconciliationReportJsonLines(report);
            if (report.summary.criticalCount > 0) {
              this.logger.warn(payload);
            } else {
              this.logger.log(payload);
            }
          }

          const terminalStatus =
            report.summary.findingCount > 0
              ? ReconciliationStatus.COMPLETED_WITH_MISMATCHES
              : ReconciliationStatus.COMPLETED;

          const completedAt = new Date();
          const mergedMetadata: Record<string, unknown> = {
            lookbackDays,
            cycleBatchId,
            reportId: report.id,
            bookingIdsExamined: report.summary.bookingIdsExamined,
            findingCount: report.summary.findingCount,
            byKind: report.summary.byKind,
            triadMismatchLogLines: report.findings.filter((f) => f.triadMismatch).length
          };

          const update = await manager.update(
            ReconciliationJobEntity,
            { id: jobId, tenantId: envelopeTenant },
            {
              status: terminalStatus,
              completedAt,
              mismatchCount: report.summary.findingCount,
              criticalCount: report.summary.criticalCount,
              metadata: mergedMetadata
            } as QueryDeepPartialEntity<ReconciliationJobEntity>
          );
          try {
            assertReconciliationJobTenantUpdate(update, "finalize_payment_finance_job", envelopeTenant, jobId);
          } catch (scopeError: unknown) {
            await Promise.resolve(
              this.alertHooks.onScopeOrConcurrencyFailure({
                tenant_id: envelopeTenant,
                job_id: jobId,
                job_kind: ReconciliationJobKind.PAYMENT_FINANCE,
                cycle_batch_id: cycleBatchId,
                at: new Date().toISOString(),
                context: "finalize_payment_finance_job"
              })
            );
            throw scopeError;
          }

          return {
            terminalStatus,
            findingCount: report.summary.findingCount,
            criticalCount: report.summary.criticalCount,
            bookingIdsExamined: report.summary.bookingIdsExamined
          };
        });

        await Promise.resolve(
          this.alertHooks.onJobFinished({
            tenant_id: envelopeTenant,
            job_id: jobId,
            job_kind: ReconciliationJobKind.PAYMENT_FINANCE,
            cycle_batch_id: cycleBatchId,
            at: new Date().toISOString(),
            status: finish.terminalStatus,
            mismatch_count: finish.findingCount,
            critical_count: finish.criticalCount,
            finding_count: finish.findingCount,
            booking_ids_examined: finish.bookingIdsExamined
          })
        );
      } catch (error: unknown) {
        await this.finalizeFailedJob(envelopeTenant, jobId, cycleBatchId, error);
        this.logger.warn(
          `payment_finance_reconciliation tenant_failed tenant=${envelopeTenant} job=${jobId} err=${String(error)}`
        );
      }
    }

    this.lastRunAt = new Date().toISOString();
    this.lastCriticalFindings = maxCritical;
  }

  private async finalizeFailedJob(
    envelopeTenant: string,
    jobId: string,
    cycleBatchId: string,
    error: unknown
  ): Promise<void> {
    try {
      await this.tenantDbContext.runInTenantScope(envelopeTenant, async (manager) => {
        const update = await manager.update(
          ReconciliationJobEntity,
          { id: jobId, tenantId: envelopeTenant },
          {
            status: ReconciliationStatus.FAILED,
            completedAt: new Date(),
            errorMessage: safeErrorMessage(error),
            metadata: {
              cycleBatchId,
              failedAt: new Date().toISOString(),
              errorCode: errorCode(error)
            }
          } as QueryDeepPartialEntity<ReconciliationJobEntity>
        );
        if (update.affected !== 1) {
          await Promise.resolve(
            this.alertHooks.onScopeOrConcurrencyFailure({
              tenant_id: envelopeTenant,
              job_id: jobId,
              job_kind: ReconciliationJobKind.PAYMENT_FINANCE,
              cycle_batch_id: cycleBatchId,
              at: new Date().toISOString(),
              context: "mark_payment_finance_job_failed"
            })
          );
        }
      });
    } catch (persistError: unknown) {
      this.logger.warn(
        `payment_finance_reconciliation failed_job_persist_error tenant=${envelopeTenant} job=${jobId} err=${String(persistError)}`
      );
    }

    await Promise.resolve(
      this.alertHooks.onJobFailed({
        tenant_id: envelopeTenant,
        job_id: jobId,
        job_kind: ReconciliationJobKind.PAYMENT_FINANCE,
        cycle_batch_id: cycleBatchId,
        at: new Date().toISOString(),
        error_code: errorCode(error),
        error_message: safeErrorMessage(error, 2000)
      })
    );
  }
}

import {
  Body,
  Controller,
  ForbiddenException,
  Get,
  Param,
  ParseUUIDPipe,
  Post,
  Query,
  UnauthorizedException,
  UseGuards
} from "@nestjs/common";
import {
  ApiBearerAuth,
  ApiForbiddenResponse,
  ApiOperation,
  ApiTags,
  ApiUnauthorizedResponse
} from "@nestjs/swagger";
import { InjectRepository } from "@nestjs/typeorm";
import { IsNull, Repository } from "typeorm";
import { AbilitiesGuard } from "../../common/casl/abilities.guard";
import { AbilityAction } from "../../common/casl/ability-actions";
import { CaslMirrorAbilitiesGuard } from "../../common/casl/casl-mirror-abilities.guard";
import { CheckAbilities } from "../../common/casl/check-abilities.decorator";
import { RequireCapability } from "../../common/casl/require-capability.decorator";
import { RequestContextService } from "../../common/request-context/request-context.service";
import { AuthorizationPresenceGuard } from "../auth/authorization-presence.guard";
import { Roles } from "../auth/roles.decorator";
import { UserRole } from "../../common/auth/user-role.enum";
import { RolesGuard } from "../auth/roles.guard";
import { UserEntity } from "../identity/entities/user.entity";
import {
  AcknowledgeReconciliationFindingDto,
  ApplyReconciliationLedgerAdjustmentDto,
  ListReconciliationFindingsQueryDto
} from "./dto/reconciliation-findings.dto";
import {
  ReconciliationFindingsService,
  type ReconciliationFindingRowDto
} from "./reconciliation-findings.service";

@ApiTags("Finance")
@Controller("api/v2/workspaces")
@UseGuards(AuthorizationPresenceGuard, RolesGuard, AbilitiesGuard, CaslMirrorAbilitiesGuard)
@RequireCapability("module.finance")
@ApiBearerAuth()
export class ReconciliationFindingsController {
  constructor(
    private readonly findings: ReconciliationFindingsService,
    @InjectRepository(UserEntity)
    private readonly userRepository: Repository<UserEntity>,
    private readonly requestContextService: RequestContextService
  ) {}

  private requireWorkspaceTenantMatch(paramTenantId: string): string {
    const jwtTenantId = this.requestContextService.resolveEffectiveTenantId()?.trim().toLowerCase();
    const normalized = paramTenantId.trim().toLowerCase();
    if (!jwtTenantId || jwtTenantId !== normalized) {
      throw new ForbiddenException({
        error: {
          code: "TENANT_SCOPE_FORBIDDEN",
          message: "Workspace reconciliation requires a token scoped to this tenant"
        }
      });
    }
    return normalized;
  }

  private async actorLabel(): Promise<{ userId: string; label: string }> {
    const userId = this.requestContextService.getUserId();
    if (!userId) {
      throw new UnauthorizedException({
        error: { code: "AUTH_UNAUTHENTICATED", message: "Authentication required" }
      });
    }
    const user = await this.userRepository.findOne({
      where: { id: userId, deletedAt: IsNull() }
    });
    return { userId, label: user?.email?.trim() || userId };
  }

  @Get(":tenantId/reconciliation-findings")
  @Roles(UserRole.Owner, UserRole.Admin, UserRole.Leader)
  @CheckAbilities(({ ability }) => ability.can(AbilityAction.Read, "Reconciliation"))
  @ApiOperation({
    summary: "List persisted payment–finance reconciliation findings (triage)",
    description:
      "Keyset-paginated open findings for the workspace. Requires JWT tenant match and read Reconciliation."
  })
  @ApiUnauthorizedResponse({ description: "Authentication required" })
  @ApiForbiddenResponse({ description: "Tenant mismatch or insufficient role" })
  async listFindings(
    @Param("tenantId", ParseUUIDPipe) tenantId: string,
    @Query() query: ListReconciliationFindingsQueryDto
  ): Promise<{ data: ReconciliationFindingRowDto[]; nextCursor: string | null }> {
    const t = this.requireWorkspaceTenantMatch(tenantId);
    return this.findings.listForTenant({
      tenantId: t,
      status: query.status,
      limit: query.limit,
      cursor: query.cursor
    });
  }

  @Post(":tenantId/reconciliation-findings/:findingId/acknowledge")
  @Roles(UserRole.Owner, UserRole.Admin)
  @CheckAbilities(({ ability }) => ability.can(AbilityAction.Manage, "Reconciliation"))
  @ApiOperation({ summary: "Acknowledge an open reconciliation finding" })
  async acknowledge(
    @Param("tenantId", ParseUUIDPipe) tenantId: string,
    @Param("findingId", ParseUUIDPipe) findingId: string,
    @Body() body: AcknowledgeReconciliationFindingDto
  ): Promise<ReconciliationFindingRowDto> {
    const t = this.requireWorkspaceTenantMatch(tenantId);
    const actor = await this.actorLabel();
    return this.findings.acknowledgeFinding({
      tenantId: t,
      findingId,
      actorUserId: actor.userId,
      actorLabel: actor.label,
      note: body.note
    });
  }

  @Post(":tenantId/reconciliation-findings/:findingId/apply-ledger-adjustment")
  @Roles(UserRole.Owner, UserRole.Admin)
  @CheckAbilities(({ ability }) => ability.can(AbilityAction.Manage, "Reconciliation"))
  @ApiOperation({
    summary: "Apply a manual clearing↔booking wallet ledger adjustment for a triad mismatch",
    description:
      "Posts `finance.ledger.double_entry_applied` (mandatory financial audit) and appends `reconciliation.ledger.adjustment_applied` on the tenant audit stream. Idempotent via `idempotencyKey` + outbox `domainEventId`."
  })
  async applyLedgerAdjustment(
    @Param("tenantId", ParseUUIDPipe) tenantId: string,
    @Param("findingId", ParseUUIDPipe) findingId: string,
    @Body() body: ApplyReconciliationLedgerAdjustmentDto
  ): Promise<ReconciliationFindingRowDto> {
    const t = this.requireWorkspaceTenantMatch(tenantId);
    const actor = await this.actorLabel();
    return this.findings.applyLedgerAdjustment({
      tenantId: t,
      findingId,
      actorUserId: actor.userId,
      actorLabel: actor.label,
      idempotencyKey: body.idempotencyKey,
      amountMinor: body.amountMinor,
      flow: body.flow,
      currencyOverride: body.currencyOverride,
      note: body.note
    });
  }
}

import {
  BadRequestException,
  ConflictException,
  Injectable,
  NotFoundException
} from "@nestjs/common";
import type { EntityManager } from "typeorm";
import { Brackets } from "typeorm";
import type { QueryDeepPartialEntity } from "typeorm/query-builder/QueryPartialEntity";
import { TenantAuditEventsService } from "../../common/audit/tenant-audit-events.service";
import { RequestContextService } from "../../common/request-context/request-context.service";
import { TenantDbContextService } from "../../database/tenant-db-context.service";
import { ReconciliationFindingEntity } from "../finance/reconciliation/entities/reconciliation-finding.entity";
import type { PaymentReconciliationFinding } from "../finance/reconciliation/payment-reconciliation-report";
import { PaymentReconciliationFindingKind } from "../finance/reconciliation/payment-reconciliation-report";
import { emitReconciliationOperatorLedgerAdjustment } from "../finance/ledger/reconciliation-operator-ledger-adjustment";
import type { ReconciliationOperatorLedgerFlow } from "../finance/ledger/reconciliation-operator-ledger-adjustment";
import { OutboxService } from "../outbox/outbox.service";
import { ReconciliationFindingStatus } from "../finance/reconciliation/reconciliation-finding-status";

const DEFAULT_LIMIT = 50;
const MAX_LIMIT = 100;

export type ReconciliationFindingListCursor = { createdAt: Date; id: string };

export function encodeReconciliationFindingListCursor(c: ReconciliationFindingListCursor): string {
  return Buffer.from(JSON.stringify({ at: c.createdAt.toISOString(), id: c.id }), "utf8").toString(
    "base64url"
  );
}

export function decodeReconciliationFindingListCursor(raw: string): ReconciliationFindingListCursor | null {
  try {
    const decoded = Buffer.from(raw.trim(), "base64url").toString("utf8");
    const j = JSON.parse(decoded) as { at?: string; id?: string };
    if (typeof j.at !== "string" || typeof j.id !== "string") return null;
    const createdAt = new Date(j.at);
    if (Number.isNaN(createdAt.getTime())) return null;
    const id = j.id.trim();
    if (!id) return null;
    return { createdAt, id };
  } catch {
    return null;
  }
}

export type ReconciliationFindingRowDto = {
  id: string;
  tenantId: string;
  reconciliationJobId: string;
  findingUuid: string;
  bookingId: string;
  kind: string;
  severity: string;
  message: string;
  data: Record<string, unknown>;
  triadMismatch: Record<string, unknown> | null;
  status: ReconciliationFindingStatus;
  resolutionNote: string | null;
  resolvedByUserId: string | null;
  resolvedAt: string | null;
  createdAt: string;
  updatedAt: string;
};

@Injectable()
export class ReconciliationFindingsService {
  constructor(
    private readonly tenantDbContext: TenantDbContextService,
    private readonly outboxService: OutboxService,
    private readonly tenantAudit: TenantAuditEventsService,
    private readonly requestContext: RequestContextService
  ) {}

  async persistForJob(
    manager: EntityManager,
    tenantId: string,
    jobId: string,
    findings: readonly PaymentReconciliationFinding[]
  ): Promise<void> {
    if (findings.length === 0) {
      return;
    }
    const envelope = tenantId.trim().toLowerCase();
    const rows = findings.map((f) => ({
      tenantId: envelope,
      reconciliationJobId: jobId,
      findingUuid: f.id,
      bookingId: f.bookingId,
      kind: f.kind,
      severity: f.severity,
      message: f.message,
      data: f.data as Record<string, unknown>,
      triadMismatch: f.triadMismatch ? ({ ...f.triadMismatch } as Record<string, unknown>) : null,
      status: ReconciliationFindingStatus.OPEN
    }));
    await manager.insert(ReconciliationFindingEntity, rows as QueryDeepPartialEntity<ReconciliationFindingEntity>[]);
  }

  async listForTenant(input: {
    tenantId: string;
    status?: ReconciliationFindingStatus;
    limit?: number;
    cursor?: string | null;
  }): Promise<{ data: ReconciliationFindingRowDto[]; nextCursor: string | null }> {
    const tenant = input.tenantId.trim().toLowerCase();
    const limit = Math.min(Math.max(input.limit ?? DEFAULT_LIMIT, 1), MAX_LIMIT);
    const cur = input.cursor?.trim() ? decodeReconciliationFindingListCursor(input.cursor.trim()) : null;

    return this.tenantDbContext.runInTenantScope(tenant, async (manager) => {
      const r = manager.getRepository(ReconciliationFindingEntity);
      const qb = r
        .createQueryBuilder("f")
        .where("f.tenant_id = :tenant", { tenant })
        .orderBy("f.created_at", "DESC")
        .addOrderBy("f.id", "DESC")
        .take(limit + 1);

      if (input.status !== undefined) {
        qb.andWhere("f.status = :st", { st: input.status });
      }

      if (cur) {
        qb.andWhere(
          new Brackets((w) => {
            w.where("f.created_at < :cAt", { cAt: cur.createdAt }).orWhere(
              new Brackets((w2) => {
                w2.where("f.created_at = :cAt2", { cAt2: cur.createdAt }).andWhere("f.id < :cId", { cId: cur.id });
              })
            );
          })
        );
      }

      const rows = await qb.getMany();
      const page = rows.slice(0, limit);
      const hasMore = rows.length > limit;
      const tail = page[page.length - 1];
      const nextCursor =
        hasMore && tail
          ? encodeReconciliationFindingListCursor({ createdAt: tail.createdAt, id: tail.id })
          : null;

      return {
        data: page.map((row) => this.toDto(row)),
        nextCursor
      };
    });
  }

  async acknowledgeFinding(input: {
    tenantId: string;
    findingId: string;
    actorUserId: string;
    actorLabel: string;
    note?: string;
  }): Promise<ReconciliationFindingRowDto> {
    return this.tenantDbContext.runInTenantScope(input.tenantId.trim().toLowerCase(), async (manager) => {
      const row = await manager.findOne(ReconciliationFindingEntity, {
        where: { id: input.findingId, tenantId: input.tenantId.trim().toLowerCase() }
      });
      if (!row) {
        throw new NotFoundException({
          error: { code: "RESOURCE_NOT_FOUND", message: "Reconciliation finding not found" }
        });
      }
      if (row.status !== ReconciliationFindingStatus.OPEN) {
        throw new ConflictException({
          error: { code: "STATE_TRANSITION_INVALID", message: "Only open findings can be acknowledged" }
        });
      }
      row.status = ReconciliationFindingStatus.ACKNOWLEDGED;
      row.resolutionNote = input.note?.trim() || null;
      await manager.save(ReconciliationFindingEntity, row);

      await this.tenantAudit.append(
        {
          tenantId: row.tenantId,
          actorUserId: input.actorUserId,
          actor: input.actorLabel,
          action: "reconciliation.finding.acknowledged",
          resourceType: "ReconciliationFinding",
          resourceId: row.id,
          metadata: {
            finding_uuid: row.findingUuid,
            reconciliation_job_id: row.reconciliationJobId,
            booking_id: row.bookingId,
            note: row.resolutionNote
          },
          clientIp: this.requestContext.tryGetClientIp() ?? "unknown",
          requestId: this.requestContext.tryGetRequestId()
        },
        manager
      );

      return this.toDto(row);
    });
  }

  async applyLedgerAdjustment(input: {
    tenantId: string;
    findingId: string;
    actorUserId: string;
    actorLabel: string;
    idempotencyKey: string;
    amountMinor: string;
    flow: ReconciliationOperatorLedgerFlow;
    currencyOverride?: string;
    note?: string;
  }): Promise<ReconciliationFindingRowDto> {
    const trimmedKey = input.idempotencyKey.trim();
    if (trimmedKey.length < 8) {
      throw new BadRequestException({
        error: { code: "VALIDATION_FAILED", message: "idempotencyKey must be at least 8 characters" }
      });
    }
    if (!/^\d+$/.test(input.amountMinor.trim())) {
      throw new BadRequestException({
        error: { code: "VALIDATION_FAILED", message: "amountMinor must be a positive integer minor string" }
      });
    }
    if (input.amountMinor.trim() === "0") {
      throw new BadRequestException({
        error: { code: "VALIDATION_FAILED", message: "amountMinor must be > 0" }
      });
    }

    return this.tenantDbContext.runInTenantScope(input.tenantId.trim().toLowerCase(), async (manager) => {
      const row = await manager.findOne(ReconciliationFindingEntity, {
        where: { id: input.findingId, tenantId: input.tenantId.trim().toLowerCase() }
      });
      if (!row) {
        throw new NotFoundException({
          error: { code: "RESOURCE_NOT_FOUND", message: "Reconciliation finding not found" }
        });
      }
      if (
        row.status !== ReconciliationFindingStatus.OPEN &&
        row.status !== ReconciliationFindingStatus.ACKNOWLEDGED
      ) {
        throw new ConflictException({
          error: { code: "STATE_TRANSITION_INVALID", message: "Finding is not eligible for ledger adjustment" }
        });
      }
      if (row.kind !== PaymentReconciliationFindingKind.AMOUNT_TRIAD_MISMATCH || !row.triadMismatch) {
        throw new BadRequestException({
          error: {
            code: "RECONCILIATION_ADJUSTMENT_NOT_SUPPORTED",
            message: "Ledger adjustments are limited to amount triad mismatches in this release"
          }
        });
      }

      const tri = row.triadMismatch as { currency?: string };
      const currency = (input.currencyOverride?.trim() || tri.currency || "").trim().toUpperCase();
      if (currency.length !== 3) {
        throw new BadRequestException({
          error: { code: "VALIDATION_FAILED", message: "Could not resolve a 3-letter currency for this finding" }
        });
      }

      const { journalId } = await emitReconciliationOperatorLedgerAdjustment({
        manager,
        outboxService: this.outboxService,
        tenantId: row.tenantId,
        registrationId: row.bookingId,
        currency,
        amountMinor: input.amountMinor.trim(),
        flow: input.flow,
        idempotencyKey: trimmedKey,
        findingId: row.id,
        operatorNote: input.note?.trim() || "reconciliation_operator_ledger_adjustment"
      });

      row.status = ReconciliationFindingStatus.RESOLVED;
      row.resolutionNote = input.note?.trim() || null;
      row.resolvedByUserId = input.actorUserId;
      row.resolvedAt = new Date();
      await manager.save(ReconciliationFindingEntity, row);

      await this.tenantAudit.append(
        {
          tenantId: row.tenantId,
          actorUserId: input.actorUserId,
          actor: input.actorLabel,
          action: "reconciliation.ledger.adjustment_applied",
          resourceType: "ReconciliationFinding",
          resourceId: row.id,
          metadata: {
            finding_uuid: row.findingUuid,
            reconciliation_job_id: row.reconciliationJobId,
            booking_id: row.bookingId,
            journal_id: journalId,
            flow: input.flow,
            amount_minor: input.amountMinor.trim(),
            currency,
            idempotency_key: trimmedKey
          },
          clientIp: this.requestContext.tryGetClientIp() ?? "unknown",
          requestId: this.requestContext.tryGetRequestId()
        },
        manager
      );

      return this.toDto(row);
    });
  }

  private toDto(r: ReconciliationFindingEntity): ReconciliationFindingRowDto {
    return {
      id: r.id,
      tenantId: r.tenantId,
      reconciliationJobId: r.reconciliationJobId,
      findingUuid: r.findingUuid,
      bookingId: r.bookingId,
      kind: r.kind,
      severity: r.severity,
      message: r.message,
      data: r.data ?? {},
      triadMismatch: r.triadMismatch ?? null,
      status: r.status,
      resolutionNote: r.resolutionNote ?? null,
      resolvedByUserId: r.resolvedByUserId ?? null,
      resolvedAt: r.resolvedAt?.toISOString() ?? null,
      createdAt: r.createdAt.toISOString(),
      updatedAt: r.updatedAt.toISOString()
    };
  }
}

import {
  Inject,
  Injectable,
  Logger,
  OnModuleDestroy,
  OnModuleInit
} from "@nestjs/common";
import { ConfigService } from "../../config/config.service";
import { SchedulerLockService } from "../../jobs/scheduler-lock.service";
import { SchedulerRuntimeMetricsService } from "../../jobs/scheduler-runtime-metrics.service";
import { ReconciliationService } from "./reconciliation.service";

@Injectable()
export class ReconciliationProcessor implements OnModuleInit, OnModuleDestroy {
  private readonly logger = new Logger(ReconciliationProcessor.name);
  private interval?: NodeJS.Timeout;
  private readonly jobName = "reconciliation_cycle";
  private readonly lockName = "scheduler:reconciliation_cycle";

  constructor(
    @Inject(ConfigService) private readonly configService: ConfigService,
    @Inject(ReconciliationService)
    private readonly reconciliationService: ReconciliationService,
    @Inject(SchedulerLockService) private readonly schedulerLock: SchedulerLockService,
    @Inject(SchedulerRuntimeMetricsService)
    private readonly schedulerMetrics: SchedulerRuntimeMetricsService
  ) {}

  onModuleInit(): void {
    if (!this.configService.shouldRunSchedulers()) {
      this.logger.log("job_skipped_runtime_role reconciliation_cycle");
      return;
    }
    if (!this.configService.getReconciliationEnabled()) {
      this.logger.log("job_disabled reconciliation_cycle");
      return;
    }
    const ms = this.configService.getReconciliationIntervalMs();
    const jitterMs = Math.floor(Math.random() * (this.configService.getSchedulerJitterMs() + 1));
    setTimeout(() => {
      void this.runOnceWithLock();
      this.interval = setInterval(() => {
        void this.runOnceWithLock();
      }, ms);
      this.interval.unref?.();
    }, jitterMs).unref?.();
  }

  onModuleDestroy(): void {
    if (this.interval) {
      clearInterval(this.interval);
    }
  }

  private async runOnceWithLock(): Promise<void> {
    const started = Date.now();
    this.schedulerMetrics.noteStarted(this.jobName);
    this.logger.log("job_started reconciliation_cycle");
    try {
      const lock = await this.schedulerLock.runWithGlobalLock(this.lockName, async () => {
        await this.reconciliationService.runReconciliationCycle();
      });
      if (!lock.acquired) {
        this.schedulerMetrics.noteSkippedDueLock(this.jobName);
        this.logger.log("job_skipped_due_lock reconciliation_cycle");
        return;
      }
      this.schedulerMetrics.noteFinished(this.jobName, Date.now() - started);
      this.logger.log("job_finished reconciliation_cycle");
    } catch (error: unknown) {
      this.schedulerMetrics.noteFailed(this.jobName);
      this.logger.warn(`reconciliation cycle failed: ${String(error)}`);
    }
  }
}

import { randomUUID } from "node:crypto";
import { Inject, Injectable } from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import { EntityManager, In, IsNull, Repository } from "typeorm";
import { TenantUsageMeteringService } from "../../common/billing/tenant-usage-metering.service";
import { TenantEntity as IdentityTenantEntity } from "../identity/entities/tenant.entity";
import { OutboxService } from "../outbox/outbox.service";
import { TourEntity } from "../tours/entities/tour.entity";
import {
  RegistrationEntity,
  RegistrationStatus
} from "../registrations/registration.entity";
import {
  WaitlistItemEntity,
  WaitlistItemStatus
} from "../registrations/waitlist-item.entity";
import { RegistrationsService } from "../registrations/registrations.service";
import { TenantRateLimitService } from "../../common/tenant-abuse/tenant-rate-limit.service";
import { TenantDbContextService } from "../../database/tenant-db-context.service";
import { enforceBackgroundTenantRuntimePolicies } from "../../common/tenant/tenant-runtime-policy";
import { PaymentFinanceReconciliationService } from "./payment-finance-reconciliation.service";

const TOUR_PAGE_SIZE = 50;
const MAX_PROMOTIONS_PER_TOUR_PER_RUN = 50;

export type ReconciliationRuntimeSnapshot = {
  lastRunAt: string | null;
  lastReconciliationAt: string | null;
  lastRunHadDrift: boolean;
  promotedInLastRun: number;
  totalDriftsDetected: number;
  totalCorrectionsApplied: number;
  totalPromotionsTriggered: number;
  /** Last payment–ledger–snapshot reconciliation run (same scheduler as capacity). */
  lastPaymentFinanceReconciliationAt: string | null;
  lastPaymentFinanceCriticalFindings: number;
};

@Injectable()
export class ReconciliationService {
  private lastRunAt: string | null = null;
  private lastReconciliationAt: string | null = null;
  private lastRunHadDrift = false;
  private promotedInLastRun = 0;
  private totalDriftsDetected = 0;
  private totalCorrectionsApplied = 0;
  private totalPromotionsTriggered = 0;

  constructor(
    @Inject(OutboxService) private readonly outboxService: OutboxService,
    @Inject(RegistrationsService) private readonly registrationsService: RegistrationsService,
    @InjectRepository(IdentityTenantEntity)
    private readonly identityTenantRepository: Repository<IdentityTenantEntity>,
    @Inject(TenantRateLimitService) private readonly tenantRateLimitService: TenantRateLimitService,
    @Inject(TenantUsageMeteringService) private readonly tenantUsageMeteringService: TenantUsageMeteringService,
    @Inject(TenantDbContextService) private readonly tenantDbContext: TenantDbContextService,
    @Inject(PaymentFinanceReconciliationService)
    private readonly paymentFinanceReconciliation: PaymentFinanceReconciliationService
  ) {}

  getSnapshot(): ReconciliationRuntimeSnapshot {
    const pf = this.paymentFinanceReconciliation.getSnapshot();
    return {
      lastRunAt: this.lastRunAt,
      lastReconciliationAt: this.lastReconciliationAt,
      lastRunHadDrift: this.lastRunHadDrift,
      promotedInLastRun: this.promotedInLastRun,
      totalDriftsDetected: this.totalDriftsDetected,
      totalCorrectionsApplied: this.totalCorrectionsApplied,
      totalPromotionsTriggered: this.totalPromotionsTriggered,
      lastPaymentFinanceReconciliationAt: pf.lastRunAt,
      lastPaymentFinanceCriticalFindings: pf.lastCriticalFindings
    };
  }

  async runReconciliationCycle(): Promise<void> {
    const tenants = await this.identityTenantRepository.find({
      select: { id: true },
      where: { deletedAt: IsNull() }
    });

    let driftThisRun = false;
    let promotedThisRun = 0;

    for (const { id: tenantId } of tenants) {
      const runtimeAllowed = await enforceBackgroundTenantRuntimePolicies(tenantId, {
        tryConsumeBackgroundJob: async (currentTenantId) =>
          this.tenantUsageMeteringService.tryConsumeBackgroundJob(currentTenantId),
        tryConsumeTenantJobRateLimit: async (currentTenantId) =>
          this.tenantRateLimitService.tryConsumeJobForTenant(currentTenantId)
      });
      if (!runtimeAllowed) {
        continue;
      }

      let skip = 0;
      while (true) {
        const tours = await this.tenantDbContext.runInTenantScope(tenantId, async (manager) => {
          return manager.find(TourEntity, {
            where: { tenantId },
            order: { id: "ASC" },
            take: TOUR_PAGE_SIZE,
            skip
          });
        });

        if (tours.length === 0) {
          break;
        }

        for (const tour of tours) {
          const { drift, promotions } = await this.tenantDbContext.runInTenantScope(
            tour.tenantId,
            async (manager) => this.reconcileSingleTour(manager, tour)
          );
          if (drift) {
            driftThisRun = true;
          }
          promotedThisRun += promotions;
        }

        skip += TOUR_PAGE_SIZE;
      }
    }

    const nowIso = new Date().toISOString();
    this.lastRunAt = nowIso;
    this.lastReconciliationAt = nowIso;
    this.lastRunHadDrift = driftThisRun;
    this.promotedInLastRun = promotedThisRun;

    await this.paymentFinanceReconciliation.runPaymentFinanceReconciliationCycle({
      cycleBatchId: randomUUID()
    });
  }

  private async reconcileSingleTour(
    manager: EntityManager,
    tour: TourEntity
  ): Promise<{ drift: boolean; promotions: number }> {
    const lockedTour = await this.registrationsService.lockTourRowForUpdate(
      manager,
      tour.id,
      tour.tenantId
    );

    const realCount = await manager.count(RegistrationEntity, {
      where: {
        tourId: tour.id,
        tenantId: tour.tenantId,
        status: In([RegistrationStatus.ACCEPTED, RegistrationStatus.ACCEPTED_PAID])
      }
    });

    let drift = false;
    if (lockedTour.acceptedCount !== realCount) {
      drift = true;
      this.totalDriftsDetected += 1;
      this.totalCorrectionsApplied += 1;

      const oldAcceptedCount = lockedTour.acceptedCount;
      lockedTour.acceptedCount = realCount;
      await manager.save(lockedTour);

      await this.outboxService.addEvent(manager, {
        tenantId: tour.tenantId,
        aggregateType: "Tour",
        aggregateId: tour.id,
        eventType: "tour.capacity.reconciled",
        payload: {
          tourId: tour.id,
          oldAcceptedCount,
          correctedAcceptedCount: realCount,
          detectedAt: new Date().toISOString()
        }
      });
    }

    let promotions = 0;
    for (; promotions < MAX_PROMOTIONS_PER_TOUR_PER_RUN; promotions++) {
      const capacityAvailable =
        lockedTour.totalCapacity - lockedTour.acceptedCount;
      if (capacityAvailable <= 0) {
        break;
      }

      const hasWaiting = await manager.exists(WaitlistItemEntity, {
        where: {
          tourId: tour.id,
          tenantId: tour.tenantId,
          status: WaitlistItemStatus.WAITING
        }
      });
      if (!hasWaiting) {
        break;
      }

      try {
        const promoted =
          await this.registrationsService.promoteNextWaitlistSlotIfEligible(
            manager,
            tour.tenantId,
            tour.id,
            lockedTour
          );
        if (!promoted) {
          break;
        }
      } catch {
        break;
      }
    }

    this.totalPromotionsTriggered += promotions;

    return { drift, promotions };
  }

}

import { BadRequestException, Inject, Injectable } from "@nestjs/common";
import { EntityManager } from "typeorm";
import { RegistrationsService } from "../registrations.service";
import { PaymentsService } from "../../payments/payments.service";
import { ConfigService } from "../../../config/config.service";
import { RegistrationEntity } from "../registration.entity";
import { CreateRegistrationDto } from "../dto/create-registration.dto";
import { PaymentResponseDto } from "../../payments/dto/payment-response.dto";
import { RegistrationResponseDto } from "../dto/get-registration.dto";

function assertPaymentIntentWhenRequired(
  requiresPayment: boolean,
  paymentIntent: PaymentResponseDto | null
): void {
  if (requiresPayment && paymentIntent == null) {
    throw new BadRequestException({
      error: {
        code: "BOOKING_PAYMENT_INTENT_MISSING",
        message:
          "This tour requires payment at signup, but no payment intent was created in the booking transaction."
      }
    });
  }
}

@Injectable()
export class RegistrationPlacementOrchestrator {
  constructor(
    @Inject(RegistrationsService) private readonly registrationsService: RegistrationsService,
    @Inject(PaymentsService) private readonly paymentsService: PaymentsService,
    @Inject(ConfigService) private readonly configService: ConfigService
  ) {}

  private async createPaymentIntentForRegistration(
    manager: EntityManager,
    registration: RegistrationEntity
  ): Promise<PaymentResponseDto> {
    const totalMinorNum =
      registration.quotedTotalMinor != null
        ? Number(String(registration.quotedTotalMinor).trim())
        : NaN;
    if (
      !Number.isFinite(totalMinorNum) ||
      totalMinorNum < 1 ||
      !Number.isSafeInteger(totalMinorNum)
    ) {
      throw new BadRequestException({
        error: {
          code: "BOOKING_PAYABLE_AMOUNT_INVALID",
          message:
            "This tour requires payment at signup, but the locked booking price is missing or cannot be used for a payment intent."
        }
      });
    }
    const currency = String(registration.quotedCurrencyCode ?? "").trim().toUpperCase();
    if (!currency) {
      throw new BadRequestException({
        error: {
          code: "BOOKING_PAYABLE_AMOUNT_INVALID",
          message: "Locked booking currency is missing; cannot create payment intent."
        }
      });
    }
    return this.paymentsService.createPaymentIntentWithManager(manager, {
      registrationId: registration.id,
      amount: totalMinorNum,
      currency,
      paymentProvider: this.configService.getDefaultPaymentProvider(),
      providerPaymentId: `mock-${registration.id}`
    });
  }

  async createAuthenticatedBooking(tourId: string): Promise<{
    registration: RegistrationResponseDto;
    paymentIntent: PaymentResponseDto | null;
  }> {
    const bookingInput = await this.registrationsService.resolveAuthenticatedBookingInput(tourId);
    const result = await this.registrationsService.createPublicRegistrationOrWaitlist({
      ...bookingInput,
      tourId,
      createPaymentIntent: async (manager, registration) =>
        this.createPaymentIntentForRegistration(manager, registration)
    });

    if (result.type === "waitlist") {
      throw new BadRequestException({
        error: {
          code: "CAPACITY_FULL",
          message: "Tour is at capacity; use the waitlist flow instead of booking."
        }
      });
    }

    assertPaymentIntentWhenRequired(result.requiresPayment, result.paymentIntent);

    return {
      registration: result.registration,
      paymentIntent: result.paymentIntent
    };
  }

  async publicRegister(input: {
    tourId: string;
    payload: CreateRegistrationDto;
  }): Promise<
    | {
        registration: RegistrationResponseDto | null;
        paymentIntent: PaymentResponseDto | null;
        waitlistItemId: string | null;
        waitlistPosition: number | null;
      }
  > {
    const result = await this.registrationsService.createPublicRegistrationOrWaitlist({
      ...input.payload,
      tourId: input.tourId,
      createPaymentIntent: async (manager: EntityManager, registration: RegistrationEntity) =>
        this.createPaymentIntentForRegistration(manager, registration)
    });

    if (result.type === "waitlist") {
      return {
        registration: null,
        paymentIntent: null,
        waitlistItemId: result.waitlistItem.id,
        waitlistPosition: result.queuePosition
      };
    }

    assertPaymentIntentWhenRequired(result.requiresPayment, result.paymentIntent);

    return {
      registration: result.registration,
      paymentIntent: result.paymentIntent,
      waitlistPosition: null,
      waitlistItemId: null
    };
  }
}

import { Inject, Injectable } from "@nestjs/common";
import type { EntityManager } from "typeorm";
