import { AbilitiesGuard } from "../../common/casl/abilities.guard";
import { CaslMirrorAbilitiesGuard } from "../../common/casl/casl-mirror-abilities.guard";
import { AbilityAction } from "../../common/casl/ability-actions";
import { CheckAbilities } from "../../common/casl/check-abilities.decorator";
import { ReplaceEmergencyContactsDto, UpsertMedicalProfileDto } from "./dto/safety-profile.dto";
import { SafetyProfileService } from "./safety-profile.service";

@ApiTags("Safety profile")
@Controller("api/v2/safety-profiles")
@UseGuards(AuthorizationPresenceGuard, RolesGuard, AbilitiesGuard, CaslMirrorAbilitiesGuard)
@ApiBearerAuth()
@Roles(UserRole.Owner, UserRole.Admin, UserRole.Leader, UserRole.Member)
export class SafetyProfileController {
  constructor(private readonly safetyProfile: SafetyProfileService) {}

  @Get(":userId/emergency-contacts")
  @CheckAbilities(({ ability }) => ability.can(AbilityAction.Read, "Workspace"))
  @ApiOperation({ summary: "List emergency contacts for a workspace member" })
  listEmergency(@Param("userId", new ParseUUIDPipe()) userId: string) {
    return this.safetyProfile.listEmergencyContacts(userId);
  }

  @Put(":userId/emergency-contacts")
  @CheckAbilities(({ ability }) => ability.can(AbilityAction.Read, "Workspace"))
  @ApiOperation({ summary: "Replace emergency contacts for a workspace member" })
  replaceEmergency(
    @Param("userId", new ParseUUIDPipe()) userId: string,
    @Body() body: ReplaceEmergencyContactsDto
  ) {
    return this.safetyProfile.replaceEmergencyContacts(userId, body);
  }

  @Get(":userId/medical-profile")
  @CheckAbilities(({ ability }) => ability.can(AbilityAction.Read, "Workspace"))
  @ApiOperation({ summary: "Read decrypted medical profile payload (authorized roles only)" })
  getMedical(@Param("userId", new ParseUUIDPipe()) userId: string) {
    return this.safetyProfile.getMedicalProfile(userId);
  }

  @Put(":userId/medical-profile")
  @CheckAbilities(({ ability }) => ability.can(AbilityAction.Read, "Workspace"))
  @ApiOperation({ summary: "Upsert medical profile (encrypted at rest)" })
  putMedical(@Param("userId", new ParseUUIDPipe()) userId: string, @Body() body: UpsertMedicalProfileDto) {
    return this.safetyProfile.upsertMedicalProfile(userId, body.plaintextPayloadUtf8);
  }
}

import { Inject, Injectable, Logger } from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import { DataSource, IsNull, Repository } from "typeorm";
import { TenantContextMissingError } from "../../common/errors/tenant-context-missing.error";
import { RequestContextService } from "../../common/request-context/request-context.service";
import { WorkspaceAbilityFactoryService } from "../../common/casl/workspace-ability.factory.service";
import { UsersAccessService } from "../identity/users-access.service";
import { EmergencyContactEntity } from "./entities/emergency-contact.entity";
import { MedicalProfileEntity } from "./entities/medical-profile.entity";
import type { ReplaceEmergencyContactsDto } from "./dto/safety-profile.dto";
import {
  assertCanReadEmergencyContacts,
  assertCanReadMedicalProfile,
  assertCanUpdateEmergencyContacts,
  assertCanUpdateMedicalProfile
} from "./safety-profile.authorization";
import type { MedicalProfileEncryptionPort } from "./encryption/medical-profile-encryption.port";
import { MEDICAL_PROFILE_ENCRYPTION } from "./encryption/medical-profile-encryption.port";

export type EmergencyContactResponse = {
  id: string;
  displayName: string;
  phoneE164: string;
  relationship: string;
  isPrimary: boolean;
  sortOrder: number;
};

export type MedicalProfileResponse = {
  userId: string;
  encryptionSchemaVersion: number;
  plaintextPayloadUtf8: string;
};

@Injectable()
export class SafetyProfileService {
  private readonly logger = new Logger(SafetyProfileService.name);

  constructor(
    @InjectRepository(EmergencyContactEntity)
    private readonly emergencyRepo: Repository<EmergencyContactEntity>,
    @InjectRepository(MedicalProfileEntity)
    private readonly medicalRepo: Repository<MedicalProfileEntity>,
    private readonly dataSource: DataSource,
    private readonly requestContext: RequestContextService,
    private readonly usersAccess: UsersAccessService,
    private readonly abilityFactory: WorkspaceAbilityFactoryService,
    @Inject(MEDICAL_PROFILE_ENCRYPTION)
    private readonly medicalCrypto: MedicalProfileEncryptionPort
  ) {}

  async listEmergencyContacts(targetUserId: string): Promise<EmergencyContactResponse[]> {
    const tenantId = this.resolveTenantId();
    const ability = this.abilityFactory.createForActiveRequest();
    assertCanReadEmergencyContacts(ability, targetUserId);
    await this.usersAccess.findTenantScopedUserOrThrow(tenantId, targetUserId);
    const rows = await this.emergencyRepo.find({
      where: { tenantId, userId: targetUserId, deletedAt: IsNull() },
      order: { sortOrder: "ASC", createdAt: "ASC" }
    });
    this.logger.log({
      msg: "safety_emergency_contacts_listed",
      tenantId,
      targetUserId,
      count: rows.length
    });
    return rows.map((r) => ({
      id: r.id,
      displayName: r.displayName,
      phoneE164: r.phoneE164,
      relationship: r.relationship,
      isPrimary: r.isPrimary,
      sortOrder: r.sortOrder
    }));
  }

  async replaceEmergencyContacts(
    targetUserId: string,
    dto: ReplaceEmergencyContactsDto
  ): Promise<EmergencyContactResponse[]> {
    const tenantId = this.resolveTenantId();
    const ability = this.abilityFactory.createForActiveRequest();
    assertCanUpdateEmergencyContacts(ability, targetUserId);
    await this.usersAccess.findTenantScopedUserOrThrow(tenantId, targetUserId);

    return this.dataSource.transaction(async (mgr) => {
      await mgr.softDelete(EmergencyContactEntity, { tenantId, userId: targetUserId });
      const created: EmergencyContactEntity[] = [];
      for (const c of dto.contacts) {
        const row = mgr.create(EmergencyContactEntity, {
          tenantId,
          userId: targetUserId,
          displayName: c.displayName,
          phoneE164: c.phoneE164,
          relationship: c.relationship,
          isPrimary: Boolean(c.isPrimary),
          sortOrder: c.sortOrder ?? 0
        });
        created.push(await mgr.save(row));
      }
      this.logger.log({
        msg: "safety_emergency_contacts_replaced",
        tenantId,
        targetUserId,
        count: created.length
      });
      return created.map((r) => ({
        id: r.id,
        displayName: r.displayName,
        phoneE164: r.phoneE164,
        relationship: r.relationship,
        isPrimary: r.isPrimary,
        sortOrder: r.sortOrder
      }));
    });
  }

  async getMedicalProfile(targetUserId: string): Promise<MedicalProfileResponse | null> {
    const tenantId = this.resolveTenantId();
    const ability = this.abilityFactory.createForActiveRequest();
    assertCanReadMedicalProfile(ability, targetUserId);
    await this.usersAccess.findTenantScopedUserOrThrow(tenantId, targetUserId);

    const row = await this.medicalRepo.findOne({
      where: { tenantId, userId: targetUserId, deletedAt: IsNull() }
    });
    if (!row) {
      this.logger.log({ msg: "safety_medical_profile_miss", tenantId, targetUserId });
      return null;
    }

    const plaintextPayloadUtf8 = await this.medicalCrypto.decrypt({
      ciphertext: row.ciphertext,
      nonce: row.nonce,
      authTag: row.authTag,
      wrappedContentKey: row.wrappedContentKey ?? null,
      kmsKeyId: row.kmsKeyId ?? null
    });

    this.logger.log({
      msg: "safety_medical_profile_read",
      tenantId,
      targetUserId,
      encryptionSchemaVersion: row.encryptionSchemaVersion
    });

    return {
      userId: targetUserId,
      encryptionSchemaVersion: row.encryptionSchemaVersion,
      plaintextPayloadUtf8
    };
  }

  async upsertMedicalProfile(targetUserId: string, plaintextPayloadUtf8: string): Promise<MedicalProfileResponse> {
    const tenantId = this.resolveTenantId();
    const ability = this.abilityFactory.createForActiveRequest();
    assertCanUpdateMedicalProfile(ability, targetUserId);
    await this.usersAccess.findTenantScopedUserOrThrow(tenantId, targetUserId);

    const material = await this.medicalCrypto.encrypt(plaintextPayloadUtf8);

    const row = await this.dataSource.transaction(async (mgr) => {
      const existing = await mgr.findOne(MedicalProfileEntity, {
        where: { tenantId, userId: targetUserId, deletedAt: IsNull() }
      });
      if (existing) {
        existing.ciphertext = material.ciphertext;
        existing.nonce = material.nonce;
        existing.authTag = material.authTag;
        existing.wrappedContentKey = material.wrappedContentKey;
        existing.kmsKeyId = material.kmsKeyId;
        existing.encryptionSchemaVersion = 1;
        return mgr.save(existing);
      }
      const created = mgr.create(MedicalProfileEntity, {
        tenantId,
        userId: targetUserId,
        encryptionSchemaVersion: 1,
        ciphertext: material.ciphertext,
        nonce: material.nonce,
        authTag: material.authTag,
        wrappedContentKey: material.wrappedContentKey,
        kmsKeyId: material.kmsKeyId
      });
      return mgr.save(created);
    });

    this.logger.log({
      msg: "safety_medical_profile_upserted",
      tenantId,
      targetUserId,
      encryptionSchemaVersion: row.encryptionSchemaVersion
    });

    return {
      userId: targetUserId,
      encryptionSchemaVersion: row.encryptionSchemaVersion,
      plaintextPayloadUtf8
    };
  }

  private resolveTenantId(): string {
    const tenantId = this.requestContext.resolveEffectiveTenantId()?.trim().toLowerCase();
    if (!tenantId) {
      throw new TenantContextMissingError("tenant context is required for safety profile access");
    }
    return tenantId;
  }
}

import {
  BadRequestException,
  ConflictException,
  ForbiddenException,
  Injectable,
  NotFoundException
} from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import { Repository } from "typeorm";

import { authRequiredError, tenantContextMissingError } from "../../common/errors/error-response-builders";
import { RequestContextService } from "../../common/request-context/request-context.service";
import type { CreateEquipmentItemDto } from "./dto/create-equipment-item.dto";
import type { UpdateEquipmentItemDto } from "./dto/update-equipment-item.dto";
import { WorkspaceEquipmentItemResponseDto } from "./dto/workspace-equipment-item-response.dto";
import { WorkspaceEquipmentItemEntity } from "./entities/workspace-equipment-item.entity";

@Injectable()
export class EquipmentSettingsService {
  constructor(
    @InjectRepository(WorkspaceEquipmentItemEntity)
    private readonly equipmentRepository: Repository<WorkspaceEquipmentItemEntity>,
    private readonly requestContext: RequestContextService
  ) {}

  private resolveWorkspaceOrThrow(): string {
    const workspaceId = this.requestContext.resolveEffectiveTenantId();
    if (!workspaceId) {
      throw new ForbiddenException(tenantContextMissingError());
    }
    const userId = this.requestContext.getUserId();
    if (!userId) {
      throw new ForbiddenException(authRequiredError());
    }
    return workspaceId;
  }

  private normalizeNullableText(value: string | null | undefined): string | null {
    if (value == null) {
      return null;
    }
    const t = String(value).trim();
    return t === "" ? null : t;
  }

  private normalizeSlug(value: string): string {
    return String(value).trim();
  }

  private toResponse(row: WorkspaceEquipmentItemEntity): WorkspaceEquipmentItemResponseDto {
    return {
      id: row.id,
      name: row.name,
      slug: row.slug,
      category: row.category ?? null,
      description: row.description ?? null,
      icon: row.icon ?? null,
      isActive: row.isActive,
      sortOrder: row.sortOrder,
      createdAt: row.createdAt.toISOString(),
      updatedAt: row.updatedAt.toISOString()
    };
  }

  async findAllByWorkspace(): Promise<WorkspaceEquipmentItemResponseDto[]> {
    const workspaceId = this.resolveWorkspaceOrThrow();
    const rows = await this.equipmentRepository.find({
      where: { workspaceId },
      order: { sortOrder: "ASC", name: "ASC" }
    });
    return rows.map((r) => this.toResponse(r));
  }

  async create(dto: CreateEquipmentItemDto): Promise<WorkspaceEquipmentItemResponseDto> {
    const workspaceId = this.resolveWorkspaceOrThrow();
    const slug = this.normalizeSlug(dto.slug);
    const exists = await this.equipmentRepository.exist({ where: { workspaceId, slug } });
    if (exists) {
      throw new ConflictException({
        error: { code: "EQUIPMENT_SLUG_CONFLICT", message: "An equipment item with this slug already exists" }
      });
    }
    const row = this.equipmentRepository.create({
      workspaceId,
      name: dto.name.trim(),
      slug,
      category: this.normalizeNullableText(dto.category),
      description: this.normalizeNullableText(dto.description),
      icon: this.normalizeNullableText(dto.icon),
      isActive: dto.isActive ?? true,
      sortOrder: dto.sortOrder ?? 0
    });
    const saved = await this.equipmentRepository.save(row);
    return this.toResponse(saved);
  }

  async update(id: string, dto: UpdateEquipmentItemDto): Promise<WorkspaceEquipmentItemResponseDto> {
    const workspaceId = this.resolveWorkspaceOrThrow();
    const row = await this.equipmentRepository.findOne({ where: { id, workspaceId } });
    if (!row) {
      throw new NotFoundException({
        error: { code: "RESOURCE_NOT_FOUND", message: "Equipment item not found" }
      });
    }
    const keys = Object.keys(dto) as (keyof UpdateEquipmentItemDto)[];
    if (keys.length === 0) {
      throw new BadRequestException({
        error: { code: "VALIDATION_FAILED", message: "No fields to update" }
      });
    }
    if (dto.slug !== undefined) {
      const nextSlug = this.normalizeSlug(dto.slug);
      if (nextSlug !== row.slug) {
        const taken = await this.equipmentRepository.exist({
          where: { workspaceId, slug: nextSlug }
        });
        if (taken) {
          throw new ConflictException({
            error: { code: "EQUIPMENT_SLUG_CONFLICT", message: "An equipment item with this slug already exists" }
          });
        }
        row.slug = nextSlug;
      }
    }
    if (dto.name !== undefined) {
      row.name = dto.name.trim();
    }
    if (dto.category !== undefined) {
      row.category = this.normalizeNullableText(dto.category);
    }
    if (dto.description !== undefined) {
      row.description = this.normalizeNullableText(dto.description);
    }
    if (dto.icon !== undefined) {
      row.icon = this.normalizeNullableText(dto.icon);
    }
    if (dto.isActive !== undefined) {
      row.isActive = dto.isActive;
    }
    if (dto.sortOrder !== undefined) {
      row.sortOrder = dto.sortOrder;
    }
    const saved = await this.equipmentRepository.save(row);
    return this.toResponse(saved);
  }

  async remove(id: string): Promise<void> {
    const workspaceId = this.resolveWorkspaceOrThrow();
    const res = await this.equipmentRepository.delete({ id, workspaceId });
    if (!res.affected) {
      throw new NotFoundException({
        error: { code: "RESOURCE_NOT_FOUND", message: "Equipment item not found" }
      });
    }
  }

  /**
   * `itemIds` must list every equipment item id for the workspace exactly once (full permutation).
   */
  async reorder(itemIds: string[]): Promise<WorkspaceEquipmentItemResponseDto[]> {
    const workspaceId = this.resolveWorkspaceOrThrow();
    const existing = await this.equipmentRepository.find({
      where: { workspaceId },
      select: { id: true }
    });
    const existingIds = new Set(existing.map((r) => r.id));
    if (existingIds.size !== itemIds.length) {
      throw new BadRequestException({
        error: {
          code: "VALIDATION_FAILED",
          message: "itemIds must include every equipment item exactly once"
        }
      });
    }
    const seen = new Set<string>();
    for (const id of itemIds) {
      if (!existingIds.has(id) || seen.has(id)) {
        throw new BadRequestException({
          error: {
            code: "VALIDATION_FAILED",
            message: "itemIds must include every equipment item exactly once"
          }
        });
      }
      seen.add(id);
    }

    await this.equipmentRepository.manager.transaction(async (em) => {
      for (let i = 0; i < itemIds.length; i += 1) {
        await em.update(
          WorkspaceEquipmentItemEntity,
          { id: itemIds[i], workspaceId },
          { sortOrder: i }
        );
      }
    });

    return this.findAllByWorkspace();
  }
}

