  async updateTemplate(
    @Body() body: UpdateWorkspaceTourWizardTemplateDto,
  ): Promise<WorkspaceTourWizardTemplateEnvelopeDto> {
    return { template: await this.templates.updateForWorkspace(body) };
  }
}

import assert from "node:assert/strict";
import test from "node:test";

import type { TourFormProfile } from "@repo/types";

import type { RequestContextService } from "../../common/request-context/request-context.service";
import type { WorkspaceTourCreationPresetEntity } from "./entities/workspace-tour-creation-preset.entity";
import type { WorkspaceTourThemeEntity } from "./entities/workspace-tour-theme.entity";
import { TourCreationPresetsSettingsService } from "./tour-creation-presets-settings.service";

/**
 * Service-level coverage for `checkAndLogThemeProfileDrift`.
 *
 * Goal: prove the wiring between the service and `detectPresetThemeProfileDrift`
 * works end-to-end (a) without hitting the database and (b) without any
 * frontend changes — per the user direction "فقط backend diagnostics".
 *
 * Policy under test: soft / warn-only (preset is saved either way, drift is
 * surfaced via `logger.warn`).
 */

const WORKSPACE = "00000000-0000-4000-8000-000000000abc";
const USER = "00000000-0000-4000-8000-000000000def";

type WarnLog = string;

type FakePresetRow = WorkspaceTourCreationPresetEntity;

function makeRequestContextStub(): RequestContextService {
  return {
    resolveEffectiveTenantId: () => WORKSPACE,
    getUserId: () => USER,
  } as unknown as RequestContextService;
}

function makePresetsRepoStub() {
  const saved: FakePresetRow[] = [];
  const stub = {
    create: (partial: Partial<FakePresetRow>): FakePresetRow => {
      const row: FakePresetRow = {
        id: "preset-" + Math.random().toString(36).slice(2, 10),
        workspaceId: WORKSPACE,
        name: "",
        description: null,
        isActive: true,
        sortOrder: 0,
        matchTourType: null,
        matchMainTourThemeId: null,
        formProfile: "general",
        defaults: {},
        createdAt: new Date(),
        updatedAt: new Date(),
        ...partial,
      } as FakePresetRow;
      return row;
    },
    save: async (row: FakePresetRow): Promise<FakePresetRow> => {
      saved.push(row);
      return row;
    },
    findOne: async () => null,
  };
  return { stub, saved };
}

function makeThemesRepoStub(catalog: Record<string, TourFormProfile>) {
  const calls: { id: unknown; workspaceId: unknown }[] = [];
  const stub = {
    findOne: async (opts: {
      where?: { id?: string; workspaceId?: string };
    }): Promise<Partial<WorkspaceTourThemeEntity> | null> => {
      const id = opts.where?.id;
      const workspaceId = opts.where?.workspaceId;
      calls.push({ id, workspaceId });
      if (typeof id !== "string") return null;
      const profile = catalog[id];
      if (!profile) return null;
      return { id, formProfile: profile };
    },
  };
  return { stub, calls };
}

function attachWarnSpy(svc: TourCreationPresetsSettingsService): WarnLog[] {
  const warnings: WarnLog[] = [];
  (svc as unknown as { logger: { warn: (msg: string) => void } }).logger = {
    warn: (msg: string) => warnings.push(msg),
  } as { warn: (msg: string) => void };
  return warnings;
}

function makeService(catalog: Record<string, TourFormProfile>) {
  const presets = makePresetsRepoStub();
  const themes = makeThemesRepoStub(catalog);
  const svc = new TourCreationPresetsSettingsService(
    presets.stub as never,
    themes.stub as never,
    makeRequestContextStub(),
    { logEvent: async () => undefined } as never,
  );
  const warnings = attachWarnSpy(svc);
  return { svc, warnings, themes, presets };
}

test("create: theme profile matches preset.formProfile → no drift warning", async () => {
  const { svc, warnings, themes } = makeService({ "theme-cinema": "cinema_event" });

  await svc.create({
    name: "Cinema preset",
    formProfile: "cinema_event",
    defaults: { overview: { mainTourThemeId: "theme-cinema" } },
  } as never);

  const drifts = warnings.filter((w) => w.includes("[presets][drift]"));
  assert.deepEqual(drifts, []);
  assert.equal(themes.calls.length, 1, "theme lookup should be invoked exactly once");
  assert.equal(themes.calls[0]?.workspaceId, WORKSPACE);
  assert.equal(themes.calls[0]?.id, "theme-cinema");
});

test("create: theme profile differs from preset.formProfile → warn (soft)", async () => {
  const { svc, warnings, presets } = makeService({ "theme-x": "cinema_event" });

  await svc.create({
    name: "Drifty preset",
    formProfile: "urban_event",
    defaults: { overview: { mainTourThemeId: "theme-x" } },
  } as never);

  const drifts = warnings.filter((w) => w.includes("[presets][drift]"));
  assert.equal(drifts.length, 1, "exactly one drift warning expected");
  assert.match(drifts[0]!, /preset_form_profile_mismatches_theme/);
  assert.match(drifts[0]!, /themeId=theme-x/);
  assert.match(drifts[0]!, /presetFormProfile=urban_event/);
  assert.match(drifts[0]!, /themeFormProfile=cinema_event/);
  assert.equal(
    presets.saved.length,
    1,
    "soft policy: preset must still be persisted on drift",
  );
});

test("create: referenced theme missing in workspace → warn (soft)", async () => {
  const { svc, warnings, presets } = makeService({});

  await svc.create({
    name: "Ghost theme preset",
    formProfile: "general",
    defaults: { overview: { mainTourThemeId: "ghost-theme" } },
  } as never);

  const drifts = warnings.filter((w) => w.includes("[presets][drift]"));
  assert.equal(drifts.length, 1);
  assert.match(drifts[0]!, /preset_theme_not_in_workspace/);
  assert.match(drifts[0]!, /themeId=ghost-theme/);
  assert.match(drifts[0]!, /presetFormProfile=general/);
  assert.equal(presets.saved.length, 1);
});

test("create: legacy matchMainTourThemeId is also consulted for drift", async () => {
  const { svc, warnings, themes } = makeService({ "legacy-theme": "cinema_event" });

  await svc.create({
    name: "Legacy match",
    formProfile: "urban_event",
    matchMainTourThemeId: "legacy-theme",
    defaults: {},
  } as never);

  const drifts = warnings.filter((w) => w.includes("[presets][drift]"));
  assert.equal(drifts.length, 1);
  assert.match(drifts[0]!, /preset_form_profile_mismatches_theme/);
  assert.match(drifts[0]!, /themeId=legacy-theme/);
  assert.equal(themes.calls[0]?.id, "legacy-theme");
});

test("create: no theme id at all → drift check is silent", async () => {
  const { svc, warnings, themes } = makeService({});

  await svc.create({
    name: "Profile-only preset",
    formProfile: "general",
    defaults: { policies: { cancellationPolicy: "flexible" } },
  } as never);

  const drifts = warnings.filter((w) => w.includes("[presets][drift]"));
  assert.deepEqual(drifts, []);
  assert.equal(
    themes.calls.length,
    0,
    "should not hit the theme repo when no theme id is referenced",
  );
});

import {
  BadRequestException,
  ForbiddenException,
  Injectable,
  Logger,
  NotFoundException
} from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import { Repository } from "typeorm";

import {
  defaultTourFormProfileForTourType,
  normalizeTourFormProfileInput,
  type TourFormProfile,
  type TourType
} from "@repo/types";

import { authRequiredError, tenantContextMissingError } from "../../common/errors/error-response-builders";
import { RequestContextService } from "../../common/request-context/request-context.service";
import type { CreateWorkspaceTourCreationPresetDto } from "./dto/create-workspace-tour-creation-preset.dto";
import type { UpdateWorkspaceTourCreationPresetDto } from "./dto/update-workspace-tour-creation-preset.dto";
import { WorkspaceTourCreationPresetResponseDto } from "./dto/workspace-tour-creation-preset-response.dto";
import { WorkspaceTourCreationPresetEntity } from "./entities/workspace-tour-creation-preset.entity";
import { WorkspaceTourThemeEntity } from "./entities/workspace-tour-theme.entity";
import {
  detectPresetThemeProfileDrift,
  formatPresetDriftWarning,
  type ThemeLookup,
} from "./tour-preset-defaults-drift";
import {
  canonicalToTemplate,
  templateToCanonical,
  type DenaliCanonicalTemplateData,
} from "@repo/types/denali";

import { parseDenaliCanonicalTemplateDataOrThrow } from "./denali-canonical-template-data.schema";
import { parsePresetDefaultsOrThrow } from "./tour-preset-defaults.schema";
import { usesDenaliCanonicalTemplate } from "../tours/strategies/workspace.strategy.registry";
import {
  mergeLegacyMatchIntoDefaults,
  migrateGatheringPointsToLogisticsArray,
} from "./tour-preset-defaults-legacy";

import { AuditLogService } from "../../common/audit/audit-log.service";
import { AUDIT_CATEGORY } from "../../common/audit/audit-category";

const MAX_DEFAULTS_JSON_BYTES = 256 * 1024;

@Injectable()
export class TourCreationPresetsSettingsService {
  private readonly logger = new Logger(TourCreationPresetsSettingsService.name);

  constructor(
    @InjectRepository(WorkspaceTourCreationPresetEntity)
    private readonly presetsRepository: Repository<WorkspaceTourCreationPresetEntity>,
    @InjectRepository(WorkspaceTourThemeEntity)
    private readonly themesRepository: Repository<WorkspaceTourThemeEntity>,
    private readonly requestContext: RequestContextService,
    private readonly auditLogService: AuditLogService
  ) {}

  private resolveWorkspaceOrThrow(): string {
    const workspaceId = this.requestContext.resolveEffectiveTenantId();
    if (!workspaceId) {
      throw new ForbiddenException(tenantContextMissingError());
    }
    const userId = this.requestContext.getUserId();
    if (!userId) {
      throw new ForbiddenException(authRequiredError());
    }
    return workspaceId;
  }

  private normalizeNullableText(value: string | null | undefined): string | null {
    if (value == null) {
      return null;
    }
    const t = String(value).trim();
    return t === "" ? null : t;
  }

  private normalizeOptionalMatchTourType(value: string | null | undefined): string | null {
    if (value == null) return null;
    const t = String(value).trim();
    return t === "" ? null : t;
  }

  private normalizeOptionalUuid(value: string | null | undefined): string | null {
    if (value == null) return null;
    const t = String(value).trim();
    return t === "" ? null : t;
  }

  private isDenaliFormProfile(formProfile: TourFormProfile): boolean {
    return usesDenaliCanonicalTemplate(formProfile);
  }

  private rejectDenaliLegacyDefaults(value: unknown): void {
    if (
      value != null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as Record<string, unknown>).length > 0
    ) {
      throw new BadRequestException({
        error: {
          code: "DENALI_TEMPLATE_LEGACY_DEFAULTS_REJECTED",
          message: "Denali templates use canonicalData only; legacy defaults are not supported.",
        },
      });
    }
  }

  private assertCanonicalData(value: unknown): Record<string, unknown> {
    if (value === null || typeof value !== "object" || Array.isArray(value)) {
      throw new BadRequestException({
        error: { code: "VALIDATION_FAILED", message: "canonicalData must be a JSON object" },
      });
    }
    const encoded = JSON.stringify(value);
    if (encoded.length > MAX_DEFAULTS_JSON_BYTES) {
      throw new BadRequestException({
        error: {
          code: "VALIDATION_FAILED",
          message: `canonicalData JSON must be at most ${MAX_DEFAULTS_JSON_BYTES} bytes`,
        },
      });
    }
    return parseDenaliCanonicalTemplateDataOrThrow(value) as Record<string, unknown>;
  }

  private assertPlainDefaults(
    value: unknown,
    formProfile: TourFormProfile,
  ): Record<string, unknown> {
    if (value === null || typeof value !== "object" || Array.isArray(value)) {
      throw new BadRequestException({
        error: { code: "VALIDATION_FAILED", message: "defaults must be a JSON object" }
      });
    }
    const encoded = JSON.stringify(value);
    if (encoded.length > MAX_DEFAULTS_JSON_BYTES) {
      throw new BadRequestException({
        error: {
          code: "VALIDATION_FAILED",
          message: `defaults JSON must be at most ${MAX_DEFAULTS_JSON_BYTES} bytes`
        }
      });
    }
    const plain = value as Record<string, unknown>;
    parsePresetDefaultsOrThrow(plain, { formProfile });
    return plain;
  }

  /**
   * Soft drift diagnostic: looks up the workspace theme referenced by either
   * `defaults.overview.mainTourThemeId` or the legacy `matchMainTourThemeId`
   * column and compares its `formProfile` with `preset.formProfile`. Mismatch
   * is emitted as a `warn` log — the preset is **always saved** (Phase-2
   * policy "soft"). See `tour-preset-defaults-drift.ts` for the contract.
   */
  private async checkAndLogThemeProfileDrift(opts: {
    workspaceId: string;
    presetFormProfile: TourFormProfile | null | undefined;
    canonicalData?: Record<string, unknown>;
    defaults?: Record<string, unknown>;
    matchMainTourThemeId: string | null;
  }): Promise<void> {
    if (!opts.presetFormProfile) return;
    const program = opts.canonicalData?.program;
    const programThemeIds =
      program != null &&
      typeof program === "object" &&
      !Array.isArray(program) &&
      Array.isArray((program as { themeIds?: unknown }).themeIds)
        ? ((program as { themeIds: unknown[] }).themeIds.filter(
            (id): id is string => typeof id === "string" && id.trim() !== "",
          )[0] ?? null)
        : null;
    const overviewRaw = opts.defaults?.overview;
    const overview =
      overviewRaw && typeof overviewRaw === "object" && !Array.isArray(overviewRaw)
        ? (overviewRaw as Record<string, unknown>)
        : {};
    const defaultsOverviewMainTourThemeId =
      programThemeIds ??
      (typeof overview.mainTourThemeId === "string" ? overview.mainTourThemeId : null);

    const lookup: ThemeLookup = async (themeId) => {
      const theme = await this.themesRepository.findOne({
        where: { id: themeId, workspaceId: opts.workspaceId },
        select: { id: true, formProfile: true },
      });
      return theme ? { id: theme.id, formProfile: theme.formProfile } : null;
    };

    const result = await detectPresetThemeProfileDrift(
      {
        presetFormProfile: opts.presetFormProfile,
        defaultsOverviewMainTourThemeId,
        matchMainTourThemeId: opts.matchMainTourThemeId,
      },
      lookup,
    );
    const warning = formatPresetDriftWarning(result);
    if (warning) this.logger.warn(warning);
  }

  private toResponse(row: WorkspaceTourCreationPresetEntity): WorkspaceTourCreationPresetResponseDto {
    const formProfile = normalizeTourFormProfileInput(row.formProfile ?? "general");
    if (this.isDenaliFormProfile(formProfile)) {
      return {
        id: row.id,
        name: row.name,
        description: row.description ?? null,
        isActive: row.isActive,
        sortOrder: row.sortOrder,
        matchTourType: row.matchTourType ?? null,
        matchMainTourThemeId: row.matchMainTourThemeId ?? null,
        formProfile,
        canonicalData: templateToCanonical(row),
        defaults: {},
        createdAt: row.createdAt.toISOString(),
        updatedAt: row.updatedAt.toISOString(),
      };
    }
    const defaults =
      row.defaults && typeof row.defaults === "object" && !Array.isArray(row.defaults)
        ? (row.defaults as Record<string, unknown>)
        : {};
    const enrichedDefaults = mergeLegacyMatchIntoDefaults(
      defaults,
      row.matchTourType ?? null,
      row.matchMainTourThemeId ?? null,
    );
    const fullyEnriched = migrateGatheringPointsToLogisticsArray(enrichedDefaults);
    return {
      id: row.id,
      name: row.name,
      description: row.description ?? null,
      isActive: row.isActive,
      sortOrder: row.sortOrder,
      matchTourType: row.matchTourType ?? null,
      matchMainTourThemeId: row.matchMainTourThemeId ?? null,
      formProfile,
      canonicalData: {},
      defaults: fullyEnriched,
      createdAt: row.createdAt.toISOString(),
      updatedAt: row.updatedAt.toISOString(),
    };
  }

  async findAllByWorkspace(): Promise<WorkspaceTourCreationPresetResponseDto[]> {
    const workspaceId = this.resolveWorkspaceOrThrow();
    const rows = await this.presetsRepository.find({
      where: { workspaceId },
      order: { sortOrder: "ASC", name: "ASC" }
    });
    return rows.map((r) => this.toResponse(r));
  }

  async findOneById(id: string): Promise<WorkspaceTourCreationPresetResponseDto> {
    const workspaceId = this.resolveWorkspaceOrThrow();
    const row = await this.presetsRepository.findOne({ where: { id, workspaceId } });
    if (!row) {
      throw new NotFoundException({
        error: { code: "RESOURCE_NOT_FOUND", message: "Tour creation preset not found" }
      });
    }
    return this.toResponse(row);
  }

  async create(dto: CreateWorkspaceTourCreationPresetDto): Promise<WorkspaceTourCreationPresetResponseDto> {
    const workspaceId = this.resolveWorkspaceOrThrow();
    const matchTourType = this.normalizeOptionalMatchTourType(dto.matchTourType);
    const matchMainTourThemeId = this.normalizeOptionalUuid(dto.matchMainTourThemeId);
    const formProfile =
      dto.formProfile != null && String(dto.formProfile).trim() !== ""
        ? normalizeTourFormProfileInput(dto.formProfile)
        : defaultTourFormProfileForTourType(matchTourType as TourType | null);
    const denali = this.isDenaliFormProfile(formProfile);
    if (denali) {
      this.rejectDenaliLegacyDefaults(dto.defaults);
    }
    const canonicalPayload = denali
      ? canonicalToTemplate(
          this.assertCanonicalData(dto.canonicalData ?? {}) as DenaliCanonicalTemplateData,
          { name: dto.name.trim(), formProfile },
        ).canonicalData
      : ({} as DenaliCanonicalTemplateData);
    const defaults = denali
      ? {}
      : this.assertPlainDefaults(dto.defaults ?? {}, formProfile);

    const row = this.presetsRepository.create({
      workspaceId,
      name: dto.name.trim(),
      description: this.normalizeNullableText(dto.description),
      isActive: dto.isActive ?? true,
      sortOrder: dto.sortOrder ?? 0,
      matchTourType,
      matchMainTourThemeId,
      formProfile,
      canonicalData: canonicalPayload,
      defaults,
    });
    await this.checkAndLogThemeProfileDrift({
      workspaceId,
      presetFormProfile: formProfile,
      canonicalData: canonicalPayload as Record<string, unknown>,
      defaults,
      matchMainTourThemeId,
    });
    const saved = await this.presetsRepository.save(row);
    void this.auditLogService.logEvent({
      category: AUDIT_CATEGORY.SECURITY,
      action: "preset.create",
      entity: "preset",
      entityId: saved.id,
      after: { name: saved.name, formProfile: saved.formProfile },
    });
    return this.toResponse(saved);
  }

  async update(id: string, dto: UpdateWorkspaceTourCreationPresetDto): Promise<WorkspaceTourCreationPresetResponseDto> {
    const workspaceId = this.resolveWorkspaceOrThrow();
    const row = await this.presetsRepository.findOne({ where: { id, workspaceId } });
    if (!row) {
      throw new NotFoundException({
        error: { code: "RESOURCE_NOT_FOUND", message: "Tour creation preset not found" }
      });
    }
    const keys = Object.keys(dto) as (keyof UpdateWorkspaceTourCreationPresetDto)[];
    if (keys.length === 0) {
      throw new BadRequestException({
        error: { code: "VALIDATION_FAILED", message: "No fields to update" }
      });
    }

    if (dto.name !== undefined) {
      row.name = dto.name.trim();
    }
    if (dto.description !== undefined) {
      row.description = this.normalizeNullableText(dto.description);
    }
    if (dto.isActive !== undefined) {
      row.isActive = dto.isActive;
    }
    if (dto.sortOrder !== undefined) {
      row.sortOrder = dto.sortOrder;
    }
    const formProfile = normalizeTourFormProfileInput(row.formProfile ?? "general");
    if (dto.canonicalData !== undefined) {
      row.canonicalData = this.assertCanonicalData(dto.canonicalData);
    }
    if (dto.defaults !== undefined) {
      if (this.isDenaliFormProfile(normalizeTourFormProfileInput(row.formProfile ?? "general"))) {
        this.rejectDenaliLegacyDefaults(dto.defaults);
        row.defaults = {};
      } else {
        row.defaults = this.assertPlainDefaults(dto.defaults, formProfile);
      }
    }
    if (dto.matchTourType !== undefined) {
      row.matchTourType = this.normalizeOptionalMatchTourType(dto.matchTourType);
    }
    if (dto.matchMainTourThemeId !== undefined) {
      row.matchMainTourThemeId = this.normalizeOptionalUuid(dto.matchMainTourThemeId);
    }
    if (dto.formProfile !== undefined) {
      row.formProfile =
        dto.formProfile == null || String(dto.formProfile).trim() === ""
          ? "general"
          : normalizeTourFormProfileInput(dto.formProfile);
    }

    if (
      dto.canonicalData !== undefined ||
      dto.defaults !== undefined ||
      dto.formProfile !== undefined ||
      dto.matchMainTourThemeId !== undefined
    ) {
      await this.checkAndLogThemeProfileDrift({
        workspaceId,
        presetFormProfile: row.formProfile,
        canonicalData: row.canonicalData as Record<string, unknown>,
        defaults: row.defaults,
        matchMainTourThemeId: row.matchMainTourThemeId,
      });
    }
    const saved = await this.presetsRepository.save(row);
    void this.auditLogService.logEvent({
      category: AUDIT_CATEGORY.SECURITY,
      action: "preset.update",
      entity: "preset",
      entityId: saved.id,
      after: { name: saved.name, formProfile: saved.formProfile },
    });
    return this.toResponse(saved);
  }

  async remove(id: string): Promise<void> {
    const workspaceId = this.resolveWorkspaceOrThrow();
    const row = await this.presetsRepository.findOne({ where: { id, workspaceId } });
    if (!row) {
      throw new NotFoundException({
        error: { code: "RESOURCE_NOT_FOUND", message: "Tour creation preset not found" }
      });
    }
    const res = await this.presetsRepository.delete({ id, workspaceId });
    if (!res.affected) {
      throw new NotFoundException({
        error: { code: "RESOURCE_NOT_FOUND", message: "Tour creation preset not found" }
      });
    }
    await this.auditLogService.logEvent({
      category: AUDIT_CATEGORY.SECURITY,
      action: "preset.delete",
      entity: "preset",
      entityId: id,
      before: { name: row.name, formProfile: row.formProfile },
    });
  }

  async reorder(itemIds: string[]): Promise<WorkspaceTourCreationPresetResponseDto[]> {
    const workspaceId = this.resolveWorkspaceOrThrow();
    const existing = await this.presetsRepository.find({
      where: { workspaceId },
      select: { id: true }
    });
    const existingIds = new Set(existing.map((r) => r.id));
    if (existingIds.size !== itemIds.length) {
      throw new BadRequestException({
        error: {
          code: "VALIDATION_FAILED",
          message: "itemIds must include every tour creation preset id exactly once"
        }
      });
    }
    const seen = new Set<string>();
    for (const pid of itemIds) {
      if (!existingIds.has(pid) || seen.has(pid)) {
        throw new BadRequestException({
          error: {
            code: "VALIDATION_FAILED",
            message: "itemIds must include every tour creation preset id exactly once"
          }
        });
      }
      seen.add(pid);
    }

    await this.presetsRepository.manager.transaction(async (em) => {
      for (let i = 0; i < itemIds.length; i += 1) {
        await em.update(
          WorkspaceTourCreationPresetEntity,
          { id: itemIds[i], workspaceId },
          { sortOrder: i }
        );
      }
    });

    return this.findAllByWorkspace();
  }
}

/**
 * Drift detection between `preset.formProfile` and the form profile of
 * `defaults.overview.mainTourThemeId` (or the legacy column
 * `matchMainTourThemeId`).
 *
 * Policy (Phase 2 — soft/warn-only, per prompt.md "Prompt 3-A" §3 and the
 * follow-up direction in the chat):
 *   - The settings service wires this helper into `create()` and `update()`,
 *     queries `workspace_tour_themes` scoped by `workspace_id`, and converts
 *     non-`ok` results into a `logger.warn(...)` call. The save is never
 *     blocked. This is the gentle path that lets us collect signal without
 *     breaking existing admin workflows.
 *   - A later hardening pass can flip POST + PATCH-with-defaults to throw
 *     `BadRequestException` while keeping PATCH-only-`formProfile` as a warn.
 *
 * Keeping the result and the warning message generator separate means tests
 * can verify the human-readable signal without standing up a real Logger.
 */
import type { TourFormProfile } from "@repo/types";

export type ThemeLookupResult = { id: string; formProfile: TourFormProfile } | null;
export type ThemeLookup = (themeId: string) => Promise<ThemeLookupResult>;

export type PresetDriftCheckInput = {
  presetFormProfile: TourFormProfile;
  defaultsOverviewMainTourThemeId: string | null | undefined;
  matchMainTourThemeId: string | null | undefined;
};

export type PresetDriftOk = { ok: true };
export type PresetDriftThemeMissing = {
  ok: false;
  reason: "preset_theme_not_in_workspace";
  themeId: string;
  presetFormProfile: TourFormProfile;
};
export type PresetDriftProfileMismatch = {
  ok: false;
  reason: "preset_form_profile_mismatches_theme";
  themeId: string;
  presetFormProfile: TourFormProfile;
  themeFormProfile: TourFormProfile;
};
export type PresetDriftResult = PresetDriftOk | PresetDriftThemeMissing | PresetDriftProfileMismatch;

export async function detectPresetThemeProfileDrift(
  input: PresetDriftCheckInput,
  lookup: ThemeLookup,
): Promise<PresetDriftResult> {
  const themeId =
    pickTrimmedNonEmpty(input.defaultsOverviewMainTourThemeId) ??
    pickTrimmedNonEmpty(input.matchMainTourThemeId);
  if (!themeId) return { ok: true };

  const theme = await lookup(themeId);
  if (!theme) {
    return {
      ok: false,
      reason: "preset_theme_not_in_workspace",
      themeId,
      presetFormProfile: input.presetFormProfile,
    };
  }
  if (theme.formProfile !== input.presetFormProfile) {
    return {
      ok: false,
      reason: "preset_form_profile_mismatches_theme",
      themeId,
      presetFormProfile: input.presetFormProfile,
      themeFormProfile: theme.formProfile,
    };
  }
  return { ok: true };
}

function pickTrimmedNonEmpty(value: string | null | undefined): string | null {
  if (value == null) return null;
  const t = String(value).trim();
  return t === "" ? null : t;
}

/**
 * Produces a structured, log-grep-friendly warning string for a non-`ok`
 * drift result, or `null` when the result is `ok`. Format keeps a stable
 * prefix (`[presets][drift]`) so dashboards / alerts can filter by code.
 */
export function formatPresetDriftWarning(result: PresetDriftResult): string | null {
  if (result.ok) return null;
  if (result.reason === "preset_theme_not_in_workspace") {
    return (
      `[presets][drift] preset_theme_not_in_workspace ` +
      `themeId=${result.themeId} presetFormProfile=${result.presetFormProfile}`
    );
  }
  return (
    `[presets][drift] preset_form_profile_mismatches_theme ` +
    `themeId=${result.themeId} presetFormProfile=${result.presetFormProfile} ` +
    `themeFormProfile=${result.themeFormProfile}`
  );
}

import {
  BadRequestException,
  ConflictException,
  ForbiddenException,
  Injectable,
  NotFoundException
} from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import { Repository } from "typeorm";

import { normalizeTourFormProfileInput } from "@repo/types";

import { authRequiredError, tenantContextMissingError } from "../../common/errors/error-response-builders";
import { RequestContextService } from "../../common/request-context/request-context.service";
import type { CreateWorkspaceTourThemeDto } from "./dto/create-workspace-tour-theme.dto";
import type { UpdateWorkspaceTourThemeDto } from "./dto/update-workspace-tour-theme.dto";
import { WorkspaceTourThemeResponseDto } from "./dto/workspace-tour-theme-response.dto";
import { WorkspaceTourThemeEntity } from "./entities/workspace-tour-theme.entity";

@Injectable()
export class TourThemesSettingsService {
  constructor(
    @InjectRepository(WorkspaceTourThemeEntity)
    private readonly tourThemesRepository: Repository<WorkspaceTourThemeEntity>,
    private readonly requestContext: RequestContextService
  ) {}

  private resolveWorkspaceOrThrow(): string {
    const workspaceId = this.requestContext.resolveEffectiveTenantId();
    if (!workspaceId) {
      throw new ForbiddenException(tenantContextMissingError());
    }
    const userId = this.requestContext.getUserId();
    if (!userId) {
      throw new ForbiddenException(authRequiredError());
    }
    return workspaceId;
  }

  private normalizeNullableText(value: string | null | undefined): string | null {
    if (value == null) {
      return null;
    }
    const t = String(value).trim();
    return t === "" ? null : t;
  }

  private normalizeSlug(value: string): string {
    return String(value).trim();
  }

  private toResponse(row: WorkspaceTourThemeEntity): WorkspaceTourThemeResponseDto {
    return {
      id: row.id,
      name: row.name,
      slug: row.slug,
      description: row.description ?? null,
      isActive: row.isActive,
      sortOrder: row.sortOrder,
      formProfile: normalizeTourFormProfileInput(row.formProfile),
      createdAt: row.createdAt.toISOString(),
      updatedAt: row.updatedAt.toISOString()
    };
  }

  async findAllByWorkspace(): Promise<WorkspaceTourThemeResponseDto[]> {
    const workspaceId = this.resolveWorkspaceOrThrow();
    const rows = await this.tourThemesRepository.find({
      where: { workspaceId },
      order: { sortOrder: "ASC", name: "ASC" }
    });
    return rows.map((r) => this.toResponse(r));
  }

  async create(dto: CreateWorkspaceTourThemeDto): Promise<WorkspaceTourThemeResponseDto> {
    const workspaceId = this.resolveWorkspaceOrThrow();
    const slug = this.normalizeSlug(dto.slug);
    const exists = await this.tourThemesRepository.exist({ where: { workspaceId, slug } });
    if (exists) {
      throw new ConflictException({
        error: { code: "TOUR_THEME_SLUG_CONFLICT", message: "A tour theme with this slug already exists" }
      });
    }
    const row = this.tourThemesRepository.create({
      workspaceId,
      name: dto.name.trim(),
      slug,
      description: this.normalizeNullableText(dto.description),
      isActive: dto.isActive ?? true,
      sortOrder: dto.sortOrder ?? 0,
      formProfile: normalizeTourFormProfileInput(dto.formProfile),
    });
    const saved = await this.tourThemesRepository.save(row);
    return this.toResponse(saved);
  }

  async update(id: string, dto: UpdateWorkspaceTourThemeDto): Promise<WorkspaceTourThemeResponseDto> {
    const workspaceId = this.resolveWorkspaceOrThrow();
    const row = await this.tourThemesRepository.findOne({ where: { id, workspaceId } });
    if (!row) {
      throw new NotFoundException({
        error: { code: "RESOURCE_NOT_FOUND", message: "Tour theme not found" }
      });
    }
    const keys = Object.keys(dto) as (keyof UpdateWorkspaceTourThemeDto)[];
    if (keys.length === 0) {
      throw new BadRequestException({
        error: { code: "VALIDATION_FAILED", message: "No fields to update" }
      });
    }
    if (dto.slug !== undefined) {
      const nextSlug = this.normalizeSlug(dto.slug);
      if (nextSlug !== row.slug) {
        const taken = await this.tourThemesRepository.exist({
          where: { workspaceId, slug: nextSlug }
        });
        if (taken) {
          throw new ConflictException({
            error: { code: "TOUR_THEME_SLUG_CONFLICT", message: "A tour theme with this slug already exists" }
          });
        }
        row.slug = nextSlug;
      }
    }
    if (dto.name !== undefined) {
      row.name = dto.name.trim();
    }
    if (dto.description !== undefined) {
      row.description = this.normalizeNullableText(dto.description);
    }
    if (dto.isActive !== undefined) {
      row.isActive = dto.isActive;
    }
    if (dto.sortOrder !== undefined) {
      row.sortOrder = dto.sortOrder;
    }
    if (dto.formProfile !== undefined) {
      row.formProfile = normalizeTourFormProfileInput(dto.formProfile);
    }
    const saved = await this.tourThemesRepository.save(row);
    return this.toResponse(saved);
  }

  async remove(id: string): Promise<void> {
    const workspaceId = this.resolveWorkspaceOrThrow();
    const res = await this.tourThemesRepository.delete({ id, workspaceId });
    if (!res.affected) {
      throw new NotFoundException({
        error: { code: "RESOURCE_NOT_FOUND", message: "Tour theme not found" }
      });
    }
  }

  async reorder(itemIds: string[]): Promise<WorkspaceTourThemeResponseDto[]> {
    const workspaceId = this.resolveWorkspaceOrThrow();
    const existing = await this.tourThemesRepository.find({
      where: { workspaceId },
      select: { id: true }
    });
    const existingIds = new Set(existing.map((r) => r.id));
    if (existingIds.size !== itemIds.length) {
      throw new BadRequestException({
        error: {
          code: "VALIDATION_FAILED",
          message: "itemIds must include every tour theme id exactly once"
        }
      });
    }
    const seen = new Set<string>();
    for (const id of itemIds) {
      if (!existingIds.has(id) || seen.has(id)) {
        throw new BadRequestException({
          error: {
            code: "VALIDATION_FAILED",
            message: "itemIds must include every tour theme id exactly once"
          }
        });
      }
      seen.add(id);
    }

    await this.tourThemesRepository.manager.transaction(async (em) => {
      for (let i = 0; i < itemIds.length; i += 1) {
        await em.update(
          WorkspaceTourThemeEntity,
          { id: itemIds[i], workspaceId },
          { sortOrder: i }
        );
      }
    });

    return this.findAllByWorkspace();
  }
}

import { ForbiddenException, Injectable, NotFoundException } from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import { Repository } from "typeorm";

import { normalizeTourFormProfileInput } from "@repo/types";

import { authRequiredError, tenantContextMissingError } from "../../common/errors/error-response-builders";
import { RequestContextService } from "../../common/request-context/request-context.service";
import { templateToCanonical } from "@repo/types/denali";

import { parseDenaliCanonicalTemplateDataOrThrow } from "./denali-canonical-template-data.schema";
import type { UpdateWorkspaceTourWizardTemplateDto } from "./dto/update-workspace-tour-wizard-template.dto";
import type { WorkspaceTourWizardTemplateResponseDto } from "./dto/workspace-tour-wizard-template-response.dto";
import { WorkspaceTourWizardTemplateEntity } from "./entities/workspace-tour-wizard-template.entity";
import { collectWorkspaceWizardTemplateValidationErrors } from "./validate-workspace-wizard-template";
import { throwValidationFailed } from "../../common/errors/throw-validation-failed";

@Injectable()
export class TourWizardTemplateSettingsService {
  constructor(
    @InjectRepository(WorkspaceTourWizardTemplateEntity)
    private readonly templatesRepository: Repository<WorkspaceTourWizardTemplateEntity>,
    private readonly requestContext: RequestContextService,
  ) {}

  private resolveWorkspaceOrThrow(): string {
    const workspaceId = this.requestContext.resolveEffectiveTenantId();
    if (!workspaceId) {
      throw new ForbiddenException(tenantContextMissingError());
    }
    const userId = this.requestContext.getUserId();
    if (!userId) {
      throw new ForbiddenException(authRequiredError());
    }
    return workspaceId;
  }

  private toResponse(row: WorkspaceTourWizardTemplateEntity): WorkspaceTourWizardTemplateResponseDto {
    const skip = Array.isArray(row.stepOverrides?.skip)
      ? row.stepOverrides.skip.filter((s): s is string => typeof s === "string")
      : [];
    const insert = Array.isArray(row.stepOverrides?.insert)
      ? row.stepOverrides.insert.filter((s): s is string => typeof s === "string")
      : [];
    return {
      id: row.id,
      workspaceId: row.workspaceId,
      baseProfile: normalizeTourFormProfileInput(row.baseProfile),
      stepOverrides: { skip, insert },
      fieldRulesOverlay:
        row.fieldRulesOverlay && typeof row.fieldRulesOverlay === "object" && !Array.isArray(row.fieldRulesOverlay)
          ? row.fieldRulesOverlay
          : {},
      presetId: row.presetId ?? null,
      canonicalData: templateToCanonical({
        canonicalData: row.canonicalData,
        fieldRulesOverlay: row.fieldRulesOverlay,
        stepOverrides: row.stepOverrides,
      }) as Record<string, unknown>,
      wizardContractVersion: row.wizardContractVersion,
      formProfileVersion: row.formProfileVersion,
    };
  }

  async findForWorkspace(): Promise<WorkspaceTourWizardTemplateResponseDto | null> {
    const workspaceId = this.resolveWorkspaceOrThrow();
    const row = await this.templatesRepository.findOne({ where: { workspaceId } });
    return row ? this.toResponse(row) : null;
  }

  async updateForWorkspace(
    body: UpdateWorkspaceTourWizardTemplateDto,
  ): Promise<WorkspaceTourWizardTemplateResponseDto> {
    const workspaceId = this.resolveWorkspaceOrThrow();
    const row = await this.templatesRepository.findOne({ where: { workspaceId } });
    if (!row) {
      throw new NotFoundException({
        error: {
          code: "RESOURCE_NOT_FOUND",
          message: "Workspace tour wizard template is not configured",
        },
      });
    }

    const nextOverlay =
      body.fieldRulesOverlay !== undefined ? body.fieldRulesOverlay : row.fieldRulesOverlay;
    const nextCanonical =
      body.canonicalData !== undefined ? body.canonicalData : row.canonicalData;

    const validationErrors = collectWorkspaceWizardTemplateValidationErrors({
      fieldRulesOverlay: nextOverlay,
      canonicalData: nextCanonical,
    });
    if (validationErrors.length > 0) {
      throwValidationFailed(validationErrors);
    }

    if (body.fieldRulesOverlay !== undefined) {
      row.fieldRulesOverlay = body.fieldRulesOverlay;
    }
    if (body.canonicalData !== undefined) {
      row.canonicalData = parseDenaliCanonicalTemplateDataOrThrow(body.canonicalData);
    }

    const saved = await this.templatesRepository.save(row);
    return this.toResponse(saved);
  }
}

import { Inject, Injectable } from "@nestjs/common";
import { InjectDataSource } from "@nestjs/typeorm";
import type { DataSource } from "typeorm";
import { parseTenantEnabledModules } from "../../common/rbac/parse-tenant-enabled-modules";
import { RequestContextService } from "../../common/request-context/request-context.service";

/**
 * Resolves `tenant_id` for a tour **before** `app.tenant_id` session binding exists.
 *
 * Used **only** for anonymous “public bootstrap” HTTP flows (e.g. `POST …/tours/:tourId/register`,
 * `POST …/tours/:tourId/waitlist`) where RLS would otherwise block reading `tours`.
 * Do **not** use for authenticated
 * routes — those must rely on JWT-bound tenant context.
 */
@Injectable()
export class TenantBootstrapService {
  constructor(
    @InjectDataSource() private readonly dataSource: DataSource,
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService
  ) {}

  async resolvePublicTourBootstrapContext(
    tourId: string
  ): Promise<{ tenantId: string; enabledModules: readonly string[] } | null> {
    return this.requestContextService.runWithoutTenantBinding(
      "public_tour_bootstrap_lookup",
      async () => {
        const rows = (await this.dataSource.query(
          `SELECT t.tenant_id::text AS tenant_id, tn.enabled_modules
             FROM tours t
             INNER JOIN tenants tn ON tn.id = t.tenant_id AND tn.deleted_at IS NULL
            WHERE t.id = $1::uuid
              AND t.deleted_at IS NULL`,
          [tourId]
        )) as Array<{ tenant_id: string | null; enabled_modules: unknown }>;
        const row = rows[0];
        if (!row?.tenant_id) {
          return null;
        }
        return {
          tenantId: row.tenant_id,
          enabledModules: parseTenantEnabledModules(row.enabled_modules)
        };
      }
    );
  }

  async resolveTenantFromTourId(tourId: string): Promise<string | null> {
    const context = await this.resolvePublicTourBootstrapContext(tourId);
    return context?.tenantId ?? null;
  }
}

import { Injectable } from "@nestjs/common";
import {
  DataSource,
  EventSubscriber,
  EntitySubscriberInterface,
  SoftRemoveEvent,
  UpdateEvent
} from "typeorm";
import { TenantEntity } from "../identity/entities/tenant.entity";
import { TenantHostResolverService } from "./tenant-host-resolver.service";

@Injectable()
@EventSubscriber()
export class TenantHostCacheInvalidationSubscriber
  implements EntitySubscriberInterface<TenantEntity>
{
  constructor(
    dataSource: DataSource,
    private readonly tenantHostResolver: TenantHostResolverService
  ) {
    if (dataSource && Array.isArray(dataSource.subscribers)) {
      dataSource.subscribers.push(this);
    }
  }

  listenTo(): typeof TenantEntity {
    return TenantEntity;
  }

  async afterUpdate(event: UpdateEvent<TenantEntity>): Promise<void> {
    const prevSubdomain =
      typeof event.databaseEntity?.subdomain === "string"
        ? event.databaseEntity.subdomain
        : null;
    const nextSubdomain =
      typeof event.entity?.subdomain === "string" ? event.entity.subdomain : null;

    if (prevSubdomain && prevSubdomain.trim() !== "") {
      await this.tenantHostResolver.invalidateTenantHostCacheByLabel(prevSubdomain);
    }
    if (nextSubdomain && nextSubdomain.trim() !== "") {
      await this.tenantHostResolver.invalidateTenantHostCacheByLabel(nextSubdomain);
    }
  }

  async afterSoftRemove(event: SoftRemoveEvent<TenantEntity>): Promise<void> {
    const subdomain =
      typeof event.databaseEntity?.subdomain === "string"
        ? event.databaseEntity.subdomain
        : typeof event.entity?.subdomain === "string"
          ? event.entity.subdomain
          : null;
    if (subdomain && subdomain.trim() !== "") {
      await this.tenantHostResolver.invalidateTenantHostCacheByLabel(subdomain);
    }
  }
}

import { Inject, Injectable, OnModuleDestroy } from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import type { Request } from "express";
import { BlockList, isIP } from "node:net";
import { Repository } from "typeorm";
import type Redis from "ioredis";
import { ObservabilityMetricsService } from "../../common/observability/observability-metrics.service";
import { ConfigService } from "../../config/config.service";
import {
  normalizeInboundHostname,
  parseWorkspaceTenantLabelFromHost,
  resolveWorkspaceSlugFromNormalizedHost,
  stripHostPort,
  TENANT_MAX_HOST_LENGTH,
  TENANT_SUBDOMAIN_REGEX,
  type WorkspaceTenantLabelOutcome,
} from "@repo/tenant-host";
import { TenantEntity } from "../identity/entities/tenant.entity";
import {
  TENANT_HOST_CACHE_TTL_SECONDS,
  TENANT_RESOLVER_REDIS
} from "./tenant-resolver.constants";

export {
  normalizeInboundHostname,
  parseWorkspaceTenantLabelFromHost,
  TENANT_MAX_HOST_LENGTH,
  TENANT_SUBDOMAIN_REGEX,
  type WorkspaceTenantLabelOutcome,
};

export type TenantHostTrustModel = {
  trustProxy: boolean;
  trustedProxyCidrs: string[];
  baseDomain: string;
};

export function resolveTenantFromHost(
  host: string,
  baseDomain: string,
  reservedLabels?: Set<string>,
): string | null {
  const normalizedHost = normalizeInboundHostname(host);
  if (!normalizedHost.ok) {
    return null;
  }
  const reserved = reservedLabels ?? new Set<string>();
  return resolveWorkspaceSlugFromNormalizedHost(
    normalizedHost.host,
    baseDomain,
    reserved,
  );
}

/**
 * Maps inbound HTTP host → tenant UUID via `tenants.subdomain` (canonical id remains `tenants.id`).
 * Disabled when `TENANT_ROOT_DOMAIN` is empty.
 */
@Injectable()
export class TenantHostResolverService implements OnModuleDestroy {
  constructor(
    @Inject(ConfigService) private readonly configService: ConfigService,
    @Inject(ObservabilityMetricsService)
    private readonly observabilityMetrics: ObservabilityMetricsService,
    @InjectRepository(TenantEntity)
    private readonly tenantRepository: Repository<TenantEntity>,
    @Inject(TENANT_RESOLVER_REDIS) private readonly redis: Redis
  ) {}

  async onModuleDestroy(): Promise<void> {
    await this.redis.quit();
  }

  private tenantHostCacheKey(normalizedHost: string): string {
    return `tenant_host:${normalizedHost}`;
  }

  private buildWorkspaceHostFromLabel(label: string): string | null {
    const root = this.configService.getTenantRootDomain();
    const l = label.trim().toLowerCase();
    if (!root || !l) {
      return null;
    }
    if (!TENANT_SUBDOMAIN_REGEX.test(l)) {
      return null;
    }
    return `${l}.${root}`;
  }

  async invalidateTenantHostCacheByHostname(hostname: string): Promise<void> {
    const norm = normalizeInboundHostname(hostname);
    if (!norm.ok) {
      return;
    }
    try {
      await this.redis.del(this.tenantHostCacheKey(norm.host));
    } catch {
      /* ignore cache invalidation failures */
    }
  }

  async invalidateTenantHostCacheByLabel(label: string): Promise<void> {
    const host = this.buildWorkspaceHostFromLabel(label);
    if (!host) {
      return;
    }
    await this.invalidateTenantHostCacheByHostname(host);
  }

  private static normalizeIp(value: unknown): string | undefined {
    if (typeof value !== "string") {
      return undefined;
    }
    const trimmed = value.trim();
    if (!trimmed) {
      return undefined;
    }
    const deMapped = trimmed.startsWith("::ffff:") ? trimmed.slice(7) : trimmed;
    return isIP(deMapped) === 0 ? undefined : deMapped;
  }

  private static buildTrustedProxyBlockList(trustedProxyCidrs: string[]): BlockList {
    const blockList = new BlockList();
    for (const rawEntry of trustedProxyCidrs) {
      const entry = rawEntry.trim();
      if (!entry) {
        continue;
      }
      const slash = entry.indexOf("/");
      if (slash < 0) {
        const ip = TenantHostResolverService.normalizeIp(entry);
        if (!ip) {
          continue;
        }
        blockList.addAddress(ip, isIP(ip) === 6 ? "ipv6" : "ipv4");
        continue;
      }
      const network = TenantHostResolverService.normalizeIp(entry.slice(0, slash));
      const prefix = Number(entry.slice(slash + 1));
      if (!network || !Number.isInteger(prefix)) {
        continue;
      }
      const family = isIP(network) === 6 ? "ipv6" : "ipv4";
      const maxBits = family === "ipv6" ? 128 : 32;
      if (prefix < 0 || prefix > maxBits) {
        continue;
      }
      blockList.addSubnet(network, prefix, family);
    }
    return blockList;
  }

  private static isTrustedProxyIp(ip: string, trustedProxyCidrs: string[]): boolean {
    const blockList = TenantHostResolverService.buildTrustedProxyBlockList(trustedProxyCidrs);
    return blockList.check(ip, isIP(ip) === 6 ? "ipv6" : "ipv4");
  }

  private static shouldTrustForwardedHost(
    req: Request,
    trustModel: TenantHostTrustModel
  ): boolean {
    if (!trustModel.trustProxy) {
      return false;
    }
    // Fail closed: forwarded host is ignored unless trusted proxy CIDRs are explicitly configured.
    if (trustModel.trustedProxyCidrs.length === 0) {
      return false;
    }
    const remoteIp = TenantHostResolverService.normalizeIp(
      req.socket?.remoteAddress ?? req.connection?.remoteAddress
    );
    if (!remoteIp) {
      return false;
    }
    return TenantHostResolverService.isTrustedProxyIp(
      remoteIp,
      trustModel.trustedProxyCidrs
    );
  }

  static extractInboundHost(req: Request, trustModel: TenantHostTrustModel): string | undefined {
    let candidate: string | undefined;
    if (TenantHostResolverService.shouldTrustForwardedHost(req, trustModel)) {
      const forwarded = req.headers["x-forwarded-host"];
      if (forwarded) {
        const raw = Array.isArray(forwarded) ? forwarded[0] : forwarded;
        const first = raw.split(",")[0]?.trim() ?? "";
        const norm = normalizeInboundHostname(first);
        if (norm.ok) {
          candidate = norm.host;
        }
      }
    }

    if (!candidate) {
      const hn = typeof req.hostname === "string" ? req.hostname : "";
      const norm = normalizeInboundHostname(hn);
      if (norm.ok) {
        candidate = norm.host;
      }
    }

    return candidate;
  }

  static stripHostPort = stripHostPort;

  parseWorkspaceTenantLabel(normalizedHost: string): WorkspaceTenantLabelOutcome {
    return parseWorkspaceTenantLabelFromHost(
      normalizedHost,
      this.configService.getTenantRootDomain(),
      this.configService.getTenantHostReservedSubdomains(),
    );
  }

  /**
   * Parse `{tenantLabel}.{TENANT_ROOT_DOMAIN}` → tenant label, or `null` if not applicable.
   */
  extractTenantLabelFromHost(host: string): string | null {
    const norm = normalizeInboundHostname(host);
    if (!norm.ok) {
      return null;
    }
    const outcome = this.parseWorkspaceTenantLabel(norm.host);
    return outcome.kind === "label" ? outcome.label : null;
  }

  extractTenantLabelFromInboundRequest(req: Request): string | null {
    const inbound = TenantHostResolverService.extractInboundHost(
      req,
      this.configService.getTenantHostTrustModel()
    );
    if (!inbound) {
      return null;
    }
    const outcome = this.parseWorkspaceTenantLabel(inbound);
    return outcome.kind === "label" ? outcome.label : null;
  }

  async resolveTenantEntityByLabel(label: string): Promise<TenantEntity | null> {
    const lowered = label.trim().toLowerCase();
    // tenant-isolation:qb-exempt — queries tenants root table by subdomain, not tenant-scoped rows.
    return this.tenantRepository
      .createQueryBuilder("t")
      .where("LOWER(t.subdomain) = :sub", { sub: lowered })
      .andWhere("t.deleted_at IS NULL")
      .getOne();
  }

  async resolveTenantEntityFromHost(host: string): Promise<TenantEntity | null> {
    const norm = normalizeInboundHostname(host);
    if (!norm.ok) {
      return null;
    }
    const outcome = this.parseWorkspaceTenantLabel(norm.host);
    if (outcome.kind !== "label") {
      return null;
    }
    const cacheKey = this.tenantHostCacheKey(norm.host);
    try {
      const cachedTenantId = await this.redis.get(cacheKey);
      if (cachedTenantId && cachedTenantId.trim() !== "") {
        this.observabilityMetrics.recordTenantResolverCacheHit();
        // tenant-isolation:qb-exempt — loads TenantEntity by primary id from trusted cache entry.
        return this.tenantRepository
          .createQueryBuilder("t")
          .where("t.id = :id", { id: cachedTenantId.trim() })
          .andWhere("t.deleted_at IS NULL")
          .getOne();
      }
    } catch {
      /* resolver cache failure must not break tenant resolution */
    }

    this.observabilityMetrics.recordTenantResolverCacheMiss();
    const tenant = await this.resolveTenantEntityByLabel(outcome.label);
    if (!tenant) {
      return null;
    }
    try {
      await this.redis.set(
        cacheKey,
        tenant.id,
        "EX",
        TENANT_HOST_CACHE_TTL_SECONDS
      );
    } catch {
      /* ignore cache set failures */
    }
    return tenant;
  }

  async resolveTenantEntityFromRequest(req: Request): Promise<TenantEntity | null> {
    const inbound = TenantHostResolverService.extractInboundHost(
      req,
      this.configService.getTenantHostTrustModel()
    );
    if (!inbound) {
      return null;
    }
    const outcome = this.parseWorkspaceTenantLabel(inbound);
    if (outcome.kind !== "label") {
      return null;
    }
    return this.resolveTenantEntityByLabel(outcome.label);
  }

  async resolveTenantIdFromHost(host: string): Promise<string | null> {
    const row = await this.resolveTenantEntityFromHost(host);
    return row?.id ?? null;
  }

  async resolveTenantIdFromRequest(req: Request): Promise<string | null> {
    const row = await this.resolveTenantEntityFromRequest(req);
    return row?.id ?? null;
  }
}

import { Inject, Injectable } from "@nestjs/common";
import { InjectDataSource } from "@nestjs/typeorm";
import type { DataSource, QueryRunner } from "typeorm";
import { LoggerService } from "../../common/logger/logger.service";
import { RequestContextService } from "../../common/request-context/request-context.service";

type AcceptInviteResult =
  | {
      ok: true;
      out_tenant_id: string;
      out_role: string;
      error_code: null;
    }
  | {
      ok: false;
      out_tenant_id: null;
      out_role: null;
      error_code:
        | "INVITE_NOT_FOUND"
        | "INVITE_EXPIRED"
        | "INVITE_ALREADY_ACCEPTED"
        | "INVITE_EMAIL_MISMATCH"
        | "OWNER_ROLE_INVITE_FORBIDDEN";
    };

@Injectable()
export class TenantManagementDbService {
  constructor(
    @InjectDataSource() private readonly dataSource: DataSource,
    @Inject(RequestContextService)
    private readonly requestContextService: RequestContextService,
    @Inject(LoggerService) private readonly loggerService: LoggerService
  ) {}

  async listUserWorkspacesForAuth(userId: string): Promise<
    Array<{
      tenant_id: string;
      tenant_name: string;
      tenant_subdomain: string;
      role: string;
      session_version: number;
    }>
  > {
    return this.runWithRowSecurityBypass(
      "list_user_workspaces_for_auth",
      async (queryRunner) =>
        queryRunner.query(
          `SELECT ut.tenant_id::text AS tenant_id,
                  t.name::text AS tenant_name,
                  COALESCE(NULLIF(trim(t.subdomain), ''), '')::text AS tenant_subdomain,
                  ut.role::text AS role,
                  ut.session_version::integer AS session_version
             FROM user_tenants ut
             INNER JOIN tenants t ON t.id = ut.tenant_id AND t.deleted_at IS NULL
            WHERE ut.user_id = $1::uuid
              AND ut.deleted_at IS NULL`,
          [userId]
        )
    );
  }

  async acceptWorkspaceInviteByToken(
    inviteToken: string,
    userId: string
  ): Promise<AcceptInviteResult> {
    return this.runWithRowSecurityBypass(
      "accept_workspace_invite",
      async (queryRunner) => this.acceptInviteInTransaction(queryRunner, inviteToken, userId)
    );
  }

  private async runWithRowSecurityBypass<T>(
    operation: string,
    fn: (queryRunner: QueryRunner) => Promise<T>
  ): Promise<T> {
    const requestId = this.requestContextService.tryGetRequestId();
    const queryRunner = this.dataSource.createQueryRunner();
    await queryRunner.connect();
    await queryRunner.startTransaction();
    try {
      // Local transaction-only bypass for legacy bootstrap/auth flows.
      await queryRunner.query("SET LOCAL row_security = off");
      this.loggerService.warn("tenant management row_security bypass opened", {
        operation,
        requestId
      });
      const result = await fn(queryRunner);
      await queryRunner.commitTransaction();
      return result;
    } catch (error) {
      if (queryRunner.isTransactionActive) {
        await queryRunner.rollbackTransaction();
      }
      this.loggerService.error("tenant management row_security bypass failed", {
        operation,
        requestId,
        error: error instanceof Error ? error.message : String(error)
      });
      throw error;
    } finally {
      await queryRunner.release();
    }
  }

  private async acceptInviteInTransaction(
    queryRunner: QueryRunner,
    inviteToken: string,
    userId: string
  ): Promise<AcceptInviteResult> {
    // Contract: TS validates, DB mutates atomically.
    const result = await queryRunner.query(
      `SELECT id, tenant_id, role, email, expires_at, status
         FROM workspace_invites
        WHERE invite_token = $1
        FOR UPDATE`,
      [inviteToken]
    );
    const rows = result as Array<{
      id: string;
      tenant_id: string;
      role: string;
      email: string;
      expires_at: Date;
      status: "PENDING" | "ACCEPTED" | "EXPIRED";
    }>;
    const invite = rows[0];
    if (!invite) {
      return {
        ok: false,
        out_tenant_id: null,
        out_role: null,
        error_code: "INVITE_NOT_FOUND"
      };
    }

    if (invite.status === "ACCEPTED") {
      return {
        ok: false,
        out_tenant_id: null,
        out_role: null,
        error_code: "INVITE_ALREADY_ACCEPTED"
      };
    }

    if (invite.status === "EXPIRED" || new Date(invite.expires_at).getTime() < Date.now()) {
      await queryRunner.query(
        `UPDATE workspace_invites
            SET status = 'EXPIRED'
          WHERE id = $1::uuid`,
        [invite.id]
      );
      return {
        ok: false,
        out_tenant_id: null,
        out_role: null,
        error_code: "INVITE_EXPIRED"
      };
    }

    await queryRunner.query(
      `INSERT INTO user_tenants (
         id,
         tenant_id,
         created_at,
         updated_at,
         deleted_at,
         user_id,
         role,
         session_version
       )
       VALUES (uuid_generate_v4(), $1::uuid, now(), now(), NULL, $2::uuid, $3::varchar, 1)
       ON CONFLICT (user_id, tenant_id)
       DO UPDATE SET
         deleted_at = NULL,
         role = EXCLUDED.role,
         updated_at = now(),
         session_version = user_tenants.session_version + 1`,
      [invite.tenant_id, userId, invite.role]
    );

    await queryRunner.query(
      `UPDATE workspace_invites
          SET status = 'ACCEPTED'
        WHERE id = $1::uuid`,
      [invite.id]
    );

    return {
      ok: true,
      out_tenant_id: invite.tenant_id,
      out_role: invite.role,
      error_code: null
    };
  }
}

import { BadRequestException, ForbiddenException, Injectable, NotFoundException } from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import { Brackets, Repository } from "typeorm";
import {
  tenantContextMissingError,
  tenantScopedResourceNotFoundError
} from "../../../common/errors/error-response-builders";
import { RequestContextService } from "../../../common/request-context/request-context.service";
import { ListToursQueryDto } from "../dto/list-tours-query.dto";
import { mapTourEntityToResponseDto, TourResponseDto } from "../dto/tour-response.dto";
import { TourEntity, TourLifecycleStatus } from "../entities/tour.entity";
import { TOUR_RESPONSE_RELATIONS } from "../constants/tour-response-relations";
import { applyRegionalTourListScope, assertTourVisibleInRegionalScope } from "../utils/apply-regional-tour-list-scope";
import { buildRegionalTourListScopeFromRequest } from "../utils/regional-tour-scope-from-request";

/**
 * Application slice: **catalog read** (tenant-scoped list + get-by-id + leader aggregate).
 * Mutations stay on {@link ToursService}; this service owns only read queries and DTO mapping.
 */
@Injectable()
export class ToursCatalogReadApplicationService {
  constructor(
    @InjectRepository(TourEntity)
    private readonly tourRepository: Repository<TourEntity>,
    private readonly requestContextService: RequestContextService
  ) {}

  async listTours(query: ListToursQueryDto): Promise<{
    items: TourResponseDto[];
    total: number;
    page: number;
    limit: number;
  }> {
    const tenantId = this.requestContextService.resolveEffectiveTenantId();
    if (!tenantId) {
      throw new ForbiddenException(tenantContextMissingError());
    }

    const page = query.page ?? 1;
    const limit = query.limit ?? 10;
    const search = query.search?.trim() ?? "";

    const hasCursorId =
      typeof query.cursor_id === "string" && query.cursor_id.trim() !== "";
    const hasCursorAt =
      typeof query.cursor_created_at === "string" && query.cursor_created_at.trim() !== "";
    if (hasCursorId !== hasCursorAt) {
      throw new BadRequestException({
        error: {
          code: "VALIDATION_FIELD_FORMAT_INVALID",
          message: "cursor_id and cursor_created_at must both be provided for keyset pagination"
        }
      });
    }
    const useKeyset = hasCursorId && hasCursorAt;
    const cursorAt = useKeyset ? new Date(query.cursor_created_at as string) : null;
    const cursorId = useKeyset ? (query.cursor_id as string).trim() : null;
    if (useKeyset && cursorAt !== null && Number.isNaN(cursorAt.getTime())) {
      throw new BadRequestException({
        error: {
          code: "VALIDATION_FIELD_FORMAT_INVALID",
          message: "cursor_created_at must be a valid ISO-8601 date-time"
        }
      });
    }

    const qb = this.tourRepository
      .createQueryBuilder("t")
      .leftJoinAndSelect("t.details", "details")
      .leftJoinAndSelect("t.destination", "destination")
      .leftJoinAndSelect("destination.region", "destinationRegion")
      .where("t.tenantId = :tenantId", { tenantId })
      .orderBy("t.createdAt", "DESC")
      .addOrderBy("t.id", "DESC");

    if (search.length > 0) {
      qb.andWhere("t.search_vector @@ plainto_tsquery('simple', :fts)", {
        fts: search
      });
    }

    if (query.status === "active") {
      qb.andWhere("t.lifecycleStatus = :lifecycleStatus", {
        lifecycleStatus: TourLifecycleStatus.DRAFT
      });
    } else if (query.status === "completed") {
      qb.andWhere("t.lifecycleStatus = :lifecycleStatus", {
        lifecycleStatus: TourLifecycleStatus.OPEN
      });
    } else if (query.status === "archived") {
      qb.andWhere("t.lifecycleStatus IN (:...archivedStatuses)", {
        archivedStatuses: [TourLifecycleStatus.CLOSED, TourLifecycleStatus.CANCELLED]
      });
    }

    applyRegionalTourListScope(qb, buildRegionalTourListScopeFromRequest(this.requestContextService));

    if (useKeyset && cursorAt !== null && cursorId !== null) {
      qb.andWhere(
        new Brackets((b) => {
          b.where("t.createdAt < :cAt", { cAt: cursorAt }).orWhere(
            new Brackets((inner) => {
              inner
                .where("t.createdAt = :cAt", { cAt: cursorAt })
                .andWhere("t.id < :cId", { cId: cursorId });
            })
          );
        })
      );
    }

    const includeTotal = query.include_total !== false;
    const total = includeTotal ? await qb.getCount() : -1;

    const dataQb = qb.clone();
    if (!useKeyset) {
      dataQb.skip((page - 1) * limit);
    }
    const rows = await dataQb.take(limit).getMany();

    const items = rows.map((row) => mapTourEntityToResponseDto(row));

    return { items, total, page, limit };
  }

  async getTourById(tourId: string): Promise<TourResponseDto> {
    const tenantId = this.requestContextService.resolveEffectiveTenantId();
    if (!tenantId) {
      throw new ForbiddenException(tenantContextMissingError());
    }

    const tour = await this.tourRepository.findOne({
      where: {
        id: tourId,
        tenantId
      },
      relations: TOUR_RESPONSE_RELATIONS
    });

    if (!tour) {
      throw new NotFoundException(tenantScopedResourceNotFoundError());
    }

    const regionalScope = buildRegionalTourListScopeFromRequest(this.requestContextService);
    if (!assertTourVisibleInRegionalScope(tour, regionalScope)) {
      throw new NotFoundException(tenantScopedResourceNotFoundError());
    }

    return mapTourEntityToResponseDto(tour);
  }

  async getLeaderWorkspaceAggregate(limit = 200): Promise<{
    tours: TourResponseDto[];
    meta: {
      partial: boolean;
      total: number;
    };
  }> {
    const { items, total } = await this.listTours({
      page: 1,
      limit,
      search: ""
    });
    return {
      tours: items,
      meta: {
        partial: total > items.length,
        total
      }
    };
  }
}

import { Controller, Get, Query, UseGuards } from "@nestjs/common";
import { ApiBearerAuth, ApiOperation, ApiQuery, ApiTags } from "@nestjs/swagger";
import { AuthorizationPresenceGuard } from "../auth/authorization-presence.guard";
import { Roles } from "../auth/roles.decorator";
import { UserRole } from "../../common/auth/user-role.enum";
import { RolesGuard } from "../auth/roles.guard";
import { AbilitiesGuard } from "../../common/casl/abilities.guard";
import { CaslMirrorAbilitiesGuard } from "../../common/casl/casl-mirror-abilities.guard";
import { AbilityAction } from "../../common/casl/ability-actions";
import { CheckAbilities } from "../../common/casl/check-abilities.decorator";
import { RegistrationsService } from "../registrations/registrations.service";
import { ToursService } from "./tours.service";
import type { TourResponseDto } from "./dto/tour-response.dto";

@ApiTags("Dashboard")
@Controller("api/v2/dashboard")
@UseGuards(AuthorizationPresenceGuard, RolesGuard, AbilitiesGuard, CaslMirrorAbilitiesGuard)
@ApiBearerAuth()
export class DashboardAggregateController {
  constructor(
    private readonly toursService: ToursService,
    private readonly registrationsService: RegistrationsService,
  ) {}

  @Get("leader-workspace")
  @Roles(UserRole.Owner, UserRole.Admin, UserRole.Leader)
  @CheckAbilities(({ ability }) => ability.can(AbilityAction.Read, "Tour"))
  @ApiOperation({
    summary: "Leader workspace aggregate",
    description: "Returns first-page tenant tours for dashboard aggregates."
  })
  @ApiQuery({
    name: "limit",
    required: false,
    description: "Max tours returned for aggregate payload",
    schema: { default: 200, minimum: 1, maximum: 500 }
  })
  async getLeaderWorkspaceAggregate(
    @Query("limit") limitRaw?: string
  ): Promise<{ tours: TourResponseDto[]; meta: { partial: boolean; total: number } }> {
    const parsed = Number(limitRaw);
    const limit = Number.isInteger(parsed) && parsed > 0 ? Math.min(parsed, 500) : 200;
    return this.toursService.getLeaderWorkspaceAggregate(limit);
  }

  @Get("leader-summary")
  @Roles(UserRole.Owner, UserRole.Admin, UserRole.Leader)
  @CheckAbilities(({ ability }) => ability.can(AbilityAction.Read, "Tour"))
  @ApiOperation({
    summary: "Leader dashboard summary",
    description:
      "Single round-trip counts for the leader dashboard (tour total + registration pending/total).",
  })
  async getLeaderDashboardSummary(): Promise<{
    tour_total: number;
    tour_partial: boolean;
    registration_pending_count: number;
    registration_total_count: number;
  }> {
    const [workspace, registrationStats] = await Promise.all([
      this.toursService.getLeaderWorkspaceAggregate(200),
      this.registrationsService.getLeaderRegistrationStats(),
    ]);
    return {
      tour_total: workspace.meta.total,
      tour_partial: workspace.meta.partial,
      registration_pending_count: registrationStats.pending_count,
      registration_total_count: registrationStats.total_count,
    };
  }

  @Get("leader-registration-rows")
  @Roles(UserRole.Owner, UserRole.Admin, UserRole.Leader)
  @CheckAbilities(({ ability }) => ability.can(AbilityAction.Read, "Tour"))
  @ApiOperation({
    summary: "Leader registration index",
    description:
      "All tenant registrations with tour titles in one response (replaces per-tour registration fan-out).",
  })
  @ApiQuery({
    name: "limit",
    required: false,
    schema: { default: 5000, minimum: 1, maximum: 10000 },
  })
  async getLeaderRegistrationRows(@Query("limit") limitRaw?: string): Promise<{
    rows: Awaited<ReturnType<RegistrationsService["listLeaderRegistrationIndex"]>>["rows"];
    partial: boolean;
  }> {
    const parsed = Number(limitRaw);
    const limit = Number.isInteger(parsed) && parsed > 0 ? parsed : 5_000;
    const result = await this.registrationsService.listLeaderRegistrationIndex(limit);
    return { rows: result.rows, partial: result.partial };
  }
}

import {
  Column,
  CreateDateColumn,
  Entity,
  JoinColumn,
  OneToOne,
  PrimaryGeneratedColumn,
  UpdateDateColumn
} from "typeorm";

import { TourEntity as Tour } from "./tour.entity";
import type { TourTripDetails } from "../types/tour-trip-details.types";

export enum DifficultyLevel {
  EASY = "easy",
  MODERATE = "moderate",
  HARD = "hard",
  TECHNICAL = "technical"
}

export interface ItineraryItem {
  day: number;
  title?: string;
  description?: string;
  distanceKm?: number;
  elevationGainM?: number;
}

export type TourItineraryItem = ItineraryItem;

@Entity("tour_details")
export class TourDetails {
  @PrimaryGeneratedColumn("uuid")
  id!: string;

  @Column({ type: "uuid", name: "tour_id", unique: true })
  tourId!: string;

  @OneToOne(() => Tour, (tour) => tour.details, { nullable: false, onDelete: "CASCADE" })
  @JoinColumn({ name: "tour_id" })
  tour!: Tour;

  @Column({ type: "varchar", name: "destination_name", nullable: true })
  destinationName!: string | null;

  @Column({ type: "int", name: "elevation_m", nullable: true })
  elevationM!: number | null;

  @Column({
    type: "enum",
    enum: DifficultyLevel,
    enumName: "difficulty_level",
    name: "difficulty",
    nullable: true
  })
  difficulty!: DifficultyLevel | null;

  @Column({ type: "int", name: "duration_days", nullable: true })
  durationDays!: number | null;

  @Column({ type: "varchar", name: "meeting_point", nullable: true })
  meetingPoint!: string | null;

  @Column({ type: "jsonb", name: "itinerary", nullable: true })
  itinerary!: ItineraryItem[] | null;

  @Column({ type: "jsonb", name: "trip_details", nullable: true })
  tripDetails!: TourTripDetails | null;

  @CreateDateColumn({ type: "timestamptz", name: "created_at" })
  createdAt!: Date;

  @UpdateDateColumn({ type: "timestamptz", name: "updated_at" })
  updatedAt!: Date;
}

import { Column, Entity, Index, JoinColumn, ManyToOne, PrimaryGeneratedColumn } from "typeorm";
import { CreateDateColumn } from "typeorm";
import { TourDepartureEntity } from "./tour-departure.entity";

export enum TourPriceType {
  BASE = "base",
  EARLY_BIRD = "early_bird",
  GROUP = "group",
  VIP = "vip",
  PROMO = "promo",
  DYNAMIC = "dynamic"
}

@Entity("tour_prices")
@Index("idx_tour_prices_departure", ["tourDepartureId"])
export class TourPriceEntity {
  @PrimaryGeneratedColumn("uuid", { name: "id" })
  id!: string;

  @Column({ type: "uuid", name: "tour_departure_id" })
  tourDepartureId!: string;

