function createMutex(): {
  acquire: () => Promise<() => void>;
} {
  let queue = Promise.resolve();
  return {
    async acquire() {
      let release: () => void = () => {};
      const ticket = new Promise<void>((resolve) => {
        release = resolve;
      });
      const previous = queue;
      queue = queue.then(() => ticket);
      await previous;
      return release;
    }
  };
}

