    RegistrationStatus.PENDING,
    "aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa"
  );
  const registrationB = buildRegistration(
    RegistrationStatus.PENDING,
    "bbbbbbbb-bbbb-4bbb-8bbb-bbbbbbbbbbbb"
