  const map: Record<string, string> = {
    CITY: t("locationsTypeCity"),
    MOUNTAIN: t("locationsTypeMountain"),
    LAKE: t("locationsTypeLake"),
    OTHER: t("locationsTypeOther"),
  };
  return map[type] ?? type;
}

