export type DestinationSortableBlockProps = {
  regionId: string;
  regionTitle: string | null;
  hideWhenEmpty: boolean;
  allDestinations: SettingsDestinationDto[];
  regionNameById: Map<string, string>;
  reorderDestinations: (
    nextDestinations: SettingsDestinationDto[],
    patches: { id: string; sortOrder: number }[],
  ) => Promise<void>;
  showToast: (args: { type: "success" | "error"; message: string }) => void;
  t: SettingsTranslate;
  onEditDestination: (d: SettingsDestinationDto) => void;
  onRequestDeleteDestination: (d: SettingsDestinationDto) => void;
  onToggleDestinationActive: (d: SettingsDestinationDto, next: boolean) => void;
  destinationsMutating: boolean;
  readOnly: boolean;
};

export function DestinationSortableBlock({
  regionId,
  regionTitle,
  hideWhenEmpty,
  allDestinations,
  regionNameById,
  reorderDestinations,
  showToast,
  t,
  onEditDestination,
  onRequestDeleteDestination,
  onToggleDestinationActive,
  destinationsMutating,
  readOnly,
}: DestinationSortableBlockProps) {
  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 8 } }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates }),
  );

  const itemsInRegion = useMemo(
    () =>
      allDestinations
        .filter((d) => d.regionId === regionId)
        .sort(
          (a, b) =>
            (a.sortOrder ?? 0) - (b.sortOrder ?? 0) || a.name.localeCompare(b.name, undefined, { sensitivity: "base" }),
        ),
    [allDestinations, regionId],
  );

  const handleDragEnd = useCallback(
    (event: DragEndEvent) => {
      if (readOnly) {
        return;
      }
      const { active, over } = event;
      if (!over || active.id === over.id) {
        return;
      }
      const prevBucket = [...itemsInRegion];
      const oldIndex = prevBucket.findIndex((d) => d.id === active.id);
      const newIndex = prevBucket.findIndex((d) => d.id === over.id);
      if (oldIndex < 0 || newIndex < 0) {
        return;
      }
      const newBucket = arrayMove(prevBucket, oldIndex, newIndex);
      const patches = pickSortOrderDeltas(prevBucket, normalizeSortOrder(newBucket));
      const nextAll = applyDestinationSortOrdersForRegion(allDestinations, regionId, newBucket);
      void (async () => {
        try {
          await reorderDestinations(nextAll, patches);
          if (patches.length > 0) {
            showToast({ type: "success", message: t("locationsToastOrderUpdated") });
          }
        } catch (e) {
          showToast({
            type: "error",
            message: e instanceof Error ? e.message : t("locationsToastOrderUpdateFailed"),
          });
        }
      })();
    },
    [allDestinations, itemsInRegion, readOnly, regionId, reorderDestinations, showToast, t],
  );

  if (itemsInRegion.length === 0) {
    if (hideWhenEmpty) {
      return null;
    }
    return (
      <div className={panelStyles.destinationGroup}>
        {regionTitle ? <p className={panelStyles.destinationGroupTitle}>{regionTitle}</p> : null}
        <EmptyState
          embedded
          className={panelStyles.emptyState}
          title={t("locationsNoDestinationsInRegion")}
          description={t("locationsNoDestinationsInRegionHint")}
        />
      </div>
    );
  }

  return (
    <div className={panelStyles.destinationGroup}>
      {regionTitle ? <p className={panelStyles.destinationGroupTitle}>{regionTitle}</p> : null}
      {readOnly ? (
        <ul className={panelStyles.list}>
          {itemsInRegion.map((d) => (
            <ReadOnlyDestinationRow
              key={d.id}
              destination={d}
              regionLabel={regionNameById.get(d.regionId) ?? d.regionId}
              t={t}
            />
          ))}
        </ul>
      ) : (
        <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
          <SortableContext items={itemsInRegion.map((d) => d.id)} strategy={verticalListSortingStrategy}>
            <ul className={panelStyles.list}>
              {itemsInRegion.map((d) => (
                <SortableDestinationRow
                  key={d.id}
                  destination={d}
                  regionLabel={regionNameById.get(d.regionId) ?? d.regionId}
                  t={t}
                  onEdit={onEditDestination}
                  onDelete={onRequestDeleteDestination}
                  onToggleActive={onToggleDestinationActive}
                  mutating={destinationsMutating}
                />
              ))}
            </ul>
          </SortableContext>
        </DndContext>
      )}
    </div>
  );
}

"use client";

import { useTranslations } from "next-intl";
import { useCallback, useEffect, useMemo, useState } from "react";

import { useSettingsDestinations } from "@/hooks/use-settings-destinations";
import { useSettingsRegions } from "@/hooks/use-settings-regions";
import type { SettingsDestinationDto, SettingsRegionDto } from "@/lib/settings-locations-client";
import { normalizeSortOrder, pickSortOrderDeltas } from "@/lib/sort-order";
import { isLeaderRole, useAuth } from "@/lib/auth/auth-context";

import {
  Button,
  Card,
  CardBody,
  CardHeader,
  CardTitle,
  ConfirmDialog,
  EmptyState,
  ErrorState,
  FormField,
  LoadingState,
  Modal,
  Select,
  cn,
  useToast,
} from "@tour/ui";

import formStyles from "../settings-profile-form.module.css";
import { DestinationForm, type DestinationFormParsed } from "./destination-form";
import { DestinationSortableBlock } from "./destinations-list";
import { RegionForm, type RegionFormParsed } from "./region-form";
import { RegionList } from "./region-list";
import panelStyles from "./locations-settings-panel.module.css";

export type SettingsRegion = SettingsRegionDto;
export type SettingsDestination = SettingsDestinationDto;

export function LocationsSettingsPanel() {
  const t = useTranslations("settings");
  const { showToast } = useToast();
  const { user } = useAuth();
  const canManageWorkspace = isLeaderRole(user?.role);
  const readOnlyList = !canManageWorkspace;

  const {
    regions,
    isLoading: regionsLoading,
    error: regionsError,
    refetch: refetchRegions,
    createRegion,
    updateRegion,
    deleteRegion,
    reorderRegions,
    isMutating: regionsMutating,
  } = useSettingsRegions();

  const {
    destinations,
    isLoading: destinationsLoading,
    error: destinationsError,
    refetch: refetchDestinations,
    createDestination,
    updateDestination,
    deleteDestination,
    reorderDestinations,
    isMutating: destinationsMutating,
  } = useSettingsDestinations();

  const sortedRegions = useMemo(
    () =>
      [...regions].sort(
        (a, b) =>
          (a.sortOrder ?? 0) - (b.sortOrder ?? 0) || a.name.localeCompare(b.name, undefined, { sensitivity: "base" }),
      ),
    [regions],
  );

  const [regionFilterId, setRegionFilterId] = useState<string | null>(null);
  const [regionFormOpen, setRegionFormOpen] = useState(false);
  const [editingRegion, setEditingRegion] = useState<SettingsRegionDto | null>(null);
  const [deleteRegionTarget, setDeleteRegionTarget] = useState<SettingsRegionDto | null>(null);

  const [destinationFormOpen, setDestinationFormOpen] = useState(false);
  const [editingDestination, setEditingDestination] = useState<SettingsDestinationDto | null>(null);
  const [defaultRegionIdForNewDestination, setDefaultRegionIdForNewDestination] = useState("");
  const [deleteDestinationTarget, setDeleteDestinationTarget] = useState<SettingsDestinationDto | null>(null);

  useEffect(() => {
    if (regionFilterId && !regions.some((r) => r.id === regionFilterId)) {
      setRegionFilterId(null);
    }
  }, [regions, regionFilterId]);

  const regionNameById = useMemo(() => {
    const m = new Map<string, string>();
    for (const r of regions) {
      m.set(r.id, r.name);
    }
    return m;
  }, [regions]);

  const regionsMut = regionsMutating;
  const destMut = destinationsMutating;
  const anyMutating = regionsMut || destMut;

  const openCreateRegion = useCallback(() => {
    setEditingRegion(null);
    setRegionFormOpen(true);
  }, []);

  const openEditRegion = useCallback((r: SettingsRegionDto) => {
    setEditingRegion(r);
    setRegionFormOpen(true);
  }, []);

  const closeRegionForm = useCallback(() => {
    setRegionFormOpen(false);
    setEditingRegion(null);
  }, []);

  const onSubmitRegionForm = useCallback(
    async (values: RegionFormParsed) => {
      try {
        const payload = {
          name: values.name,
          country: values.country,
          sortOrder: values.sortOrder ?? null,
          isActive: values.isActive,
        };
        if (editingRegion) {
          await updateRegion(editingRegion.id, payload);
        } else {
          await createRegion(payload);
        }
        showToast({ type: "success", message: t("locationsToastRegionSaved") });
        closeRegionForm();
      } catch (e) {
        showToast({
          type: "error",
          message: e instanceof Error ? e.message : t("locationsToastRegionSaveFailed"),
        });
      }
    },
    [closeRegionForm, createRegion, editingRegion, showToast, t, updateRegion],
  );

  const onToggleRegionActive = useCallback(
    async (item: SettingsRegionDto, next: boolean) => {
      if (item.isActive === next) {
        return;
      }
      try {
        await updateRegion(item.id, { isActive: next });
        showToast({ type: "success", message: t("locationsToastRegionSaved") });
      } catch (e) {
        showToast({
          type: "error",
          message: e instanceof Error ? e.message : t("locationsToastRegionSaveFailed"),
        });
      }
    },
    [showToast, t, updateRegion],
  );

  const onReorderRegions = useCallback(
    async (itemIds: string[]) => {
      const byId = new Map(sortedRegions.map((r) => [r.id, r]));
      const reordered = itemIds.map((id) => byId.get(id)).filter((r): r is SettingsRegionDto => r != null);
      const nextOrdered = reordered.map((r, index) => ({ ...r, sortOrder: index }));
      const patches = pickSortOrderDeltas(sortedRegions, normalizeSortOrder(nextOrdered));
      try {
        await reorderRegions(nextOrdered, patches);
        if (patches.length > 0) {
          showToast({ type: "success", message: t("locationsToastOrderUpdated") });
        }
      } catch (e) {
        showToast({
          type: "error",
          message: e instanceof Error ? e.message : t("locationsToastOrderUpdateFailed"),
        });
      }
    },
    [reorderRegions, showToast, sortedRegions, t],
  );

  const openCreateDestination = useCallback(() => {
    setEditingDestination(null);
    setDefaultRegionIdForNewDestination(regionFilterId ?? "");
    setDestinationFormOpen(true);
  }, [regionFilterId]);

  const openEditDestination = useCallback((d: SettingsDestinationDto) => {
    setEditingDestination(d);
    setDestinationFormOpen(true);
  }, []);

  const closeDestinationForm = useCallback(() => {
    setDestinationFormOpen(false);
    setEditingDestination(null);
  }, []);

  const onSubmitDestinationForm = useCallback(
    async (values: DestinationFormParsed) => {
      try {
        const payload = {
          name: values.name,
          regionId: values.regionId,
          type: values.type,
          altitudeM: values.altitudeM,
          sortOrder: values.sortOrder ?? null,
          isActive: values.isActive,
        };
        if (editingDestination) {
          await updateDestination(editingDestination.id, payload);
        } else {
          await createDestination(payload);
        }
        showToast({ type: "success", message: t("locationsToastDestinationSaved") });
        closeDestinationForm();
      } catch (e) {
        showToast({
          type: "error",
          message: e instanceof Error ? e.message : t("locationsToastDestinationSaveFailed"),
        });
      }
    },
    [closeDestinationForm, createDestination, editingDestination, showToast, t, updateDestination],
  );

  const onToggleDestinationActive = useCallback(
    async (item: SettingsDestinationDto, next: boolean) => {
      if (item.isActive === next) {
        return;
      }
      try {
        await updateDestination(item.id, { isActive: next });
        showToast({ type: "success", message: t("locationsToastDestinationSaved") });
      } catch (e) {
        showToast({
          type: "error",
          message: e instanceof Error ? e.message : t("locationsToastDestinationSaveFailed"),
        });
      }
    },
    [showToast, t, updateDestination],
  );

  const confirmDeleteRegion = useCallback(async () => {
    if (!deleteRegionTarget) {
      return;
    }
    try {
      if (editingRegion?.id === deleteRegionTarget.id) {
        closeRegionForm();
      }
      await deleteRegion(deleteRegionTarget.id);
      showToast({ type: "success", message: t("locationsToastRegionDeleted") });
      setDeleteRegionTarget(null);
    } catch (e) {
      showToast({
        type: "error",
        message: e instanceof Error ? e.message : t("locationsToastDeleteFailed"),
      });
    }
  }, [closeRegionForm, deleteRegion, deleteRegionTarget, editingRegion?.id, showToast, t]);

  const confirmDeleteDestination = useCallback(async () => {
    if (!deleteDestinationTarget) {
      return;
    }
    try {
      if (editingDestination?.id === deleteDestinationTarget.id) {
        closeDestinationForm();
      }
      await deleteDestination(deleteDestinationTarget.id);
      showToast({ type: "success", message: t("locationsToastDestinationDeleted") });
      setDeleteDestinationTarget(null);
    } catch (e) {
      showToast({
        type: "error",
        message: e instanceof Error ? e.message : t("locationsToastDeleteFailed"),
      });
    }
  }, [closeDestinationForm, deleteDestination, deleteDestinationTarget, editingDestination?.id, showToast, t]);

  const loadError = regionsError ?? destinationsError;
  const loadErrorMessage = loadError instanceof Error ? loadError.message : String(loadError ?? "");
  const tBlock = t as (key: string, values?: Record<string, string>) => string;

  if (loadError && regions.length === 0 && destinations.length === 0 && !regionsLoading && !destinationsLoading) {
    return (
      <div className={cn(formStyles.form, panelStyles.panel)}>
        <ErrorState
          title={t("locationsLoadErrorTitle")}
          message={loadErrorMessage}
          onRetry={() => {
            void refetchRegions();
            void refetchDestinations();
          }}
        />
      </div>
    );
  }

  return (
    <div className={cn(formStyles.form, panelStyles.panel)}>
      <p className={panelStyles.catalogIntro}>{t("locationsPanelIntro")}</p>
      <div className={panelStyles.cardStack}>
        <Card>
          <CardHeader>
            <div
              style={{
                display: "flex",
                flexWrap: "wrap",
                alignItems: "center",
                justifyContent: "space-between",
                gap: "var(--space-3)",
              }}
            >
              <CardTitle>{t("locationsCardRegionsTitle")}</CardTitle>
              {canManageWorkspace ? (
                <Button type="button" variant="primary" size="sm" onClick={openCreateRegion} disabled={anyMutating}>
                  {t("locationsRegionAdd")}
                </Button>
              ) : null}
            </div>
          </CardHeader>
          <CardBody>
            {readOnlyList && regions.length > 0 ? (
              <p className={formStyles.readOnlyBanner}>{t("locationsReadOnlyBanner")}</p>
            ) : null}
            {regionsLoading ? <LoadingState message={t("locationsLoadingRegions")} /> : null}

            {!regionsLoading && regionsError && regions.length === 0 ? (
              <ErrorState
                title={t("locationsLoadErrorTitle")}
                message={regionsError instanceof Error ? regionsError.message : t("locationsLoadErrorTitle")}
                onRetry={() => void refetchRegions()}
              />
            ) : null}

            {!regionsLoading && regions.length === 0 ? (
              <EmptyState
                embedded
                className={panelStyles.emptyState}
                title={t("locationsEmptyRegionsTitle")}
                description={readOnlyList ? t("locationsReadOnlyHint") : t("locationsEmptyRegionsDescription")}
              />
            ) : null}

            {regions.length > 0 ? (
              <RegionList
                items={regions}
                onEdit={openEditRegion}
                onDelete={readOnlyList ? () => {} : (r) => setDeleteRegionTarget(r)}
                onToggleActive={onToggleRegionActive}
                onReorder={onReorderRegions}
                mutating={regionsMutating}
                readOnly={readOnlyList}
              />
            ) : null}
          </CardBody>
        </Card>

        <Card>
          <CardHeader>
            <div
              style={{
                display: "flex",
                flexWrap: "wrap",
                alignItems: "center",
                justifyContent: "space-between",
                gap: "var(--space-3)",
              }}
            >
              <CardTitle>{t("locationsCardDestinationsTitle")}</CardTitle>
              {canManageWorkspace ? (
                <Button
                  type="button"
                  variant="primary"
                  size="sm"
                  onClick={openCreateDestination}
                  disabled={anyMutating || regions.length === 0}
                >
                  {t("locationsDestinationAdd")}
                </Button>
              ) : null}
            </div>
          </CardHeader>
          <CardBody>
            {readOnlyList && destinations.length > 0 ? (
              <p className={formStyles.readOnlyBanner}>{t("locationsReadOnlyBanner")}</p>
            ) : null}
            {destinationsLoading ? <LoadingState message={t("locationsLoadingDestinations")} /> : null}

            {!destinationsLoading && destinationsError && destinations.length === 0 ? (
              <ErrorState
                title={t("locationsLoadErrorTitle")}
                message={
                  destinationsError instanceof Error ? destinationsError.message : t("locationsLoadErrorTitle")
                }
                onRetry={() => void refetchDestinations()}
              />
            ) : null}

            <div className={panelStyles.filterRow}>
              <FormField label={t("locationsFilterDestinationsLabel")}>
                <Select
                  value={regionFilterId ?? ""}
                  onChange={(e) => {
                    const v = e.target.value;
                    setRegionFilterId(v === "" ? null : v);
                  }}
                  disabled={regions.length === 0}
                >
                  <option value="">{t("locationsFilterAll")}</option>
                  {regions.map((r) => (
                    <option key={r.id} value={r.id}>
                      {r.name}
                    </option>
                  ))}
                </Select>
              </FormField>
            </div>

            {!destinationsLoading && destinations.length === 0 ? (
              <EmptyState
                embedded
                className={panelStyles.emptyState}
                title={t("locationsEmptyDestinationsTitle")}
                description={
                  regions.length === 0
                    ? t("locationsEmptyDestinationsNoRegions")
                    : readOnlyList
                      ? t("locationsReadOnlyHint")
                      : t("locationsEmptyDestinationsDescription")
                }
              />
            ) : null}

            {destinations.length > 0 ? (
              regionFilterId ? (
                <DestinationSortableBlock
                  regionId={regionFilterId}
                  regionTitle={t("locationsRegionSubheading", {
                    name: regionNameById.get(regionFilterId) ?? regionFilterId,
                  })}
                  hideWhenEmpty={false}
                  allDestinations={destinations}
                  regionNameById={regionNameById}
                  reorderDestinations={reorderDestinations}
                  showToast={showToast}
                  t={tBlock}
                  onEditDestination={openEditDestination}
                  onRequestDeleteDestination={
                    readOnlyList ? () => {} : (d) => setDeleteDestinationTarget(d)
                  }
                  onToggleDestinationActive={onToggleDestinationActive}
                  destinationsMutating={destinationsMutating}
                  readOnly={readOnlyList}
                />
              ) : (
                regions.map((r) => (
                  <DestinationSortableBlock
                    key={r.id}
                    regionId={r.id}
                    regionTitle={t("locationsRegionSubheading", { name: r.name })}
                    hideWhenEmpty
                    allDestinations={destinations}
                    regionNameById={regionNameById}
                    reorderDestinations={reorderDestinations}
                    showToast={showToast}
                    t={tBlock}
                    onEditDestination={openEditDestination}
                    onRequestDeleteDestination={
                      readOnlyList ? () => {} : (d) => setDeleteDestinationTarget(d)
                    }
                    onToggleDestinationActive={onToggleDestinationActive}
                    destinationsMutating={destinationsMutating}
                    readOnly={readOnlyList}
                  />
                ))
              )
            ) : null}
          </CardBody>
        </Card>
      </div>

      <Modal
        open={regionFormOpen}
        onClose={closeRegionForm}
        title={editingRegion ? t("locationsRegionEditTitle") : t("locationsRegionAddTitle")}
        footer={null}
      >
        <RegionForm
          editing={editingRegion}
          onSubmit={onSubmitRegionForm}
          onCancel={closeRegionForm}
          isPending={regionsMutating}
        />
      </Modal>

      <Modal
        open={destinationFormOpen}
        onClose={closeDestinationForm}
        title={editingDestination ? t("locationsDestinationEditTitle") : t("locationsDestinationAddTitle")}
        footer={null}
      >
        <DestinationForm
          editing={editingDestination}
          defaultRegionIdWhenCreating={defaultRegionIdForNewDestination}
          allRegions={regions}
          onSubmit={onSubmitDestinationForm}
          onCancel={closeDestinationForm}
          isPending={destinationsMutating}
        />
      </Modal>

      <ConfirmDialog
        open={deleteRegionTarget != null}
        title={t("locationsDeleteRegionConfirmTitle")}
        description={
          deleteRegionTarget
            ? t("locationsDeleteRegionConfirmDescription", { name: deleteRegionTarget.name })
            : undefined
        }
        confirmLabel={t("locationsDeleteConfirmAction")}
        cancelLabel={t("locationsModalCancel")}
        variant="danger"
        onConfirm={() => void confirmDeleteRegion()}
        onCancel={() => setDeleteRegionTarget(null)}
      />

      <ConfirmDialog
        open={deleteDestinationTarget != null}
        title={t("locationsDeleteDestinationConfirmTitle")}
        description={
          deleteDestinationTarget
            ? t("locationsDeleteDestinationConfirmDescription", { name: deleteDestinationTarget.name })
            : undefined
        }
        confirmLabel={t("locationsDeleteConfirmAction")}
        cancelLabel={t("locationsModalCancel")}
        variant="danger"
        onConfirm={() => void confirmDeleteDestination()}
        onCancel={() => setDeleteDestinationTarget(null)}
      />
    </div>
  );
}

"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import { useTranslations } from "next-intl";
import { useEffect, useId, useMemo } from "react";
import type { Resolver } from "react-hook-form";
import { Controller, useForm } from "react-hook-form";
import { z } from "zod";

import { PersianNumberInput } from "@/components/forms/PersianNumberInput";
import type { SettingsRegionDto } from "@/lib/settings-locations-client";

import { Button, Checkbox, FormField, Input } from "@tour/ui";

import formStyles from "../settings-profile-form.module.css";
import panelStyles from "./locations-settings-panel.module.css";

export type RegionFormParsed = {
  name: string;
  country: string | null;
  sortOrder: number | undefined;
  isActive: boolean;
};

type RegionFormInput = {
  name: string;
  country: string;
  sortOrder: string;
  isActive: boolean;
};

export type RegionFormProps = {
  editing: SettingsRegionDto | null;
  onSubmit: (values: RegionFormParsed) => Promise<void>;
  onCancel: () => void;
  isPending: boolean;
};

export function RegionForm({ editing, onSubmit, onCancel, isPending }: RegionFormProps) {
  const t = useTranslations("settings");
  const activeId = useId();
  const activeDomId = `loc-region-active-${activeId.replace(/:/g, "")}`;

  const schema = useMemo(
    () =>
      z.object({
        name: z.string().trim().min(1, t("locationsValidationRegionName")),
        country: z.string().trim().max(128, t("locationsValidationCountryMax")).optional(),
        sortOrder: z
          .string()
          .trim()
          .optional()
          .transform((v) => (v && v !== "" ? Number(v) : undefined))
          .refine((v) => v === undefined || !Number.isNaN(v), {
            message: t("locationsValidationOrderNumber"),
          }),
        isActive: z.boolean(),
      }),
    [t],
  );

  const resolver = useMemo(() => zodResolver(schema) as Resolver<RegionFormInput, unknown, RegionFormParsed>, [schema]);

  const form = useForm<RegionFormInput, unknown, RegionFormParsed>({
    resolver,
    defaultValues: {
      name: "",
      country: "",
      sortOrder: "",
      isActive: true,
    },
  });

  const { register, control, handleSubmit, reset, formState } = form;
  const errors = formState.errors;

  useEffect(() => {
    if (editing) {
      reset({
        name: editing.name,
        country: editing.country ?? "",
        sortOrder: editing.sortOrder != null ? String(editing.sortOrder) : "",
        isActive: Boolean(editing.isActive),
      });
    } else {
      reset({
        name: "",
        country: "",
        sortOrder: "",
        isActive: true,
      });
    }
  }, [editing, reset]);

  return (
    <form
      className={panelStyles.formBlock}
      onSubmit={handleSubmit(async (values) => {
        const countryRaw = values.country;
        const countryValue =
          typeof countryRaw === "string" && countryRaw.trim() !== "" ? countryRaw.trim() : null;
        await onSubmit({
          name: values.name.trim(),
          country: countryValue,
          sortOrder: values.sortOrder,
          isActive: values.isActive,
        });
      })}
      noValidate
    >
      <FormField
        label={t("locationsRegionNameLabel")}
        description={t("locationsRegionNameHint")}
        required
        error={errors.name?.message}
      >
        <Input autoComplete="off" aria-invalid={errors.name ? true : undefined} {...register("name")} />
      </FormField>
      <FormField label={t("locationsCountryLabel")} description={t("locationsCountryHint")} error={errors.country?.message}>
        <Input autoComplete="off" {...register("country")} />
      </FormField>
      <FormField label={t("locationsSortOrderLabel")} description={t("locationsSortOrderHint")} error={errors.sortOrder?.message}>
        <Controller
          control={control}
          name="sortOrder"
          render={({ field }) => (
            <PersianNumberInput
              autoComplete="off"
              aria-invalid={errors.sortOrder ? true : undefined}
              numericMode="integer"
              value={field.value ?? ""}
              onChange={field.onChange}
              onBlur={field.onBlur}
              name={field.name}
              ref={field.ref}
            />
          )}
        />
      </FormField>
      <FormField
        htmlFor={activeDomId}
        label={t("locationsActiveLabel")}
        description={t("locationsActiveHint")}
        error={errors.isActive?.message}
      >
        <Controller
          control={control}
          name="isActive"
          render={({ field }) => (
            <Checkbox
              bare
              id={activeDomId}
              name={field.name}
              ref={field.ref}
              checked={field.value}
              onBlur={field.onBlur}
              onChange={(e) => field.onChange(e.currentTarget.checked)}
            />
          )}
        />
      </FormField>
      <div className={formStyles.actions}>
        <Button type="submit" variant="primary" loading={isPending} disabled={isPending}>
          {editing ? t("locationsSaveRegionEdit") : t("locationsSaveRegionCreate")}
        </Button>
        <Button type="button" variant="secondary" disabled={isPending} onClick={onCancel}>
          {t("locationsModalCancel")}
        </Button>
      </div>
    </form>
  );
}

"use client";

import {
  DndContext,
  type DragEndEvent,
  KeyboardSensor,
  PointerSensor,
  closestCenter,
  useSensor,
  useSensors,
} from "@dnd-kit/core";
import {
  SortableContext,
  arrayMove,
  sortableKeyboardCoordinates,
  useSortable,
  verticalListSortingStrategy,
} from "@dnd-kit/sortable";
import { CSS } from "@dnd-kit/utilities";
import { useTranslations } from "next-intl";
import type { CSSProperties } from "react";
import { useCallback, useMemo } from "react";

import type { SettingsRegionDto } from "@/lib/settings-locations-client";

import { Button, Checkbox } from "@tour/ui";

import panelStyles from "./locations-settings-panel.module.css";

type SortableRegionRowProps = {
  region: SettingsRegionDto;
  onEdit: (r: SettingsRegionDto) => void;
  onDelete: (r: SettingsRegionDto) => void;
  onToggleActive: (r: SettingsRegionDto, next: boolean) => void;
  mutating: boolean;
};

function SortableRegionRow({ region, onEdit, onDelete, onToggleActive, mutating }: SortableRegionRowProps) {
  const t = useTranslations("settings");
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: region.id,
  });
  const style: CSSProperties = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.92 : 1,
    position: "relative",
    zIndex: isDragging ? 2 : undefined,
  };

  return (
    <li ref={setNodeRef} style={style} className={panelStyles.listItem}>
      <div className={panelStyles.listItemInner}>
        <button
          type="button"
          className={panelStyles.dragHandle}
          aria-label={t("locationsDragHandleLabel")}
          {...attributes}
          {...listeners}
        >
          ⠿
        </button>
        <div className={panelStyles.listItemMain}>
          <div>
            <strong>{region.name}</strong>
            {region.country ? <span className={panelStyles.listItemMeta}>({region.country})</span> : null}
            <span className={panelStyles.listItemMeta}>
              {t("locationsOrderInList", { n: String(region.sortOrder ?? 0) })}
            </span>
            {!region.isActive ? <span className={panelStyles.listItemBadge}>— {t("locationsInactiveBadge")}</span> : null}
          </div>
          <div className={panelStyles.listItemActions}>
            <label
              className={panelStyles.listItemMeta}
              style={{ display: "inline-flex", alignItems: "center", gap: 6 }}
            >
              <Checkbox
                bare
                checked={region.isActive}
                disabled={mutating}
                onChange={(e) => onToggleActive(region, e.currentTarget.checked)}
                aria-label={t("locationsActiveLabel")}
              />
              <span>{t("locationsActiveLabel")}</span>
            </label>
            <Button type="button" variant="ghost" size="sm" onClick={() => onEdit(region)} disabled={mutating}>
              {t("locationsEdit")}
            </Button>
            <Button type="button" variant="danger" size="sm" onClick={() => void onDelete(region)} disabled={mutating}>
              {t("locationsDeleteRegion")}
            </Button>
          </div>
        </div>
      </div>
    </li>
  );
}

export type RegionListProps = {
  items: SettingsRegionDto[];
  onEdit: (item: SettingsRegionDto) => void;
  onDelete: (item: SettingsRegionDto) => void;
  onToggleActive: (item: SettingsRegionDto, next: boolean) => void;
  onReorder: (itemIds: string[]) => Promise<void>;
  mutating: boolean;
  readOnly?: boolean;
};

export function RegionList({
  items,
  onEdit,
  onDelete,
  onToggleActive,
  onReorder,
  mutating,
  readOnly = false,
}: RegionListProps) {
  const t = useTranslations("settings");
  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 8 } }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates }),
  );

  const sorted = useMemo(
    () =>
      [...items].sort(
        (a, b) =>
          (a.sortOrder ?? 0) - (b.sortOrder ?? 0) || a.name.localeCompare(b.name, undefined, { sensitivity: "base" }),
      ),
    [items],
  );

  const handleDragEnd = useCallback(
    (event: DragEndEvent) => {
      const { active, over } = event;
      if (!over || active.id === over.id) {
        return;
      }
      const oldIndex = sorted.findIndex((r) => r.id === active.id);
      const newIndex = sorted.findIndex((r) => r.id === over.id);
      if (oldIndex < 0 || newIndex < 0) {
        return;
      }
      const newOrder = arrayMove(sorted, oldIndex, newIndex);
      const itemIds = newOrder.map((r) => r.id);
      const prevIds = sorted.map((r) => r.id);
      if (itemIds.every((id, i) => id === prevIds[i])) {
        return;
      }
      void onReorder(itemIds);
    },
    [onReorder, sorted],
  );

  if (readOnly) {
    return (
      <ul className={panelStyles.list}>
        {sorted.map((region) => (
          <li key={region.id} className={panelStyles.listItem}>
            <div className={panelStyles.listItemInner}>
              <div className={panelStyles.listItemMain}>
                <div>
                  <strong>{region.name}</strong>
                  {region.country ? <span className={panelStyles.listItemMeta}>({region.country})</span> : null}
                  <span className={panelStyles.listItemMeta}>
                    {t("locationsOrderInList", { n: String(region.sortOrder ?? 0) })}
                  </span>
                  {!region.isActive ? (
                    <span className={panelStyles.listItemBadge}>— {t("locationsInactiveBadge")}</span>
                  ) : null}
                </div>
              </div>
            </div>
          </li>
        ))}
      </ul>
    );
  }

  return (
    <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
      <SortableContext items={sorted.map((r) => r.id)} strategy={verticalListSortingStrategy}>
        <ul className={panelStyles.list}>
          {sorted.map((region) => (
            <SortableRegionRow
              key={region.id}
              region={region}
              onEdit={onEdit}
              onDelete={onDelete}
              onToggleActive={onToggleActive}
              mutating={mutating}
            />
          ))}
        </ul>
      </SortableContext>
    </DndContext>
  );
}

"use client";

import { cn, Button, FormField, Input, useToast } from "@tour/ui";
import { useLocale, useTranslations } from "next-intl";
import { useMemo, useState } from "react";

import { normalizeOtpPhoneInput } from "@/lib/otp-phone-normalize";
import { convertNumbers, toEnglishIntegerString, uiLocaleDigits } from "../../../src/lib/number-utils";

import styles from "./settings-profile-form.module.css";
import { pickMeErrorMessage } from "@/lib/me-api-error";

import type { RefreshWorkspaceMeOptions, WorkspaceMeData } from "./workspace-me-provider";

export type PhoneSettingsPanelProps = {
  me: WorkspaceMeData;
  refresh: (opts?: RefreshWorkspaceMeOptions) => Promise<void>;
};

type PhoneStep = "idle" | "new_number" | "otp";

export function PhoneSettingsPanel({ me, refresh }: PhoneSettingsPanelProps) {
  const t = useTranslations("settings");
  const locale = useLocale();
  const { showToast } = useToast();

  const [step, setStep] = useState<PhoneStep>("idle");
  const [newMobile, setNewMobile] = useState("");
  const [otp, setOtp] = useState("");
  const [challengeId, setChallengeId] = useState<string | null>(null);
  const [requesting, setRequesting] = useState(false);
  const [verifying, setVerifying] = useState(false);
  const [phoneError, setPhoneError] = useState<string | undefined>(undefined);
  const [otpError, setOtpError] = useState<string | undefined>(undefined);
  const [phoneSuccessInline, setPhoneSuccessInline] = useState("");

  const currentPhone =
    typeof me.phone === "string" && me.phone.trim() !== "" ? me.phone.trim() : null;

  const phoneBadge = useMemo(() => {
    if (!currentPhone) {
      return { kind: "none" as const, label: t("phoneStatusNoNumber") };
    }
    if (me.is_phone_verified === true) {
      return { kind: "verified" as const, label: t("phoneStatusVerified") };
    }
    return { kind: "unverified" as const, label: t("phoneStatusUnverified") };
  }, [currentPhone, me.is_phone_verified, t]);

  const phoneBadgeClass =
    phoneBadge.kind === "verified"
      ? styles.badgeVerified
      : phoneBadge.kind === "unverified"
        ? styles.badgeUnverified
        : styles.badgeNeutral;

  function goIdle(): void {
    setStep("idle");
    setNewMobile("");
    setOtp("");
    setChallengeId(null);
    setPhoneError(undefined);
    setOtpError(undefined);
  }

  async function requestCode(): Promise<void> {
    setOtpError(undefined);
    setPhoneSuccessInline("");
    const normalized = normalizeOtpPhoneInput(newMobile);
    if (normalized.length < 8) {
      const msg = t("phoneValidationTooShort");
      setPhoneError(msg);
      showToast({ type: "error", message: msg });
      return;
    }
    setPhoneError(undefined);
    setRequesting(true);
    try {
      const res = await fetch("/api/me/change-mobile/request", {
        method: "POST",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ new_mobile: normalized }),
      });
      const body = (await res.json().catch(() => ({}))) as { challenge_id?: string };
      if (!res.ok || typeof body.challenge_id !== "string") {
        const msg = pickMeErrorMessage(body, t("phoneRequestCodeFailedToast"), t);
        setPhoneError(msg);
        showToast({ type: "error", message: msg });
        return;
      }
      setChallengeId(body.challenge_id);
      setOtp("");
      setStep("otp");
      showToast({ type: "success", message: t("phoneCodeSentToast") });
    } catch {
      const msg = t("phoneRequestCodeFailedToast");
      setPhoneError(msg);
      showToast({ type: "error", message: msg });
    } finally {
      setRequesting(false);
    }
  }

  async function verifyCode(): Promise<void> {
    setPhoneSuccessInline("");
    if (!challengeId) {
      const msg = t("phoneRequestCodeFirstToast");
      setOtpError(msg);
      showToast({ type: "error", message: msg });
      return;
    }
    const code = toEnglishIntegerString(otp);
    if (code.length < 1) {
      const msg = t("phoneOtpRequiredToast");
      setOtpError(msg);
      showToast({ type: "error", message: msg });
      return;
    }
    setOtpError(undefined);
    setVerifying(true);
    try {
      const res = await fetch("/api/me/change-mobile/verify", {
        method: "POST",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ challenge_id: challengeId, code }),
      });
      const body = (await res.json().catch(() => ({}))) as { status?: string };
      if (!res.ok || body.status !== "mobile_changed") {
        const msg = pickMeErrorMessage(body, t("phoneVerifyFailedToast"), t);
        setOtpError(msg);
        showToast({ type: "error", message: msg });
        return;
      }
      setPhoneSuccessInline(t("phoneChangedInlineSuccess"));
      showToast({ type: "success", message: t("phoneChangedToast") });
      goIdle();
      await refresh({ silent: true });
    } catch {
      const msg = t("phoneVerifyFailedToast");
      setOtpError(msg);
      showToast({ type: "error", message: msg });
    } finally {
      setVerifying(false);
    }
  }

  return (
    <div className={styles.phoneBlock}>
      {step === "idle" ? (
        <>
          <div className={styles.settingsRow}>
            <p className={styles.currentPhone} dir="ltr">
              {currentPhone ? convertNumbers(currentPhone, "fa") : t("phoneNone")}
            </p>
            <span className={cn(styles.badge, phoneBadgeClass)}>{phoneBadge.label}</span>
          </div>
          {phoneSuccessInline !== "" ? (
            <p className={styles.inlineSuccess} aria-live="polite">
              {phoneSuccessInline}
            </p>
          ) : null}
          <div className={styles.actions}>
            <Button
              type="button"
              variant="primary"
              onClick={() => {
                setPhoneSuccessInline("");
                setStep("new_number");
              }}
            >
              {t("phoneChangeNumber")}
            </Button>
          </div>
        </>
      ) : null}

      {step === "new_number" ? (
        <>
          <FormField label={t("phoneNewLabel")} description={t("phoneNewDescription")} error={phoneError}>
            <Input
              type="tel"
              autoComplete="tel"
              dir="ltr"
              placeholder={uiLocaleDigits(t("phoneNewPlaceholder"), locale)}
              value={convertNumbers(newMobile, "fa")}
              disabled={requesting}
              aria-invalid={phoneError ? true : undefined}
              onChange={(e) => {
                const ascii = normalizeOtpPhoneInput(convertNumbers(e.target.value, "en"));
                setNewMobile(ascii);
                if (phoneError) {
                  setPhoneError(undefined);
                }
              }}
            />
          </FormField>
          <div className={styles.actions}>
            <Button type="button" variant="primary" loading={requesting} onClick={() => void requestCode()}>
              {t("phoneSendCode")}
            </Button>
            <Button
              type="button"
              variant="secondary"
              disabled={requesting}
              onClick={() => {
                setPhoneError(undefined);
                goIdle();
              }}
            >
              {t("phoneCancelChange")}
            </Button>
          </div>
        </>
      ) : null}

      {step === "otp" ? (
        <>
          <FormField label={t("phoneOtpLabel")} error={otpError}>
            <Input
              type="text"
              autoComplete="one-time-code"
              dir="ltr"
              placeholder={uiLocaleDigits(t("phoneOtpPlaceholder"), locale)}
              disabled={verifying}
              aria-invalid={otpError ? true : undefined}
              value={otp === "" ? "" : convertNumbers(otp, "fa")}
              onChange={(e) => {
                const en = toEnglishIntegerString(convertNumbers(e.target.value, "en"));
                setOtp(en);
                if (otpError) {
                  setOtpError(undefined);
                }
              }}
            />
          </FormField>
          {process.env.NODE_ENV === "development" ? <p className={styles.devHint}>{t("phoneDevOtpHint")}</p> : null}
          <div className={styles.actions}>
            <Button type="button" variant="primary" loading={verifying} disabled={requesting} onClick={() => void verifyCode()}>
              {t("phoneVerifySubmit")}
            </Button>
            <Button
              type="button"
              variant="secondary"
              disabled={verifying}
              onClick={() => {
                setChallengeId(null);
                setOtp("");
                setOtpError(undefined);
                setStep("new_number");
              }}
            >
              {t("phoneCancelChange")}
            </Button>
          </div>
        </>
      ) : null}
    </div>
  );
}

"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import { FormField, JalaliDatePicker, Select, Button, Checkbox, Input, useToast } from "@tour/ui";
import { ME_PROFILE_GENDER_VALUES } from "@repo/types";
import { useTranslations } from "next-intl";
import { useEffect, useMemo, useRef } from "react";
import type { Resolver } from "react-hook-form";
import { Controller, useForm } from "react-hook-form";
import { z } from "zod";

import { PersianNumberInput } from "@/components/forms/PersianNumberInput";
import { asciiDigitsFromNationalIdRaw, isValidIranNationalIdChecksum } from "@/lib/iran-national-id";
import {
  isBirthDateGregorianEligible,
  utcOldestBirthYmdYearsAgo,
  utcTodayGregorianYmd,
} from "@/lib/profile-birth-date";
import { pickMeErrorMessage } from "@/lib/me-api-error";

import { patchMe } from "@/lib/me-client";

import styles from "./settings-profile-form.module.css";
import { mapMeToProfileForm } from "./settings-me-shared";
import { type RefreshWorkspaceMeOptions, type WorkspaceMeData } from "./workspace-me-provider";

export type ProfileSettingsPanelProps = {
  me: WorkspaceMeData;
  refresh: (opts?: RefreshWorkspaceMeOptions) => Promise<void>;
};

type ProfileFormValues = ReturnType<typeof mapMeToProfileForm>;

const genderLiterals = [...ME_PROFILE_GENDER_VALUES] as [string, ...string[]];

export function ProfileSettingsPanel({ me, refresh }: ProfileSettingsPanelProps) {
  const t = useTranslations("settings");
  const { showToast } = useToast();
  const initialSnapshotRef = useRef(mapMeToProfileForm(me));
  /** Keeps If-Match in sync after PATCH responses so rapid saves / overlapping refreshes avoid stale versions. */
  const profileRowVersionRef = useRef<number | undefined>(undefined);

  useEffect(() => {
    if (typeof me.profile_row_version === "number") {
      profileRowVersionRef.current = me.profile_row_version;
    }
  }, [me.profile_row_version]);

  const birthMinYmd = useMemo(() => utcOldestBirthYmdYearsAgo(120), []);
  const birthMaxYmd = useMemo(() => utcTodayGregorianYmd(), []);

  const schema = useMemo(() => {
    const genderEnum = z.union([z.literal(""), z.enum(genderLiterals)]);
    return z
      .object({
        fullName: z.string().trim().max(255, { message: t("validationFullNameMax") }),
        notificationsEnabled: z.boolean(),
        nationalId: z.string(),
        gender: genderEnum,
        birthDate: z.string(),
      })
      .superRefine((data, ctx) => {
        const nid = asciiDigitsFromNationalIdRaw(data.nationalId.trim());
        if (nid.length > 0 && nid.length !== 10) {
          ctx.addIssue({
            code: "custom",
            message: t("validationNationalIdLength"),
            path: ["nationalId"],
          });
        }
        if (nid.length === 10 && !isValidIranNationalIdChecksum(nid)) {
          ctx.addIssue({
            code: "custom",
            message: t("validationNationalIdInvalid"),
            path: ["nationalId"],
          });
        }
        const dob = data.birthDate.trim();
        if (dob !== "" && !isBirthDateGregorianEligible(dob)) {
          ctx.addIssue({
            code: "custom",
            message: t("validationBirthDateInvalid"),
            path: ["birthDate"],
          });
        }
      });
  }, [t]);

  const resolver = useMemo(() => zodResolver(schema) as Resolver<ProfileFormValues>, [schema]);

  const {
    register,
    control,
    handleSubmit,
    reset,
    formState: { errors, isSubmitting },
  } = useForm<ProfileFormValues>({
    resolver,
    defaultValues: mapMeToProfileForm(me),
  });

  useEffect(() => {
    const defaults = mapMeToProfileForm(me);
    initialSnapshotRef.current = defaults;
    reset(defaults);
  }, [me, reset]);

  async function onValid(formData: ProfileFormValues) {
    try {
      const init = initialSnapshotRef.current;
      const patchBody: Record<string, unknown> = {};
      if (formData.notificationsEnabled !== init.notificationsEnabled) {
        patchBody.notifications_enabled = formData.notificationsEnabled;
      }

      const trimmedName = formData.fullName.trim();
      const initNameTrimmed = init.fullName.trim();
      if (trimmedName !== initNameTrimmed) {
        patchBody.full_name = trimmedName === "" ? null : trimmedName;
      }

      const nidAscii = asciiDigitsFromNationalIdRaw(formData.nationalId.trim());
      const initNid = asciiDigitsFromNationalIdRaw(init.nationalId.trim());
      if (nidAscii !== initNid) {
        patchBody.national_id = nidAscii === "" ? null : nidAscii;
      }

      if (formData.gender !== init.gender) {
        patchBody.gender = formData.gender === "" ? null : formData.gender;
      }

      const bd = formData.birthDate.trim();
      const ibd = init.birthDate.trim();
      if (bd !== ibd) {
        patchBody.birth_date = bd === "" ? null : bd;
      }

      if (Object.keys(patchBody).length === 0) {
        showToast({ type: "info", message: t("toastNoChanges") });
        return;
      }

      const versionForMatch = profileRowVersionRef.current ?? me.profile_row_version;
      const ifMatch =
        typeof versionForMatch === "number" ? `W/"${String(versionForMatch)}"` : undefined;

      const res = await patchMe(patchBody, ifMatch !== undefined ? { ifMatch } : undefined);
      const body = (await res.json().catch(() => ({}))) as WorkspaceMeData | { status?: string };
      if (!res.ok) {
        showToast({
          type: "error",
          message: pickMeErrorMessage(body, t("saveFailedToast"), t),
        });
        return;
      }
      if (
        typeof body !== "object" ||
        body === null ||
        !("id" in body) ||
        typeof (body as WorkspaceMeData).profile_row_version !== "number"
      ) {
        showToast({ type: "error", message: t("saveFailedToast") });
        await refresh({ silent: true });
        return;
      }
      const profileBody = body as WorkspaceMeData;
      profileRowVersionRef.current = profileBody.profile_row_version;
      const nextDefaults = mapMeToProfileForm(profileBody);
      initialSnapshotRef.current = nextDefaults;
      reset(nextDefaults);
      showToast({ type: "success", message: t("toastSaved") });
      await refresh({ silent: true });
    } catch {
      showToast({ type: "error", message: t("saveFailedToast") });
    }
  }

  return (
    <form className={styles.form} onSubmit={handleSubmit(onValid)} noValidate>
      <FormField label={t("fieldFullName")} error={errors.fullName?.message}>
        <Input autoComplete="name" aria-invalid={errors.fullName ? true : undefined} {...register("fullName")} />
      </FormField>

      <FormField label={t("fieldNationalId")} description={t("fieldNationalIdDescription")} error={errors.nationalId?.message}>
        <Controller
          name="nationalId"
          control={control}
          render={({ field }) => (
            <PersianNumberInput
              ref={field.ref}
              name={field.name}
              value={field.value}
              onChange={field.onChange}
              onBlur={field.onBlur}
              numericMode="integer"
              maxLength={10}
              aria-invalid={errors.nationalId ? true : undefined}
              autoComplete="off"
            />
          )}
        />
      </FormField>

      <FormField label={t("fieldGender")} error={errors.gender?.message}>
        <Select invalid={Boolean(errors.gender)} {...register("gender")}>
          <option value="">{t("genderUnset")}</option>
          <option value="female">{t("genderFemale")}</option>
          <option value="male">{t("genderMale")}</option>
          <option value="non_binary">{t("genderNonBinary")}</option>
          <option value="prefer_not_to_say">{t("genderPreferNotToSay")}</option>
        </Select>
      </FormField>

      <FormField label={t("fieldBirthDate")} description={t("fieldBirthDateDescription")} error={errors.birthDate?.message}>
        <Controller
          name="birthDate"
          control={control}
          render={({ field }) => (
            <JalaliDatePicker
              ref={field.ref}
              name={field.name}
              value={typeof field.value === "string" ? field.value : ""}
              onChange={field.onChange}
              onBlur={field.onBlur}
              invalid={Boolean(errors.birthDate)}
              maxDate={birthMaxYmd}
              minDate={birthMinYmd}
              clearLabel={t("profileJalaliClear")}
              openCalendarAriaLabel={t("profileOpenCalendarAria")}
            />
          )}
        />
      </FormField>

      <FormField
        label={t("fieldNotifications")}
        description={t("fieldNotificationsDescription")}
        error={errors.notificationsEnabled?.message}
      >
        <Checkbox bare {...register("notificationsEnabled")} />
      </FormField>

      <div className={styles.actions}>
        <Button type="submit" variant="primary" loading={isSubmitting} disabled={isSubmitting}>
          {t("submitButton")}
        </Button>
      </div>
    </form>
  );
}

"use client";

import { useTranslations } from "next-intl";
import { useCallback, useMemo, useState } from "react";

import {
  useCreateTourPreset,
  useDeleteTourPreset,
  useReorderTourPresets,
  useSettingsTourPresets,
  useUpdateTourPreset,
} from "@/hooks/use-settings-tour-presets";
import { useSettingsTourThemes } from "@/hooks/use-settings-tour-themes";
import type { SettingsTourPresetDto } from "@/lib/settings-tour-presets.client";
import { nextTourPresetSortOrder } from "@/lib/tour-preset-duplicate";
import { matchRulesFromPresetDefaults } from "@/lib/tour-preset-match-from-defaults";
import { isLeaderRole, isWorkspaceOwner, useAuth } from "@/lib/auth/auth-context";

