const DESCRIPTION_PREVIEW_MAX = 120;

function previewDescription(text: string | null | undefined): string {
  if (!text?.trim()) {
    return "—";
  }
  const s = text.trim();
  return s.length > DESCRIPTION_PREVIEW_MAX ? `${s.slice(0, DESCRIPTION_PREVIEW_MAX)}…` : s;
}

