    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.92 : 1,
    position: "relative",
    zIndex: isDragging ? 2 : undefined,
  };
  const { usesDenaliWizardShell } = getCapabilitiesForProfile(
    normalizeTourFormProfileInput(item.formProfile),
  );

  const matchParts: string[] = [];
  const ovRaw = item.defaults?.overview;
  let presetTourType: string | null = null;
  let presetThemeId: string | null = null;
  if (ovRaw != null && typeof ovRaw === "object" && !Array.isArray(ovRaw)) {
    const o = ovRaw as Record<string, unknown>;
    if (typeof o.tourType === "string" && o.tourType.trim() !== "") {
      presetTourType = o.tourType.trim();
    }
    if (typeof o.mainTourThemeId === "string" && o.mainTourThemeId.trim() !== "") {
      presetThemeId = o.mainTourThemeId.trim();
    }
  }
  if (presetTourType && (TOUR_TYPES as readonly string[]).includes(presetTourType)) {
    matchParts.push(
      t("tourPresetsMetaMatchPartType", {
        label: t(`tourPresetsTourType_${presetTourType}` as never),
      }),
    );
  } else if (presetTourType) {
    matchParts.push(t("tourPresetsMetaDefaultsTourTypeRaw", { value: presetTourType }));
  }
  if (presetThemeId) {
    const tn = themeNameById.get(presetThemeId);
    matchParts.push(
      t("tourPresetsMetaMatchPartTheme", {
        name: tn ?? presetThemeId.slice(0, 8),
      }),
    );
  }
  const matchLine =
    matchParts.length > 0 ? t("tourPresetsMetaMatch", { parts: matchParts.join(" · ") }) : t("tourPresetsMatchNone");

  const rootKeys = Object.keys(item.defaults ?? {});
  const keysLine =
    rootKeys.length > 0 ? t("tourPresetsMetaDefaultsKeys", { keys: rootKeys.slice(0, 8).join(", ") }) : "—";

  return (
    <li ref={setNodeRef} style={style} className={panelStyles.listItem}>
      <div className={panelStyles.listItemInner}>
        <button
          type="button"
          className={panelStyles.dragHandle}
          aria-label={t("tourPresetsDragHandleLabel")}
          {...attributes}
          {...listeners}
        >
          ⠿
        </button>
        <div className={panelStyles.listItemMain}>
          <div>
            <strong>{item.name}</strong>
            <span className={panelStyles.listItemMeta}>{previewDescription(item.description)}</span>
            <span className={panelStyles.listItemMeta}>{matchLine}</span>
            <span className={panelStyles.listItemMeta}>
              {t("tourPresetsMetaFormProfile", { profile: item.formProfile ?? "general" })}
            </span>
            <span className={panelStyles.listItemMeta}>{keysLine}</span>
            <span className={panelStyles.listItemMeta}>{t("tourPresetsSortOrderLabel", { n: String(item.sortOrder) })}</span>
            {!item.isActive ? <span className={panelStyles.listItemBadge}>— {t("tourPresetsInactiveBadge")}</span> : null}
          </div>
          <div className={panelStyles.listItemActions}>
            <label className={panelStyles.listItemMeta} style={{ display: "inline-flex", alignItems: "center", gap: 6 }}>
              <Checkbox
                bare
                checked={item.isActive}
                disabled={mutating}
                onChange={(e) => onToggleActive(item, e.currentTarget.checked)}
                aria-label={t("tourPresetsFieldActive")}
              />
              <span>{t("tourPresetsFieldActive")}</span>
            </label>
            {usesDenaliWizardShell && item.isActive ? (
              <Button
                type="button"
                variant="primary"
                size="sm"
                disabled={mutating}
                data-testid={`tour-preset-create-tour-${item.id}`}
                onClick={() => router.push(`/tours/new?presetId=${encodeURIComponent(item.id)}`)}
              >
                {t("tourPresetsCreateTourFromTemplate")}
              </Button>
            ) : null}
            <Button type="button" variant="ghost" size="sm" onClick={() => onEdit(item)} disabled={mutating}>
              {t("tourPresetsEdit")}
            </Button>
            {showDuplicate ? (
              <Button type="button" variant="ghost" size="sm" onClick={() => onDuplicate(item)} disabled={mutating}>
                {t("tourPresetsCopy")}
              </Button>
            ) : null}
            <Button type="button" variant="danger" size="sm" onClick={() => void onDelete(item)} disabled={mutating}>
              {t("tourPresetsDelete")}
            </Button>
          </div>
        </div>
      </div>
    </li>
  );
}

export type TourPresetListProps = {
  items: SettingsTourPresetDto[];
  themeNameById: Map<string, string>;
  onEdit: (item: SettingsTourPresetDto) => void;
  showDuplicate?: boolean;
  onDuplicate: (item: SettingsTourPresetDto) => void;
  onDelete: (item: SettingsTourPresetDto) => void;
  onToggleActive: (item: SettingsTourPresetDto, next: boolean) => void;
  onReorder: (itemIds: string[]) => Promise<void>;
  mutating: boolean;
  readOnly?: boolean;
};

export function TourPresetList({
  items,
  themeNameById,
  onEdit,
  showDuplicate = false,
  onDuplicate,
  onDelete,
  onToggleActive,
  onReorder,
  mutating,
  readOnly = false,
}: TourPresetListProps) {
  const t = useTranslations("settings");
  const router = useRouter();
  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 8 } }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates }),
  );

  const sorted = useMemo(
    () =>
      [...items].sort(
        (a, b) => a.sortOrder - b.sortOrder || a.name.localeCompare(b.name, undefined, { sensitivity: "base" }),
      ),
    [items],
  );

  const handleDragEnd = useCallback(
    (event: DragEndEvent) => {
      const { active, over } = event;
      if (!over || active.id === over.id) {
        return;
      }
      const oldIndex = sorted.findIndex((r) => r.id === active.id);
      const newIndex = sorted.findIndex((r) => r.id === over.id);
      if (oldIndex < 0 || newIndex < 0) {
        return;
      }
      const newOrder = arrayMove(sorted, oldIndex, newIndex);
      const itemIds = newOrder.map((r) => r.id);
      const prevIds = sorted.map((r) => r.id);
      if (itemIds.every((id, i) => id === prevIds[i])) {
        return;
      }
      void onReorder(itemIds);
    },
    [onReorder, sorted],
  );

  if (readOnly) {
    return (
      <ul className={panelStyles.list}>
        {sorted.map((item) => {
          const { usesDenaliWizardShell } = getCapabilitiesForProfile(
            normalizeTourFormProfileInput(item.formProfile),
          );
          return (
            <li key={item.id} className={panelStyles.listItem}>
              <div className={panelStyles.listItemInner}>
                <div className={panelStyles.listItemMain}>
                  <div>
                    <strong>{item.name}</strong>
                    <span className={panelStyles.listItemMeta}>{previewDescription(item.description)}</span>
                    {!item.isActive ? (
                      <span className={panelStyles.listItemBadge}>— {t("tourPresetsInactiveBadge")}</span>
                    ) : null}
                  </div>
                  {usesDenaliWizardShell && item.isActive ? (
                    <div className={panelStyles.listItemActions}>
                      <Button
                        type="button"
                        variant="primary"
                        size="sm"
                        data-testid={`tour-preset-create-tour-${item.id}`}
                        onClick={() => router.push(`/tours/new?presetId=${encodeURIComponent(item.id)}`)}
                      >
                        {t("tourPresetsCreateTourFromTemplate")}
                      </Button>
                    </div>
                  ) : null}
                </div>
              </div>
            </li>
          );
        })}
      </ul>
    );
  }

  return (
    <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
      <SortableContext items={sorted.map((r) => r.id)} strategy={verticalListSortingStrategy}>
        <ul className={panelStyles.list}>
          {sorted.map((item) => (
            <SortableTourPresetRow
              key={item.id}
              item={item}
              themeNameById={themeNameById}
              onEdit={onEdit}
              showDuplicate={showDuplicate}
              onDuplicate={onDuplicate}
              onDelete={onDelete}
              onToggleActive={onToggleActive}
              mutating={mutating}
            />
          ))}
        </ul>
      </SortableContext>
    </DndContext>
  );
}

"use client";

import { useTranslations } from "next-intl";
import { useCallback, useMemo, useState } from "react";

import {
  useCreateTourPreset,
  useDeleteTourPreset,
  useReorderTourPresets,
  useSettingsTourPresets,
  useUpdateTourPreset,
} from "@/hooks/use-settings-tour-presets";
import { useSettingsTourThemes } from "@/hooks/use-settings-tour-themes";
import type { SettingsTourPresetDto } from "@/lib/settings-tour-presets.client";
import { nextTourPresetSortOrder } from "@/lib/tour-preset-duplicate";
import { matchRulesFromPresetDefaults } from "@/lib/tour-preset-match-from-defaults";
import { isLeaderRole, isWorkspaceOwner, useAuth } from "@/lib/auth/auth-context";

import {
  Button,
  Card,
  CardBody,
  CardHeader,
  CardTitle,
  ConfirmDialog,
  EmptyState,
  ErrorState,
  LoadingState,
  Modal,
  cn,
  useToast,
} from "@tour/ui";

import formStyles from "../settings-profile-form.module.css";
import panelStyles from "../locations/locations-settings-panel.module.css";
import { TourPresetForm, type TourPresetFormParsed } from "./tour-preset-form";
import { TourPresetList } from "./tour-preset-list";

export function TourPresetsSettingsPanel() {
  const t = useTranslations("settings");
  const { showToast } = useToast();
  const { user } = useAuth();
  const canManageWorkspace = isLeaderRole(user?.role);
  const canDuplicatePreset = isWorkspaceOwner(user?.role);
  const readOnlyList = !canManageWorkspace;

  const themesQuery = useSettingsTourThemes();
  const themeCatalog = themesQuery.data ?? [];
  const themeNameById = useMemo(() => new Map(themeCatalog.map((row) => [row.id, row.name])), [themeCatalog]);

  const presetsQuery = useSettingsTourPresets();
  const presets = presetsQuery.data ?? [];
  const createMutation = useCreateTourPreset();
  const updateMutation = useUpdateTourPreset();
  const deleteMutation = useDeleteTourPreset();
  const reorderMutation = useReorderTourPresets();

  const [formOpen, setFormOpen] = useState(false);
  const [editing, setEditing] = useState<SettingsTourPresetDto | null>(null);
  const [duplicateFrom, setDuplicateFrom] = useState<SettingsTourPresetDto | null>(null);
  const [deleteTarget, setDeleteTarget] = useState<SettingsTourPresetDto | null>(null);

  const existingPresetNames = useMemo(() => presets.map((p) => p.name), [presets]);
  const duplicateSortOrder = useMemo(() => nextTourPresetSortOrder(presets), [presets]);

  const isMutating =
    createMutation.isPending ||
    updateMutation.isPending ||
    deleteMutation.isPending ||
    reorderMutation.isPending;

  const openCreate = useCallback(() => {
    setEditing(null);
    setDuplicateFrom(null);
    setFormOpen(true);
  }, []);

  const openEdit = useCallback((item: SettingsTourPresetDto) => {
    setEditing(item);
    setDuplicateFrom(null);
    setFormOpen(true);
  }, []);

  const openDuplicate = useCallback((item: SettingsTourPresetDto) => {
    setEditing(null);
    setDuplicateFrom(item);
    setFormOpen(true);
  }, []);

  const closeForm = useCallback(() => {
    setFormOpen(false);
    setEditing(null);
    setDuplicateFrom(null);
  }, []);

  const onSubmitForm = useCallback(
    async (values: TourPresetFormParsed) => {
      try {
        const { matchTourType, matchMainTourThemeId } = matchRulesFromPresetDefaults(values.defaults);
        const payload = {
          name: values.name,
          description: values.description,
          isActive: values.isActive,
          defaults: values.defaults,
          formProfile: values.formProfile,
          matchTourType,
          matchMainTourThemeId,
          ...(values.sortOrder !== undefined ? { sortOrder: values.sortOrder } : {}),
        };
        if (editing) {
          await updateMutation.mutateAsync({ id: editing.id, input: payload });
          showToast({ type: "success", message: t("tourPresetsToastUpdated") });
        } else {
          await createMutation.mutateAsync(payload);
          showToast({ type: "success", message: t("tourPresetsToastCreated") });
        }
        closeForm();
      } catch (e) {
        showToast({
          type: "error",
          message: e instanceof Error ? e.message : t("tourPresetsToastSaveFailed"),
        });
      }
    },
    [closeForm, createMutation, editing, showToast, t, updateMutation],
  );

  const onToggleActive = useCallback(
    async (item: SettingsTourPresetDto, next: boolean) => {
      if (item.isActive === next) {
        return;
      }
      try {
        await updateMutation.mutateAsync({ id: item.id, input: { isActive: next } });
        showToast({ type: "success", message: t("tourPresetsToastUpdated") });
      } catch (e) {
        showToast({
          type: "error",
          message: e instanceof Error ? e.message : t("tourPresetsToastSaveFailed"),
        });
      }
    },
    [showToast, t, updateMutation],
  );

  const onReorder = useCallback(
    async (itemIds: string[]) => {
      try {
        await reorderMutation.mutateAsync(itemIds);
        showToast({ type: "success", message: t("tourPresetsToastOrderUpdated") });
      } catch (e) {
        showToast({
          type: "error",
          message: e instanceof Error ? e.message : t("tourPresetsToastOrderFailed"),
        });
      }
    },
    [reorderMutation, showToast, t],
  );

  const requestDelete = useCallback((item: SettingsTourPresetDto) => {
    setDeleteTarget(item);
  }, []);

  const confirmDelete = useCallback(async () => {
    if (!deleteTarget) {
      return;
    }
    try {
      await deleteMutation.mutateAsync(deleteTarget.id);
      showToast({ type: "success", message: t("tourPresetsToastDeleted") });
      setDeleteTarget(null);
    } catch (e) {
      showToast({
        type: "error",
        message: e instanceof Error ? e.message : t("tourPresetsToastDeleteFailed"),
      });
    }
  }, [deleteMutation, deleteTarget, showToast, t]);

  const loadError = presetsQuery.error;
  const loadErrorMessage = loadError instanceof Error ? loadError.message : t("tourPresetsLoadErrorTitle");

  if (loadError && presets.length === 0 && !presetsQuery.isLoading) {
    return (
      <div className={cn(formStyles.form, panelStyles.panel)}>
        <ErrorState
          title={t("tourPresetsLoadErrorTitle")}
          message={loadErrorMessage}
          onRetry={() => void presetsQuery.refetch()}
        />
      </div>
    );
  }

  return (
    <div className={cn(formStyles.form, panelStyles.panel)}>
      <p className={panelStyles.catalogIntro}>{t("tourPresetsPanelIntro")}</p>
      <div className={panelStyles.cardStack}>
        <Card>
          <CardHeader>
            <div
              style={{
                display: "flex",
                flexWrap: "wrap",
                alignItems: "center",
                justifyContent: "space-between",
                gap: "var(--space-3)",
              }}
            >
              <CardTitle>{t("tourPresetsListTitle")}</CardTitle>
              {canManageWorkspace ? (
                <Button type="button" variant="primary" size="sm" onClick={openCreate} disabled={isMutating}>
                  {t("tourPresetsAdd")}
                </Button>
              ) : null}
            </div>
          </CardHeader>
          <CardBody>
            {readOnlyList && presets.length > 0 ? (
              <p className={formStyles.readOnlyBanner}>{t("tourPresetsReadOnlyBanner")}</p>
            ) : null}
            {presetsQuery.isLoading ? <LoadingState message={t("tourPresetsLoading")} /> : null}

            {!presetsQuery.isLoading && presets.length === 0 ? (
              <EmptyState
                embedded
                className={panelStyles.emptyState}
                title={t("tourPresetsEmptyTitle")}
                description={readOnlyList ? t("tourPresetsReadOnlyHint") : t("tourPresetsEmptyDescription")}
              />
            ) : null}

            {presets.length > 0 ? (
              <TourPresetList
                items={presets}
                themeNameById={themeNameById}
                onEdit={openEdit}
                showDuplicate={canDuplicatePreset}
                onDuplicate={openDuplicate}
                onDelete={requestDelete}
                onToggleActive={onToggleActive}
                onReorder={onReorder}
                mutating={isMutating}
                readOnly={readOnlyList}
              />
            ) : null}
          </CardBody>
        </Card>
      </div>

      <Modal
        open={formOpen}
        onClose={closeForm}
        title={
          editing ? t("tourPresetsEditTitle") : duplicateFrom ? t("tourPresetsDuplicateTitle") : t("tourPresetsAddTitle")
        }
        footer={null}
      >
        <TourPresetForm
          editing={editing}
          duplicateFrom={duplicateFrom}
          existingPresetNames={existingPresetNames}
          duplicateSortOrder={duplicateSortOrder}
          onSubmit={onSubmitForm}
          onCancel={closeForm}
          isPending={isMutating}
        />
      </Modal>

      <ConfirmDialog
        open={deleteTarget != null}
        title={t("tourPresetsDeleteConfirmTitle")}
        description={deleteTarget ? t("tourPresetsDeleteConfirmDescription", { name: deleteTarget.name }) : undefined}
        confirmLabel={t("tourPresetsDeleteConfirmAction")}
        cancelLabel={t("tourPresetsCancel")}
        variant="danger"
        onConfirm={() => void confirmDelete()}
        onCancel={() => setDeleteTarget(null)}
      />
    </div>
  );
}

"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import {
  DEFAULT_TOUR_FORM_PROFILE,
  getTourFormProfileOptions,
  getTourFormProfileZodEnumValues,
  type TourFormProfile,
} from "@repo/types";
import { useTranslations } from "next-intl";
import { useEffect, useId, useMemo } from "react";
import type { Resolver } from "react-hook-form";
import { Controller, useForm } from "react-hook-form";
import { z } from "zod";

import { PersianNumberInput } from "@/components/forms/PersianNumberInput";
import type { SettingsTourThemeDto } from "@/lib/settings-tour-themes.client";

import { Button, Checkbox, FormField, Input, Select, Textarea } from "@tour/ui";

import formStyles from "../settings-profile-form.module.css";
import panelStyles from "../locations/locations-settings-panel.module.css";

export type TourThemeFormProps = {
  editing: SettingsTourThemeDto | null;
  onSubmit: (values: TourThemeFormParsed) => Promise<void>;
  onCancel: () => void;
  isPending: boolean;
};

export type TourThemeFormParsed = {
  name: string;
  slug: string;
  description: string | null;
  sortOrder: number | undefined;
  isActive: boolean;
  formProfile: TourFormProfile;
};

type TourThemeFormInput = {
  name: string;
  slug: string;
  description: string;
  sortOrder: string;
  isActive: boolean;
  formProfile: TourFormProfile;
};

export function TourThemeForm({ editing, onSubmit, onCancel, isPending }: TourThemeFormProps) {
  const t = useTranslations("settings");
  const activeId = useId();
  const activeDomId = `tour-theme-active-${activeId.replace(/:/g, "")}`;
  const formProfileOptions = useMemo(() => getTourFormProfileOptions(), []);

  const schema = useMemo(
    () =>
      z.object({
        name: z.string().trim().min(1, t("tourThemesValidationName")),
        slug: z.string().trim().min(1, t("tourThemesValidationSlug")).max(120),
        description: z.string().optional(),
        sortOrder: z
          .string()
          .trim()
          .optional()
          .transform((v) => (v && v !== "" ? Number(v) : undefined))
          .refine((v) => v === undefined || !Number.isNaN(v), { message: t("tourThemesValidationSortOrder") }),
        isActive: z.boolean(),
        formProfile: z.enum(getTourFormProfileZodEnumValues()),
      }),
    [t],
  );

  const resolver = useMemo(() => zodResolver(schema) as Resolver<TourThemeFormInput, unknown, TourThemeFormParsed>, [schema]);

  const form = useForm<TourThemeFormInput, unknown, TourThemeFormParsed>({
    resolver,
    defaultValues: {
      name: "",
      slug: "",
      description: "",
      sortOrder: "",
      isActive: true,
      formProfile: DEFAULT_TOUR_FORM_PROFILE,
    },
  });

  const { register, control, handleSubmit, reset, formState } = form;
  const errors = formState.errors;

  useEffect(() => {
    if (editing) {
      reset({
        name: editing.name,
        slug: editing.slug,
        description: editing.description ?? "",
        sortOrder: String(editing.sortOrder),
        isActive: Boolean(editing.isActive),
        formProfile: editing.formProfile,
      });
    } else {
      reset({
        name: "",
        slug: "",
        description: "",
        sortOrder: "",
        isActive: true,
        formProfile: DEFAULT_TOUR_FORM_PROFILE,
      });
    }
  }, [editing, reset]);

  return (
    <form
      className={panelStyles.formBlock}
      onSubmit={handleSubmit(async (values) => {
        const descriptionTrim = values.description?.trim();
        await onSubmit({
          name: values.name.trim(),
          slug: values.slug.trim(),
          description: descriptionTrim ? descriptionTrim : null,
          sortOrder: values.sortOrder,
          isActive: values.isActive,
          formProfile: values.formProfile,
        });
      })}
      noValidate
    >
      <FormField
        label={t("tourThemesFieldName")}
        description={t("tourThemesFieldNameHint")}
        required
        error={errors.name?.message}
      >
        <Input autoComplete="off" aria-invalid={errors.name ? true : undefined} {...register("name")} />
      </FormField>
      <FormField
        label={t("tourThemesFieldSlug")}
        description={t("tourThemesFieldSlugHint")}
        required
        error={errors.slug?.message}
      >
        <Input autoComplete="off" aria-invalid={errors.slug ? true : undefined} {...register("slug")} />
      </FormField>
      <FormField
        label={t("tourThemesFieldDescription")}
        description={t("tourThemesFieldDescriptionHint")}
        error={errors.description?.message}
      >
        <Textarea rows={3} {...register("description")} />
      </FormField>
      <FormField
        label={t("tourThemesFieldFormProfile")}
        description={t("tourThemesFieldFormProfileHint")}
        error={errors.formProfile?.message}
      >
        <Select
          aria-invalid={errors.formProfile ? true : undefined}
          {...register("formProfile")}
        >
          {formProfileOptions.map(({ value, labelKey }) => (
            <option key={value} value={value}>
              {t(labelKey)}
            </option>
          ))}
        </Select>
      </FormField>
      <FormField label={t("tourThemesFieldSortOrder")} description={t("tourThemesFieldSortOrderHint")} error={errors.sortOrder?.message}>
        <Controller
          control={control}
          name="sortOrder"
          render={({ field }) => (
            <PersianNumberInput
              autoComplete="off"
              aria-invalid={errors.sortOrder ? true : undefined}
              numericMode="integer"
              value={field.value ?? ""}
              onChange={field.onChange}
              onBlur={field.onBlur}
              name={field.name}
              ref={field.ref}
            />
          )}
        />
      </FormField>
      <FormField
        htmlFor={activeDomId}
        label={t("tourThemesFieldActive")}
        description={t("tourThemesFieldActiveHint")}
        error={errors.isActive?.message}
      >
        <Controller
          control={control}
          name="isActive"
          render={({ field }) => (
            <Checkbox
              bare
              id={activeDomId}
              name={field.name}
              ref={field.ref}
              checked={field.value}
              onBlur={field.onBlur}
              onChange={(e) => field.onChange(e.currentTarget.checked)}
            />
          )}
        />
      </FormField>
      <div className={formStyles.actions}>
        <Button type="submit" variant="primary" loading={isPending} disabled={isPending}>
          {editing ? t("tourThemesSaveEdit") : t("tourThemesSaveCreate")}
        </Button>
        <Button type="button" variant="secondary" disabled={isPending} onClick={onCancel}>
          {t("tourThemesCancel")}
        </Button>
      </div>
    </form>
  );
}

"use client";

import {
  DndContext,
  type DragEndEvent,
  KeyboardSensor,
  PointerSensor,
  closestCenter,
  useSensor,
  useSensors,
} from "@dnd-kit/core";
import {
  SortableContext,
  arrayMove,
  sortableKeyboardCoordinates,
  useSortable,
  verticalListSortingStrategy,
} from "@dnd-kit/sortable";
import { CSS } from "@dnd-kit/utilities";
import { useTranslations } from "next-intl";
import type { CSSProperties } from "react";
import { useCallback, useMemo } from "react";

import type { SettingsTourThemeDto } from "@/lib/settings-tour-themes.client";

import { Button, Checkbox } from "@tour/ui";

import panelStyles from "../locations/locations-settings-panel.module.css";

const DESCRIPTION_PREVIEW_MAX = 120;

function previewDescription(text: string | null | undefined): string {
  if (!text?.trim()) {
    return "—";
  }
  const t = text.trim();
  return t.length > DESCRIPTION_PREVIEW_MAX ? `${t.slice(0, DESCRIPTION_PREVIEW_MAX)}…` : t;
}

type SortableTourThemeRowProps = {
  item: SettingsTourThemeDto;
  onEdit: (item: SettingsTourThemeDto) => void;
  onDelete: (item: SettingsTourThemeDto) => void;
  onToggleActive: (item: SettingsTourThemeDto, next: boolean) => void;
  mutating: boolean;
};

function SortableTourThemeRow({
  item,
  onEdit,
  onDelete,
  onToggleActive,
  mutating,
}: SortableTourThemeRowProps) {
  const t = useTranslations("settings");
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: item.id,
  });
  const style: CSSProperties = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.92 : 1,
    position: "relative",
    zIndex: isDragging ? 2 : undefined,
  };

  return (
    <li ref={setNodeRef} style={style} className={panelStyles.listItem}>
      <div className={panelStyles.listItemInner}>
        <button
          type="button"
          className={panelStyles.dragHandle}
          aria-label={t("tourThemesDragHandleLabel")}
          {...attributes}
          {...listeners}
        >
          ⠿
        </button>
        <div className={panelStyles.listItemMain}>
          <div>
            <strong>{item.name}</strong>
            <span className={panelStyles.listItemMeta}>{previewDescription(item.description)}</span>
            <span className={panelStyles.listItemMeta}>
              {t("tourThemesSortOrderLabel", { n: String(item.sortOrder) })}
            </span>
            <span className={panelStyles.listItemMeta} title={item.formProfile}>
              {t(`tourThemesFormProfileOption_${item.formProfile}` as never)}
            </span>
            {!item.isActive ? <span className={panelStyles.listItemBadge}>— {t("tourThemesInactiveBadge")}</span> : null}
          </div>
          <div className={panelStyles.listItemActions}>
            <label
              className={panelStyles.listItemMeta}
              style={{ display: "inline-flex", alignItems: "center", gap: 6 }}
            >
              <Checkbox
                bare
                checked={item.isActive}
                disabled={mutating}
                onChange={(e) => onToggleActive(item, e.currentTarget.checked)}
                aria-label={t("tourThemesFieldActive")}
              />
              <span>{t("tourThemesFieldActive")}</span>
            </label>
            <Button type="button" variant="ghost" size="sm" onClick={() => onEdit(item)} disabled={mutating}>
              {t("tourThemesEdit")}
            </Button>
            <Button type="button" variant="danger" size="sm" onClick={() => void onDelete(item)} disabled={mutating}>
              {t("tourThemesDelete")}
            </Button>
          </div>
        </div>
      </div>
    </li>
  );
}

export type TourThemeListProps = {
  items: SettingsTourThemeDto[];
  onEdit: (item: SettingsTourThemeDto) => void;
  onDelete: (item: SettingsTourThemeDto) => void;
  onToggleActive: (item: SettingsTourThemeDto, next: boolean) => void;
  onReorder: (itemIds: string[]) => Promise<void>;
  mutating: boolean;
  readOnly?: boolean;
};

export function TourThemeList({
  items,
  onEdit,
  onDelete,
  onToggleActive,
  onReorder,
  mutating,
  readOnly = false,
}: TourThemeListProps) {
  const t = useTranslations("settings");
  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 8 } }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates }),
  );

  const sorted = useMemo(
    () =>
      [...items].sort(
        (a, b) => a.sortOrder - b.sortOrder || a.name.localeCompare(b.name, undefined, { sensitivity: "base" }),
      ),
    [items],
  );

  const handleDragEnd = useCallback(
    (event: DragEndEvent) => {
      const { active, over } = event;
      if (!over || active.id === over.id) {
        return;
      }
      const oldIndex = sorted.findIndex((r) => r.id === active.id);
      const newIndex = sorted.findIndex((r) => r.id === over.id);
      if (oldIndex < 0 || newIndex < 0) {
        return;
      }
      const newOrder = arrayMove(sorted, oldIndex, newIndex);
      const itemIds = newOrder.map((r) => r.id);
      const prevIds = sorted.map((r) => r.id);
      if (itemIds.every((id, i) => id === prevIds[i])) {
        return;
      }
      void onReorder(itemIds);
    },
    [onReorder, sorted],
  );

  if (readOnly) {
    return (
      <ul className={panelStyles.list}>
        {sorted.map((item) => (
          <li key={item.id} className={panelStyles.listItem}>
            <div className={panelStyles.listItemInner}>
              <div className={panelStyles.listItemMain}>
                <div>
                  <strong>{item.name}</strong>
                  <span className={panelStyles.listItemMeta}>{previewDescription(item.description)}</span>
                  <span className={panelStyles.listItemMeta}>
                    {t("tourThemesSortOrderLabel", { n: String(item.sortOrder) })}
                  </span>
                  <span className={panelStyles.listItemMeta} title={item.formProfile}>
                    {t(`tourThemesFormProfileOption_${item.formProfile}` as never)}
                  </span>
                  {!item.isActive ? (
                    <span className={panelStyles.listItemBadge}>— {t("tourThemesInactiveBadge")}</span>
                  ) : null}
                </div>
              </div>
            </div>
          </li>
        ))}
      </ul>
    );
  }

  return (
    <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
      <SortableContext items={sorted.map((r) => r.id)} strategy={verticalListSortingStrategy}>
        <ul className={panelStyles.list}>
          {sorted.map((item) => (
            <SortableTourThemeRow
              key={item.id}
              item={item}
              onEdit={onEdit}
              onDelete={onDelete}
              onToggleActive={onToggleActive}
              mutating={mutating}
            />
          ))}
        </ul>
      </SortableContext>
    </DndContext>
  );
}

"use client";

import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
  type ReactNode
} from "react";

import type { MeProfileWire } from "@repo/types";
import { useToast } from "@tour/ui";
import { useTranslations } from "next-intl";

import { pickMeErrorMessage } from "@/lib/me-api-error";

import { fetchMe } from "@/lib/me-client";

/** Payload from `GET /api/v2/me` (proxied as `GET /api/me`). */
export type WorkspaceMeData = MeProfileWire;

export type RefreshWorkspaceMeOptions = {
  /** When true, skip `isLoading` toggles so children do not unmount (e.g. after PATCH). */
  silent?: boolean;
};

export type WorkspaceMeContextValue = {
  data: WorkspaceMeData | null;
  isLoading: boolean;
  error: Error | null;
  refresh: (opts?: RefreshWorkspaceMeOptions) => Promise<void>;
};

const WorkspaceMeContext = createContext<WorkspaceMeContextValue | null>(null);

export function WorkspaceMeProvider({ children }: { children: ReactNode }) {
  const t = useTranslations("settings");
  const { showToast } = useToast();
  const [data, setData] = useState<WorkspaceMeData | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);

  const toastRef = useRef(showToast);
  const translateRef = useRef(t);
  toastRef.current = showToast;
  translateRef.current = t;

  const refresh = useCallback(async (opts?: RefreshWorkspaceMeOptions) => {
    const silent = opts?.silent === true;
    if (!silent) {
      setIsLoading(true);
    }
    setError(null);
    try {
      const res = await fetchMe();
      const body = (await res.json().catch(() => ({}))) as WorkspaceMeData;
      if (!res.ok) {
        setData(null);
        const msg = pickMeErrorMessage(body, translateRef.current("loadFailedToast"), translateRef.current);
        setError(new Error(msg));
        toastRef.current({ type: "error", message: msg });
        return;
      }
      setData(body);
    } catch {
      setData(null);
      setError(new Error(translateRef.current("loadFailedToast")));
      toastRef.current({ type: "error", message: translateRef.current("loadFailedToast") });
    } finally {
      if (!silent) {
        setIsLoading(false);
      }
    }
  }, []);

  useEffect(() => {
    void refresh();
  }, [refresh]);

  const value = useMemo<WorkspaceMeContextValue>(
    () => ({
      data,
      isLoading,
      error,
      refresh
    }),
    [data, isLoading, error, refresh]
  );

  return <WorkspaceMeContext.Provider value={value}>{children}</WorkspaceMeContext.Provider>;
}

export function useWorkspaceMe(): WorkspaceMeContextValue {
  const ctx = useContext(WorkspaceMeContext);
  if (ctx == null) {
    throw new Error("useWorkspaceMe must be used within WorkspaceMeProvider");
  }
  return ctx;
}

"use client";

import { useState } from "react";

import {
  Badge,
  Button,
  Card,
  CardBody,
  CardHeader,
  CardTitle,
  EmptyState,
  Modal,
  Select,
} from "@tour/ui";

import { TOUR_WORKSPACE_COPY } from "./tour-workspace-copy";
import type { DriverWithLoad, TransportPassengerRow } from "./use-tour-transport-ops";

import workspaceStyles from "./tour-workspace.module.css";
import styles from "./tour-workspace-transport.module.css";

const copy = TOUR_WORKSPACE_COPY.transport.driversTable;

export type DriversManagementTableProps = {
  drivers: DriverWithLoad[];
  unassignedPassengers: TransportPassengerRow[];
  readOnly: boolean;
  onAssign: (passengerRegistrationId: string, driverId: string) => void;
};

function formatCount(n: number): string {
  return new Intl.NumberFormat("fa-IR").format(n);
}

export function DriversManagementTable({
  drivers,
  unassignedPassengers,
  readOnly,
  onAssign,
}: DriversManagementTableProps) {
  const [assignDriverId, setAssignDriverId] = useState<string | null>(null);
  const [selectedPassengerId, setSelectedPassengerId] = useState("");

  const activeDriver = drivers.find((d) => d.id === assignDriverId) ?? null;
  const canAssignMore =
    activeDriver != null &&
    unassignedPassengers.length > 0 &&
    (activeDriver.availableSeats === 0 || activeDriver.passengersAssigned < activeDriver.availableSeats);

  function closeAssignModal() {
    setAssignDriverId(null);
    setSelectedPassengerId("");
  }

  function confirmAssign() {
    if (!assignDriverId || !selectedPassengerId) {
      return;
    }
    onAssign(selectedPassengerId, assignDriverId);
    closeAssignModal();
  }

  return (
    <>
      <Card data-testid="drivers-management-table">
        <CardHeader>
          <CardTitle>{copy.title}</CardTitle>
        </CardHeader>
        <CardBody>
          {drivers.length === 0 ? (
            <EmptyState title={copy.emptyTitle} description={copy.emptyDescription} />
          ) : (
            <div className={workspaceStyles.tableWrap}>
              <table className={workspaceStyles.table}>
                <thead>
                  <tr>
                    <th scope="col">{copy.colDriverName}</th>
                    <th scope="col">{copy.colAvailableSeats}</th>
                    <th scope="col">{copy.colPassengersAssigned}</th>
                    <th scope="col">{copy.colStatus}</th>
                    <th scope="col">{copy.colAction}</th>
                  </tr>
                </thead>
                <tbody>
                  {drivers.map((driver) => (
                    <tr key={driver.id} data-testid={`driver-row-${driver.id}`}>
                      <th scope="row" className={workspaceStyles.rowHeader}>
                        {driver.driverName}
                        {driver.source === "manual" ? (
                          <span className={workspaceStyles.muted}> ({copy.manualBadge})</span>
                        ) : null}
                      </th>
                      <td>{formatCount(driver.availableSeats)}</td>
                      <td>
                        {formatCount(driver.passengersAssigned)}
                        {driver.passengerNames.length > 0 ? (
                          <p className={styles.assignedNames} title={driver.passengerNames.join("، ")}>
                            {driver.passengerNames.join("، ")}
                          </p>
                        ) : null}
                      </td>
                      <td>
                        <Badge
                          variant={driver.status === "full" ? "success" : "warning"}
                          data-testid={`driver-status-${driver.id}`}
                        >
                          {driver.status === "full" ? copy.statusFull : copy.statusHasCapacity}
                        </Badge>
                      </td>
                      <td>
                        <Button
                          type="button"
                          size="sm"
                          variant="secondary"
                          disabled={
                            readOnly ||
                            unassignedPassengers.length === 0 ||
                            (driver.availableSeats > 0 &&
                              driver.passengersAssigned >= driver.availableSeats)
                          }
                          data-testid={`driver-assign-${driver.id}`}
                          onClick={() => {
                            setAssignDriverId(driver.id);
                            setSelectedPassengerId(unassignedPassengers[0]?.registrationId ?? "");
                          }}
                        >
                          {copy.assign}
                        </Button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
          {unassignedPassengers.length > 0 ? (
            <p className={styles.unassignedHint} role="status">
              {copy.unassignedCount}: <strong>{formatCount(unassignedPassengers.length)}</strong>
            </p>
          ) : null}
        </CardBody>
      </Card>

      <Modal
        open={assignDriverId != null}
        onClose={closeAssignModal}
        title={copy.assignModalTitle}
        footer={
          <>
            <Button type="button" variant="ghost" onClick={closeAssignModal}>
              {copy.cancel}
            </Button>
            <Button
              type="button"
              variant="primary"
              disabled={!canAssignMore || !selectedPassengerId}
              onClick={confirmAssign}
            >
              {copy.confirmAssign}
            </Button>
          </>
        }
      >
        {activeDriver ? (
          <p className={styles.assignModalLead}>{copy.assignModalDescription(activeDriver.driverName)}</p>
        ) : null}
        {unassignedPassengers.length === 0 ? (
          <p>{copy.noUnassigned}</p>
        ) : (
          <label className={styles.assignField}>
            <span className={styles.assignLabel}>{copy.selectPassenger}</span>
            <Select
              value={selectedPassengerId}
              onChange={(e) => setSelectedPassengerId(e.target.value)}
              data-testid="assign-passenger-select"
            >
              {unassignedPassengers.map((p) => (
                <option key={p.registrationId} value={p.registrationId}>
                  {p.passengerName}
                </option>
              ))}
            </Select>
          </label>
        )}
      </Modal>
    </>
  );
}

"use client";

import { memo } from "react";

import type { BookingDto } from "@repo/types";
import type { RegistrationPaymentStatus, RegistrationStatus } from "@repo/types";

import { RegistrationTransportCrmCell } from "@/components/registrations/registration-transport-crm-cell";
import { BookingStatusBadgeFa, PaymentStatusBadgeFa } from "@/components/registrations/registration-status-badges-fa";
import { formatPaymentStatusFa, formatRegistrationStatusFa } from "@/lib/registrations/format-registration-status-fa";
import { TOUR_WORKSPACE_COPY } from "./tour-workspace-copy";

import { Button, Input, Select } from "@tour/ui";

import type { BookingAggregatePaymentStatus } from "@/lib/booking-transition-policy";
import {
  getAllowedBookingTransitions,
  getAllowedPaymentTransitions,
  isTerminalBookingState,
  isTerminalPaymentState,
} from "@/lib/booking-transition-policy";

import styles from "./tour-workspace.module.css";

const copy = TOUR_WORKSPACE_COPY.registrations;
const PUBLIC_PATCH_PAYMENT: ReadonlySet<string> = new Set(["NotPaid", "Partial", "Paid"]);

function uniqueOrdered<T extends string>(items: readonly T[]): T[] {
  const seen = new Set<T>();
  const out: T[] = [];
  for (const x of items) {
    if (seen.has(x)) continue;
    seen.add(x);
    out.push(x);
  }
  return out;
}

function persistPaymentWire(reg: BookingDto): BookingAggregatePaymentStatus {
  return reg.paymentStatus as BookingAggregatePaymentStatus;
}

export type RegistrationTableRowProps = {
  reg: BookingDto;
  statusValue: RegistrationStatus;
  paymentValue: RegistrationPaymentStatus;
  amountValue: string;
  readOnly: boolean;
  statusPendingRowId: string | null;
  paymentPendingRowId: string | null;
  statusRowError: boolean;
  paymentRowError: boolean;
  statusErrorMessage: string | null;
  paymentErrorMessage: string | null;
  paymentSaveIsNoOp: boolean;
  onStatusDraftChange: (id: string, status: RegistrationStatus) => void;
  onPayDraftChange: (id: string, payment: RegistrationPaymentStatus) => void;
  onAmountDraftChange: (id: string, amount: string) => void;
  onApplyStatus: (reg: BookingDto, targetStatus: RegistrationStatus) => void;
  onSavePayment: (reg: BookingDto, paymentStatus: RegistrationPaymentStatus, rawAmount: string) => void;
};

function registrationTableRowPropsEqual(
  prev: RegistrationTableRowProps,
  next: RegistrationTableRowProps,
): boolean {
  return (
    prev.reg.id === next.reg.id &&
    prev.reg.rowVersion === next.reg.rowVersion &&
    prev.reg.status === next.reg.status &&
    prev.reg.paymentStatus === next.reg.paymentStatus &&
    prev.reg.participantFullName === next.reg.participantFullName &&
    prev.reg.participantContactPhone === next.reg.participantContactPhone &&
    prev.reg.transportMode === next.reg.transportMode &&
    prev.reg.vehicleSeatCapacity === next.reg.vehicleSeatCapacity &&
    prev.reg.participantNote === next.reg.participantNote &&
    prev.statusValue === next.statusValue &&
    prev.paymentValue === next.paymentValue &&
    prev.amountValue === next.amountValue &&
    prev.readOnly === next.readOnly &&
    prev.statusPendingRowId === next.statusPendingRowId &&
    prev.paymentPendingRowId === next.paymentPendingRowId &&
    prev.statusRowError === next.statusRowError &&
    prev.paymentRowError === next.paymentRowError &&
    prev.statusErrorMessage === next.statusErrorMessage &&
    prev.paymentErrorMessage === next.paymentErrorMessage &&
    prev.paymentSaveIsNoOp === next.paymentSaveIsNoOp &&
    prev.onStatusDraftChange === next.onStatusDraftChange &&
    prev.onPayDraftChange === next.onPayDraftChange &&
    prev.onAmountDraftChange === next.onAmountDraftChange &&
    prev.onApplyStatus === next.onApplyStatus &&
    prev.onSavePayment === next.onSavePayment
  );
}

export const RegistrationTableRow = memo(function RegistrationTableRow({
  reg,
  statusValue,
  paymentValue,
  amountValue,
  readOnly,
  statusPendingRowId,
  paymentPendingRowId,
  statusRowError,
  paymentRowError,
  statusErrorMessage,
  paymentErrorMessage,
  paymentSaveIsNoOp,
  onStatusDraftChange,
  onPayDraftChange,
  onAmountDraftChange,
  onApplyStatus,
  onSavePayment,
}: RegistrationTableRowProps) {
  const bookingTerminal = isTerminalBookingState(reg.status);
  const paymentWire = persistPaymentWire(reg);
  const paymentTerminal = isTerminalPaymentState(paymentWire);

  const statusSelectDisabled =
    readOnly || bookingTerminal || (statusPendingRowId != null && statusPendingRowId === reg.id);
  const statusApplyHidden = readOnly || bookingTerminal;
  const statusApplyDisabled =
    statusPendingRowId === reg.id ? true : statusValue === reg.status;

  const paymentSelectDisabled =
    readOnly ||
    bookingTerminal ||
    paymentTerminal ||
    (paymentPendingRowId != null && paymentPendingRowId === reg.id);
  const paymentSaveHidden = readOnly || bookingTerminal || paymentTerminal;
  const paymentSaveDisabled =
    paymentPendingRowId === reg.id || paymentSaveIsNoOp;

  const rowErrored = statusRowError || paymentRowError;

  const statusOptions = (() => {
    const persisted = reg.status;
    if (readOnly || isTerminalBookingState(persisted)) {
      return uniqueOrdered([statusValue, persisted]);
    }
    const allowed = [...getAllowedBookingTransitions(persisted)];
    const legal = new Set<RegistrationStatus>([persisted, ...allowed]);
    return uniqueOrdered([persisted, statusValue, ...allowed]).filter((s) => legal.has(s));
  })();

  const paymentOptions = (() => {
    const persistedWire = persistPaymentWire(reg);
    const persistedPublic = reg.paymentStatus as RegistrationPaymentStatus;
    if (readOnly || isTerminalBookingState(reg.status) || isTerminalPaymentState(persistedWire)) {
      return uniqueOrdered([paymentValue, persistedPublic]);
    }
    const patchAllowed = [...getAllowedPaymentTransitions(persistedWire, reg.status)].filter(
      (p): p is RegistrationPaymentStatus => PUBLIC_PATCH_PAYMENT.has(p),
    );
    const legal = new Set<RegistrationPaymentStatus>([persistedPublic, ...patchAllowed]);
    return uniqueOrdered([persistedPublic, paymentValue, ...patchAllowed]).filter((s) => legal.has(s));
  })();

  return (
    <tr className={rowErrored ? styles.workspaceRowErrored : undefined}>
      <th scope="row" className={styles.rowHeader}>
        <div>{reg.participantFullName}</div>
        <div className={styles.muted}>{reg.participantContactPhone}</div>
        <div className={styles.mono}>{reg.id.slice(0, 8)}…</div>
      </th>
      <td>
        <RegistrationTransportCrmCell reg={reg} />
      </td>
      <td>
        <div className={styles.badgeRow}>
          <BookingStatusBadgeFa status={reg.status} />
          <PaymentStatusBadgeFa payment={reg.paymentStatus} />
        </div>
      </td>
      <td>
        <div className={styles.controls}>
          <Select
            aria-label={`Status for ${reg.id}`}
            value={statusValue}
            disabled={statusSelectDisabled}
            onChange={(e) => onStatusDraftChange(reg.id, e.target.value as RegistrationStatus)}
          >
            {statusOptions.map((s) => (
              <option key={s} value={s}>
                {formatRegistrationStatusFa(s)}
              </option>
            ))}
          </Select>
          {statusApplyHidden ? null : (
            <Button
              type="button"
              size="sm"
              variant="secondary"
              disabled={statusApplyDisabled}
              onClick={() => onApplyStatus(reg, statusValue)}
            >
              {copy.apply}
            </Button>
          )}
          {statusRowError && statusErrorMessage ? (
            <span className={styles.waitlistInlineError} role="alert">
              {statusErrorMessage}
            </span>
          ) : null}
        </div>
      </td>
      <td>
        <div className={styles.controls}>
          <Select
            aria-label={`Payment for ${reg.id}`}
            value={paymentValue}
            disabled={paymentSelectDisabled}
            onChange={(e) => onPayDraftChange(reg.id, e.target.value as RegistrationPaymentStatus)}
          >
            {paymentOptions.map((s) => (
              <option key={s} value={s}>
                {formatPaymentStatusFa(s)}
              </option>
            ))}
          </Select>
          <Input
            type="number"
            min={0}
            placeholder={copy.paidAmountPlaceholder}
            disabled={paymentSelectDisabled}
            value={amountValue}
            aria-label={`Paid amount for ${reg.participantFullName}`}
            onChange={(e) => onAmountDraftChange(reg.id, e.target.value)}
          />
          {paymentSaveHidden ? null : (
            <Button
              type="button"
              size="sm"
              variant="secondary"
              disabled={paymentSaveDisabled}
              onClick={() => onSavePayment(reg, paymentValue, amountValue)}
            >
              {copy.savePayment}
            </Button>
          )}
          {paymentRowError && paymentErrorMessage ? (
            <span className={styles.waitlistInlineError} role="alert">
              {paymentErrorMessage}
            </span>
          ) : null}
        </div>
      </td>
    </tr>
  );
}, registrationTableRowPropsEqual);

