  return (
    <svg width={18} height={18} viewBox="0 0 24 24" aria-hidden focusable="false">
      <path
        fill="currentColor"
        d="M12 16 7 11h3V4h4v7h3l-5 5Zm-7 4h14v2H5v-2Z"
      />
    </svg>
  );
}

type UserFiltersProps = {
  searchQuery: string;
  roleFilter: RoleFilter;
  isRefreshing: boolean;
  exportDisabled: boolean;
  onSearchChange: (value: string) => void;
  onRoleFilterChange: (value: RoleFilter) => void;
  onExportCsv: () => void;
  onInviteUser: () => void;
};

export function UserFilters({
  searchQuery,
  roleFilter,
  isRefreshing,
  exportDisabled,
  onSearchChange,
  onRoleFilterChange,
  onExportCsv,
  onInviteUser,
}: UserFiltersProps) {
  const ability = useAbility();

  return (
    <div className={styles.toolbarRow} role="group" aria-label={copy.membersToolbarAriaLabel}>
      <div className={styles.toolbarFilters}>
        <FormField label={copy.searchLabel} className={styles.toolbarSearchField}>
          <Input
            type="search"
            placeholder={copy.searchPlaceholder}
            value={searchQuery}
            onChange={(e) => onSearchChange(e.target.value)}
            autoComplete="off"
          />
        </FormField>
        <FormField label={copy.filterRoleLabel} className={styles.toolbarRoleField}>
          <Select value={roleFilter} onChange={(e) => onRoleFilterChange(e.target.value as RoleFilter)}>
            <option value="all">{copy.roleFilterAll}</option>
            <option value="owner">{copy.roleFilterOwner}</option>
            <option value="leader">{copy.roleFilterLeader}</option>
            <option value="admin">{copy.roleFilterAdmin}</option>
            <option value="member">{copy.roleFilterMember}</option>
            <option value="viewer">{copy.roleFilterViewer}</option>
          </Select>
        </FormField>
        {isRefreshing ? <small className={styles.toolbarRefreshing}>{copy.refreshingLabel}</small> : null}
      </div>
      <div className={styles.toolbarActions}>
        <Button
          type="button"
          variant="ghost"
          size="sm"
          className={styles.toolbarIconButton}
          aria-label={copy.exportCsvAriaLabel}
          title={copy.exportCsvAriaLabel}
          disabled={exportDisabled}
          onClick={onExportCsv}
        >
          <ExportCsvIcon />
        </Button>
        <Can<AppAbility> ability={ability} I={AbilityAction.Create} a="UserMembership">
          {(allowed) => (
            <Button type="button" variant="primary" onClick={onInviteUser} disabled={!allowed}>
              {copy.inviteUserButton}
            </Button>
          )}
        </Can>
      </div>
    </div>
  );
}

"use client";

import type { UseMutationResult } from "@tanstack/react-query";
import type { CSSProperties } from "react";
import { memo } from "react";

import { Badge, TableCell, TableRow } from "@tour/ui";

import type { AuthUser } from "@/lib/auth/auth-context";
import type { WorkspaceUserDto } from "@/lib/services/users.service";
import type { UserRole as UserRoleType } from "@/lib/auth/user-role";

import { CopyToClipboardButton } from "./components/copy-to-clipboard-button";
import { UserRowActionsMenu } from "./components/user-row-actions-menu";
import { UserAvatar } from "./user-avatar";
import {
  formatActiveAgoLabelFa,
  formatTripSummaryLabelFa,
  formatWalletBalanceMinor
} from "./users-format";
import { USERS_ROUTE_COPY } from "./users-copy";
import { formatMembershipLabelDisplay, normalizeRole, roleVariant, systemRoleBadgeLabel } from "./users-page-logic";
import styles from "./users-page.module.css";

const copy = USERS_ROUTE_COPY.list;

type UserRowProps = {
  row: WorkspaceUserDto;
  sessionUser: AuthUser | null;
  activeRoleMutationUserId: string | null;
  roleMutation: UseMutationResult<WorkspaceUserDto, unknown, { userId: string; role: UserRoleType }, unknown>;
  onManageRewards?: (user: WorkspaceUserDto) => void;
  directoryListQueryKey?: readonly unknown[];
  trStyle?: CSSProperties;
  className?: string;
};

function UserRowBase({
  row,
  sessionUser,
  activeRoleMutationUserId,
  roleMutation,
  onManageRewards,
  directoryListQueryKey,
  trStyle,
  className,
}: UserRowProps) {
  const sessionUserId = sessionUser?.userId ?? "";
  const isSelfTarget = row.id === sessionUserId;
  const isOwnerTarget = normalizeRole(row.role) === "owner";
  const email = row.email?.trim() ?? "";
  const hasEmail = email.length > 0;
  const phoneDisplay = row.phone?.trim() ? row.phone.trim() : null;
  const walletLabel = formatWalletBalanceMinor(row.walletBalanceMinor, row.walletCurrency);
  const tripSummaryLabel = formatTripSummaryLabelFa(row.completedTrips, row.cancelledTrips);
  const activityLabel = formatActiveAgoLabelFa(row.lastActiveAt, copy.neverActiveLabel);
  const discountPct = row.permanentDiscountPercentage ?? 0;
  const badges = row.rewardBadges ?? [];
  const hasVip = badges.includes("VIP_MEMBER");
  const hasGold = badges.includes("GOLD_CLUB");
  const labelChips = (row.labels ?? []).filter((l) => l.trim().length > 0);

  return (
    <TableRow className={className} style={trStyle}>
      <TableCell className={styles.userCell}>
        <div className={styles.userProfileStack}>
          <UserAvatar user={row} />
          <div className={styles.userProfileText}>
            <span className={styles.userCellName}>{row.name}</span>
            {hasEmail ? (
              <span className={styles.userCellSecondary}>
                <span className={styles.userCellSecondaryText}>{email}</span>
                <CopyToClipboardButton
                  value={email}
                  ariaLabel={`کپی ایمیل ${row.name}`}
                  successToast={copy.copyEmailSuccessToast}
                />
              </span>
            ) : null}
            {phoneDisplay ? (
              <span className={styles.userCellSecondary}>
                <span className={styles.userCellSecondaryText}>{phoneDisplay}</span>
                <CopyToClipboardButton
                  value={phoneDisplay}
                  ariaLabel={`کپی شماره ${row.name}`}
                  successToast={copy.copyPhoneSuccessToast}
                />
              </span>
            ) : null}
            <span className={styles.userActiveHint}>{activityLabel}</span>
            {labelChips.length > 0 ? (
              <div className={styles.profileLabelChips}>
                {labelChips.map((label) => (
                  <span key={label} className={styles.profileLabelChip}>
                    {formatMembershipLabelDisplay(label)}
                  </span>
                ))}
              </div>
            ) : null}
          </div>
        </div>
      </TableCell>
      <TableCell className={styles.roleCell}>
        <Badge className={styles.roleBadge} variant={roleVariant(row.role)}>
          {systemRoleBadgeLabel(row.role)}
        </Badge>
      </TableCell>
      <TableCell className={styles.financialsCell}>
        <div className={styles.financialsStack}>
          <span className={styles.walletBalanceLabel}>{walletLabel}</span>
          <span className={styles.tripSummaryLabel}>{tripSummaryLabel}</span>
          <div className={styles.financialsBadgeRow}>
            {discountPct > 0 ? (
              <span className={styles.discountMicroBadge}>
                {copy.discountMicroBadge.replace("{n}", String(discountPct))}
              </span>
            ) : null}
            {hasVip ? (
              <Badge className={`${styles.rewardBadgeHighContrast} ${styles.rewardBadgeVip}`}>
                {copy.vipMicroBadge}
              </Badge>
            ) : null}
            {hasGold ? (
              <Badge className={`${styles.rewardBadgeHighContrast} ${styles.rewardBadgeGold}`}>
                {copy.goldMicroBadge}
              </Badge>
            ) : null}
          </div>
        </div>
      </TableCell>
      <TableCell className={styles.actionsCell} onClick={(e) => e.stopPropagation()}>
        <UserRowActionsMenu
          rowId={row.id}
          rowName={row.name}
          rowRole={row.role}
          rowStatus={row.status}
          isSelfTarget={isSelfTarget}
          isOwnerTarget={isOwnerTarget}
          sessionUser={sessionUser}
          activeRoleMutationUserId={activeRoleMutationUserId}
          roleMutation={roleMutation}
          onManageRewards={onManageRewards ? () => onManageRewards(row) : undefined}
          directoryListQueryKey={directoryListQueryKey}
        />
      </TableCell>
    </TableRow>
  );
}

export const UserRow = memo(UserRowBase);

"use client";

import { useVirtualizer } from "@tanstack/react-virtual";
import type { UseMutationResult } from "@tanstack/react-query";
import { memo, useCallback, useEffect, useRef } from "react";

import { Button, Table, TableBody, TableHead, TableHeaderCell, TableRow } from "@tour/ui";

import type { AuthUser } from "@/lib/auth/auth-context";
import type { WorkspaceUserDto } from "@/lib/services/users.service";
import type { UserRole } from "@/lib/auth/user-role";

import { type UserSortColumn, type UserSortDirection } from "./users-page-logic";
import styles from "./users-page.module.css";
import { USERS_ROUTE_COPY } from "./users-copy";
import { UserRow } from "./user-row";

const copy = USERS_ROUTE_COPY.list;

const VIRTUAL_USER_ROW_HEIGHT_PX = 100;

function ariaSortForColumn(
  column: UserSortColumn,
  activeColumn: UserSortColumn,
  sortDir: UserSortDirection
): "ascending" | "descending" | "none" {
  if (activeColumn !== column) return "none";
  return sortDir === "asc" ? "ascending" : "descending";
}

type UserTableProps = {
  rows: WorkspaceUserDto[];
  sortColumn: UserSortColumn;
  sortDir: UserSortDirection;
  sessionUser: AuthUser | null;
  activeRoleMutationUserId: string | null;
  roleMutation: UseMutationResult<WorkspaceUserDto, unknown, { userId: string; role: UserRole }, unknown>;
  onToggleSort: (column: UserSortColumn) => void;
  onManageRewards?: (user: WorkspaceUserDto) => void;
  directoryListQueryKey?: readonly unknown[];
  hasMoreBelow?: boolean;
  onRequestLoadMore?: () => void;
};

function UserTableBase({
  rows,
  sortColumn,
  sortDir,
  sessionUser,
  activeRoleMutationUserId,
  roleMutation,
  onToggleSort,
  onManageRewards,
  directoryListQueryKey,
  hasMoreBelow = false,
  onRequestLoadMore,
}: UserTableProps) {
  const scrollRef = useRef<HTMLDivElement | null>(null);
  const loadMoreRequestedRef = useRef(false);

  const virtualizer = useVirtualizer({
    count: rows.length,
    getScrollElement: () => scrollRef.current,
    estimateSize: () => VIRTUAL_USER_ROW_HEIGHT_PX,
    overscan: 14,
  });

  const requestLoadMore = useCallback(() => {
    if (!hasMoreBelow || !onRequestLoadMore) {
      return;
    }
    if (loadMoreRequestedRef.current) {
      return;
    }
    loadMoreRequestedRef.current = true;
    onRequestLoadMore();
    window.setTimeout(() => {
      loadMoreRequestedRef.current = false;
    }, 400);
  }, [hasMoreBelow, onRequestLoadMore]);

  useEffect(() => {
    virtualizer.measure();
  }, [rows, virtualizer]);

  useEffect(() => {
    const el = scrollRef.current;
    if (!el) {
      return undefined;
    }
    const onScroll = () => {
      const { scrollTop, scrollHeight, clientHeight } = el;
      const distanceToBottom = scrollHeight - scrollTop - clientHeight;
      if (distanceToBottom < 480) {
        requestLoadMore();
      }
      const items = virtualizer.getVirtualItems();
      if (items.length === 0) {
        return;
      }
      const last = items[items.length - 1];
      if (last && last.index >= rows.length - 8) {
        requestLoadMore();
      }
    };
    el.addEventListener("scroll", onScroll, { passive: true });
    onScroll();
    return () => el.removeEventListener("scroll", onScroll);
  }, [virtualizer, rows.length, requestLoadMore]);

  const totalSize = virtualizer.getTotalSize();

  return (
    <div ref={scrollRef} className={styles.virtualScrollViewport} dir="rtl">
      <Table className={styles.directoryTable} aria-label={copy.tableAriaLabel}>
        <TableHead className={styles.stickyDirectoryThead}>
          <TableRow className={styles.directoryGridRow}>
            <TableHeaderCell aria-sort={ariaSortForColumn("name", sortColumn, sortDir)}>
              <Button type="button" variant="ghost" size="sm" onClick={() => onToggleSort("name")}>
                {copy.columnUser}{" "}
                {sortColumn === "name" ? (sortDir === "asc" ? "↑" : "↓") : ""}
              </Button>
            </TableHeaderCell>
            <TableHeaderCell>{copy.columnSystemRole}</TableHeaderCell>
            <TableHeaderCell>{copy.columnFinancialsAnalytics}</TableHeaderCell>
            <TableHeaderCell className={styles.actionsCell} aria-label={copy.columnActions}>
              <span className={styles.actionsHeaderLabel}>{copy.columnActions}</span>
            </TableHeaderCell>
          </TableRow>
        </TableHead>
        <TableBody className={styles.virtualTbody} style={{ height: `${totalSize}px` }}>
          {virtualizer.getVirtualItems().map((virtualRow) => {
            const row = rows[virtualRow.index];
            if (!row) {
              return null;
            }
            return (
              <UserRow
                key={row.id}
                row={row}
                sessionUser={sessionUser}
                activeRoleMutationUserId={activeRoleMutationUserId}
                roleMutation={roleMutation}
                onManageRewards={onManageRewards}
                directoryListQueryKey={directoryListQueryKey}
                trStyle={{
                  height: `${virtualRow.size}px`,
                  transform: `translateY(${virtualRow.start}px)`,
                }}
                className={`${styles.directoryGridRow} ${styles.virtualDataRow}`}
              />
            );
          })}
        </TableBody>
      </Table>
    </div>
  );
}

