import { NextResponse } from "next/server";

import { AppError } from "@/lib/errors/app-error";
import { bffFetchAuth, bffFetchWithInternalKey, proxyBffPatch, readSessionToken } from "@/lib/api/bff-proxy";
import {
  mergeResolvedGearIntoTour,
  mergeResolvedThemesIntoTour,
  parseCatalogJson,
} from "@/lib/api/tour-catalog-aggregation";
import { mergeRegistrationPolicyIntoTour } from "@/lib/tours/registration-policy";
import { buildTourDetailViewForAccess } from "@/lib/tours/tour-detail-redaction";
import { resolveTourDetailAccessLevel } from "@/lib/tours/resolve-tour-detail-access";
import { logBffError } from "@/lib/logging/bff-logger";

type RouteContext = { params: { tourId: string } };

export async function GET(req: Request, context: RouteContext): Promise<NextResponse> {
  if (!readSessionToken(req)) {
    return NextResponse.json(
      { error: { code: "AUTH_UNAUTHENTICATED", message: "Authentication required" } },
      { status: 401 },
    );
  }
  const { tourId } = context.params;

  try {
    const tourRes = await bffFetchAuth(req, `/api/v2/tours/${encodeURIComponent(tourId)}`);
    if (!tourRes.ok) {
      const error = await tourRes.json().catch(() => ({}));
      return NextResponse.json(error, { status: tourRes.status });
    }
    const tourRaw = (await tourRes.json()) as Record<string, unknown>;

    const { accessLevel, viewHints } = await resolveTourDetailAccessLevel(req, tourId, tourRaw);
    const tour = buildTourDetailViewForAccess(tourRaw, accessLevel, viewHints);

    let equipmentCatalog = null;
    let themesCatalog = null;

    try {
      const [equipmentRes, themesRes] = await Promise.all([
        bffFetchWithInternalKey(req, "/api/v2/settings/equipment"),
        bffFetchWithInternalKey(req, "/api/v2/settings/tour-themes"),
      ]);

      if (!equipmentRes.ok) {
        const equipmentError = await equipmentRes.json().catch(() => ({}));
        logBffError("tour_aggregate_equipment_upstream_failed", {
          tourId,
          status: equipmentRes.status,
          error: equipmentError,
        });
      } else {
        equipmentCatalog = await parseCatalogJson(equipmentRes);
      }

      if (!themesRes.ok) {
        const themesError = await themesRes.json().catch(() => ({}));
        logBffError("tour_aggregate_themes_upstream_failed", {
          tourId,
          status: themesRes.status,
          error: themesError,
        });
      } else {
        themesCatalog = await parseCatalogJson(themesRes);
      }
    } catch (catalogError) {
      logBffError("tour_aggregate_catalog_fetch_failed", {
        tourId,
        message: catalogError instanceof Error ? catalogError.message : String(catalogError),
      });
    }

    mergeResolvedGearIntoTour(tour, equipmentCatalog, { tourId, catalog: "equipment" });
    mergeResolvedThemesIntoTour(tour, themesCatalog, { tourId });
    mergeRegistrationPolicyIntoTour(tour);

    return NextResponse.json({
      ...tour,
      accessLevel,
      viewHints,
    });
  } catch (error) {
    if (error instanceof AppError && error.code === "AUTH_SESSION_INVALID") {
      return NextResponse.json(
        { error: { code: "AUTH_UNAUTHENTICATED", message: "Authentication required" } },
        { status: 401 },
      );
    }
    console.error("BFF Tour Aggregation Error:", error);
    return NextResponse.json(
      { error: { code: "INTERNAL_SERVER_ERROR", message: "Failed to aggregate tour data" } },
      { status: 500 },
    );
  }
}

export async function PATCH(req: Request, context: RouteContext): Promise<NextResponse> {
  if (!readSessionToken(req)) {
    return NextResponse.json(
      { error: { code: "AUTH_UNAUTHENTICATED", message: "Authentication required" } },
      { status: 401 },
    );
  }
  const { tourId } = context.params;
  return proxyBffPatch(req, `/api/v2/tours/${encodeURIComponent(tourId)}`);
}

"use client";

import { useMemo, useState } from "react";
import { zodResolver } from "@hookform/resolvers/zod";
import { useLocale, useTranslations } from "next-intl";
import { useForm } from "react-hook-form";
import { z } from "zod";

import { Button, FormField, Input, useToast } from "@tour/ui";

import { useSearchParams } from "next/navigation";

import { useRouter } from "@/i18n/navigation";
import { useAuth } from "@/lib/auth/auth-context";
import { ApiError } from "@/lib/api-client";
import { resolveAuthUiErrorMessage } from "@/lib/errors/auth-ui-error-message";
import { useDigitLocalization } from "@/hooks/useDigitLocalization";
import { normalizeOtpPhoneInput } from "@/lib/otp-phone-normalize";
import {
  syntheticChangeForInputValue,
  toEnglishIntegerString,
  withIntegerDigitNormalization,
} from "../../../src/lib/number-utils";

import authStyles from "../auth-forms.module.css";

type LoginFormValues = {
  phone: string;
  otp: string;
};

type LoginStep = "phone" | "otp";

function loginToastMessage(err: unknown, t: (key: string) => string): string {
  if (err instanceof ApiError) {
    if (err.code === "AUTH_OTP_INVALID") {
      return t("login.toastInvalidPhoneOrOtp");
    }
    if (err.code === "AUTH_OTP_EXPIRED") {
      return t("login.toastGeneric");
    }
    if (err.code === "AUTH_PHONE_INVALID" || err.code === "AUTH_UNAUTHENTICATED") {
      return t("login.toastInvalidPhoneOrOtp");
    }
    return err.message.trim() || t("login.toastGeneric");
  }
  if (err instanceof Error) {
    const m = err.message.trim();
    if (m === "Invalid phone number or OTP code.") {
      return t("login.toastInvalidPhoneOrOtp");
    }
    if (m === "Failed to request OTP") {
      return t("login.toastFailedRequestOtp");
    }
    if (m === "Session was not established. Please try again.") {
      return t("login.toastSessionNotEstablished");
    }
    if (m === "Login failed") {
      return t("login.toastLoginFailed");
    }
    if (m) {
      return resolveAuthUiErrorMessage(err);
    }
  }
  return t("login.toastGeneric");
}

export function LoginForm() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const { showToast } = useToast();
  const { setSession } = useAuth();
  const t = useTranslations("auth");
  const locale = useLocale();
  const { toPersian, toDisplayPersianDigits } = useDigitLocalization();
  const [step, setStep] = useState<LoginStep>("phone");
  const [otpChallengeId, setOtpChallengeId] = useState<string | null>(null);
  const inviteToken = searchParams.get("invite")?.trim() || "";

  const loginSchema = useMemo(
    () =>
      z.object({
        phone: z
          .string()
          .transform((s) => normalizeOtpPhoneInput(s))
          .pipe(
            z
              .string()
              .min(1, t("login.validationPhoneRequired"))
              .min(8, t("login.validationPhoneInvalid")),
          ),
        otp:
          step === "phone"
            ? z.string()
            : z
                .string()
                .transform((s) => toEnglishIntegerString(s.trim()))
                .pipe(z.string().min(1, t("login.validationOtpRequired"))),
      }),
    [step, t],
  );

  const {
    register,
    handleSubmit,
    setValue,
    clearErrors,
    watch,
    formState: { errors, isSubmitting },
  } = useForm<LoginFormValues>({
    resolver: zodResolver(loginSchema),
    defaultValues: { phone: "", otp: "" },
    mode: "onChange",
  });

  const phoneRegister = register("phone");
  const otpRegister = withIntegerDigitNormalization(register("otp"));

  async function onValid(data: LoginFormValues): Promise<void> {
    try {
      if (step === "phone") {
        if (!data.phone) return;
        const normalizedPhone = normalizeOtpPhoneInput(data.phone);
        const otpRequestResponse = await fetch("/api/auth/request-otp", {
          method: "POST",
          credentials: "include",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            phone: normalizedPhone,
            ...(inviteToken ? { invite_token: inviteToken } : {}),
          }),
        });
        const otpRequestPayload = (await otpRequestResponse.json().catch(() => ({}))) as {
          ok?: boolean;
          challenge_id?: string;
          error_code?: string;
          message?: string;
          error?: { message?: string };
        };
        const otpRequestMessage =
          otpRequestPayload.message ??
          (typeof otpRequestPayload.error?.message === "string" ? otpRequestPayload.error.message : undefined);
        if (!otpRequestResponse.ok || !otpRequestPayload.ok) {
          throw new Error(otpRequestMessage ?? "Failed to request OTP");
        }
        const challengeId =
          typeof otpRequestPayload.challenge_id === "string"
            ? otpRequestPayload.challenge_id.trim()
            : "";
        setOtpChallengeId(challengeId || null);
        setStep("otp");
        clearErrors();
        return;
      }
      if (step === "otp") {
        if (!data.phone) return;
      }
      const loginBody = {
        phone: normalizeOtpPhoneInput(data.phone),
        otp: toEnglishIntegerString(data.otp.trim()),
        ...(inviteToken ? { invite_token: inviteToken } : {}),
        // Dev static OTP path does not require challenge rows; sending a stale/missing
        // challenge_id yields AUTH_OTP_INVALID and blocks registration redirect.
        ...(process.env.NODE_ENV !== "development" && otpChallengeId
          ? { challenge_id: otpChallengeId }
          : {}),
      };
      const postLoginWebSession = (body: Record<string, string>) =>
        fetch("/api/auth/login-web-session", {
          method: "POST",
          credentials: "include",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(body),
        });

      let response = await postLoginWebSession(loginBody);
      let payload = (await response.json().catch(() => ({}))) as {
        ok?: boolean;
        requires_registration?: boolean;
        onboarding_token?: string;
        session_token?: string;
        user_id?: string;
        tenant_id?: string;
        error_code?: string;
        message?: string;
        error?: { code?: string; message?: string };
      };
      const loginErrorCode =
        payload.error?.code?.trim() || payload.error_code?.trim() || "";
      if (
        (!response.ok || !payload.ok) &&
        loginErrorCode === "AUTH_OTP_INVALID" &&
        "challenge_id" in loginBody
      ) {
        const { challenge_id: _dropped, ...loginBodyWithoutChallenge } = loginBody;
        response = await postLoginWebSession(loginBodyWithoutChallenge);
        payload = (await response.json().catch(() => ({}))) as typeof payload;
      }
      if (
        payload.requires_registration === true &&
        typeof payload.onboarding_token === "string" &&
        payload.onboarding_token.trim() !== ""
      ) {
        const params = new URLSearchParams({
          onboarding: payload.onboarding_token.trim(),
        });
        if (inviteToken) {
          params.set("invite", inviteToken);
        }
        router.push(`/auth/register?${params.toString()}`);
        return;
      }
      if (!response.ok || !payload.ok) {
        const code =
          payload.error?.code?.trim() ||
          payload.error_code?.trim() ||
          "AUTH_FAILED";
        if (code === "AUTH_OTP_INVALID" || code === "AUTH_PHONE_INVALID") {
          throw new Error("Invalid phone number or OTP code.");
        }
        throw new Error(
          payload.error?.message?.trim() || payload.message?.trim() || "Login failed",
        );
      }
      const tokenFromLogin =
        typeof payload.session_token === "string" ? payload.session_token.trim() : "";
      const userIdFromLogin =
        typeof payload.user_id === "string" ? payload.user_id.trim() : "";
      const tenantIdFromLogin =
        typeof payload.tenant_id === "string" ? payload.tenant_id.trim() : "";

      if (tokenFromLogin && userIdFromLogin && tenantIdFromLogin) {
        await setSession({
          session_token: tokenFromLogin,
          user_id: userIdFromLogin,
          tenant_id: tenantIdFromLogin,
          entry_mode: "web",
        });
      } else {
        const sessionPayload = (await fetch("/api/auth/session", {
          method: "GET",
          credentials: "include",
          cache: "no-store",
        })
          .then((r) => r.json())
          .catch(() => ({}))) as {
          authenticated?: boolean;
          session_token?: string;
          user_id?: string;
          tenant_id?: string;
        };
        if (
          sessionPayload.authenticated &&
          typeof sessionPayload.session_token === "string" &&
          typeof sessionPayload.user_id === "string" &&
          typeof sessionPayload.tenant_id === "string"
        ) {
          await setSession({
            session_token: sessionPayload.session_token,
            user_id: sessionPayload.user_id,
            tenant_id: sessionPayload.tenant_id,
            entry_mode: "web",
          });
        } else {
          throw new Error("Session was not established. Please try again.");
        }
      }
      showToast({ type: "success", message: t("login.toastSuccess") });
      void router.refresh();
      router.push("/dashboard");
    } catch (err: unknown) {
      showToast({ type: "error", message: loginToastMessage(err, t) });
    }
  }

  return (
    <>
      <h1 className={authStyles.heading}>{t("login.title")}</h1>
      <p className={authStyles.lead}>{t("login.subtitle")}</p>
      <form className={authStyles.form} onSubmit={handleSubmit(onValid)} noValidate>
        {step === "phone" && (
          <FormField label={t("login.phoneLabel")} error={errors.phone?.message}>
            <Input
              type="tel"
              autoComplete="tel"
              placeholder={
                locale === "fa" ? toDisplayPersianDigits(t("login.phonePlaceholder")) : t("login.phonePlaceholder")
              }
              aria-invalid={errors.phone ? true : undefined}
              disabled={isSubmitting}
              {...phoneRegister}
              onChange={(e) => {
                const el = e.target;
                const ascii = normalizeOtpPhoneInput(el.value);
                el.value = toPersian(ascii);
                void phoneRegister.onChange(syntheticChangeForInputValue(e, el, ascii));
              }}
            />
          </FormField>
        )}
        {step === "otp" && (
          <FormField label={t("login.otpLabel")} error={errors.otp?.message}>
            <Input
              type="text"
              autoComplete="one-time-code"
              placeholder={
                locale === "fa" ? toDisplayPersianDigits(t("login.otpPlaceholder")) : t("login.otpPlaceholder")
              }
              aria-invalid={errors.otp ? true : undefined}
              disabled={step !== "otp" || isSubmitting}
              {...otpRegister}
            />
          </FormField>
        )}
        {step === "otp" && (
          <p dir="ltr" style={{ unicodeBidi: "plaintext" }}>
            {toPersian(watch("phone") ?? "")}
          </p>
        )}
        {step === "otp" && (
          <p
            onClick={() => {
              setStep("phone");
              setOtpChallengeId(null);
              clearErrors();
              setValue("otp", "");
            }}
            style={{ cursor: "pointer" }}
          >
            {t("login.editPhone")}
          </p>
        )}
        {process.env.NODE_ENV === "development" ? (
          <p className={authStyles.helperText}>{t("login.devOtpHint")}</p>
        ) : null}
        <Button type="submit" variant="primary" loading={isSubmitting} disabled={isSubmitting}>
          {step === "phone" ? t("login.continue") : t("login.submit")}
        </Button>
      </form>
    </>
  );
}

"use client";

import { useEffect, useMemo } from "react";
import { zodResolver } from "@hookform/resolvers/zod";
import { useTranslations } from "next-intl";
import { useSearchParams } from "next/navigation";
import { useForm } from "react-hook-form";

import { Button, FormField, Input, useToast } from "@tour/ui";

import { Link, useRouter } from "@/i18n/navigation";
import { useAuth } from "@/lib/auth/auth-context";

import authStyles from "../auth-forms.module.css";
import { buildRegisterFormSchema, type RegisterFormValues } from "./register-schema";

export function RegisterForm() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const { showToast } = useToast();
  const { setSession } = useAuth();
  const t = useTranslations("auth");
  const onboardingToken = searchParams.get("onboarding")?.trim() || "";
  const inviteToken = searchParams.get("invite")?.trim() || "";

  useEffect(() => {
    if (!onboardingToken) {
      showToast({ type: "error", message: t("register.toastMissingSession") });
      router.replace("/login");
    }
  }, [onboardingToken, router, showToast, t]);

  const registerSchema = useMemo(() => buildRegisterFormSchema(t), [t]);

  if (!onboardingToken) {
    return null;
  }

  const {
    register,
    handleSubmit,
    formState: { errors, isSubmitting },
  } = useForm<RegisterFormValues>({
    resolver: zodResolver(registerSchema),
    defaultValues: { name: "", email: "" },
  });

  async function onValid(data: RegisterFormValues) {
    if (!onboardingToken) {
      showToast({ type: "error", message: t("register.toastMissingSession") });
      return;
    }
    const response = await fetch("/api/auth/complete-registration", {
      method: "POST",
      credentials: "include",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        onboarding_token: onboardingToken,
        full_name: data.name.trim(),
        email: data.email?.trim() || undefined,
      }),
    });
    const payload = (await response.json().catch(() => ({}))) as {
      ok?: boolean;
      error?: { message?: string };
      session_token?: string;
      user_id?: string;
      tenant_id?: string;
    };
    if (!response.ok || !payload.ok) {
      showToast({
        type: "error",
        message: payload.error?.message?.trim() || t("register.toastCompletionFailed"),
      });
      return;
    }
    if (
      typeof payload.session_token === "string" &&
      typeof payload.user_id === "string" &&
      typeof payload.tenant_id === "string"
    ) {
      await setSession({
        session_token: payload.session_token,
        user_id: payload.user_id,
        tenant_id: payload.tenant_id,
        entry_mode: "web",
      });
    }
    if (inviteToken) {
      const inviteResponse = await fetch("/api/auth/accept-invite", {
        method: "POST",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ invite_token: inviteToken }),
      });
      if (!inviteResponse.ok) {
        showToast({ type: "error", message: t("register.toastInviteFailed") });
      }
    }
    showToast({ type: "success", message: t("register.toastSuccess") });
    void router.refresh();
    router.push("/dashboard");
  }

  return (
    <>
      <h1 className={authStyles.heading}>{t("register.title")}</h1>
      <p className={authStyles.lead}>{t("register.subtitle")}</p>
      <form className={authStyles.form} onSubmit={handleSubmit(onValid)} noValidate>
        <FormField label={t("register.nameLabel")} error={errors.name?.message}>
          <Input
            autoComplete="name"
            placeholder={t("register.namePlaceholder")}
            aria-invalid={errors.name ? true : undefined}
            disabled={isSubmitting}
            {...register("name")}
          />
        </FormField>
        <FormField label={t("register.emailOptionalLabel")} error={errors.email?.message}>
          <Input
            type="email"
            autoComplete="email"
            placeholder={t("register.emailPlaceholder")}
            aria-invalid={errors.email ? true : undefined}
            disabled={isSubmitting}
            {...register("email")}
          />
        </FormField>
        <Button type="submit" variant="primary" loading={isSubmitting} disabled={!onboardingToken}>
          {t("register.submit")}
        </Button>
      </form>
      <p className={authStyles.footerNote}>
        <Link href="/login" className={authStyles.footerLink}>
          {t("register.footerBackToLogin")}
        </Link>
      </p>
    </>
  );
}

import { z } from "zod";

/** Shared with tests; `t` is `useTranslations("auth")`. */
export function buildRegisterFormSchema(tAuth: (key: string) => string) {
  return z.object({
    name: z.string().trim().min(1, tAuth("register.validationNameRequired")),
    email: z.union([
      z.literal(""),
      z.string().trim().email({ message: tAuth("register.validationEmailInvalid") }),
    ]),
  });
}

export type RegisterFormValues = z.infer<ReturnType<typeof buildRegisterFormSchema>>;

/**
 * Axios HTTP client for Tour-Ops API (see `resolveTourOpsApiBaseUrl` / `tour-ops-api-origin.ts`).
 *
 * Auth transport (browser → Nest):
 * - The HttpOnly `session` cookie is scoped to the **Next.js origin** only, so it is **not** sent to
 *   a different API host/port even with `withCredentials: true`.
 * - The same JWT is mirrored into `sessionStorage` by `persistSessionToken` (`lib/auth/session.ts`).
 *   We attach it as `Authorization: Bearer <token>` so `AuthMiddleware` on Nest receives a token on
 *   the first cross-origin request after login.
 * - Route protection in `middleware.ts` still relies on the Next-only cookie; that stays unchanged.
 *
 * Clears session and redirects on 401 (except login flows).
 */

import axios, {
  AxiosError,
  type AxiosInstance,
  type AxiosResponseHeaders,
  type RawAxiosResponseHeaders,
} from "axios";

import { clearAuthAndRedirectToLogin } from "./auth/session";
import { getStoredSessionToken } from "./auth/session";
import { emitGlobalApiToast } from "./global-api-toast";
import { resolveTourOpsApiBaseUrl } from "./tour-ops-api-origin";

export { normalizeTourOpsApiOrigin } from "./tour-ops-api-origin";

declare module "axios" {
  export interface AxiosRequestConfig {
  /**
   * @deprecated Prefer explicit UX via {@link getUIError} / auth context. When false (default), 401 does not navigate away.
   */
  skipAuthRedirectOn401?: boolean;
  /** Opt-in: clear session and redirect to login on 401 (legacy axios client only). */
  redirectOn401?: boolean;
  /** Do not full-page redirect to `/403` on 403 (caller handles inline) */
  skip403Redirect?: boolean;
  /** Opt-in: navigate to `/403` on forbidden responses. */
  redirectOn403?: boolean;
    /** Request interceptor sets Idempotency-Key when true */
    attachIdempotency?: boolean;
    /** Skip global interceptor toasts (500 / connection) for this request */
    skipGlobalErrorToast?: boolean;
  }
}

const API_TIMEOUT_MS = 15_000;

function assertNoDoubleApiV2InUrl(resolvedUrl: string): void {
  if (resolvedUrl.includes("/api/v2/api/v2")) {
    throw new Error("Invalid API path: double /api/v2 detected");
  }
}

export class ApiError extends Error {
  code: string;

  status?: number;

  data?: unknown;

  /** Correlates with API `requestId` / `x-request-id` for support and logging. */
  requestId?: string;

  constructor(
    code: string,
    message: string,
    status?: number,
    data?: unknown,
    requestId?: string,
  ) {
    super(message);
    this.name = "ApiError";
    this.code = code;
    this.status = status;
    this.data = data;
    this.requestId = requestId;
  }
}

export class ForbiddenError extends ApiError {
  constructor(
    message = "You are not allowed to perform this action.",
    data?: unknown,
    requestId?: string,
  ) {
    super("FORBIDDEN", message, 403, data, requestId);
    this.name = "ForbiddenError";
  }
}

export class NotFoundError extends ApiError {
  constructor(
    message: string = "The requested resource was not found.",
    code = "RESOURCE_NOT_FOUND",
    data?: unknown,
    requestId?: string,
  ) {
    super(code, message, 404, data, requestId);
    this.name = "NotFoundError";
  }
}

function extractMessage(status: number, data: unknown): string {
  if (data && typeof data === "object") {
    const envelope = data as {
      error?: { message?: string; code?: string };
      message?: unknown;
    };
    if (typeof envelope.error?.message === "string" && envelope.error.message.trim()) {
      return envelope.error.message;
    }
    if (typeof envelope.message === "string" && envelope.message.trim()) {
      return envelope.message;
    }
  }
  return `Request failed with status ${status}`;
}

function extractBackendCode(data: unknown): string | undefined {
  if (!data || typeof data !== "object") return undefined;
  const envelope = data as {
    error?: { code?: unknown };
    code?: unknown;
  };
  if (typeof envelope.error?.code === "string" && envelope.error.code.trim()) {
    return envelope.error.code.trim();
  }
  if (typeof envelope.code === "string" && envelope.code.trim()) {
    return envelope.code.trim();
  }
  return undefined;
}

type ApiResponseHeaders = AxiosResponseHeaders | Partial<RawAxiosResponseHeaders>;

function readHeaderRequestId(headers?: ApiResponseHeaders): string | undefined {
  if (!headers) return undefined;
  const raw =
    typeof headers.get === "function"
      ? headers.get("x-request-id")
      : (headers as Record<string, unknown>)["x-request-id"] ??
        (headers as Record<string, unknown>)["X-Request-Id"];
  if (typeof raw === "string" && raw.trim()) {
    return raw.trim();
  }
  if (Array.isArray(raw) && typeof raw[0] === "string" && raw[0].trim()) {
    return raw[0].trim();
  }
  return undefined;
}

/** Reads API envelope `requestId` (top-level or `error.details.requestId`) and response header. */
export function extractRequestIdFromResponse(
  data: unknown,
  headers?: ApiResponseHeaders,
): string | undefined {
  if (data && typeof data === "object" && !Array.isArray(data)) {
    const envelope = data as {
      requestId?: unknown;
      error?: { details?: { requestId?: unknown } };
    };
    if (typeof envelope.requestId === "string" && envelope.requestId.trim()) {
      return envelope.requestId.trim();
    }
    const detailsId = envelope.error?.details?.requestId;
    if (typeof detailsId === "string" && detailsId.trim()) {
      return detailsId.trim();
    }
  }
  return readHeaderRequestId(headers);
}

function createApiError(
  code: string,
  message: string,
  status?: number,
  data?: unknown,
  headers?: ApiResponseHeaders,
): ApiError {
  return new ApiError(code, message, status, data, extractRequestIdFromResponse(data, headers));
}

function toApiError(error: unknown): ApiError {
  if (axios.isAxiosError(error)) {
    const ax = error as AxiosError<unknown>;
    const status = ax.response?.status;
    const data = ax.response?.data;
    const headers = ax.response?.headers;
    const requestUrl = String(ax.config?.url ?? "");
    const errCode = String(ax.code ?? "").toUpperCase();
    const msg = typeof ax.message === "string" ? ax.message.toLowerCase() : "";
    const isTimeout = errCode === "ECONNABORTED" || errCode === "ETIMEDOUT" || msg.includes("timeout");
    if (isTimeout) {
      return createApiError("TIMEOUT", "Request timed out. Please try again.", status, data, headers);
    }
    if (!ax.response) {
      return new ApiError("NETWORK_ERROR", "Connection lost. Please check your network and try again.");
    }
    if (typeof status === "number") {
      const backendCode = extractBackendCode(data);
      const requestId = extractRequestIdFromResponse(data, headers);
      if (status === 401) {
        const code = backendCode ?? "UNAUTHORIZED";
        const isLoginPath = requestUrl.includes("/api/v2/auth/web/session/otp");
        if (code === "AUTH_OTP_INVALID") {
          return new ApiError(code, "Invalid OTP code.", status, data, requestId);
        }
        if (code === "AUTH_OTP_EXPIRED") {
          return new ApiError(code, "OTP has expired. Request a new code and try again.", status, data, requestId);
        }
        if (code === "AUTH_PHONE_INVALID") {
          return new ApiError(code, "Invalid phone number or OTP.", status, data, requestId);
        }
        if (isLoginPath && code === "AUTH_UNAUTHENTICATED") {
          return new ApiError(code, "Invalid phone number or OTP.", status, data, requestId);
        }
        if (code === "AUTH_TOKEN_REVOKED") {
          return new ApiError(code, "Your session has expired. Please sign in again.", status, data, requestId);
        }
        return new ApiError(code, "Your session has expired. Please sign in again.", status, data, requestId);
      }
      if (status === 403) {
        return new ForbiddenError("You are not allowed to perform this action.", data, requestId);
      }
      if (status === 404) {
        const code = backendCode ?? "RESOURCE_NOT_FOUND";
        return new NotFoundError(extractMessage(status, data), code, data, requestId);
      }
      if (status === 500) {
        return createApiError(
          backendCode ?? "SERVER_ERROR",
          "Server error. Please try again later.",
          status,
          data,
          headers,
        );
      }
      return createApiError(
        backendCode ?? "REQUEST_FAILED",
        extractMessage(status, data),
        status,
        data,
        headers,
      );
    }
    return new ApiError("REQUEST_FAILED", "Request failed.");
  }
  if (error instanceof Error) {
    return new ApiError("REQUEST_FAILED", error.message);
  }
  return new ApiError("REQUEST_FAILED", String(error));
}

export type ApiRequestOptions = {
  /** Send Idempotency-Key; use `true` to generate a UUID per request */
  idempotencyKey?: string | boolean;
  /** Set on auth session POST so invalid OTP 401 does not wipe cookies or redirect */
  skipAuthRedirectOn401?: boolean;
  /** When true, 403 responses reject without navigating to `/403` (inline UX) */
  skip403Redirect?: boolean;
  /** Opt out of global 500 / connection-lost toasts for this call */
  skipGlobalErrorToast?: boolean;
  /** Override: use this JWT instead of the token from session storage. */
  authToken?: string;
};

function mergeRequestConfig(options?: ApiRequestOptions) {
  const headers: Record<string, string> = {};
  if (typeof options?.idempotencyKey === "string") {
    headers["Idempotency-Key"] = options.idempotencyKey;
  }
  if (typeof options?.authToken === "string" && options.authToken.trim()) {
    headers.Authorization = `Bearer ${options.authToken.trim()}`;
  } else {
    const storedToken = getStoredSessionToken();
    if (storedToken) {
      headers.Authorization = `Bearer ${storedToken}`;
    }
  }
  return {
    headers,
    attachIdempotency: options?.idempotencyKey === true,
    skipAuthRedirectOn401: options?.skipAuthRedirectOn401,
    skip403Redirect: options?.skip403Redirect,
    skipGlobalErrorToast: options?.skipGlobalErrorToast,
  };
}

export const axiosApi: AxiosInstance = axios.create({
  headers: { "Content-Type": "application/json" },
  withCredentials: true,
  timeout: API_TIMEOUT_MS,
});

axiosApi.interceptors.request.use((config) => {
  const base = resolveTourOpsApiBaseUrl().trim();
  if (!base) {
    return Promise.reject(new Error("Tour-Ops API is not configured (use NEXT_PUBLIC_API_DYNAMIC_ORIGIN=true)."));
  }
  config.baseURL = base;

  assertNoDoubleApiV2InUrl(axios.getUri({ ...config, baseURL: base }));

  const method = (config.method ?? "get").toUpperCase();
  if (
    (method === "POST" || method === "PATCH") &&
    config.attachIdempotency &&
    config.headers["Idempotency-Key"] === undefined
  ) {
    config.headers["Idempotency-Key"] =
      typeof crypto !== "undefined" && crypto.randomUUID ? crypto.randomUUID() : `${Date.now()}-${Math.random()}`;
  }

  return config;
});

function isLikelyNetworkOrTimeout(error: AxiosError): boolean {
  if (axios.isCancel(error)) return false;
  if (error.response) return false;
  const code = error.code;
  if (code === "ERR_CANCELED") return false;
  if (code === "ERR_NETWORK" || code === "ECONNABORTED" || code === "ETIMEDOUT") return true;
  const msg = typeof error.message === "string" ? error.message.toLowerCase() : "";
  if (msg.includes("network error") || msg.includes("timeout")) return true;
  return false;
}

function devLogApiFailure(error: AxiosError): void {
  if (process.env.NODE_ENV !== "development") return;
  const status = error.response?.status;
  const code = error.code;
  const method = (error.config?.method ?? "GET").toUpperCase();
  const url = error.config?.url ?? "unknown";
  console.error("[api-client] request failed", {
    method,
    url,
    status,
    code,
    message: error.message,
  });
}

axiosApi.interceptors.response.use(
  (response) => response,
  (error: AxiosError) => {
    if (typeof window === "undefined") {
      return Promise.reject(error);
    }
    devLogApiFailure(error);

    const cfg = error.config;
    const status = error.response?.status;

    if (status === 401 && cfg?.redirectOn401 === true) {
      void clearAuthAndRedirectToLogin();
      return Promise.reject(error);
    }

    if (status === 403 && cfg?.redirectOn403 === true) {
      const path = window.location.pathname;
      if (path !== "/403") {
        window.location.assign("/403");
      }
      return Promise.reject(error);
    }

    if (!cfg?.skipGlobalErrorToast) {
      if (isLikelyNetworkOrTimeout(error)) {
        emitGlobalApiToast({ type: "error", message: "Connection lost. Please try again." });
      } else if (status === 500) {
        emitGlobalApiToast({ type: "error", message: "Server error. Please try again later." });
      }
    }

    return Promise.reject(error);
  }
);

export const apiClient = {
  async get<T>(path: string, options?: ApiRequestOptions): Promise<T> {
    if (!resolveTourOpsApiBaseUrl().trim()) {
      throw new ApiError("CONFIG_ERROR", "Tour-Ops API is not configured (use NEXT_PUBLIC_API_DYNAMIC_ORIGIN=true).");
    }
    try {
      const res = await axiosApi.get<T>(path, mergeRequestConfig(options));
      return res.data;
    } catch (e) {
      throw toApiError(e);
    }
  },

  async post<T>(path: string, body?: unknown, options?: ApiRequestOptions): Promise<T> {
    if (!resolveTourOpsApiBaseUrl().trim()) {
      throw new ApiError("CONFIG_ERROR", "Tour-Ops API is not configured (use NEXT_PUBLIC_API_DYNAMIC_ORIGIN=true).");
    }
    try {
      const res = await axiosApi.post<T>(path, body, mergeRequestConfig(options));
      return res.data;
    } catch (e) {
      throw toApiError(e);
    }
  },

  async patch<T>(path: string, body?: unknown, options?: ApiRequestOptions): Promise<T> {
    if (!resolveTourOpsApiBaseUrl().trim()) {
      throw new ApiError("CONFIG_ERROR", "Tour-Ops API is not configured (use NEXT_PUBLIC_API_DYNAMIC_ORIGIN=true).");
    }
    try {
      const res = await axiosApi.patch<T>(path, body, mergeRequestConfig(options));
      return res.data;
    } catch (e) {
      throw toApiError(e);
    }
  },

  async delete<T = void>(path: string, options?: ApiRequestOptions): Promise<T> {
    if (!resolveTourOpsApiBaseUrl().trim()) {
      throw new ApiError("CONFIG_ERROR", "Tour-Ops API is not configured (use NEXT_PUBLIC_API_DYNAMIC_ORIGIN=true).");
    }
    try {
      const res = await axiosApi.delete<T>(path, mergeRequestConfig(options));
      return res.data as T;
    } catch (e) {
      throw toApiError(e);
    }
  },

  /**
   * Binary GET (CSV export, file downloads). Caller should handle non-JSON error bodies.
   */
  async getBlob(path: string, options?: ApiRequestOptions): Promise<Blob> {
    if (!resolveTourOpsApiBaseUrl().trim()) {
      throw new ApiError("CONFIG_ERROR", "Tour-Ops API is not configured (use NEXT_PUBLIC_API_DYNAMIC_ORIGIN=true).");
    }
    try {
      const res = await axiosApi.get<Blob>(path, {
        ...mergeRequestConfig(options),
        responseType: "blob"
      });
      return res.data;
    } catch (e) {
      throw toApiError(e);
    }
  }
};

"use client";

import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
  type ReactNode,
} from "react";

import { inflightBffGet } from "./inflight-bff-get";
import { decodeJwtPayload } from "./decode-jwt-payload";
import { fetchMembershipAbilityContext } from "./membership-ability-context";
import { clearSessionToken, persistSessionToken } from "./session";
import type { WebSessionResponseBody } from "./types";

export { isLeaderRole, isParticipantRole, isWorkspaceOwner } from "./role-tags";

export type AuthUser = {
  userId: string;
  tenantId: string;
  /** From JWT `role` claim (`owner` | `admin` | `leader` | `member` | `viewer`, …). */
  role?: string;
  /** When set, passed into CASL `defineAbilityFor` (defaults to ACTIVE if omitted). */
  membershipStatus?: string;
  /** Optional marketing / CRM labels for CASL (future: hydrate from API). */
  abilityLabels?: readonly string[] | null;
  /** Optional explicit capability grants (membership row / session). */
  capabilities?: readonly string[] | null;
  /** Regional scope when actor has `tour.regional.manage`. */
  allowedRegionIds?: readonly string[] | null;
  /** Tenant product modules from API hydration. */
  tenantModules?: readonly string[] | null;
};

/** Canonical copy when the UI exposes leader-only tooling (owner / admin; participants excluded). */
export const LEADER_WORKSPACE_ACCESS_DENIED = {
  title: "Leader access only",
  description: "This workspace is restricted to tenant owners and admins.",
} as const;

type AuthContextValue = {
  user: AuthUser | null;
  isAuthenticated: boolean;
  /** True after client-side cookie/session hydration finishes (always safe for gated queries). */
  isHydrated: boolean;
  setSession: (session: WebSessionResponseBody) => Promise<void>;
  clearSession: () => Promise<void>;
};

const AuthContext = createContext<AuthContextValue | null>(null);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<AuthUser | null>(null);
  const [isHydrated, setIsHydrated] = useState(false);
  const prevTenantIdRef = useRef<string | null>(null);

  useEffect(() => {
    let active = true;
    const ac = new AbortController();
    const timeoutMs = 8_000;
    const tid = window.setTimeout(() => ac.abort(), timeoutMs);
    void (async () => {
      try {
        const response = await inflightBffGet("/api/auth/session", () =>
          fetch("/api/auth/session", {
            method: "GET",
            credentials: "include",
            cache: "no-store",
            signal: ac.signal,
          }),
        );
        const payload = (await response.json().catch(() => ({}))) as {
          authenticated?: boolean;
          user?: AuthUser;
          user_id?: string;
          tenant_id?: string;
          session_token?: string;
          decoded?: { payload?: { role?: unknown } };
        };
        void response;
        if (!active) {
          return;
        }
        if (!payload.authenticated) {
          setUser(null);
        } else {
          const userId =
            payload.user?.userId?.trim() ||
            (typeof payload.user_id === "string" ? payload.user_id.trim() : "");
          const tenantId =
            payload.user?.tenantId?.trim() ||
            (typeof payload.tenant_id === "string" ? payload.tenant_id.trim() : "");
          const tokenForClaims =
            typeof payload.session_token === "string" ? payload.session_token.trim() : "";
          const roleFromJwt =
            tokenForClaims !== "" ? decodeJwtPayload(tokenForClaims)?.role : undefined;
          const role =
            payload.user?.role ||
            (typeof payload.decoded?.payload?.role === "string"
              ? payload.decoded.payload.role.trim()
              : undefined) ||
            (typeof roleFromJwt === "string" ? roleFromJwt.trim() : undefined);
          if (!userId || !tenantId) {
            setUser(null);
          } else {
            const baseUser = { userId, tenantId, role };
            setUser(baseUser);
            void fetchMembershipAbilityContext(ac.signal).then((ctx) => {
              if (!active || !ctx) {
                return;
              }
              setUser((prev) => {
                if (!prev || prev.userId !== userId || prev.tenantId !== tenantId) {
                  return prev;
                }
                return {
                  ...prev,
                  abilityLabels: ctx.labels.length > 0 ? ctx.labels : null,
                  capabilities:
                    ctx.capabilities.length > 0 ? ctx.capabilities : null,
                  allowedRegionIds:
                    (ctx.allowed_region_ids?.length ?? 0) > 0
                      ? ctx.allowed_region_ids
                      : null,
                  tenantModules:
                    (ctx.tenant_modules?.length ?? 0) > 0 ? ctx.tenant_modules : null,
                };
              });
            });
          }
        }
      } catch {
        if (active) {
          setUser(null);
        }
      } finally {
        window.clearTimeout(tid);
        if (active) {
          setIsHydrated(true);
        }
      }
    })();
    return () => {
      active = false;
      ac.abort();
      window.clearTimeout(tid);
    };
  }, []);

  useEffect(() => {
    prevTenantIdRef.current = user?.tenantId?.trim() || null;
  }, [user?.tenantId]);

  const setSession = useCallback(async (session: WebSessionResponseBody) => {
    await persistSessionToken(session.session_token);
    const claims = decodeJwtPayload(session.session_token);
    const role = typeof claims?.role === "string" ? claims.role.trim() : undefined;
    const baseUser = {
      userId: session.user_id,
      tenantId: session.tenant_id,
      role,
    };
    setUser(baseUser);
    const ctx = await fetchMembershipAbilityContext();
    if (ctx) {
      setUser({
        ...baseUser,
        abilityLabels: ctx.labels.length > 0 ? ctx.labels : null,
        capabilities: ctx.capabilities.length > 0 ? ctx.capabilities : null,
        allowedRegionIds:
          (ctx.allowed_region_ids?.length ?? 0) > 0 ? ctx.allowed_region_ids : null,
        tenantModules: (ctx.tenant_modules?.length ?? 0) > 0 ? ctx.tenant_modules : null,
      });
    }
  }, []);

  const clearSession = useCallback(async () => {
    await clearSessionToken();
    setUser(null);
    prevTenantIdRef.current = null;
  }, []);

  const value = useMemo<AuthContextValue>(
    () => ({
      user,
      isAuthenticated: Boolean(user),
      isHydrated,
      setSession,
      clearSession,
    }),
    [user, isHydrated, setSession, clearSession],
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth(): AuthContextValue {
  const ctx = useContext(AuthContext);
  if (!ctx) {
    throw new Error("useAuth must be used within AuthProvider");
  }
  return ctx;
}

