import { useAbility as useCaslAbility } from "@casl/react";
import { useMemo, type ReactNode } from "react";

import { useAuth } from "@/lib/auth/auth-context";
import { defineAbilityFor, type AppAbility, type UserAbilityMembershipStatus } from "@repo/shared";

import { AbilityContext, GUEST_APP_ABILITY } from "./ability-context";

/**
 * Binds CASL {@link AppAbility} to the authenticated workspace session.
 * Rebuilds when `userId`, `tenantId`, or `role` changes (e.g. workspace switch / token refresh).
 */
export function AbilityProvider({ children }: { children: ReactNode }) {
  const { user, isAuthenticated } = useAuth();

  const ability = useMemo<AppAbility>(() => {
    if (!isAuthenticated || !user?.userId?.trim() || !user?.role?.trim()) {
      return GUEST_APP_ABILITY;
    }
    const status = (user.membershipStatus ?? "ACTIVE") as UserAbilityMembershipStatus;
    return defineAbilityFor({
      id: user.userId.trim(),
      role: user.role.trim(),
      status,
      labels: user.abilityLabels ?? null,
      capabilities: user.capabilities ?? null,
      tenantModules: user.tenantModules ?? null,
      membershipMetadata:
        user.allowedRegionIds && user.allowedRegionIds.length > 0
          ? { allowedRegionIds: [...user.allowedRegionIds] }
          : null,
    });
  }, [
    isAuthenticated,
    user?.userId,
    user?.tenantId,
    user?.role,
    user?.membershipStatus,
    user?.abilityLabels,
    user?.capabilities,
    user?.allowedRegionIds,
    user?.tenantModules,
  ]);

  return <AbilityContext.Provider value={ability}>{children}</AbilityContext.Provider>;
}

/** CASL ability for the active workspace actor (UI gating only). */
export function useAbility(): AppAbility {
  return useCaslAbility(AbilityContext);
}

import type { FieldPath, FieldValues, UseFormSetError } from "react-hook-form";

import { canonicalZodPathToFormFieldPath } from "@/features/tours/wizard/denali/rules/denaliCanonicalPathLookup";
import type { DenaliCreateTourWizardForm } from "@/features/tours/wizard/schemas/denaliTourCreateFormModel";
import type { ApiError } from "@/lib/api-client";

/** Field-level item from API `error.details.validationErrors`. */
export type ApiValidationFieldError = {
  readonly path: string;
  readonly code: string;
  readonly message: string;
};

const API_ROOT_TO_DENALI_FORM: Readonly<Record<string, FieldPath<DenaliCreateTourWizardForm>>> = {
  title: "basicInfo.title",
  total_capacity: "basicInfo.capacityMax",
  capacity: "basicInfo.capacityMax",
  lifecycle_status: "basicInfo.publishStatus",
  description: "programNature.longDescription",
  chat_link: "basicInfo.socialMediaLink",
  communicationLink: "basicInfo.socialMediaLink",
  destinationId: "basicInfo.destinationId",
  meetingPoint: "basicInfo.meetingPoint",
  tourType: "basicInfo.tourType",
  transportModes: "transport.transportMode",
  "cost_context.totalCost": "pricingPayment.basePricePerPerson",
  "overview.title": "basicInfo.title",
  "pricing.basePrice": "pricingPayment.basePricePerPerson",
  "logistics.primaryTransportMode": "transport.transportMode",
  "itinerary.days": "programNature.itinerary",
};

function isRecord(value: unknown): value is Record<string, unknown> {
  return value != null && typeof value === "object" && !Array.isArray(value);
}

function parseValidationFieldError(item: unknown): ApiValidationFieldError | null {
  if (!isRecord(item)) {
    return null;
  }
  const path = typeof item.path === "string" ? item.path.trim() : "";
  const message = typeof item.message === "string" ? item.message.trim() : "";
  if (!path || !message) {
    return null;
  }
  const code = typeof item.code === "string" && item.code.trim() ? item.code.trim() : "VALIDATION_FAILED";
  return { path, code, message };
}

/** Reads structured `validationErrors` from an API error envelope on {@link ApiError.data}. */
export function extractApiValidationErrors(error: ApiError): ApiValidationFieldError[] {
  const data = error.data;
  if (!isRecord(data)) {
    return [];
  }
  const envelope = data as { error?: { details?: { validationErrors?: unknown } } };
  const raw = envelope.error?.details?.validationErrors;
  if (!Array.isArray(raw)) {
    return [];
  }
  const out: ApiValidationFieldError[] = [];
  for (const item of raw) {
    const parsed = parseValidationFieldError(item);
    if (parsed) {
      out.push(parsed);
    }
  }
  return out;
}

/**
 * Maps create/update tour API validation paths to Denali wizard RHF paths.
 * Paths that already match the form shape (e.g. `tripDetails.*`) pass through unchanged.
 */
export function mapApiValidationPathToDenaliFormPath(
  apiPath: string,
): FieldPath<DenaliCreateTourWizardForm> | undefined {
  const trimmed = apiPath.trim();
  if (!trimmed) {
    return undefined;
  }

  const direct = API_ROOT_TO_DENALI_FORM[trimmed];
  if (direct) {
    return direct;
  }

  if (
    trimmed.startsWith("basicInfo.") ||
    trimmed.startsWith("programNature.") ||
    trimmed.startsWith("transport.") ||
    trimmed.startsWith("pricingPayment.") ||
    trimmed.startsWith("participantRequirements.") ||
    trimmed.startsWith("policies.") ||
    trimmed.startsWith("photosData.") ||
    trimmed.startsWith("tripDetails.")
  ) {
    return trimmed as FieldPath<DenaliCreateTourWizardForm>;
  }

  if (trimmed.startsWith("cost_context.")) {
    if (trimmed === "cost_context.totalCost") {
      return "pricingPayment.basePricePerPerson";
    }
    return undefined;
  }

  const segments = trimmed.split(".").filter(Boolean);
  const canonicalRoot = segments[0];
  if (canonicalRoot && KNOWN_CANONICAL_VALIDATION_ROOTS.has(canonicalRoot)) {
    return canonicalZodPathToFormFieldPath(segments);
  }

  return undefined;
}

/** Canonical segment heads understood by {@link canonicalZodPathToFormFieldPath}. */
const KNOWN_CANONICAL_VALIDATION_ROOTS = new Set([
  "title",
  "category",
  "duration",
  "destinationId",
  "startDateTime",
  "endDateTime",
  "capacityMax",
  "capacityMin",
  "meetingPoint",
  "startPointLocationText",
  "gatheringPoint",
  "startPoint",
  "summitPoint",
  "campPoint",
  "endPoint",
  "approximateReturnTime",
  "leaderUserIds",
  "requiresLocalGuide",
  "localGuideName",
  "requiresManualAdminApproval",
  "socialMediaLink",
  "program",
  "transport",
  "pricing",
  "participants",
  "policies",
]);

export type ApplyApiValidationErrorsOptions = {
  /** When omitted, {@link mapApiValidationPathToDenaliFormPath} is used. Return `undefined` to skip a row. */
  mapPath?: (apiPath: string) => FieldPath<DenaliCreateTourWizardForm> | undefined;
};

/**
 * Applies API field validation errors to a react-hook-form instance.
 * @returns Count of fields that received a server error.
 */
export function applyApiValidationErrorsToForm(
  setError: UseFormSetError<DenaliCreateTourWizardForm>,
  errors: readonly ApiValidationFieldError[],
  options?: ApplyApiValidationErrorsOptions,
): number {
  return applyApiValidationErrorsToFormAtPaths(setError, errors, {
    mapPath: options?.mapPath ?? mapApiValidationPathToDenaliFormPath,
  });
}

/**
 * Applies API `validationErrors` onto any react-hook-form instance.
 * @returns Count of fields that received a server error.
 */
export function applyApiValidationErrorsToFormAtPaths<TFieldValues extends FieldValues>(
  setError: UseFormSetError<TFieldValues>,
  errors: readonly ApiValidationFieldError[],
  options?: {
    mapPath?: (apiPath: string) => FieldPath<TFieldValues> | undefined;
  },
): number {
  const mapPath =
    options?.mapPath ??
    ((apiPath: string) => apiPath.trim() as FieldPath<TFieldValues> | undefined);
  let applied = 0;

  for (const item of errors) {
    const formPath = mapPath(item.path);
    if (!formPath) {
      continue;
    }
    setError(formPath, { type: "server", message: item.message });
    applied += 1;
  }

  return applied;
}

export type HandleValidationApiErrorOptions<TFieldValues extends FieldValues> = {
  mapPath?: (apiPath: string) => FieldPath<TFieldValues> | undefined;
  clearErrors?: (name?: "root") => void;
  onApplied?: (issues: readonly { path: string; message: string }[]) => void;
};

/** Maps `VALIDATION_FAILED` envelope errors onto a form; returns true when at least one field was set. */
export function handleValidationApiError<TFieldValues extends FieldValues>(
  error: ApiError,
  setError: UseFormSetError<TFieldValues>,
  options?: HandleValidationApiErrorOptions<TFieldValues>,
): boolean {
  if (error.code !== "VALIDATION_FAILED") {
    return false;
  }

  const validationErrors = extractApiValidationErrors(error);
  if (validationErrors.length === 0) {
    return false;
  }

  const mapPath =
    options?.mapPath ??
    ((apiPath: string) => apiPath.trim() as FieldPath<TFieldValues> | undefined);
  const appliedIssues: { path: string; message: string }[] = [];

  for (const item of validationErrors) {
    const formPath = mapPath(item.path);
    if (!formPath) {
      continue;
    }
    setError(formPath, { type: "server", message: item.message });
    appliedIssues.push({ path: String(formPath), message: item.message });
  }

  if (appliedIssues.length === 0) {
    return false;
  }

  options?.clearErrors?.("root");
  options?.onApplied?.(appliedIssues);
  return true;
}

export type DenaliWizardAppliedValidationIssue = {
  readonly path: string;
  readonly message: string;
};

export type HandleDenaliWizardValidationApiErrorOptions = ApplyApiValidationErrorsOptions & {
  clearErrors?: (name?: "root") => void;
  onApplied?: (issues: readonly DenaliWizardAppliedValidationIssue[]) => void;
};

/**
 * When `error.code === VALIDATION_FAILED`, maps `details.validationErrors` onto the Denali wizard form.
 * @returns `true` if at least one field error was applied.
 */
export function handleDenaliWizardValidationApiError(
  error: ApiError,
  setError: UseFormSetError<DenaliCreateTourWizardForm>,
  options?: HandleDenaliWizardValidationApiErrorOptions,
): boolean {
  if (error.code !== "VALIDATION_FAILED") {
    return false;
  }

  const validationErrors = extractApiValidationErrors(error);
  if (validationErrors.length === 0) {
    return false;
  }

  const resolvePath = options?.mapPath ?? mapApiValidationPathToDenaliFormPath;
  const appliedIssues: DenaliWizardAppliedValidationIssue[] = [];

  for (const item of validationErrors) {
    const formPath = resolvePath(item.path);
    if (!formPath) {
      continue;
    }
    setError(formPath, { type: "server", message: item.message });
    appliedIssues.push({ path: formPath, message: item.message });
  }

  if (appliedIssues.length === 0) {
    return false;
  }

  options?.clearErrors?.("root");
  options?.onApplied?.(appliedIssues);
  return true;
}

import type { ApiError } from "@/lib/api-client";

/** Backend codes for `tripDetails` workspace catalog validation (400). */
export const TENANT_CATALOG_ERROR_CODES = {
  EQUIPMENT: "INVALID_EQUIPMENT_IDS_FOR_TENANT",
  TOUR_THEMES: "INVALID_TOUR_THEME_IDS_FOR_TENANT",
  GUIDE_LANGUAGES: "INVALID_GUIDE_LANGUAGE_IDS_FOR_TENANT",
} as const;

/**
 * Keys under the next-intl namespace `tours.catalogErrors` (see messages/en.json & fa.json).
 * UI maps `error.code` → localized string via `useTranslations("tours.catalogErrors")`.
 */
export const TENANT_CATALOG_MESSAGE_KEYS = [
  "invalidEquipmentIdsTenant",
  "invalidTourThemeIdsTenant",
  "invalidGuideLanguageIdsTenant",
  "genericInvalidCatalogTenant",
] as const;

export type TenantCatalogMessageKey = (typeof TENANT_CATALOG_MESSAGE_KEYS)[number];

type ErrorEnvelope = {
  error?: {
    code?: unknown;
    invalidIds?: unknown;
  };
};

/**
 * Reads optional `invalidIds` from the API error body (`error.data` on {@link ApiError}).
 * Shape matches `{ error: { code, message, invalidIds?: string[] } }`.
 */
export function parseTenantCatalogErrorPayload(data: unknown): {
  code?: string;
  invalidIds: string[];
} {
  if (data == null || typeof data !== "object") {
    return { invalidIds: [] };
  }
  const envelope = data as ErrorEnvelope;
  const err = envelope.error;
  if (!err || typeof err !== "object") {
    return { invalidIds: [] };
  }
  const code = typeof err.code === "string" && err.code.trim() ? err.code.trim() : undefined;
  const raw = err.invalidIds;
  const invalidIds = Array.isArray(raw)
    ? raw.filter((id): id is string => typeof id === "string" && id.length > 0)
    : [];
  return { code, invalidIds };
}

/**
 * When `code` is a known tenant-catalog mismatch, returns the i18n message key; otherwise
 * matches generic `INVALID_*_IDS_FOR_TENANT` and returns the generic catalog hint key.
 */
export function getCatalogErrorMessageKey(code: string | undefined): TenantCatalogMessageKey | null {
  if (!code) {
    return null;
  }
  switch (code) {
    case TENANT_CATALOG_ERROR_CODES.EQUIPMENT:
      return "invalidEquipmentIdsTenant";
    case TENANT_CATALOG_ERROR_CODES.TOUR_THEMES:
      return "invalidTourThemeIdsTenant";
    case TENANT_CATALOG_ERROR_CODES.GUIDE_LANGUAGES:
      return "invalidGuideLanguageIdsTenant";
    default:
      if (code.startsWith("INVALID_") && code.endsWith("_IDS_FOR_TENANT")) {
        return "genericInvalidCatalogTenant";
      }
      return null;
  }
}

/** Dev-only: logs invalid catalog UUIDs without exposing them in the UI. */
export function logTenantCatalogMismatchDev(apiError: ApiError): void {
  if (process.env.NODE_ENV !== "development") {
    return;
  }
  const { invalidIds } = parseTenantCatalogErrorPayload(apiError.data);
  if (invalidIds.length > 0) {
    console.warn("[tour] workspace catalog reference rejected", {
      code: apiError.code,
      invalidIds,
    });
  }
}

import { GeocodingProviderError, isProviderFailStatus } from "./geocoding-provider-error";
import { searchIranMountainLandmarks } from "./iran-mountain-landmarks";
import { fetchMapIrSearch } from "./map-ir";
import { fetchNeshanSearch } from "./neshan";
import {
  fetchNominatimReverse,
  fetchNominatimSearch,
  type GeocodingSearchResult,
} from "./nominatim";

export const GEOCODING_SEARCH_LIMIT = 6;
export const GEOCODING_FALLBACK_LOG = "GEOCODING_PROVIDER_FAIL_SWITCHING_TO_FALLBACK";

type GeocodingProviderId = "neshan" | "mapir" | "nominatim";

function resolvePrimaryProvider(): GeocodingProviderId {
  if (process.env.NESHAN_API_KEY?.trim()) {
    return "neshan";
  }
  if (process.env.MAP_IR_TOKEN?.trim()) {
    return "mapir";
  }
  return "nominatim";
}

function coordKey(result: GeocodingSearchResult): string {
  return `${result.latitude.toFixed(4)}:${result.longitude.toFixed(4)}`;
}

/** Local landmark matches first; dedupe remote rows by rounded coordinates. */
export function mergeGeocodingResults(
  local: GeocodingSearchResult[],
  remote: GeocodingSearchResult[],
  limit = GEOCODING_SEARCH_LIMIT,
): GeocodingSearchResult[] {
  const seen = new Set<string>();
  const out: GeocodingSearchResult[] = [];
  for (const row of [...local, ...remote]) {
    const key = coordKey(row);
    if (seen.has(key)) {
      continue;
    }
    seen.add(key);
    out.push(row);
    if (out.length >= limit) {
      break;
    }
  }
  return out;
}

async function fetchFromProvider(
  provider: GeocodingProviderId,
  query: string,
  limit: number,
): Promise<GeocodingSearchResult[]> {
  if (provider === "neshan") {
    const key = process.env.NESHAN_API_KEY?.trim();
    if (!key) {
      throw new GeocodingProviderError("neshan", 503);
    }
    return fetchNeshanSearch(query, key, { limit });
  }
  if (provider === "mapir") {
    const key = process.env.MAP_IR_TOKEN?.trim();
    if (!key) {
      throw new GeocodingProviderError("mapir", 503);
    }
    return fetchMapIrSearch(query, key, { limit });
  }
  return fetchNominatimSearch(query, { limit, countryCodes: "ir" });
}

function logProviderFallback(provider: GeocodingProviderId, err: unknown): void {
  const status = err instanceof GeocodingProviderError ? err.status : 0;
  if (status === 0 || isProviderFailStatus(status)) {
    console.warn(GEOCODING_FALLBACK_LOG, { provider, status });
  }
}

async function fetchNominatimFallback(query: string, limit: number): Promise<GeocodingSearchResult[]> {
  try {
    return await fetchNominatimSearch(query, { limit, countryCodes: "ir" });
  } catch {
    return [];
  }
}

/**
 * Resilient geocoding: static Iranian mountain dictionary + optional Neshan/Map.ir primary
 * with Nominatim fallback. Never throws — callers always get a merged result array.
 */
export async function searchGeocodingWithFallback(
  query: string,
  options?: { limit?: number },
): Promise<GeocodingSearchResult[]> {
  const limit = options?.limit ?? GEOCODING_SEARCH_LIMIT;
  const local = searchIranMountainLandmarks(query, limit);
  const primary = resolvePrimaryProvider();
  let remote: GeocodingSearchResult[] = [];

  try {
    remote = await fetchFromProvider(primary, query, limit);
  } catch (err) {
    logProviderFallback(primary, err);
    if (primary !== "nominatim") {
      remote = await fetchNominatimFallback(query, limit);
    }
  }

  return mergeGeocodingResults(local, remote, limit);
}

/**
 * Reverse geocoding: gets human address from coordinates.
 */
export async function reverseGeocode(lat: number, lon: number): Promise<string | null> {
  // We can add MapIr/Neshan reverse later if needed; Nominatim is the current standard.
  return fetchNominatimReverse(lat, lon);
}

