export type LeaderRegistrationRow = BookingDto & {
  tourTitle: string;
};

function isLeaderReviewRoute(pathname: string): boolean {
  return pathname === "/leader/review" || pathname.startsWith("/leader/review/");
}

/**
 * Leader review queue data — single tenant index request (no per-tour fan-out).
 * Gated to `/leader/review` after client mount so dashboard navigation cannot prefetch it.
 */
export function useLeaderTourRegistrations(enabled: boolean) {
  const pathname = usePathname() ?? "";
  const mounted = useClientMounted();
  const routeActive = isLeaderReviewRoute(pathname);
  const queriesEnabled = Boolean(enabled && mounted && routeActive);

  const indexQuery = useQuery({
    queryKey: leaderRegistrationIndexKeys.list(),
    queryFn: () => listLeaderRegistrationRows(),
    enabled: queriesEnabled,
    staleTime: 30_000,
  });

  const rows = indexQuery.data?.rows ?? [];
  const pendingRows = useMemo(() => rows.filter((r) => r.status === "Pending"), [rows]);

  const stubToursQuery = {
    isPending: false,
    isError: false,
    error: null,
    refetch: async () => undefined,
  };

  return {
    toursQuery: stubToursQuery,
    tourIds: [] as string[],
    rows,
    pendingRows,
    pendingCount: pendingRows.length,
    totalRegistrationCount: rows.length,
    partial: indexQuery.data?.partial ?? false,
    usingAggregateApi: true,
    isLoading: queriesEnabled && indexQuery.isPending,
    isError: indexQuery.isError,
    registrationsError: indexQuery.error,
    registrationsQueries: [],
    refetchTours: () => void indexQuery.refetch(),
    refetchAll: async () => {
      await indexQuery.refetch();
    },
  };
}

type BffLogContext = Record<string, string | number | boolean | undefined>;

/** Structured BFF logs (dev: console; production: hook to observability later). */
export function logBffEvent(event: string, context: BffLogContext): void {
  const payload = { event, ...context, layer: "bff" as const };
  if (process.env.NODE_ENV === "production") {
    console.info(JSON.stringify(payload));
  } else {
    console.info("[bff]", payload);
  }
}

/** Phase 15.2 — correlate FE failures with API `requestId` / tenant / role. */
export function logBffError(
  message: string,
  context: BffLogContext & {
    requestId?: string;
    traceparent?: string;
    endpoint?: string;
    tenantSlug?: string;
    tenantId?: string;
    role?: string;
  },
): void {
  logBffEvent("bff_error", { message, ...context });
}

/** Shape from {@link apps/api/src/common/errors/global-exception.filter.ts} */
type GlobalErrorEnvelope = {
  success?: false;
  requestId?: string;
  error?: { code?: string; message?: string; correlationId?: string; traceId?: string };
};

/** Legacy `{ error: { code, message } }` bodies from Nest `HttpException` */
type LegacyNestedError = { error?: { code?: string; message?: string } };

function extractMeApiError(payload: unknown): { code?: string; message?: string } | null {
  if (!payload || typeof payload !== "object") {
    return null;
  }
  const envelope = payload as GlobalErrorEnvelope & LegacyNestedError;
  const nested = envelope.error;
  if (!nested || typeof nested !== "object") {
    return null;
  }
  const message = typeof nested.message === "string" ? nested.message.trim() : "";
  const code = typeof nested.code === "string" ? nested.code.trim() : "";
  if (message === "" && code === "") {
    return null;
  }
  return { message: message === "" ? undefined : message, code: code === "" ? undefined : code };
}

export type TranslateSettings = (key: string) => string;

/** User-facing message for `/api/me` error JSON (global envelope or legacy nested `error`). */
export function pickMeErrorMessage(
  payload: unknown,
  fallback: string,
  tSettings: TranslateSettings
): string {
  const extracted = extractMeApiError(payload);
  if (extracted?.message && extracted.message.trim() !== "") {
    return extracted.message.trim();
  }
  if (extracted?.code && extracted.code !== "") {
    const key = `meErrors.${extracted.code}`;
    const translated = tSettings(key);
    if (translated !== key && translated.trim() !== "") {
      return translated.trim();
    }
  }
  return fallback;
}

