/**
 * Registry integrity audit: registry vs generated artifacts, path map, Zod.
 * Run: pnpm --filter web audit:denali-registry
 */
import { z } from "zod";

import {
  DENALI_FIELD_REGISTRY,
  isDenaliFieldInMatrixCell,
} from "../src/features/tours/wizard/denali/registry/DenaliFieldRegistry";
import { DENALI_MATRIX_CELLS } from "../src/features/tours/wizard/denali/registry/denaliRuleMatrixRecipes";
import { DENALI_FIELD_DEFINITIONS } from "../src/features/tours/wizard/denali/registry/denaliFieldRegistryData";
import { collectGeneratedArtifactSyncErrors } from "../src/features/tours/wizard/denali/registry/denaliRegistryCodegen";
import { DENALI_CANONICAL_TO_FORM_PATH_MAP } from "../src/features/tours/wizard/denali/rules/generated/denaliCanonicalPathMap.generated";
import {
  denaliRuleSet,
  findDenaliRuleField,
  listDenaliRuleFieldPaths,
} from "../src/features/tours/wizard/denali/rules/denaliRuleModel";
import { mapDenaliCanonicalToFormPath } from "../src/features/tours/wizard/denali/rules/denaliRuleRequired";
import { denaliTourCreateBaseSchema } from "../src/features/tours/wizard/schemas/denaliTourCreateBaseSchema";
import { buildDenaliTourCreateDefaultValues } from "@/features/tours/wizard/schemas/denaliCore.schema";

function zodShapeHasPath(schema: z.ZodTypeAny, path: string): boolean {
  const parts = path.split(".");
  let cur: z.ZodTypeAny = schema;
  for (const part of parts) {
    while (cur instanceof z.ZodOptional || cur instanceof z.ZodDefault) {
      cur = cur._def.innerType as z.ZodTypeAny;
    }
    if (!(cur instanceof z.ZodObject)) return false;
    const shape = cur.shape as Record<string, z.ZodTypeAny>;
    if (!(part in shape)) return false;
    cur = shape[part]!;
  }
  return true;
}

const rulePaths = new Set(listDenaliRuleFieldPaths());
const mf = denaliRuleSet.mountain.single_day!;
const form = buildDenaliTourCreateDefaultValues();

interface Issue {
  canonical: string;
  layer: string;
  detail: string;
}

const issues: Issue[] = [];

for (const message of collectGeneratedArtifactSyncErrors(
  denaliRuleSet,
  DENALI_CANONICAL_TO_FORM_PATH_MAP,
)) {
  issues.push({
    canonical: "*",
    layer: "generated",
    detail: message,
  });
}

for (const e of DENALI_FIELD_REGISTRY) {
  if (e.inRuleModel === false) {
    if (!rulePaths.has(e.canonicalPath)) {
      // zod-only fields are OK
    }
  } else if (!rulePaths.has(e.canonicalPath)) {
    issues.push({
      canonical: e.canonicalPath,
      layer: "denaliRuleModel",
      detail: "missing from listDenaliRuleFieldPaths()",
    });
  }

  const def = DENALI_FIELD_DEFINITIONS.find((d) => d.canonicalPath === e.canonicalPath);
  if (def && e.inRuleModel !== false) {
    const inMountain = isDenaliFieldInMatrixCell(def, "mountain:single_day");
    const row = findDenaliRuleField(mf, e.canonicalPath);
    if (inMountain && !row) {
      issues.push({
        canonical: e.canonicalPath,
        layer: "denaliRuleModel",
        detail: "expected on mountain.single_day but missing",
      });
    }
    if (row && row.step !== e.stepId) {
      issues.push({
        canonical: e.canonicalPath,
        layer: "denaliRuleModel",
        detail: `step mismatch registry=${e.stepId} rule=${row.step}`,
      });
    }
  }

  const mapped = mapDenaliCanonicalToFormPath(e.canonicalPath);
  if (mapped !== e.rhfPath) {
    issues.push({
      canonical: e.canonicalPath,
      layer: "denaliRuleRequired",
      detail: `CANONICAL_TO_FORM_MAP=${mapped} registry rhf=${e.rhfPath}`,
    });
  }

  if (!zodShapeHasPath(denaliTourCreateBaseSchema, e.zodPath)) {
    issues.push({
      canonical: e.canonicalPath,
      layer: "denaliTourCreateBaseSchema",
      detail: `zodPath missing from schema shape: ${e.zodPath}`,
    });
  } else if (e.zodPath.split(".").length > 0) {
    void form;
  }
}

const registryPaths = new Set(
  DENALI_FIELD_REGISTRY.filter((e) => e.inRuleModel !== false).map((e) => e.canonicalPath),
);
const ruleNotInRegistry = [...rulePaths].filter((p) => !registryPaths.has(p));

let matrixCellsOk = true;
for (const cell of DENALI_MATRIX_CELLS) {
  const model = denaliRuleSet[cell.split(":")[0] as keyof typeof denaliRuleSet]?.[
    cell.split(":")[1] as "single_day" | "multi_day"
  ];
  if (DENALI_MATRIX_CELLS.includes(cell) && cell === "event:multi_day") {
    if (model != null) matrixCellsOk = false;
  }
}

  JSON.stringify(
    {
      registryCount: DENALI_FIELD_REGISTRY.length,
      rulePathCount: rulePaths.size,
      issues,
      ruleNotInRegistryCount: ruleNotInRegistry.length,
      ruleNotInRegistry,
      matrixCellsOk,
    },
    null,
    2,
  ),
);

if (issues.length > 0 || ruleNotInRegistry.length > 0) {
  console.error("\nARCHITECTURAL_DRIFT_DETECTED");
  process.exit(1);
}

"use client";

import type { BookingDto } from "@repo/types";
import type { TourDto } from "@repo/types";
import { zodResolver } from "@hookform/resolvers/zod";
import { useEffect } from "react";
import { useForm } from "react-hook-form";

import { Alert, Button, Card, FormField, Input, Select, Textarea } from "@tour/ui";

import { BookingSchema, type BookingFormInput, type BookingFormValues } from "./booking-schema";

import styles from "./BookingForm.module.css";

export type BookingFormProps = {
  booking?: Partial<BookingDto> & { participantEmailValue?: string };
  tours?: TourDto[];
  onSubmit: (values: BookingFormValues) => void | Promise<void>;
  onCancel?: () => void;
};

function toDefaultValues(booking?: BookingFormProps["booking"]): BookingFormValues {
  if (!booking?.tourId) {
    return {
      participantName: "",
      participantEmail: "",
      tourId: "",
      seats: 1,
      note: "",
    };
  }

  return {
    participantName: booking.participantFullName ?? "",
    participantEmail: booking.participantEmailValue ?? "",
    tourId: booking.tourId ?? "",
    seats:
      typeof booking.vehicleSeatCapacity === "number" && booking.vehicleSeatCapacity >= 1
        ? booking.vehicleSeatCapacity
        : 1,
    note: typeof booking.participantNote === "string" ? booking.participantNote : "",
  };
}

export function BookingForm({ booking, tours = [], onSubmit, onCancel }: BookingFormProps) {
  const {
    register,
    handleSubmit,
    reset,
    setError,
    formState: { errors, isSubmitting, isSubmitted, isValid },
  } = useForm<BookingFormInput, unknown, BookingFormValues>({
    resolver: zodResolver(BookingSchema),
    defaultValues: toDefaultValues(booking),
    mode: "onChange",
  });

  useEffect(() => {
    reset(toDefaultValues(booking));
  }, [booking, reset]);

  const fieldMessages = Object.entries(errors)
    .filter(([key]) => key !== "root")
    .map(([, err]) => err?.message)
    .filter(Boolean) as string[];

  async function submitValid(data: BookingFormValues) {
    try {
      await onSubmit(data);
    } catch {
      setError("root", {
        type: "submit",
        message: "Something went wrong — please try again.",
      });
    }
  }

  return (
    <Card title="Booking details" description="Maps to RegistrationResponseDto fields.">
      <div className={styles.inner}>
        {isSubmitted && fieldMessages.length > 0 ? (
          <Alert variant="error" title="Please fix the form" role="alert">
            <ul style={{ margin: 0, paddingLeft: "1.25rem" }}>
              {fieldMessages.map((msg) => (
                <li key={msg}>{msg}</li>
              ))}
            </ul>
          </Alert>
        ) : null}

        {errors.root?.message ? (
          <Alert variant="error" title="Could not save" role="alert">
            {errors.root.message}
          </Alert>
        ) : null}

        <form className={styles.form} onSubmit={handleSubmit(submitValid)} noValidate>
          <FormField label="Participant name" error={errors.participantName?.message}>
            <Input autoComplete="name" aria-invalid={errors.participantName ? true : undefined} {...register("participantName")} />
          </FormField>

          <FormField label="Email" error={errors.participantEmail?.message}>
            <Input
              type="email"
              autoComplete="email"
              aria-invalid={errors.participantEmail ? true : undefined}
              {...register("participantEmail")}
            />
          </FormField>

          <FormField label="Tour" error={errors.tourId?.message}>
            <Select invalid={Boolean(errors.tourId)} {...register("tourId")}>
              <option value="">Select a tour…</option>
              {tours.map((t) => (
                <option key={t.id} value={t.id}>
                  {t.title}
                </option>
              ))}
            </Select>
          </FormField>

          <FormField label="Seats" description="Maps to vehicleSeatCapacity on the DTO." error={errors.seats?.message}>
            <Input type="number" min={1} step={1} aria-invalid={errors.seats ? true : undefined} {...register("seats", { valueAsNumber: true })} />
          </FormField>

          <FormField label="Note" error={errors.note?.message}>
            <Textarea rows={3} invalid={Boolean(errors.note)} {...register("note")} />
          </FormField>

          <div className={styles.actions}>
            <Button type="button" variant="ghost" disabled={isSubmitting} onClick={() => onCancel?.()}>
              Cancel
            </Button>
            <Button type="submit" variant="primary" loading={isSubmitting} disabled={isSubmitting || !isValid}>
              Save changes
            </Button>
          </div>
        </form>
      </div>
    </Card>
  );
}

