                <DenaliWizardStepper steps={visibleSteps} currentIndex={currentStep} />
                <DenaliStepBody stepId={activeStepId} />

                {staleDraftNoticeOpen ? (
                  <div
                    role="status"
                    data-testid="denali-draft-stale-notice"
                    style={{
