import assert from "node:assert/strict";
import test from "node:test";

import {
  emitWizardRulesValidationFailure,
  tourProfileObservabilityWizardFailuresEnabled,
} from "./tourProfileObservability";

test("emitWizardRulesValidationFailure: no console when result is valid", () => {
  const calls: unknown[][] = [];
  const orig = console.warn;
  console.warn = (...a: unknown[]) => {
    calls.push(a);
  };
  process.env.NEXT_PUBLIC_TOUR_PROFILE_OBSERVABILITY = "1";
  try {
    emitWizardRulesValidationFailure({
      level: "submit",
      form_profile: "general",
      result: {
        isValid: true,
        ok: true,
        fieldErrors: {},
        issues: [],
        messages: [],
      },
    });
    assert.equal(calls.length, 0);
  } finally {
    console.warn = orig;
    delete process.env.NEXT_PUBLIC_TOUR_PROFILE_OBSERVABILITY;
  }
});

test("emitWizardRulesValidationFailure: emits one JSON line when invalid and obs enabled", () => {
  const calls: unknown[][] = [];
  const orig = console.warn;
  console.warn = (...a: unknown[]) => {
    calls.push(a);
  };
  process.env.NEXT_PUBLIC_TOUR_PROFILE_OBSERVABILITY = "1";
  try {
    assert.equal(tourProfileObservabilityWizardFailuresEnabled(), true);
    emitWizardRulesValidationFailure({
      level: "step_nav",
      form_profile: "mountain_outdoor",
      step_id: "basic",
      visible_step_ids: ["basic", "theme"],
      zod_trigger_ok: true,
      result: {
        isValid: false,
        ok: false,
        fieldErrors: { "overview.title": "x" },
        issues: [
          {
            path: "overview.title",
            pathSegments: ["overview", "title"],
            code: "required",
            message: "x",
          },
        ],
        messages: [],
      },
    });
    assert.equal(calls.length, 1);
    const line = String(calls[0]![0]);
    assert.ok(line.includes("tour_profile_obs"));
    const brace = line.indexOf("{");
    assert.ok(brace >= 0);
    const json = JSON.parse(line.slice(brace)) as { event: string; form_profile: string; issue_paths: string[] };
    assert.equal(json.event, "wizard_rules_validation_failed");
    assert.equal(json.form_profile, "mountain_outdoor");
    assert.deepEqual(json.issue_paths, ["overview.title"]);
  } finally {
    console.warn = orig;
    delete process.env.NEXT_PUBLIC_TOUR_PROFILE_OBSERVABILITY;
  }
});

test("emitWizardRulesValidationFailure: dedupes identical signature within window", () => {
  const calls: unknown[][] = [];
  const orig = console.warn;
  console.warn = (...a: unknown[]) => {
    calls.push(a);
  };
  process.env.NEXT_PUBLIC_TOUR_PROFILE_OBSERVABILITY = "1";
  const bad = {
    isValid: false,
    ok: false,
    fieldErrors: { "overview.title": "x" },
    issues: [
      {
        path: "overview.title",
        pathSegments: ["overview", "title"],
        code: "required" as const,
        message: "x",
      },
    ],
    messages: [] as const,
  };
  try {
    emitWizardRulesValidationFailure({ level: "step_nav", form_profile: "general", step_id: "basic", result: bad });
    emitWizardRulesValidationFailure({ level: "step_nav", form_profile: "general", step_id: "basic", result: bad });
    assert.equal(calls.length, 1, "second identical emission within dedupe window should be dropped");
  } finally {
    console.warn = orig;
    delete process.env.NEXT_PUBLIC_TOUR_PROFILE_OBSERVABILITY;
  }
});

/**
 * Client-side observability for the unified tour profile / `ProfileRules` stack.
 *
 * Emits **one-line JSON** to `console.warn` so log aggregators can grep `tour_profile_obs`
 * without shipping a separate analytics SDK. All emissions are:
 *
 * - **Failure / drift only** — never logs successful validation.
 * - **Env-gated in production** — set `NEXT_PUBLIC_TOUR_PROFILE_OBSERVABILITY=1` to enable
 *   in prod builds. In `NODE_ENV === "development"`, wizard rule failures are emitted by
 *   default (still throttled).
 * - **Throttled** — repeated identical signatures within `DEDUPE_MS` are dropped to
 *   avoid spam when users hammer "Next".
 */

import { Legacy, type TourFormProfile } from "@repo/types";

type EventKind = Legacy.EventKind;

import type { TourCreateWizardStepId } from "@/features/tours/wizard/stepConfig";
import type { ValidationIssue, ValidationResult } from "@/features/tours/wizard/profileRules/validation";

const LOG_PREFIX = "tour_profile_obs";

const DEDUPE_MS = 2_000;
const lastEmitted = new Map<string, number>();

function envFlagEnabled(raw: string | undefined): boolean {
  if (!raw) return false;
  const v = raw.trim().toLowerCase();
  return v === "1" || v === "true" || v === "yes" || v === "on";
}

/** True when client should emit `tour_profile_obs` lines for wizard validation failures. */
export function tourProfileObservabilityWizardFailuresEnabled(): boolean {
  if (typeof process !== "undefined" && process.env.NODE_ENV === "development") {
    return true;
  }
  return envFlagEnabled(process.env.NEXT_PUBLIC_TOUR_PROFILE_OBSERVABILITY);
}

/** True for Edit drift / save-failure logs (stricter: only when env explicitly on). */
export function tourProfileObservabilityEditEnabled(): boolean {
  return envFlagEnabled(process.env.NEXT_PUBLIC_TOUR_PROFILE_OBSERVABILITY);
}

function shouldEmitDeduped(signature: string): boolean {
  const now = Date.now();
  const prev = lastEmitted.get(signature);
  if (prev != null && now - prev < DEDUPE_MS) {
    return false;
  }
  lastEmitted.set(signature, now);
  if (lastEmitted.size > 64) {
    const cutoff = now - DEDUPE_MS * 10;
    for (const [k, t] of lastEmitted) {
      if (t < cutoff) lastEmitted.delete(k);
    }
  }
  return true;
}

export type WizardRulesValidationFailurePayload = {
  readonly level: "autosave" | "step_nav" | "submit";
  readonly form_profile: TourFormProfile;
  readonly step_id?: TourCreateWizardStepId;
  readonly visible_step_ids?: readonly TourCreateWizardStepId[];
  readonly zod_trigger_ok?: boolean;
  readonly result: ValidationResult;
};

/**
 * Logs a single structured line when rules-layer validation fails.
 * `rule_id` is always `profile_rules` (source); per-field codes come from `issues`.
 */
export function emitWizardRulesValidationFailure(payload: WizardRulesValidationFailurePayload): void {
  if (!tourProfileObservabilityWizardFailuresEnabled()) return;
  if (payload.result.isValid) return;

  const issuePaths = payload.result.issues.map((i: ValidationIssue) => i.path).sort();
  const issueCodes = payload.result.issues.map((i: ValidationIssue) => i.code);
  const signature = `wiz:${payload.level}:${payload.form_profile}:${payload.step_id ?? ""}:${issuePaths.join(",")}`;
  if (!shouldEmitDeduped(signature)) return;

  const line = {
    event: "wizard_rules_validation_failed",
    source: "profile_rules",
    level: payload.level,
    form_profile: payload.form_profile,
    step_id: payload.step_id,
    visible_step_ids: payload.visible_step_ids,
    zod_trigger_ok: payload.zod_trigger_ok,
    issue_paths: issuePaths,
    issue_codes: issueCodes,
    issue_count: payload.result.issues.length,
  };
  if (typeof console !== "undefined" && typeof console.warn === "function") {
    console.warn(`[${LOG_PREFIX}] ${JSON.stringify(line)}`);
  }
}

export type EditDomainClassificationDriftPayload = {
  readonly tour_id?: string;
  readonly domain_profile: TourFormProfile;
  readonly legacy_event_kind: EventKind;
  readonly projected_event_kind: EventKind;
  readonly unified_edit_resolver_enabled: boolean;
};

/** Emitted when Edit's dual classification reports `agrees: false` (Wizard vs legacy mismatch risk). */
export function emitEditDomainClassificationDrift(payload: EditDomainClassificationDriftPayload): void {
  if (!tourProfileObservabilityEditEnabled()) return;
  const signature = `edit:drift:${payload.tour_id ?? "new"}:${payload.domain_profile}`;
  if (!shouldEmitDeduped(signature)) return;

  const line = {
    event: "edit_domain_classification_drift",
    source: "tourDomainProfileAdapters",
    ...payload,
  };
  if (typeof console !== "undefined" && typeof console.warn === "function") {
    console.warn(`[${LOG_PREFIX}] ${JSON.stringify(line)}`);
  }
}

export type EditSaveProfileRelatedFailurePayload = {
  readonly tour_id?: string;
  readonly http_status: number;
  readonly error_code?: string;
  readonly error_message?: string;
  readonly domain_profile?: TourFormProfile;
  readonly unified_edit_resolver_enabled: boolean;
};

/** Emitted on Edit save 400 responses (often catalog / validation; may include profile strip rejects). */
export function emitEditSaveHttpFailure(payload: EditSaveProfileRelatedFailurePayload): void {
  if (!tourProfileObservabilityEditEnabled()) return;
  if (payload.http_status !== 400) return;
  const signature = `edit:save400:${payload.tour_id ?? "unknown"}:${payload.error_code ?? "none"}`;
  if (!shouldEmitDeduped(signature)) return;

  const line = {
    event: "edit_save_http_400",
    source: "TourForm",
    ...payload,
  };
  if (typeof console !== "undefined" && typeof console.warn === "function") {
    console.warn(`[${LOG_PREFIX}] ${JSON.stringify(line)}`);
  }
}

"use client";

import { Button, Select } from "@tour/ui";
import { useTranslations } from "next-intl";
import { useCallback, useEffect, useMemo, useState } from "react";
import { useFormContext } from "react-hook-form";

import type { TourFormProfile } from "@repo/types";

import { useTenantWizardTemplate } from "@/hooks/use-tenant-wizard-template";
import type { SettingsTourPresetDto } from "@/lib/settings-tour-presets.client";

import { mapTemplateToRuleModel } from "@/features/tours/wizard/domain/ruleModelConverter";
import type { DenaliCreateTourWizardForm } from "./schemas/denaliCore.schema";

import { applyDenaliWizardPreset } from "./tourCreationPresetApply";
import { listAllTourWizardPresetsSorted } from "./tourCreationPresetMatch";
import { resolveWorkspaceTourFormProfileFromTemplate } from "./resolveWorkspaceTourFormProfile";

export type DenaliTourCreationPresetBannerProps = {
  presets: SettingsTourPresetDto[] | undefined;
  /** Called after preset hydrate + form reset (use to bump canonical sync). */
  onApplied?: (presetId: string) => void;
  /**
   * @deprecated Banner reads profile from {@link useTenantWizardTemplate} (`base_profile`).
   */
  resolvedFormProfile?: TourFormProfile;
};

export function DenaliTourCreationPresetBanner({
  presets,
  onApplied,
}: DenaliTourCreationPresetBannerProps) {
  const t = useTranslations("tours.new");
  const { getValues, reset } = useFormContext<DenaliCreateTourWizardForm>();
  const wizardTemplateQuery = useTenantWizardTemplate();

  const templateReady =
    !wizardTemplateQuery.isLoading &&
    !wizardTemplateQuery.isError &&
    wizardTemplateQuery.data != null;

  const workspaceFormProfile = useMemo((): TourFormProfile | undefined => {
    if (!wizardTemplateQuery.data) {
      return undefined;
    }
    return resolveWorkspaceTourFormProfileFromTemplate(wizardTemplateQuery.data);
  }, [wizardTemplateQuery.data]);

  const mergedRuleSet = useMemo(
    () => mapTemplateToRuleModel(wizardTemplateQuery.data ?? null).ruleSet,
    [wizardTemplateQuery.data],
  );

  const choiceList = useMemo(
    () =>
      templateReady && workspaceFormProfile != null
        ? listAllTourWizardPresetsSorted(presets, workspaceFormProfile)
        : [],
    [presets, templateReady, workspaceFormProfile],
  );

  const [selectedId, setSelectedId] = useState<string>("");
  const [lastAppliedPresetId, setLastAppliedPresetId] = useState<string | null>(null);

  useEffect(() => {
    const ids = new Set(choiceList.map((p) => p.id));
    setSelectedId((prev) => (prev && ids.has(prev) ? prev : (choiceList[0]?.id ?? "")));
  }, [choiceList]);

  const selected = useMemo(
    () => choiceList.find((p) => p.id === selectedId) ?? null,
    [choiceList, selectedId],
  );

  const appliedForCurrentChoice = selected != null && lastAppliedPresetId === selected.id;

  const applySelected = useCallback(() => {
    if (!selected?.isActive || workspaceFormProfile == null) {
      return;
    }
    const mergedValues = applyDenaliWizardPreset({
      workspaceFormProfile,
      ruleSet: mergedRuleSet,
      canonicalData: selected.canonicalData,
      baseValues: getValues(),
    });
    reset(mergedValues, { keepDefaultValues: true, keepDirty: true });
    setLastAppliedPresetId(selected.id);
    onApplied?.(selected.id);
  }, [getValues, mergedRuleSet, onApplied, reset, selected, workspaceFormProfile]);

  const onSelectChange = useCallback((nextId: string) => {
    setSelectedId(nextId);
    setLastAppliedPresetId(null);
  }, []);

  if (!presets?.length) {
    return null;
  }

  if (!templateReady || workspaceFormProfile == null) {
    return null;
  }

  if (choiceList.length === 0) {
    return null;
  }

  return (
    <div
      role="region"
      aria-label={t("wizardPresetBannerAria")}
      style={{
        display: "grid",
        gap: "0.5rem",
        padding: "0.65rem 0.75rem",
        borderRadius: 8,
        background: "var(--color-primary-50, #eff6ff)",
        border: "1px solid var(--color-primary-100, #dbeafe)",
        fontSize: "0.875rem",
        color: "var(--color-neutral-800, #1e293b)",
      }}
    >
      <p style={{ margin: 0 }}>
        <strong>{t("wizardPresetBannerTitle")}</strong> {t("wizardPresetIntroHint")}
      </p>
      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          alignItems: "center",
          gap: "0.65rem",
        }}
      >
        <label htmlFor="denali-wizard-preset-select" style={{ fontWeight: 600 }}>
          {t("wizardPresetSelectLabel")}
        </label>
        <Select
          id="denali-wizard-preset-select"
          data-testid="denali-wizard-preset-select"
          aria-label={t("wizardPresetSelectLabel")}
          value={selectedId}
          onChange={(e) => onSelectChange(e.target.value)}
          style={{ minWidth: "14rem", flex: "1 1 12rem" }}
        >
          {choiceList.map((p) => (
            <option key={p.id} value={p.id} title={p.description ?? undefined} disabled={!p.isActive}>
              {p.name}
              {!p.isActive ? ` (${t("wizardPresetInactiveOptionSuffix")})` : ""}
            </option>
          ))}
        </Select>
        <span style={{ display: "inline-flex", gap: "0.5rem", alignItems: "center", flexWrap: "wrap" }}>
          {appliedForCurrentChoice ? (
            <span style={{ fontSize: "0.8125rem", color: "var(--color-neutral-600, #525252)" }}>
              {t("wizardPresetAppliedStatus")}
            </span>
          ) : null}
          <Button
            type="button"
            variant="primary"
            data-testid="denali-wizard-preset-apply"
            onClick={applySelected}
            disabled={!selected?.isActive || workspaceFormProfile == null}
          >
            {t("wizardPresetApply")}
          </Button>
        </span>
      </div>
      <p style={{ margin: 0, fontSize: "0.8125rem", color: "var(--color-neutral-600, #525252)" }}>
        {selected && !selected.isActive
          ? t("wizardPresetInactiveApplyBlocked")
          : t("wizardPresetSuggestedHint")}
      </p>
    </div>
  );
}

