import { useEffect } from "react";

import type { DenaliCreateWizardStepId } from "@/features/tours/wizard/denaliStepConfig";

import { useDenaliWizardNavigationOptional } from "./DenaliWizardNavigationContext";

/** Consumes pending field focus after navigating to a wizard step. */
export function DenaliStepFocusBridge({ stepId }: { stepId: DenaliCreateWizardStepId }) {
  const navigation = useDenaliWizardNavigationOptional();

  useEffect(() => {
    navigation?.consumePendingFocus(stepId);

    const timer = window.setTimeout(() => {
      // Let step transition/render settle before fallback focus probing.
      window.requestAnimationFrame(() => {
        window.requestAnimationFrame(() => {
          const stepTestId = resolveStepContainerTestId(stepId);
          const stepContainer = document.querySelector<HTMLElement>(`[data-testid="${stepTestId}"]`);
          if (!stepContainer) {
            if (process.env.NODE_ENV !== "production") {
              console.debug("[DenaliStepFocusBridge] fallback skipped: step container missing", {
                stepId,
                stepTestId,
              });
            }
            return;
          }

          const active = document.activeElement as HTMLElement | null;
          const activeInsideStep = active != null && stepContainer.contains(active);
          if (activeInsideStep) {
            return;
          }

          const fallbackTarget = findFirstInteractableField(stepContainer);
          if (!fallbackTarget) {
            if (process.env.NODE_ENV !== "production") {
              console.debug("[DenaliStepFocusBridge] fallback target not found", {
                stepId,
                stepTestId,
              });
            }
            return;
          }

          fallbackTarget.focus();
        });
      });
    }, 60);

    return () => {
      window.clearTimeout(timer);
    };
  }, [navigation, stepId]);

  return null;
}

function resolveStepContainerTestId(stepId: DenaliCreateWizardStepId): string {
  switch (stepId) {
    case "denali_basic":
      return "denali-step-basics";
    case "denali_photos":
      return "denali-step-photos";
    case "denali_program":
      return "denali-step-program";
    case "denali_logistics":
      return "denali-step-logistics";
    case "denali_pricing":
      return "denali-step-pricing";
    case "review":
      return "denali-step-review";
    default:
      return `denali-step-${stepId}`;
  }
}

function isVisibleElement(el: HTMLElement): boolean {
  const style = window.getComputedStyle(el);
  if (style.display === "none" || style.visibility === "hidden" || style.opacity === "0") {
    return false;
  }
  if (el.hasAttribute("hidden") || el.getAttribute("aria-hidden") === "true") {
    return false;
  }
  return el.getClientRects().length > 0;
}

function findFirstInteractableField(root: HTMLElement): HTMLElement | null {
  const candidates = root.querySelectorAll<HTMLElement>("input, select, textarea");
  for (const node of candidates) {
    if (node.matches(":disabled")) continue;
    if (!isVisibleElement(node)) continue;
    return node;
  }
  return null;
}

"use client";

import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useState,
  type ReactNode,
} from "react";

import type { DenaliCreateWizardStepId } from "@/features/tours/wizard/denaliStepConfig";

import {
  clearDenaliWizardFieldFocus,
  focusDenaliWizardField,
} from "./denaliWizardFieldFocus";

type DenaliWizardNavigationContextValue = {
  pendingFocusPath: string | null;
  navigateToField: (stepId: DenaliCreateWizardStepId, formPath: string) => void;
  consumePendingFocus: (activeStepId: DenaliCreateWizardStepId) => void;
  clearPendingFocus: () => void;
};

const DenaliWizardNavigationContext = createContext<DenaliWizardNavigationContextValue | null>(
  null,
);

export function DenaliWizardNavigationProvider({
  visibleSteps,
  currentStepIndex,
  setCurrentStep,
  children,
}: {
  visibleSteps: readonly DenaliCreateWizardStepId[];
  currentStepIndex: number;
  setCurrentStep: (updater: (prev: number) => number) => void;
  children: ReactNode;
}) {
  const [pendingFocusPath, setPendingFocusPath] = useState<string | null>(null);
  const [pendingStepId, setPendingStepId] = useState<DenaliCreateWizardStepId | null>(null);

  const navigateToField = useCallback(
    (stepId: DenaliCreateWizardStepId, formPath: string) => {
      const stepIndex = visibleSteps.indexOf(stepId);
      if (stepIndex < 0) return;
      setPendingFocusPath(formPath);
      setPendingStepId(stepId);
      if (stepIndex !== currentStepIndex) {
        setCurrentStep(() => stepIndex);
      } else {
        window.requestAnimationFrame(() => {
          focusDenaliWizardField(formPath);
        });
      }
      window.scrollTo(0, 0);
    },
    [currentStepIndex, setCurrentStep, visibleSteps],
  );

  const consumePendingFocus = useCallback(
    (activeStepId: DenaliCreateWizardStepId) => {
      if (pendingFocusPath == null || pendingStepId !== activeStepId) return;
      const path = pendingFocusPath;
      setPendingFocusPath(null);
      setPendingStepId(null);
      window.requestAnimationFrame(() => {
        window.setTimeout(() => focusDenaliWizardField(path), 50);
      });
    },
    [pendingFocusPath, pendingStepId],
  );

  const clearPendingFocus = useCallback(() => {
    setPendingFocusPath(null);
    setPendingStepId(null);
    clearDenaliWizardFieldFocus();
  }, []);

  const value = useMemo(
    () => ({
      pendingFocusPath,
      navigateToField,
      consumePendingFocus,
      clearPendingFocus,
    }),
    [clearPendingFocus, consumePendingFocus, navigateToField, pendingFocusPath],
  );

  return (
    <DenaliWizardNavigationContext.Provider value={value}>
      {children}
    </DenaliWizardNavigationContext.Provider>
  );
}

export function useDenaliWizardNavigation(): DenaliWizardNavigationContextValue {
  const ctx = useContext(DenaliWizardNavigationContext);
  if (ctx == null) {
    throw new Error("useDenaliWizardNavigation must be used within DenaliWizardNavigationProvider");
  }
  return ctx;
}

export function useDenaliWizardNavigationOptional() {
  return useContext(DenaliWizardNavigationContext);
}

