/**
 * Denali rule engine — UI visibility and required state only.
 *
 * Public API: {@link isDenaliFieldVisibleOnStep}, {@link isDenaliFieldRequiredOnStep},
 * {@link isDenaliFieldVisibleInModel}, {@link isDenaliFieldRequiredInModel} (aliases: {@link isVisible}, {@link isRequired}).
 * Validation: {@link ../validation/denaliWizardFormZod.ts}.
 */
export type DenaliCanonicalUIContext = {
  readonly canonical: Pick<DenaliCanonicalTourModel, "category" | "duration">;
  readonly ruleModel: DenaliRuleModel | null;
  stepUI: (step: DenaliRuleFieldStep | DenaliCreateWizardStepId) => DenaliUIFieldMetadata | null;
  isVisible: (
    step: DenaliRuleFieldStep | DenaliCreateWizardStepId,
    path: string,
    form?: DenaliCreateTourWizardForm,
  ) => boolean;
  isRequired: (
    step: DenaliRuleFieldStep | DenaliCreateWizardStepId,
    path: string,
    form?: DenaliCreateTourWizardForm,
  ) => boolean;
  arePathsVisible: (
    step: DenaliRuleFieldStep | DenaliCreateWizardStepId,
    paths: readonly string[],
    form?: DenaliCreateTourWizardForm,
  ) => boolean;
  isVisibleInModel: (path: string, form?: DenaliCreateTourWizardForm) => boolean;
  isRequiredInModel: (path: string, form?: DenaliCreateTourWizardForm) => boolean;
  isDurationAllowed: (duration: DenaliRuleModelDuration) => boolean;
};

export type DenaliUIFieldMetadata = {
  readonly visibleFields: readonly string[];
  readonly hiddenFields: readonly string[];
  readonly requiredFields: readonly string[];
};

/** @deprecated Theme no longer drives form visibility; kept for call-site compat. */
export type DenaliUIContextOptions = {
  mainThemeFormProfile?: TourFormProfile;
  /** Resolved workspace template profile (for registry `capability` visibility rules). */
  workspaceFormProfile?: TourFormProfile;
};

export type DenaliUIAdapterInput = {
  step: DenaliRuleFieldStep | DenaliCreateWizardStepId;
  category: DenaliRuleModelCategory;
  duration: DenaliRuleModelDuration;
  ruleSet?: DenaliRuleSet;
};

const DEFINITION_BY_CANONICAL_PATH = new Map<string, DenaliFieldDefinition>(
  DENALI_FIELD_DEFINITIONS.map((def) => [def.canonicalPath, def]),
);

export function getDenaliFieldDefinitionByCanonicalPath(
  canonicalPath: string,
): DenaliFieldDefinition | undefined {
  return DEFINITION_BY_CANONICAL_PATH.get(canonicalPath);
}

function readCanonicalPathValue(form: DenaliCreateTourWizardForm, watchCanonical: string): unknown {
  const formPath = DENALI_CANONICAL_TO_FORM_PATH_MAP[watchCanonical] ?? watchCanonical;
  return getDenaliFormPathValue(form, formPath);
}

function isTruthyFormValue(value: unknown): boolean {
  if (value === true) return true;
  if (typeof value === "string") return value.trim() !== "";
  if (typeof value === "number") return Number.isFinite(value);
  if (Array.isArray(value)) return value.length > 0;
  return false;
}

function transportModeFromForm(form: DenaliCreateTourWizardForm): DenaliCanonicalTransportMode {
  return form.transport.transportMode as DenaliCanonicalTransportMode;
}

function transportPersonalCarInput(form: DenaliCreateTourWizardForm): {
  mode: DenaliCanonicalTransportMode;
  allowPersonalCar?: boolean;
} {
  return {
    mode: transportModeFromForm(form),
    allowPersonalCar: form.transport.allowPersonalCar,
  };
}

/** Maps registry `contextualVisibility` / `contextualRequired` kinds to `@repo/types/denali` predicates. */
export function evaluateDenaliContextualRule(
  rule: DenaliContextualRule,
  form: DenaliCreateTourWizardForm,
  mode: "visibility" | "required",
  options?: DenaliUIContextOptions,
): boolean {
  switch (rule.kind) {
    case "whenTruthy":
      return isTruthyFormValue(readCanonicalPathValue(form, rule.watchCanonical));
    case "capability": {
      const profile =
        options?.workspaceFormProfile ?? options?.mainThemeFormProfile;
      if (!profile) {
        // Callers that don't provide UI options should not accidentally wipe capability-gated fields.
        return mode === "visibility";
      }
      const capabilities = getCapabilitiesForProfile(profile);
      if (rule.flag === "canDefineCustomServices") {
        return capabilities.canDefineCustomServices;
      }
      return false;
    }
    case "transportOrganizedCostVisible":
      return isDenaliTransportCostVisible(transportModeFromForm(form));
    case "transportPersonalCarOptionVisible":
      return isDenaliAllowPersonalCarVisible(transportModeFromForm(form));
    case "transportDongVisible":
      return mode === "required"
        ? isDenaliTransportDongAmountRequired(transportPersonalCarInput(form))
        : isDenaliTransportDongAmountVisible(transportPersonalCarInput(form));
    case "transportAdminCapacityVisible":
      return isDenaliAdminCapacityApprovalVisible(transportPersonalCarInput(form));
    case "transportTrainSeatVisible":
      return isDenaliSeatPreferenceRequired(transportModeFromForm(form));
    case "multiDayEndDateTimeRequired":
      return denaliTourKindToIsMultiDay(form.basicInfo.tourType as DenaliTourKind);
    default: {
      const _exhaustive: never = rule;
      return _exhaustive;
    }
  }
}

export function evaluateDenaliContextualVisibility(
  canonicalPath: string,
  form: DenaliCreateTourWizardForm | undefined,
  options?: DenaliUIContextOptions,
): boolean {
  if (form == null) return true;
  const def = getDenaliFieldDefinitionByCanonicalPath(canonicalPath);
  if (def?.contextualVisibility == null) return true;
  return evaluateDenaliContextualRule(def.contextualVisibility, form, "visibility", options);
}

export function evaluateDenaliContextualRequired(
  canonicalPath: string,
  form: DenaliCreateTourWizardForm,
  options?: DenaliUIContextOptions,
): boolean | null {
  const def = getDenaliFieldDefinitionByCanonicalPath(canonicalPath);
  if (def?.contextualRequired == null) return null;
  return evaluateDenaliContextualRule(def.contextualRequired, form, "required", options);
}

function resolveDenaliRuleModel(
  category: DenaliRuleModelCategory,
  duration: DenaliRuleModelDuration,
  ruleSet: DenaliRuleSet,
): DenaliRuleModel | null {
  return ruleSet[category][duration];
}

function fieldsForStep(
  model: DenaliRuleModel,
  step: DenaliRuleFieldStep | DenaliCreateWizardStepId,
): readonly DenaliRuleFieldDefinition[] {
  if (step === "review") {
    return model.fields;
  }
  return model.fields.filter((field) => field.step === step);
}

/** Derive visible / hidden / required path lists for one wizard step from {@link DenaliRuleModel}. */
export function deriveDenaliUIFieldMetadata(
  model: DenaliRuleModel,
  step: DenaliRuleFieldStep | DenaliCreateWizardStepId,
): DenaliUIFieldMetadata {
  const scoped = fieldsForStep(model, step);

  const hiddenFields = scoped.filter((field) => field.hidden).map((field) => field.path);
  const visibleFields = scoped.filter((field) => !field.hidden).map((field) => field.path);
  const requiredFields = scoped
    .filter((field) => field.required && !field.hidden)
    .map((field) => field.path);

  return { visibleFields, hiddenFields, requiredFields };
}

export function visibleFields(
  step: DenaliUIAdapterInput["step"],
  category: DenaliRuleModelCategory,
  duration: DenaliRuleModelDuration,
  ruleSet: DenaliRuleSet = denaliRuleSet,
): readonly string[] {
  const model = resolveDenaliRuleModel(category, duration, ruleSet);
  if (model == null) return [];
  return deriveDenaliUIFieldMetadata(model, step).visibleFields;
}

export function hiddenFields(
  step: DenaliUIAdapterInput["step"],
  category: DenaliRuleModelCategory,
  duration: DenaliRuleModelDuration,
  ruleSet: DenaliRuleSet = denaliRuleSet,
): readonly string[] {
  const model = resolveDenaliRuleModel(category, duration, ruleSet);
  if (model == null) return [];
  return deriveDenaliUIFieldMetadata(model, step).hiddenFields;
}

export function requiredFields(
  step: DenaliUIAdapterInput["step"],
  category: DenaliRuleModelCategory,
  duration: DenaliRuleModelDuration,
  ruleSet: DenaliRuleSet = denaliRuleSet,
): readonly string[] {
  const model = resolveDenaliRuleModel(category, duration, ruleSet);
  if (model == null) return [];
  return deriveDenaliUIFieldMetadata(model, step).requiredFields;
}

/** Full metadata bundle for one step (convenience for hooks / tests). */
export function getDenaliUIAdapterMetadata(input: DenaliUIAdapterInput): DenaliUIFieldMetadata | null {
  const ruleSet = input.ruleSet ?? denaliRuleSet;
  const model = resolveDenaliRuleModel(input.category, input.duration, ruleSet);
  if (model == null) return null;
  return deriveDenaliUIFieldMetadata(model, input.step);
}

export function isDenaliDurationAllowed(
  category: DenaliRuleModelCategory,
  duration: DenaliRuleModelDuration,
  ruleSet: DenaliRuleSet = denaliRuleSet,
): boolean {
  return resolveDenaliRuleModel(category, duration, ruleSet) != null;
}

function isDenaliFieldContextuallyVisible(
  path: string,
  form: DenaliCreateTourWizardForm | undefined,
  options?: DenaliUIContextOptions,
): boolean {
  return evaluateDenaliContextualVisibility(path, form, options);
}

/**
 * Whether `path` is visible on `step` for the current rule model and form state.
 */
export function isDenaliFieldVisibleOnStep(
  model: DenaliRuleModel | null,
  step: DenaliRuleFieldStep | DenaliCreateWizardStepId,
  path: string,
  form?: DenaliCreateTourWizardForm,
  options?: DenaliUIContextOptions,
): boolean {
  if (model == null) return false;
  const canonicalPath = mapFormPathToCanonical(path);
  if (!isDenaliFieldContextuallyVisible(canonicalPath, form, options)) return false;

  const field = findDenaliRuleField(model, canonicalPath);
  if (field == null) {
    const registryOnly = getDenaliFieldDefinitionByCanonicalPath(canonicalPath);
    if (registryOnly?.contextualVisibility == null) return false;
    if (step === "review") return true;
    return registryOnly.stepId === step;
  }
  if (field.hidden) return false;
  if (step === "review") return true;
  return field.step === step;
}

export function isDenaliFieldRequiredOnStep(
  model: DenaliRuleModel | null,
  step: DenaliRuleFieldStep | DenaliCreateWizardStepId,
  path: string,
  form?: DenaliCreateTourWizardForm,
  options?: DenaliUIContextOptions,
): boolean {
  if (model == null) return false;
  const canonicalPath = mapFormPathToCanonical(path);

  const field = findDenaliRuleField(model, canonicalPath);
  if (field == null) {
    const registryOnly = getDenaliFieldDefinitionByCanonicalPath(canonicalPath);
    if (registryOnly?.contextualRequired == null) return false;
    if (step !== "review" && registryOnly.stepId !== step) return false;
    if (form != null) {
      return isDenaliFieldRequired(model, canonicalPath, form, options);
    }
    return false;
  }
  if (field.hidden) return false;
  if (step !== "review" && field.step !== step) return false;
  if (form != null) {
    return isDenaliFieldRequired(model, canonicalPath, form, options);
  }
  return field.required;
}

/** True when every path in `paths` is visible on `step` (e.g. outdoor program block). */
export function areDenaliFieldPathsVisibleOnStep(
  model: DenaliRuleModel | null,
  step: DenaliRuleFieldStep | DenaliCreateWizardStepId,
  paths: readonly string[],
  form?: DenaliCreateTourWizardForm,
  options?: DenaliUIContextOptions,
): boolean {
  return paths.every((path) => isDenaliFieldVisibleOnStep(model, step, path, form, options));
}

/** Category-wide visibility (ignores `field.step`). */
export function isDenaliFieldVisibleInModel(
  model: DenaliRuleModel | null,
  path: string,
  form?: DenaliCreateTourWizardForm,
  options?: DenaliUIContextOptions,
): boolean {
  if (model == null) return false;
  const canonicalPath = mapFormPathToCanonical(path);
  if (!isDenaliFieldContextuallyVisible(canonicalPath, form, options)) return false;
  const field = findDenaliRuleField(model, canonicalPath);
  if (field == null) {
    const registryOnly = getDenaliFieldDefinitionByCanonicalPath(canonicalPath);
    return registryOnly?.contextualVisibility != null;
  }
  return !field.hidden;
}

export function isDenaliFieldRequiredInModel(
  model: DenaliRuleModel | null,
  path: string,
  form?: DenaliCreateTourWizardForm,
  options?: DenaliUIContextOptions,
): boolean {
  if (model == null) return false;
  const canonicalPath = mapFormPathToCanonical(path);
  if (form != null) {
    return isDenaliFieldRequired(model, canonicalPath, form, options);
  }
  const field = findDenaliRuleField(model, canonicalPath);
  return field != null && field.required && !field.hidden;
}

/** Unique hidden paths for a resolved rule model (normalize / clone hygiene). */
export function getHiddenFieldPathsFromModel(model: DenaliRuleModel): readonly string[] {
  return [...new Set(model.fields.filter((field) => field.hidden).map((field) => field.path))];
}

/** Rule engine: field visible on step (or whole form on `review`). */
export const isVisible = isDenaliFieldVisibleOnStep;

/** Rule engine: field required on step (or whole form on `review`). */
export const isRequired = isDenaliFieldRequiredOnStep;

function buildDenaliUIContext(
  ruleModel: DenaliRuleModel | null,
  classification: Pick<DenaliCanonicalTourModel, "category" | "duration">,
  ruleSet: DenaliRuleSet,
  form?: DenaliCreateTourWizardForm,
  options?: DenaliUIContextOptions,
): DenaliCanonicalUIContext {
  return {
    canonical: classification,
    ruleModel,
    stepUI: (step) =>
      ruleModel == null ? null : deriveDenaliUIFieldMetadata(ruleModel, step),
    isVisible: (step, path, f) =>
      isDenaliFieldVisibleOnStep(ruleModel, step, path, f ?? form, options),
    isRequired: (step, path, f) =>
      isDenaliFieldRequiredOnStep(ruleModel, step, path, f ?? form, options),
    arePathsVisible: (step, paths, f) =>
      areDenaliFieldPathsVisibleOnStep(ruleModel, step, paths, f ?? form, options),
    isVisibleInModel: (path, f) => isDenaliFieldVisibleInModel(ruleModel, path, f ?? form, options),
    isRequiredInModel: (path, f) => isDenaliFieldRequiredInModel(ruleModel, path, f ?? form, options),
    isDurationAllowed: (duration) =>
      isDenaliDurationAllowed(classification.category, duration, ruleSet),
  };
}

export function getDenaliUIFromCanonical(
  canonical: DenaliCanonicalTourModel,
  ruleSet: DenaliRuleSet = denaliRuleSet,
  form?: DenaliCreateTourWizardForm,
  options?: DenaliUIContextOptions,
): DenaliCanonicalUIContext {
  const ruleModel = getDenaliRulesFromCanonical(canonical, ruleSet);
  return buildDenaliUIContext(
    ruleModel,
    { category: canonical.category, duration: canonical.duration },
    ruleSet,
    form,
    options,
  );
}

/** UI rules resolved from `basicInfo.tourType` (authoritative classification). */
export function getDenaliUIFromForm(
  form: DenaliCreateTourWizardForm,
  ruleSet: DenaliRuleSet = denaliRuleSet,
  options?: DenaliUIContextOptions,
): DenaliCanonicalUIContext {
  const basics = readDenaliCanonicalBasics(form.basicInfo.tourType as DenaliTourKind | undefined);
  const ruleModel =
    basics == null ? null : ruleSet[basics.category][basics.duration];
  const category = basics?.category ?? "mountain";
  const duration = basics?.duration === "multi_day" ? "multi" : "single";
  return buildDenaliUIContext(ruleModel, { category, duration }, ruleSet, form, options);
}

"use client";

import { useCallback, useEffect, useLayoutEffect, useMemo, useRef, useState } from "react";
import { useFormContext } from "react-hook-form";
import { useTranslations } from "next-intl";
import { FormField, Textarea } from "@tour/ui";

import type { DenaliCanonicalTourModel } from "@repo/types/denali";

import type { DenaliCreateTourWizardForm } from "@/features/tours/wizard/schemas/denaliCore.schema";

import { useDenaliCanonical } from "../DenaliCanonicalContext";
import { useDenaliCanonicalValue } from "../hooks/useDenaliCanonicalValue";
import { DenaliItineraryDayLocationField } from "../components/DenaliItineraryDayLocationField";
import { DenaliItineraryDayPhotos } from "../components/DenaliItineraryDayPhotos";
import {
  computeDenaliTourDayCountFromKind,
  syncDenaliItineraryRows,
  type DenaliItineraryDayRow,
} from "../denaliItinerarySync";

const ITINERARY_DEBOUNCE_MS = 300;

function readItineraryPhotosError(itineraryErrors: unknown, index: number): string | undefined {
  if (!Array.isArray(itineraryErrors)) {
    return undefined;
  }
  const row = itineraryErrors[index] as
    | {
        photos?: { message?: string } | Array<{ url?: { message?: string }; id?: { message?: string } }>;
      }
    | undefined;
  const photos = row?.photos;
  if (!photos) {
    return undefined;
  }
  if (typeof photos === "object" && photos !== null && "message" in photos) {
    const message = (photos as { message?: string }).message;
    return typeof message === "string" ? message : undefined;
  }
  if (Array.isArray(photos)) {
    for (const entry of photos) {
      const urlMsg = entry?.url?.message;
      if (typeof urlMsg === "string" && urlMsg.trim() !== "") {
        return urlMsg;
      }
      const idMsg = entry?.id?.message;
      if (typeof idMsg === "string" && idMsg.trim() !== "") {
        return idMsg;
      }
    }
  }
  return undefined;
}

export function DenaliDailyItinerarySection() {
  const t = useTranslations("tours.denali");
  const {
    formState: { errors },
    getValues,
  } = useFormContext<DenaliCreateTourWizardForm>();

  const { updateCanonical } = useDenaliCanonical();
  const startDateTime = useDenaliCanonicalValue<string | undefined>("startDateTime");
  const endDateTime = useDenaliCanonicalValue<string | undefined>("endDateTime");
  const program = useDenaliCanonicalValue<DenaliCanonicalTourModel["program"]>("program");
  const form = getValues();
  const dayCount = computeDenaliTourDayCountFromKind(
    form.basicInfo.tourType,
    startDateTime ?? "",
    endDateTime,
  );
  const rows = useMemo(
    () => syncDenaliItineraryRows(program.itinerary, dayCount),
    [program.itinerary, dayCount],
  );

  const [draftRows, setDraftRows] = useState<DenaliItineraryDayRow[]>(rows);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const canonicalProgramRef = useRef(program);

  canonicalProgramRef.current = program;

  useEffect(() => {
    setDraftRows(rows);
  }, [rows]);

  useLayoutEffect(() => {
    if ((program.itinerary?.length ?? 0) !== rows.length) {
      updateCanonical({ program: { ...program, itinerary: rows } });
    }
  }, [rows.length, program.itinerary?.length, program, updateCanonical]);

  const scheduleCommit = useCallback(
    (nextRows: DenaliItineraryDayRow[]) => {
      if (debounceRef.current != null) {
        clearTimeout(debounceRef.current);
      }
      debounceRef.current = setTimeout(() => {
        debounceRef.current = null;
        updateCanonical({
          program: { ...canonicalProgramRef.current, itinerary: nextRows },
        });
      }, ITINERARY_DEBOUNCE_MS);
    },
    [updateCanonical],
  );

  useEffect(
    () => () => {
      if (debounceRef.current != null) {
        clearTimeout(debounceRef.current);
      }
    },
    [],
  );

  const itineraryErrors = errors.programNature?.itinerary;
  const rootMessage =
    itineraryErrors != null && typeof itineraryErrors === "object" && "message" in itineraryErrors
      ? String((itineraryErrors as { message?: string }).message ?? "")
      : undefined;

  return (
    <div style={{ display: "grid", gap: "0.75rem" }} data-testid="denali-daily-itinerary">
      {rootMessage ? (
        <p role="alert" style={{ margin: 0, color: "var(--color-danger-800, #991b1b)", fontSize: "0.85rem" }}>
          {rootMessage}
        </p>
      ) : null}
      {draftRows.map((row, index) => {
        const dayError = Array.isArray(itineraryErrors)
          ? itineraryErrors[index]?.activities?.message
          : undefined;
        const rowErrors = Array.isArray(itineraryErrors) ? itineraryErrors[index] : undefined;
        const locationFieldErrors = rowErrors?.location as
          | {
              addressText?: { message?: string };
              latitude?: { message?: string };
              longitude?: { message?: string };
            }
          | undefined;
        const photosError = readItineraryPhotosError(itineraryErrors, index);
        return (
          <div
            key={row.day}
            style={{
              display: "grid",
              gap: "0.5rem",
              padding: "0.65rem 0",
              borderTop: index > 0 ? "1px solid var(--color-border-subtle, #e2e8f0)" : undefined,
            }}
          >
            <DenaliItineraryDayLocationField
              day={row.day}
              value={row.location}
              fieldErrors={locationFieldErrors}
              onChange={(location, locationText) => {
                const next = draftRows.map((r, i) =>
                  i === index
                    ? {
                        ...r,
                        location,
                        locationText,
                      }
                    : r,
                );
                setDraftRows(next);
                scheduleCommit(next);
              }}
            />
            <FormField
              label={t("program.dailyActivitiesDay", { day: row.day })}
              error={dayError}
            >
              <Textarea
                rows={3}
                value={row.activities}
                onBlur={() => {
                  if (debounceRef.current != null) {
                    clearTimeout(debounceRef.current);
                    debounceRef.current = null;
                    updateCanonical({
                      program: { ...canonicalProgramRef.current, itinerary: draftRows },
                    });
                  }
                }}
                onChange={(e) => {
                  const next = draftRows.map((r, i) =>
                    i === index ? { ...r, activities: e.target.value } : r,
                  );
                  setDraftRows(next);
                  scheduleCommit(next);
                }}
                placeholder={t("program.dailyActivitiesPlaceholder")}
                data-testid={`denali-itinerary-day-${row.day}`}
              />
            </FormField>
            <DenaliItineraryDayPhotos
              day={row.day}
              photos={row.photos}
              label={t("program.dailyPhotosDay", { day: row.day })}
              hint={t("program.dailyPhotosHint")}
              error={photosError}
              onChange={(photos) => {
                const next = draftRows.map((r, i) =>
                  i === index ? { ...r, photos } : r,
                );
                setDraftRows(next);
                scheduleCommit(next);
              }}
            />
          </div>
        );
      })}
    </div>
  );
}

"use client";

import { useCallback, useState } from "react";
import { useFormContext } from "react-hook-form";
import { Alert, Button, FormField, Input } from "@tour/ui";

import type { DenaliCreateTourWizardForm } from "@/features/tours/wizard/schemas/denaliCore.schema";
import { DENALI_MAX_PHOTO_COUNT } from "@/features/tours/wizard/schemas/denaliFileAssetSchema";
import { uploadTourPhotos } from "@/lib/services/tours.service";

import { useDenaliCanonical } from "../DenaliCanonicalContext";
import { useDenaliStepFieldRules } from "../hooks/useDenaliStepFieldRules";
import { DenaliProgramContentSection } from "./DenaliProgramContentSection";

const STEP = "denali_photos" as const;
const ACCEPT = "image/jpeg, image/png, image/webp";

type DenaliPhotosStepProps = {
  /** Edit mode: existing tour id. Create mode: omit — context creates a draft shell on first upload. */
  tourId?: string;
};

export function DenaliPhotosStep({ tourId: tourIdProp }: DenaliPhotosStepProps = {}) {
  const {
    getValues,
    setValue,
    formState: { errors },
  } = useFormContext<DenaliCreateTourWizardForm>();
  const {
    updateCanonical,
    ensureUploadTourId,
    uploadTourId: contextUploadTourId,
    photoPersistenceWarning,
    clearPhotoPersistenceWarning,
    checkPhotoPersistence,
  } = useDenaliCanonical();
  const { isRequired } = useDenaliStepFieldRules(STEP);
  const [uploading, setUploading] = useState(false);
  const [uploadError, setUploadError] = useState<string | null>(null);

  const rows = getValues().photosData.photos ?? [];
  const photoErrors = errors.photosData?.photos;
  const rootError = Array.isArray(photoErrors) ? undefined : photoErrors?.message;
  const required = isRequired("photos", getValues());
  const atLimit = rows.length >= DENALI_MAX_PHOTO_COUNT;

  const commitPhotos = useCallback(
    (next: DenaliCreateTourWizardForm["photosData"]["photos"]) => {
      setValue("photosData.photos", next, {
        shouldDirty: true,
        shouldValidate: true,
      });
      updateCanonical({ photos: next });
      clearPhotoPersistenceWarning();
      checkPhotoPersistence({ ...getValues(), photosData: { photos: next ?? [] } });
    },
    [checkPhotoPersistence, clearPhotoPersistenceWarning, getValues, setValue, updateCanonical],
  );

  const resolveUploadTourId = useCallback(async (): Promise<string> => {
    const fromProp = tourIdProp?.trim();
    if (fromProp) {
      return fromProp;
    }
    if (contextUploadTourId?.trim()) {
      return contextUploadTourId.trim();
    }
    return ensureUploadTourId();
  }, [contextUploadTourId, ensureUploadTourId, tourIdProp]);

  const handleFileChange = useCallback(
    async (e: React.ChangeEvent<HTMLInputElement>) => {
      const fileList = e.target.files;
      if (!fileList?.length) return;

      const slots = Math.max(0, DENALI_MAX_PHOTO_COUNT - rows.length);
      const files = Array.from(fileList).slice(0, slots);
      if (files.length === 0) {
        e.target.value = "";
        return;
      }

      setUploading(true);
      setUploadError(null);
      try {
        const tourId = await resolveUploadTourId();
        const uploaded = await uploadTourPhotos(tourId, files);
        if (uploaded.length === 0) {
          setUploadError("آپلود عکس انجام نشد.");
          return;
        }
        const next = [...rows, ...uploaded];
        commitPhotos(next);
      } catch (err) {
        setUploadError(err instanceof Error ? err.message : "آپلود عکس ناموفق بود.");
      } finally {
        setUploading(false);
        e.target.value = "";
      }
    },
    [commitPhotos, resolveUploadTourId, rows],
  );

  return (
    <div style={{ display: "grid", gap: "0.85rem" }} data-testid="denali-step-photos">
      <DenaliProgramContentSection />

      {photoPersistenceWarning ? (
        <Alert variant="warning" role="status" data-testid="denali-photos-persistence-warning">
          {photoPersistenceWarning}
        </Alert>
      ) : null}

      <FormField
        label={
          required
            ? "آپلود عکس (الزامی - حداکثر ۱۰ فایل، هر فایل ۵ مگابایت)"
            : "آپلود عکس (حداکثر ۱۰ فایل، هر فایل ۵ مگابایت)"
        }
        error={uploadError ?? rootError}
      >
        <Input
          type="file"
          multiple
          accept={ACCEPT}
          disabled={atLimit || uploading}
          onChange={(event) => void handleFileChange(event)}
          data-testid="denali-photos-upload-input"
        />
      </FormField>

      {uploading ? (
        <p style={{ margin: 0, fontSize: "0.85rem", color: "#64748b" }}>در حال آپلود…</p>
      ) : null}

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fill, minmax(150px, 1fr))",
          gap: "1rem",
          marginTop: "0.25rem",
        }}
        data-testid="denali-photos-container"
      >
        {rows.map((field, index) => (
          <div
            key={`${field.id}-${index}`}
            style={{
              border: "1px solid #e2e8f0",
              borderRadius: "8px",
              overflow: "hidden",
              position: "relative",
            }}
          >
            <img
              src={field.url}
              alt={field.filename}
              style={{ width: "100%", height: "150px", objectFit: "cover" }}
              data-testid={`denali-photos-preview-${index}`}
            />
            <div
              style={{
                padding: "0.5rem",
                background: "#f8fafc",
                fontSize: "0.75rem",
                whiteSpace: "nowrap",
                overflow: "hidden",
                textOverflow: "ellipsis",
              }}
            >
              {field.filename}
            </div>
            <Button
              type="button"
              variant="secondary"
              size="sm"
              style={{ position: "absolute", top: "4px", right: "4px" }}
              onClick={() => {
                const next = rows.filter((_, i) => i !== index);
                commitPhotos(next);
              }}
              data-testid={`denali-photos-remove-${index}`}
            >
              حذف
            </Button>
          </div>
        ))}
      </div>
    </div>
  );
}

"use client";

