import type { TourFormLifecycleStatus } from "@/components/tours/tour-lifecycle";

import type { DenaliWizardPublishReadinessIssue } from "./denaliWizardPublishReadiness";

export type WizardPublishStatus = "draft" | "active";

export type HandleStatusChangeReason = "NOOP" | "BLOCKED_NOT_READY" | "APPLIED";

export type HandleStatusChangeResult = {
  appliedStatus: WizardPublishStatus;
  blocked: boolean;
  reason: HandleStatusChangeReason;
  issues: DenaliWizardPublishReadinessIssue[];
};

type HandleStatusChangeInput = {
  currentStatus: WizardPublishStatus;
  nextStatus: TourFormLifecycleStatus;
  publishIssues: DenaliWizardPublishReadinessIssue[];
  setStatus: (
    next: WizardPublishStatus,
    options?: { shouldDirty?: boolean; shouldValidate?: boolean },
  ) => void;
};

/**
 * Atomic status transition guard for wizard publish status.
 * Applies deterministic draft fallback when active readiness is blocked.
 */
export function handleStatusChange({
  currentStatus,
  nextStatus,
  publishIssues,
  setStatus,
}: HandleStatusChangeInput): HandleStatusChangeResult {
  if (nextStatus === "archived") {
    return {
      appliedStatus: currentStatus,
      blocked: false,
      reason: "NOOP",
      issues: [],
    };
  }

  const normalizedNext: WizardPublishStatus = nextStatus === "active" ? "active" : "draft";
  if (normalizedNext === currentStatus) {
    return {
      appliedStatus: currentStatus,
      blocked: false,
      reason: "NOOP",
      issues: [],
    };
  }

  if (normalizedNext === "active" && publishIssues.length > 0) {
    setStatus("draft", { shouldDirty: true, shouldValidate: true });
    return {
      appliedStatus: "draft",
      blocked: true,
      reason: "BLOCKED_NOT_READY",
      issues: publishIssues,
    };
  }

  setStatus(normalizedNext, { shouldDirty: true, shouldValidate: true });
  return {
    appliedStatus: normalizedNext,
    blocked: false,
    reason: "APPLIED",
    issues: [],
  };
}

"use client";

import { useCallback } from "react";

import type { TourCreateFormValues } from "@/features/tours/wizard/schemas/classic/tourCreateSchema";
import {
  requiredFieldsForProfile,
  requiredFieldsForStep,
  validateForAutosave,
  validateForStepNavigation,
  validateForSubmit,
  type ValidationResult,
} from "@/features/tours/wizard/profileRules";
import type { WizardFieldPath } from "@/features/tours/wizard/profileRules/types";
import type { TourCreateWizardStepId } from "@/features/tours/wizard/stepConfig";

import { useCurrentProfile } from "./useProfileRules";

/**
 * React bindings (L3) over the pure validation helpers in `profileRules/validation.ts`.
 * These hooks read the resolved profile from `TourWizardProfileContext` and return stable,
 * memoized callbacks that the caller invokes with current form values.
 *
 * Three flavours mirror the three validation levels:
 *
 * - {@link useAutosaveValidator} — returns a callback
 *   `(data) => validateForAutosave(profile, stepId, data)` for the current profile + fixed step.
 *   Used (or composable) by the wizard shell's debounced localStorage writer.
 * - {@link useStepValidator} — used by the wizard shell's `handleNext` to enforce required-
 *   ness for the step the user is leaving. Hidden steps short-circuit to "ok".
 * - {@link useSubmitValidator} — used by the wizard shell's `onSubmit` to gate the create
 *   mutation alongside Zod.
 *
 * Step components do **not** call these hooks today: they consume the cheaper
 * `useIsFieldRequired(path)` for per-field `aria-required` / `*` markers and rely on the
 * wizard shell to enforce step + submit transitions. The hooks are still exposed here so a
 * future "what's still missing on this step?" hint can be added inside a step in one line.
 */

export function useAutosaveValidator(
  stepId: TourCreateWizardStepId,
): (data: Partial<TourCreateFormValues>) => ValidationResult {
  const profile = useCurrentProfile();
  return useCallback((data) => validateForAutosave(profile, stepId, data), [profile, stepId]);
}

export function useStepValidator(
  stepId: TourCreateWizardStepId,
  visibleSteps: readonly TourCreateWizardStepId[],
): (data: TourCreateFormValues) => ValidationResult {
  const profile = useCurrentProfile();
  return useCallback(
    (data) => validateForStepNavigation(profile, stepId, data, visibleSteps),
    [profile, stepId, visibleSteps],
  );
}

export function useSubmitValidator(): (data: TourCreateFormValues) => ValidationResult {
  const profile = useCurrentProfile();
  return useCallback((data) => validateForSubmit(profile, data), [profile]);
}

/** Stable list of required field paths for the current profile (across all visible steps). */
export function useRequiredFieldsForProfile(): readonly WizardFieldPath[] {
  const profile = useCurrentProfile();
  return requiredFieldsForProfile(profile);
}

/** Stable list of required field paths for one step under the current profile. */
export function useRequiredFieldsForStep(stepId: TourCreateWizardStepId): readonly WizardFieldPath[] {
  const profile = useCurrentProfile();
  return requiredFieldsForStep(profile, stepId);
}

"use client";

import { useQuery } from "@tanstack/react-query";
import { useMemo } from "react";

import { settingsLocationsKeys } from "@/lib/query-keys";

import { useWorkspaceQueryScope } from "./use-workspace-query-scope";
import {
  fetchSettingsDestinations,
  fetchSettingsRegions,
  type SettingsDestinationDto,
} from "@/lib/settings-locations-client";

export type TourDestinationGroup = {
  regionId: string;
  regionName: string;
  items: SettingsDestinationDto[];
};

/**
 * Active destinations from `/api/settings/destinations`, grouped by region for tour forms.
 */
export function useTourDestinations() {
  const tenantId = useWorkspaceQueryScope();
  const regionsQuery = useQuery({
    queryKey: settingsLocationsKeys.regions(tenantId ?? ""),
    queryFn: fetchSettingsRegions,
    enabled: Boolean(tenantId),
  });

  const destinationsQuery = useQuery({
    queryKey: settingsLocationsKeys.destinations(tenantId ?? ""),
    queryFn: fetchSettingsDestinations,
    enabled: Boolean(tenantId),
  });

  const allDestinations = destinationsQuery.data ?? [];

  const groupedRegions = useMemo((): TourDestinationGroup[] => {
    const regions = regionsQuery.data ?? [];
    const activeDestinations = allDestinations
      .filter((d) => d.isActive)
      .sort(
        (a, b) =>
          (a.sortOrder ?? 0) - (b.sortOrder ?? 0) ||
          a.name.localeCompare(b.name, undefined, { sensitivity: "base" }),
      );
    const regionOrder = [...regions].sort(
      (a, b) => (a.sortOrder ?? 0) - (b.sortOrder ?? 0) || a.name.localeCompare(b.name),
    );
    const byRegion = new Map<string, SettingsDestinationDto[]>();
    for (const d of activeDestinations) {
      const list = byRegion.get(d.regionId);
      if (list) {
        list.push(d);
      } else {
        byRegion.set(d.regionId, [d]);
      }
    }
    return regionOrder
      .map((r) => ({
        regionId: r.id,
        regionName: r.name,
        items: byRegion.get(r.id) ?? [],
      }))
      .filter((g) => g.items.length > 0);
  }, [allDestinations, regionsQuery.data]);

  const destinations = useMemo(
    () => allDestinations.filter((d) => d.isActive),
    [allDestinations],
  );

  return {
    groupedRegions,
    destinations,
    allDestinations,
    isLoading: regionsQuery.isLoading || destinationsQuery.isLoading,
    error: regionsQuery.error ?? destinationsQuery.error,
  };
}

"use client";

import { Component, type ErrorInfo, type ReactNode } from "react";

import { Button, Card, CardBody, CardHeader, CardTitle } from "@tour/ui";

type Props = {
  children: ReactNode;
};

type State = { error: Error | null };

export class ErrorBoundary extends Component<Props, State> {
  state: State = { error: null };

  static getDerivedStateFromError(error: Error): State {
    return { error };
  }

  componentDidCatch(error: Error, info: ErrorInfo): void {
    console.error("[AppErrorBoundary]", error, info.componentStack);
  }

  private reset = (): void => {
    this.setState({ error: null });
  }

  render() {
    if (this.state.error) {
      return (
        <Card role="alert">
          <CardHeader>
            <CardTitle>Something went wrong</CardTitle>
          </CardHeader>
          <CardBody>
            <p style={{ marginTop: 0 }}>
              We hit an unexpected problem. You can try again without reloading the whole app.
            </p>
            <p style={{ marginTop: "var(--space-2)", color: "var(--color-text-secondary)" }}>
              {this.state.error.message || "Unexpected application error."}
            </p>
            <div style={{ display: "flex", gap: "var(--space-3)", flexWrap: "wrap" }}>
              <Button type="button" variant="primary" onClick={this.reset}>
                Try again
              </Button>
              <Button type="button" variant="secondary" onClick={() => window.location.reload()}>
                Reload page
              </Button>
            </div>
          </CardBody>
        </Card>
      );
    }
    return this.props.children;
  }
}

import type { ChangeEvent, MutableRefObject, Ref, RefCallback, RefObject } from "react";

import { normalizeNumericInput, toEnglishDigits, toPersianDigits } from "@/lib/digit-localization";

/**
 * String normalization and react-hook-form wiring for numeric inputs.
 *
 * **Digit conversion** (Persian / Arabic-Indic ↔ ASCII) is defined only in
 * `@repo/digit-localization`. This module must not reimplement that logic; it only
 * composes {@link normalizeNumericInput}, {@link toEnglishDigits}, and {@link toPersianDigits}
 * with digit stripping, decimal rules, and UI sync helpers.
 */

/** Use on translated UI strings (placeholders, hints) so `0–9` show as Persian when `locale === "fa"`. */
export function uiLocaleDigits(text: string, locale: string): string {
  return locale === "fa" ? convertNumbers(text, "fa") : text;
}

/** Thin wrapper over {@link toEnglishDigits} / {@link toPersianDigits} for callers that choose direction via `"en"` | `"fa"`. */
export function convertNumbers(text: string, to: "fa" | "en"): string {
  if (!text) {
    return text;
  }
  return to === "en" ? toEnglishDigits(text) : toPersianDigits(text);
}

/** After script normalization via {@link normalizeNumericInput}, keep ASCII digits only (empty allowed). */
export function toEnglishIntegerString(value: string): string {
  return normalizeNumericInput(value).replace(/\D/g, "");
}

/** Commas / thin spaces / Arabic thousands separator ، (U+066C) typed or pasted — strip before numeric parse. */
export function stripNumericSeparators(value: string): string {
  return value.replace(/[,٬\s\u202f\u200c']/g, "");
}

/**
 * Group integer chunk with commas (ASCII) before Persian digit shaping; fractional part untouched.
 */
export function formatEnglishWithThousands(english: string, mode: "integer" | "decimal"): string {
  const safe = english.trim();
  if (safe === "") {
    return "";
  }

  if (mode === "integer") {
    const digitsOnly = safe.replace(/\D/g, "");
    if (digitsOnly === "") {
      return "";
    }
    return digitsOnly.replace(/\B(?=(\d{3})+(?!\d))/g, ",");
  }

  const dotIdx = safe.indexOf(".");
  const intRaw = dotIdx === -1 ? safe : safe.slice(0, dotIdx);
  const fracRaw = dotIdx === -1 ? undefined : safe.slice(dotIdx + 1);

  const intDigits = intRaw.replace(/\D/g, "");
  const groupedInt = intDigits.replace(/\B(?=(\d{3})+(?!\d))/g, ",");

  if (dotIdx === -1) {
    return groupedInt;
  }

  return `${groupedInt}.${fracRaw ?? ""}`;
}

/** After script normalization, keep one optional decimal point and ASCII digits. */
export function toEnglishDecimalString(value: string): string {
  /** Arabic decimal separator `٫` (U+066B), common in Persian numeric typing. */
  const en = normalizeNumericInput(value).replace(/\u066b/g, ".");
  let out = "";
  let sawDot = false;
  for (const ch of en) {
    if (ch >= "0" && ch <= "9") {
      out += ch;
    } else if (ch === "." && !sawDot) {
      out += ch;
      sawDot = true;
    }
  }
  return out;
}

type InputRegisterLike = {
  onChange: (e: ChangeEvent<HTMLInputElement>) => void;
  onBlur: (e: ChangeEvent<HTMLInputElement>) => void;
  name: string;
  ref: RefCallback<HTMLInputElement> | RefObject<HTMLInputElement | null>;
};

function assignRef<T>(ref: Ref<T> | undefined, instance: T | null): void {
  if (ref == null) {
    return;
  }
  if (typeof ref === "function") {
    (ref as RefCallback<T | null>)(instance);
  } else {
    (ref as MutableRefObject<T | null>).current = instance;
  }
}

/** Sync `<input>` display to Persian digits; keep `+` / separators outside digit runs unchanged. */
function syncIntegerInputPersianDisplay(el: HTMLInputElement): void {
  const en = toEnglishIntegerString(el.value);
  el.value = en === "" ? "" : toPersianDigits(en);
}

function syncDecimalInputPersianDisplay(el: HTMLInputElement): void {
  const en = toEnglishDecimalString(el.value);
  el.value = en === "" ? "" : toPersianDigits(en);
}

function composeInputRef(
  fieldRef: InputRegisterLike["ref"],
  syncDisplay: (el: HTMLInputElement) => void,
): RefCallback<HTMLInputElement> {
  return (instance) => {
    assignRef(fieldRef, instance);
    if (instance) {
      queueMicrotask(() => syncDisplay(instance));
    }
  };
}

/**
 * react-hook-form reads `event.target.name` / `.value` / `.type`.
 * Spreading a DOM `HTMLInputElement` into `{}` does not copy those fields, so the
 * form state can stay empty while the visible `<input>` shows Persian digits.
 */
export function syntheticChangeForInputValue(
  base: ChangeEvent<HTMLInputElement>,
  el: HTMLInputElement,
  valueForForm: string,
): ChangeEvent<HTMLInputElement> {
  const target = {
    name: el.name,
    value: valueForForm,
    type: el.type,
  } as unknown as EventTarget & HTMLInputElement;

  return {
    ...base,
    target,
    currentTarget: target,
  } as ChangeEvent<HTMLInputElement>;
}

/** Merge with `react-hook-form` `register()` for whole-number fields. */
export function withIntegerDigitNormalization<T extends InputRegisterLike>(field: T): T {
  return {
    ...field,
    ref: composeInputRef(field.ref, syncIntegerInputPersianDisplay),
    onChange: (e: ChangeEvent<HTMLInputElement>) => {
      const el = e.target;
      const next = toEnglishIntegerString(el.value);
      el.value = next === "" ? "" : toPersianDigits(next);
      field.onChange(syntheticChangeForInputValue(e, el, next));
    },
    onBlur: (e: ChangeEvent<HTMLInputElement>) => {
      const el = e.target;
      const next = toEnglishIntegerString(el.value);
      el.value = next === "" ? "" : toPersianDigits(next);
      field.onBlur(syntheticChangeForInputValue(e, el, next));
    },
  };
}

/** Merge with `react-hook-form` `register()` for decimal fields (price). */
export function withDecimalDigitNormalization<T extends InputRegisterLike>(field: T): T {
  return {
    ...field,
    ref: composeInputRef(field.ref, syncDecimalInputPersianDisplay),
    onChange: (e: ChangeEvent<HTMLInputElement>) => {
      const el = e.target;
      const next = toEnglishDecimalString(el.value);
      el.value = next === "" ? "" : toPersianDigits(next);
      field.onChange(syntheticChangeForInputValue(e, el, next));
    },
    onBlur: (e: ChangeEvent<HTMLInputElement>) => {
      const el = e.target;
      const next = toEnglishDecimalString(el.value);
      el.value = next === "" ? "" : toPersianDigits(next);
      field.onBlur(syntheticChangeForInputValue(e, el, next));
    },
  };
}

