let logStream: string[] = [];

function log(tag: string, message: string): void {
  const line = `[${tag}] ${message}`;
  console.log(line);
  logStream.push(line);
}

function flushLog(logFile: string): void {
  const header = `\n--- Denali field update ${new Date().toString()} ---\n`;
  fs.appendFileSync(path.join(REPO_ROOT, logFile), header + logStream.join("\n") + "\n");
}

function fail(tag: string, message: string): never {
  log(tag, `ERROR: ${message}`);
  throw new Error(message);
}

// ---------------------------------------------------------------------------
// Manifest parsing (JSON + minimal YAML for `fields:` lists)
// ---------------------------------------------------------------------------
function parseSimpleYamlFields(text: string): Manifest {
  const fields: DenaliFieldSpec[] = [];
  const lines = text.split(/\r?\n/);
  let current: Partial<DenaliFieldSpec> | null = null;
  let inFields = false;

  const set = (key: string, raw: string) => {
    if (!current) return;
    const v = raw.trim().replace(/^["']|["']$/g, "");
    switch (key) {
      case "name":
        current.name = v;
        break;
      case "tab":
        current.tab = v;
        break;
      case "type":
        current.type = v as DenaliFieldType;
        break;
      case "required":
        current.required = v === "true";
        break;
      case "read-only":
      case "readOnly":
        current.readOnly = v === "true";
        break;
      case "conditional":
        current.conditional = v === "null" ? null : v;
        break;
      case "default":
        current.default = v === "null" ? null : v;
        break;
      default:
        break;
    }
  };

  for (const line of lines) {
    if (/^fields:\s*$/.test(line)) {
      inFields = true;
      continue;
    }
    if (!inFields) continue;
    const item = line.match(/^\s*-\s*$/);
    const kv = line.match(/^\s+([a-zA-Z-]+):\s*(.*)$/);
    if (line.match(/^\s*-\s*name:/)) {
      if (current?.name) fields.push(current as DenaliFieldSpec);
      const name = line.replace(/^\s*-\s*name:\s*/, "").trim();
      current = { name, tab: "", type: "string", required: false, readOnly: false };
      continue;
    }
    if (item && current?.name) {
      fields.push(current as DenaliFieldSpec);
      current = { name: "", tab: "", type: "string", required: false, readOnly: false };
      continue;
    }
    if (kv && current) set(kv[1], kv[2]);
  }
  if (current?.name) fields.push(current as DenaliFieldSpec);
  return { fields };
}

function loadManifest(fieldsPath?: string): Manifest {
  const raw = fieldsPath
    ? fs.readFileSync(path.resolve(REPO_ROOT, fieldsPath), "utf-8")
    : DEFAULT_MANIFEST_YAML;
  const trimmed = raw.trim();
  if (fieldsPath?.endsWith(".json") || trimmed.startsWith("{")) {
    return JSON.parse(trimmed) as Manifest;
  }
  return parseSimpleYamlFields(raw);
}

// ---------------------------------------------------------------------------
// Field resolution
// ---------------------------------------------------------------------------
function resolveField(spec: DenaliFieldSpec): ResolvedField {
  if (!TAB_CONFIG[spec.tab]) {
    fail("Manifest", `Unknown tab "${spec.tab}" on field "${spec.name}". Use: ${Object.keys(TAB_CONFIG).join(", ")}`);
  }
  const tab = TAB_CONFIG[spec.tab];
  const reg = FIELD_REGISTRY[spec.name];
  const canonical = reg?.canonical ?? spec.name;
  const formLeaf = reg?.formLeaf ?? spec.name;
  const formPath = `${tab.formSection}.${formLeaf}`;
  return {
    ...spec,
    canonical,
    formPath,
    step: tab.step,
    registryKnown: reg != null,
  };
}

function readExistingCanonicalPaths(filePath: string): string[] {
  const content = fs.readFileSync(path.join(REPO_ROOT, filePath), "utf-8");
  const m = content.match(/DENALI_WIZARD_CANONICAL_FIELD_PATHS = new Set\(\[([\s\S]*?)\]\)/);
  if (!m) return [];
  return [...m[1].matchAll(/"([^"]+)"/g)].map((x) => x[1]);
}

function buildCanonicalPathSet(fields: ResolvedField[], prune: boolean, existing: string[]): string[] {
  const fromManifest = fields.map((f) => f.canonical);
  const merged = prune ? fromManifest : [...new Set([...existing, ...fromManifest])];
  return merged.sort();
}

function buildFormPathMapEntries(fields: ResolvedField[]): string[] {
  const lines: string[] = [];
  const seen = new Set<string>();
  for (const f of fields) {
    if (seen.has(f.canonical)) continue;
    seen.add(f.canonical);
    lines.push(`  "${f.canonical}": "${f.formPath}",`);
  }
  return lines;
}

// ---------------------------------------------------------------------------
// Idempotent file patching
// ---------------------------------------------------------------------------
function syncCanonicalFieldPathsSet(
  paths: string[],
  dryRun: boolean,
): { changed: boolean; content: string } {
  const filePath = path.join(REPO_ROOT, PATHS.ruleRequired);
  let content = fs.readFileSync(filePath, "utf-8");
  const body = paths.map((p) => `  "${p}",`).join("\n");
  const nextBlock = `export const DENALI_WIZARD_CANONICAL_FIELD_PATHS = new Set([\n${body}\n]);`;
  const pattern = /export const DENALI_WIZARD_CANONICAL_FIELD_PATHS = new Set\(\[[\s\S]*?\]\);/;
  if (!pattern.test(content)) fail("Patch", "DENALI_WIZARD_CANONICAL_FIELD_PATHS block missing");
  const next = content.replace(pattern, nextBlock);
  const changed = next !== content;
  if (changed && !dryRun) fs.writeFileSync(filePath, next, "utf-8");
  return { changed, content: next };
}

function syncCanonicalToFormMap(
  fields: ResolvedField[],
  dryRun: boolean,
): { changed: boolean } {
  const filePath = path.join(REPO_ROOT, PATHS.ruleRequired);
  let content = fs.readFileSync(filePath, "utf-8");
  const existing = content.match(
    /const CANONICAL_TO_FORM_PATH_MAP: Record<string, string> = \{([\s\S]*?)\};/,
  );
  if (!existing) fail("Patch", "CANONICAL_TO_FORM_PATH_MAP block missing");

  const mapBody = existing[1];
  const mapEntries = new Map<string, string>();
  for (const m of mapBody.matchAll(/"([^"]+)":\s*"([^"]+)",/g)) {
    mapEntries.set(m[1], m[2]);
  }
  for (const f of fields) {
    mapEntries.set(f.canonical, f.formPath);
  }
  const sortedKeys = [...mapEntries.keys()].sort();
  const newBody = sortedKeys.map((k) => `  "${k}": "${mapEntries.get(k)}",`).join("\n");
  const nextMap = `const CANONICAL_TO_FORM_PATH_MAP: Record<string, string> = {\n${newBody}\n};`;
  const next = content.replace(
    /const CANONICAL_TO_FORM_PATH_MAP: Record<string, string> = \{[\s\S]*?\};/,
    nextMap,
  );
  const changed = next !== content;
  if (changed && !dryRun) fs.writeFileSync(filePath, next, "utf-8");
  return { changed };
}

// ---------------------------------------------------------------------------
// Layer verification (read-only checks; logs warnings for manual follow-up)
// ---------------------------------------------------------------------------
function readRepoFile(rel: string): string {
  return fs.readFileSync(path.join(REPO_ROOT, rel), "utf-8");
}

function verifyCanonicalModel(fields: ResolvedField[]): boolean {
  log("Canonical", "Verifying DenaliCanonicalTourModel + denaliCanonicalFromForm...");
  const model = readRepoFile(PATHS.canonicalModel);
  const fromForm = readRepoFile(PATHS.canonicalFromForm);
  let ok = true;
  for (const f of fields) {
    const key = FIELD_REGISTRY[f.name]?.canonicalInterfaceKey ?? f.canonical.split(".").pop() ?? f.name;
    const topLevel = !f.canonical.includes(".");
    if (topLevel) {
      if (!new RegExp(`\\b${key}\\b`).test(model)) {
        log("Canonical", `Warning: top-level "${key}" not found in interface (field "${f.name}")`);
        ok = false;
      }
    } else {
      const [section, leaf] = f.canonical.split(".");
      if (!model.includes(`${section}:`) || !model.includes(`${leaf}`)) {
        log("Canonical", `Warning: nested "${f.canonical}" may be missing in interface`);
        ok = false;
      }
    }
    if (FIELD_REGISTRY[f.name]?.adapterNeedle && !fromForm.includes(f.canonical.split(".").pop()!)) {
      // soft check on fromForm mapping
    }
  }
  return ok;
}

function verifyRules(fields: ResolvedField[]): boolean {
  log("Rules", "Verifying denaliRuleModel path definitions...");
  const model = readRepoFile(PATHS.ruleModel);
  let ok = true;
  for (const f of fields) {
    const needle = `path: "${f.canonical}"`;
    if (!model.includes(needle)) {
      log(
        "Rules",
        `Warning: ${needle} not in denaliRuleModel — add a DenaliRuleFieldDefinition constant and include it in denaliRuleSet spreads (field "${f.name}").`,
      );
      ok = false;
    }
  }
  return ok;
}

function verifyNormalization(fields: ResolvedField[]): boolean {
  log("Normalization", "Verifying ghost-field registry drives normalizeDenaliWizardForm...");
  const access = readRepoFile(PATHS.ruleAccess);
  let ok = true;
  if (!access.includes("export function normalizeDenaliWizardForm")) {
    fail("Normalization", "normalizeDenaliWizardForm missing");
  }
  if (!access.includes("DENALI_WIZARD_CANONICAL_FIELD_PATHS")) {
    log("Normalization", "Warning: rule access should iterate DENALI_WIZARD_CANONICAL_FIELD_PATHS");
    ok = false;
  }
  for (const f of fields) {
    if (!access.includes(f.canonical) && !access.includes(f.formPath)) {
      log("Normalization", `Info: "${f.name}" relies on generic path clearing via canonical set`);
    }
  }
  return ok;
}

function verifyUiSync(fields: ResolvedField[]): boolean {
  log("UI Sync", "Verifying applyCanonicalMvpToForm / denaliCanonicalToForm...");
  const adapter = readRepoFile(PATHS.formAdapter);
  let ok = true;
  if (!adapter.includes("export function applyCanonicalMvpToForm")) {
    fail("UI Sync", "applyCanonicalMvpToForm missing");
  }
  for (const f of fields) {
    const needle = FIELD_REGISTRY[f.name]?.adapterNeedle ?? f.formPath.split(".")[1];
    if (needle && !adapter.includes(needle)) {
      log("UI Sync", `Warning: adapter may not sync "${f.name}" (look for "${needle}")`);
      ok = false;
    }
  }
  return ok;
}

function verifyProjection(fields: ResolvedField[]): boolean {
  log("Projection", "Verifying buildDenaliCreateTourPayloadProjection...");
  const proj = readRepoFile(PATHS.projection);
  let ok = true;
  if (!proj.includes("export function buildDenaliCreateTourPayloadProjection")) {
    fail("Projection", "projection function missing");
  }
  if (!proj.includes("const tripDetails = {")) {
    log("Projection", "Warning: tripDetails builder block not found");
    ok = false;
  }
  for (const f of fields) {
    const needle = FIELD_REGISTRY[f.name]?.projectionNeedle;
    if (needle && !proj.includes(needle)) {
      log("Projection", `Warning: projection may not map "${f.name}" (expected ref "${needle}")`);
      ok = false;
    }
  }
  return ok;
}

// ---------------------------------------------------------------------------
// Run existing gates + tests
// ---------------------------------------------------------------------------
function runNodeGate(scriptName: string): void {
  const script = path.join(REPO_ROOT, TEMPLATES_DIR, scriptName);
  log("Gate", `Running ${scriptName}...`);
  const r = spawnSync("node", [script], { cwd: REPO_ROOT, encoding: "utf-8" });
  if (r.stdout) process.stdout.write(r.stdout);
  if (r.stderr) process.stderr.write(r.stderr);
  if (r.status !== 0) fail("Gate", `${scriptName} exited with code ${r.status}`);
}

function runUnitTests(): void {
  log("Test", "Running apps/web unit tests (pnpm test)...");
  const r = spawnSync("pnpm", ["test"], { cwd: path.join(REPO_ROOT, "apps/web"), encoding: "utf-8", shell: true });
  if (r.stdout) process.stdout.write(r.stdout);
  if (r.stderr) process.stderr.write(r.stderr);
  if (r.status !== 0) fail("Test", `Unit tests failed (exit ${r.status})`);
}

function runE2ETests(): void {
  log("Test", "Running Denali negative invariant E2E...");
  const spec = "test/e2e/denali-negative-invariants.e2e-spec.ts";
  const r = spawnSync("node", ["--import", "tsx", "--test", spec], {
    cwd: path.join(REPO_ROOT, "apps/api"),
    encoding: "utf-8",
  });
  if (r.stdout) process.stdout.write(r.stdout);
  if (r.stderr) process.stderr.write(r.stderr);
  if (r.status !== 0) fail("Test", `E2E tests failed (exit ${r.status})`);
}

// ---------------------------------------------------------------------------
// Main pipeline
// ---------------------------------------------------------------------------
function main(): void {
  const opts = parseArgs(process.argv.slice(2));
  logStream = [];

  log("Pipeline", `Denali field update started (dryRun=${opts.dryRun}, prune=${opts.prune})`);

  const manifest = loadManifest(opts.fieldsPath);
  if (!manifest.fields?.length) fail("Manifest", "No fields in manifest");

  const resolved = manifest.fields.map(resolveField);
  log("Manifest", `Loaded ${resolved.length} field(s): ${resolved.map((f) => f.name).join(", ")}`);

  for (const f of resolved) {
    if (!f.registryKnown) {
      log(
        "Manifest",
        `Warning: "${f.name}" is not in FIELD_REGISTRY — canonical path defaults to "${f.canonical}"; extend run-denali-field-update.ts registry.`,
      );
    }
    if (f.conditional) {
      log(
        "Manifest",
        `Info: conditional visibility for "${f.name}" (${f.conditional}) must be implemented in denaliRuleModel / denaliUIAdapter manually.`,
      );
    }
    if (f.readOnly) {
      log("Manifest", `Info: read-only "${f.name}" — enforce in UI step components, not auto-patched.`);
    }
  }

  // Phase 1 — Registry sync (idempotent)
  log("Apply", "Phase 1: Sync DENALI_WIZARD_CANONICAL_FIELD_PATHS + form path map");
  const existing = readExistingCanonicalPaths(PATHS.ruleRequired);
  const pathSet = buildCanonicalPathSet(resolved, opts.prune, existing);
  const { changed: pathsChanged } = syncCanonicalFieldPathsSet(pathSet, opts.dryRun);
  const { changed: mapChanged } = syncCanonicalToFormMap(resolved, opts.dryRun);
  const changeVerb = opts.dryRun ? "would update" : "updated";
  log("Apply", `Registry paths: ${pathSet.length} (${pathsChanged ? changeVerb : "unchanged"})`);
  log("Apply", `Form path map: ${mapChanged ? changeVerb : "unchanged"}`);

  // Phase 2 — Layer verification
  log("Verify", "Phase 2: Cross-layer presence checks");
  const layerOk =
    verifyCanonicalModel(resolved) &&
    verifyRules(resolved) &&
    verifyNormalization(resolved) &&
    verifyUiSync(resolved) &&
    verifyProjection(resolved);

  if (!layerOk) {
    log(
      "Verify",
      "Some layers need manual edits (see warnings). Registry sync still applied where safe.",
    );
  }

  // Phase 3 — CI gates
  log("CI", "Phase 3: Static gates");
  const gates = [
    "check-canonical-gate.ts",
    "check-rules-gate.ts",
    "check-normalization-gate.ts",
    "check-projection-gate.ts",
    "check-ui-sync-gate.ts",
  ];
  for (const g of gates) runNodeGate(g);

  // Phase 4 — Tests
  if (!opts.skipTests && !opts.dryRun) {
    log("CI", "Phase 4: Unit + E2E tests");
    runUnitTests();
    runE2ETests();
  } else if (opts.dryRun) {
    log("CI", "Phase 4: Skipped (dry-run)");
  } else {
    log("CI", "Phase 4: Skipped (--skip-tests)");
  }

  flushLog(opts.logFile);
  log("Pipeline", "COMPLETED successfully");
  process.exit(0);
}

try {
  main();
} catch (err) {
  const msg = err instanceof Error ? err.message : String(err);
  log("Pipeline", `FAILED: ${msg}`);
  try {
    flushLog(process.argv.find((a) => a.startsWith("--log="))?.slice(6) ?? LOG_FILE_DEFAULT);
  } catch {
    /* ignore */
  }
  process.exit(1);
}

import {
  DraftConflictError,
  type DraftEngineConfig,
  type DraftEngineState,
  type DraftSetDataOptions,
  type DraftSyncPayload,
} from "./types";

const DEFAULT_DEBOUNCE_MS = 500;

export class DraftEngine<T> {
  private readonly config: DraftEngineConfig<T>;
  private readonly debounceMs: number;

  private data: T | null = null;
  private pendingDraft: DraftSyncPayload<T> | null = null;
  private status: DraftEngineState<T>["status"] = "IDLE";
  private version = 0;
  private schemaVersion = 1;
  private lastModified = 0;
  private error: Error | undefined;

  private debounceTimer: ReturnType<typeof setTimeout> | null = null;
  private syncInFlight: Promise<void> | null = null;
  private pendingSync = false;
  private readonly listeners = new Set<(state: DraftEngineState<T>) => void>();

  constructor(config: DraftEngineConfig<T>) {
    this.config = config;
    this.debounceMs = config.debounceMs ?? DEFAULT_DEBOUNCE_MS;
  }

  subscribe(listener: (state: DraftEngineState<T>) => void): () => void {
    this.listeners.add(listener);
    listener(this.getState());
    return () => {
      this.listeners.delete(listener);
    };
  }

  private notify(): void {
    const snapshot = this.getState();
    for (const listener of this.listeners) {
      listener(snapshot);
    }
  }

  async initialize(): Promise<void> {
    this.clearDebounce();
    this.status = "SYNCING";
    this.error = undefined;
    this.notify();

    try {
      await this.fetchAndHydrate({ forceApply: false });
      if (this.status === "SYNCING") {
        this.status = "IDLE";
      }
    } catch (err) {
      this.status = "ERROR";
      this.error = err instanceof Error ? err : new Error(String(err));
    }
    this.notify();
  }

  async retry(): Promise<void> {
    const state = this.getState();
    if (state.status !== "ERROR") {
      return;
    }
    if (state.data == null) {
      await this.initialize();
      return;
    }
    this.status = "DIRTY";
    this.error = undefined;
    this.notify();
    await this.flushSync();
  }

  /**
   * UI entry point: update local draft and optionally schedule sync via the engine debouncer.
   * Use `{ source: 'remote' }` for server hydration (no DIRTY, no push).
   */
  setDraftData(newData: T, options?: DraftSetDataOptions): void {
    const source = options?.source ?? "user";

    if (source === "remote") {
      this.clearDebounce();
      this.data = newData;
      if (options?.version != null) {
        this.version = options.version;
      }
      if (options?.schemaVersion != null) {
        this.schemaVersion = options.schemaVersion;
      }
      if (options?.lastModified != null) {
        this.lastModified = options.lastModified;
      }
      this.status = "IDLE";
      this.error = undefined;
      this.notify();
      return;
    }

    if (this.status === "CONFLICT_RESOLVING") {
      return;
    }
    if (this.status === "DRAFT_AVAILABLE") {
      this.pendingDraft = null;
      this.status = "IDLE";
    }
    this.data = newData;
    this.lastModified = Date.now();
    this.status = "DIRTY";
    this.error = undefined;
    this.notify();
    this.scheduleSync();
  }

  /** @deprecated Prefer setDraftData — kept for tests and backward compatibility. */
  update(newData: T, options?: DraftSetDataOptions): void {
    this.setDraftData(newData, options);
  }

  applyDraft(): void {
    if (this.pendingDraft == null) {
      return;
    }
    this.hydrateFromRemote(this.pendingDraft);
    this.pendingDraft = null;
    this.status = "IDLE";
    this.error = undefined;
    this.notify();
  }

  async clearDraft(): Promise<void> {
    if (this.config.onDelete == null) {
      throw new Error("clearDraft requires config.onDelete");
    }
    await this.config.onDelete();
    this.clearDebounce();
    this.pendingDraft = null;
    this.data = null;
    this.version = 0;
    this.schemaVersion = 1;
    this.lastModified = 0;
    this.status = "IDLE";
    this.error = undefined;
    this.notify();
  }

  getState(): DraftEngineState<T> {
    return {
      data: this.data,
      status: this.status,
      version: this.version,
      schemaVersion: this.schemaVersion,
      lastModified: this.lastModified,
      ...(this.pendingDraft != null ? { pendingDraft: this.pendingDraft } : {}),
      ...(this.error != null ? { error: this.error } : {}),
    };
  }

  private async fetchAndHydrate(options: { forceApply: boolean }): Promise<void> {
    const payload = await this.config.onFetch();
    if (payload == null) {
      this.pendingDraft = null;
      return;
    }
    if (options.forceApply || this.config.autoApply !== false) {
      this.hydrateFromRemote(payload);
      this.pendingDraft = null;
      return;
    }
    this.pendingDraft = payload;
    this.status = "DRAFT_AVAILABLE";
  }

  /** Server / snapshot hydration — updates version metadata without marking DIRTY or pushing. */
  private hydrateFromRemote(payload: DraftSyncPayload<T>): void {
    this.setDraftData(payload.data, {
      source: "remote",
      version: payload.version,
      schemaVersion: payload.schemaVersion,
      lastModified: payload.lastModified,
    });
  }

  private buildPayload(): DraftSyncPayload<T> {
    if (this.data == null) {
      throw new Error("Cannot push draft: data is null");
    }
    return {
      data: this.data,
      version: this.version,
      schemaVersion: this.schemaVersion,
      lastModified: this.lastModified,
    };
  }

  private clearDebounce(): void {
    if (this.debounceTimer != null) {
      clearTimeout(this.debounceTimer);
      this.debounceTimer = null;
    }
  }

  private scheduleSync(): void {
    if (this.status === "CONFLICT_RESOLVING") {
      return;
    }
    this.scheduleDebouncedSync();
  }

  /** Debounced sync scheduler — runs on the timer queue, not during React render. */
  private scheduleDebouncedSync(): void {
    if (this.status === "CONFLICT_RESOLVING") {
      return;
    }
    this.clearDebounce();
    this.debounceTimer = setTimeout(() => {
      this.debounceTimer = null;
      if (this.status === "CONFLICT_RESOLVING") {
        return;
      }
      void this.flushSync();
    }, this.debounceMs);
  }

  private async flushSync(): Promise<void> {
    if (this.syncInFlight != null) {
      this.pendingSync = true;
      return;
    }

    if (this.status !== "DIRTY") {
      return;
    }

    this.syncInFlight = this.doPush();
    try {
      await this.syncInFlight;
    } finally {
      this.syncInFlight = null;
      if (this.pendingSync) {
        this.pendingSync = false;
        if (this.status === "DIRTY") {
          await this.flushSync();
        }
      }
    }
  }

  private async doPush(): Promise<void> {
    if (this.status === "CONFLICT_RESOLVING") {
      return;
    }
    if (this.status !== "DIRTY" || this.data == null) {
      return;
    }

    this.status = "SYNCING";
    this.error = undefined;
    this.notify();

    try {
      const pushedPayload = this.buildPayload();
      const result = await this.config.onPush(pushedPayload);
      const localChangedDuringPush =
        this.data !== pushedPayload.data || this.lastModified !== pushedPayload.lastModified;
      if (localChangedDuringPush) {
        this.status = "DIRTY";
        this.scheduleSync();
      } else {
        this.hydrateFromRemote(result);
        this.status = "IDLE";
      }
    } catch (err) {
      if (err instanceof DraftConflictError) {
        await this.handleConflict(err);
        this.notify();
        return;
      }
      this.status = "ERROR";
      this.error = err instanceof Error ? err : new Error(String(err));
    }
    this.notify();
  }

  private async handleConflict(conflict: DraftConflictError<T>): Promise<void> {
    const { conflictStrategy } = this.config;
    const serverPayload = conflict.serverPayload;

    if (conflictStrategy === "REFETCH_REAPPLY") {
      await this.refetchAndReapplyLocal(conflict);
      return;
    }

    if (conflictStrategy === "SERVER_WINS") {
      this.hydrateFromRemote(serverPayload);
      this.status = "IDLE";
      this.notify();
      return;
    }

    if (conflictStrategy === "CLIENT_WINS") {
      try {
        const result = await this.config.onPush(this.buildPayload());
        this.hydrateFromRemote(result);
        this.status = "IDLE";
        this.notify();
      } catch (retryErr) {
        if (retryErr instanceof DraftConflictError) {
          await this.handleConflict(retryErr);
          return;
        }
        this.status = "ERROR";
        this.error = retryErr instanceof Error ? retryErr : new Error(String(retryErr));
        this.notify();
      }
      return;
    }

    if (conflictStrategy === "MERGE") {
      if (this.config.merge == null) {
        this.status = "ERROR";
        this.error = new Error("MERGE conflict strategy requires config.merge");
        this.notify();
        return;
      }
      if (this.data == null) {
        this.status = "ERROR";
        this.error = new Error("Cannot merge draft: local data is null");
        this.notify();
        return;
      }
      this.data = this.config.merge(this.data, serverPayload.data);
      this.lastModified = Date.now();
      this.status = "DIRTY";
      this.notify();
      this.scheduleSync();
    }
  }

  /**
   * On 409: re-fetch server state, merge with local edits, hydrate quietly (no auto-push).
   */
  private async refetchAndReapplyLocal(conflict: DraftConflictError<T>): Promise<void> {
    const localPending = this.data;
    if (localPending == null) {
      this.hydrateFromRemote(conflict.serverPayload);
      this.status = "IDLE";
      this.error = undefined;
      this.notify();
      return;
    }

    this.status = "CONFLICT_RESOLVING";
    this.error = undefined;
    this.notify();
    try {
      const serverPayload = await this.config.onFetch();
      const fallback = conflict.serverPayload;
      const occSource = serverPayload ?? fallback;
      const merged =
        serverPayload != null
          ? this.config.merge != null
            ? this.config.merge(localPending, serverPayload.data)
            : serverPayload.data
          : this.config.merge != null
            ? this.config.merge(localPending, fallback.data)
            : localPending;

      this.setDraftData(merged, {
        source: "remote",
        version: occSource.version,
        schemaVersion: occSource.schemaVersion,
        lastModified: occSource.lastModified,
      });
      this.status = "IDLE";
      this.error = undefined;
      this.notify();
    } catch {
      this.hydrateFromRemote(conflict.serverPayload);
      this.status = "IDLE";
      this.error = undefined;
      this.notify();
    } finally {
      if (this.status === "CONFLICT_RESOLVING") {
        this.status = "IDLE";
        this.notify();
      }
    }
  }
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

import { DraftEngine } from "./engine";
import type { DraftEngineConfig, DraftEngineState, DraftSetDataOptions } from "./types";

function createEngineWithLiveConfig<T>(configRef: { current: DraftEngineConfig<T> }): DraftEngine<T> {
  const config: DraftEngineConfig<T> = {
    get id() {
      return configRef.current.id;
    },
    get conflictStrategy() {
      return configRef.current.conflictStrategy;
    },
    get autoApply() {
      return configRef.current.autoApply;
    },
    get debounceMs() {
      return configRef.current.debounceMs;
    },
    get merge() {
      return configRef.current.merge;
    },
    onFetch: () => configRef.current.onFetch(),
    onPush: (payload) => configRef.current.onPush(payload),
  };
  if (configRef.current.onDelete != null) {
    config.onDelete = async () => {
      await configRef.current.onDelete?.();
    };
  }
  return new DraftEngine<T>(config);
}

export function useDraftEngine<T>(config: DraftEngineConfig<T>): {
  state: DraftEngineState<T>;
  setDraftData: (data: T, options?: DraftSetDataOptions) => void;
  retry: () => Promise<void>;
  initialize: () => Promise<void>;
  applyDraft: () => void;
  clearDraft: () => Promise<void>;
} {
  const configRef = useRef(config);
  configRef.current = config;

  const engineRef = useRef<DraftEngine<T> | null>(null);
  const [state, setState] = useState<DraftEngineState<T>>(() => {
    engineRef.current = createEngineWithLiveConfig(configRef);
    return engineRef.current.getState();
  });

  useEffect(() => {
    engineRef.current = createEngineWithLiveConfig(configRef);
    setState(engineRef.current.getState());
    return engineRef.current.subscribe((next) => {
      setState(next);
    });
  }, [config.id]);

  const initialize = useCallback(async () => {
    await engineRef.current?.initialize();
  }, []);

  const setDraftData = useCallback((data: T, options?: DraftSetDataOptions) => {
    engineRef.current?.setDraftData(data, options);
  }, []);

  const retry = useCallback(async () => {
    await engineRef.current?.retry();
  }, []);

  const applyDraft = useCallback(() => {
    engineRef.current?.applyDraft();
  }, []);

  const clearDraft = useCallback(async () => {
    await engineRef.current?.clearDraft();
  }, []);

  return { state, setDraftData, retry, initialize, applyDraft, clearDraft };
}

export type DraftStatus =
  | "IDLE"
  | "SYNCING"
  | "DIRTY"
  | "DRAFT_AVAILABLE"
  | "CONFLICT_RESOLVING"
  | "ERROR";

export type DraftSyncPayload<T> = {
  data: T;
  version: number;
  /** Draft `data` blob schema generation (see `@repo/shared-contracts` `DRAFT_SNAPSHOT_DEFAULT_SCHEMA_VERSION`). */
  schemaVersion: number;
  lastModified: number;
};

/** Origin of a {@link DraftEngine.setDraftData} call — controls dirty + sync scheduling. */
export type DraftDataSource = "user" | "remote";

export type DraftSetDataOptions = {
  /** Default `user` — marks DIRTY and schedules debounced push. `remote` is quiet hydration only. */
  source?: DraftDataSource;
  /** When `source` is `remote`, apply server OCC fields so the next user push uses the latest version. */
  version?: number;
  schemaVersion?: number;
  lastModified?: number;
};

export type ConflictStrategy =
  | "SERVER_WINS"
  | "CLIENT_WINS"
  | "MERGE"
  /** Re-fetch via onFetch, merge with local, hydrate quietly — no automatic retry push. */
  | "REFETCH_REAPPLY";

export type DraftEngineConfig<T> = {
  id: string;
  conflictStrategy: ConflictStrategy;
  /** Default true. If false, fetched drafts are staged as pending until applyDraft(). */
  autoApply?: boolean;
  onFetch: () => Promise<DraftSyncPayload<T> | null>;
  onPush: (payload: DraftSyncPayload<T>) => Promise<DraftSyncPayload<T>>;
  /** Optional delete handler used by clearDraft(). */
  onDelete?: () => Promise<void>;
  /** Debounce interval before triggering onPush after update(). Default: 500ms. */
  debounceMs?: number;
  /** Required when conflictStrategy is MERGE; optional for REFETCH_REAPPLY (defaults to keeping local). */
  merge?: (local: T, server: T) => T;
};

export type DraftEngineState<T> = {
  readonly data: T | null;
  readonly status: DraftStatus;
  readonly version: number;
  readonly schemaVersion: number;
  readonly lastModified: number;
  readonly pendingDraft?: DraftSyncPayload<T> | null;
  readonly error?: Error;
};

export class DraftConflictError<T> extends Error {
  readonly serverPayload: DraftSyncPayload<T>;

  constructor(serverPayload: DraftSyncPayload<T>, message = "Draft sync conflict") {
    super(message);
    this.name = "DraftConflictError";
    this.serverPayload = serverPayload;
  }
}

import {
  CURRENT_DRAFT_SCHEMA_VERSION,
  DRAFT_SNAPSHOT_DEFAULT_SCHEMA_VERSION,
  type DraftSnapshot,
} from "./draft-snapshot.contract";

export type DraftMigrationResult<TData = Record<string, unknown>> = {
  readonly snapshot: DraftSnapshot<TData>;
  readonly upgraded: boolean;
};

export type DraftMigrator<TData = Record<string, unknown>> = (
  data: unknown,
  fromSchemaVersion: number,
) => { data: TData; toSchemaVersion: number };

export const DENALI_CREATE_DRAFT_KEY = "denali-create";

/** Pre–phase 3 Denali create wizard rail (photos last). */
const LEGACY_DENALI_WIZARD_RAIL = [
  "denali_basic",
  "denali_program",
  "denali_logistics",
  "denali_pricing",
  "denali_photos",
  "review",
] as const;

/** Phase 3 Denali create wizard rail (content + gallery on step 2). */
const CURRENT_DENALI_WIZARD_RAIL = [
  "denali_basic",
  "denali_photos",
  "denali_program",
  "denali_logistics",
  "denali_pricing",
  "review",
] as const;

export const DENALI_WIZARD_RAIL_LAYOUT_VERSION = 2;

function migrateDenaliDraftStepIndex(
  storedIndex: number,
  railLayoutVersion: number | undefined,
): number {
  const safeIndex = Number.isFinite(storedIndex) ? Math.floor(storedIndex) : 0;

  if ((railLayoutVersion ?? 1) >= DENALI_WIZARD_RAIL_LAYOUT_VERSION) {
    return Math.max(0, Math.min(safeIndex, CURRENT_DENALI_WIZARD_RAIL.length - 1));
  }

  const legacyIndex = Math.max(0, Math.min(safeIndex, LEGACY_DENALI_WIZARD_RAIL.length - 1));
  const stepId = LEGACY_DENALI_WIZARD_RAIL[legacyIndex]!;
  const mapped = CURRENT_DENALI_WIZARD_RAIL.indexOf(stepId);
  return mapped >= 0 ? mapped : 0;
}

/** Minimal safe Denali wizard draft blob when legacy rows are incomplete. */
export const migrateDenaliCreateDraftData: DraftMigrator = (
  data: unknown,
  _fromSchemaVersion: number,
) => {
  const record =
    data != null && typeof data === "object" && !Array.isArray(data)
      ? (data as Record<string, unknown>)
      : {};

  const form =
    record.form != null && typeof record.form === "object" && !Array.isArray(record.form)
      ? (record.form as Record<string, unknown>)
      : {};

  const stepRaw = record.currentStepIndex;
  const railLayoutRaw = record.railLayoutVersion;
  const railLayoutVersion =
    typeof railLayoutRaw === "number" && Number.isFinite(railLayoutRaw)
      ? Math.floor(railLayoutRaw)
      : 1;
  const currentStepIndex = migrateDenaliDraftStepIndex(
    typeof stepRaw === "number" && Number.isFinite(stepRaw) ? stepRaw : 0,
    railLayoutVersion,
  );

  return {
    data: {
      form,
      currentStepIndex,
      railLayoutVersion: DENALI_WIZARD_RAIL_LAYOUT_VERSION,
    } as Record<string, unknown>,
    toSchemaVersion: CURRENT_DRAFT_SCHEMA_VERSION,
  };
};

export class DraftMigratorRegistry {
  private readonly migrators = new Map<string, DraftMigrator>();

  register(draftKey: string, migrator: DraftMigrator): void {
    this.migrators.set(draftKey.trim(), migrator);
  }

  migrateEnvelope<TData = Record<string, unknown>>(
    draftKey: string,
    envelope: DraftSnapshot,
  ): DraftMigrationResult<TData> {
    const key = draftKey.trim();
    const fromVersion = Number(envelope.schemaVersion) || DRAFT_SNAPSHOT_DEFAULT_SCHEMA_VERSION;
    const migrator = this.migrators.get(key);

    if (!migrator && fromVersion >= CURRENT_DRAFT_SCHEMA_VERSION) {
      return { snapshot: envelope as DraftSnapshot<TData>, upgraded: false };
    }

    const { data, toSchemaVersion } = migrator
      ? migrator(envelope.data, fromVersion)
      : { data: envelope.data, toSchemaVersion: fromVersion };

    const upgraded =
      toSchemaVersion !== fromVersion ||
      JSON.stringify(data) !== JSON.stringify(envelope.data);

    if (!upgraded) {
      return { snapshot: envelope as DraftSnapshot<TData>, upgraded: false };
    }

    return {
      snapshot: {
        data: data as TData,
        version: envelope.version,
        schemaVersion: toSchemaVersion,
        lastModified: envelope.lastModified,
      },
      upgraded: true,
    };
  }
}

export function createDefaultDraftMigratorRegistry(): DraftMigratorRegistry {
  const registry = new DraftMigratorRegistry();
  registry.register(DENALI_CREATE_DRAFT_KEY, migrateDenaliCreateDraftData);
  return registry;
}

import type { DraftSnapshot } from "./draft-snapshot.contract";

/** Workspace-scoped draft identity (domain-agnostic; not tied to Tour entities). */
export type DraftScope = {
  readonly workspaceId: string;
  readonly userId: string;
  readonly   draftKey: string;
};

/** MAP alias: any entity addressable by workspace + user + draft key. */
export type Draftable = DraftScope;

export function toDraftScope(
  workspaceId: string,
  userId: string,
  draftKey: string,
): DraftScope {
  return {
    workspaceId: workspaceId.trim().toLowerCase(),
    userId: userId.trim(),
    draftKey: draftKey.trim(),
  };
}

/**
 * Persistence adapter for draft snapshots (Postgres today; Redis or other backends later).
 */
export type DraftStoragePort = {
  find(scope: DraftScope): Promise<DraftSnapshot | null>;
  upsert(scope: DraftScope, snapshot: DraftSnapshot): Promise<DraftSnapshot>;
  delete(scope: DraftScope): Promise<void>;
  /**
   * Upgrade `data` + `schemaVersion` without bumping OCC `version` (used after read-time migration).
   */
  upgradeSchemaInPlace(
    scope: DraftScope,
    input: Pick<DraftSnapshot, "data" | "schemaVersion" | "version">,
  ): Promise<DraftSnapshot | null>;
};

