import assert from "node:assert/strict";
import test from "node:test";

import { FormRuleEngine } from "./formRuleEngine";
import { LookupRegistry } from "./lookupRegistry";
import type { RuleConfig } from "./types";

type TestForm = {
  basicInfo: { tourType: string; destinationId: string };
  filters: { regionId: string };
};

const DESTINATION_PATH = "basicInfo.destinationId";
const TOUR_TYPE_PATH = "basicInfo.tourType";
const REGION_PATH = "filters.regionId";

function createEngine(
  form: TestForm,
  registry: LookupRegistry,
  searchImpl: (query: {
    searchText: string;
    dependencyValues: Record<string, unknown>;
  }) => Promise<{ items: { id: string; name: string }[] }>,
) {
  const rules: RuleConfig<TestForm>[] = [
    {
      path: DESTINATION_PATH,
      lookupProvider: "destination.search",
      dependencies: [TOUR_TYPE_PATH, REGION_PATH],
      required: true,
    },
  ];

  registry.register("destination.search", async (query) => {
    return searchImpl({
      searchText: query.searchText,
      dependencyValues: query.dependencyValues,
    });
  });

  return new FormRuleEngine<TestForm>({
    rules,
    registry,
    getFormValues: () => form,
  });
}

test("LookupRegistry rejects unknown provider at search time", async () => {
  const registry = new LookupRegistry();
  await assert.rejects(
    () =>
      registry.search("missing", {
        providerId: "missing",
        fieldPath: "x",
        searchText: "",
        form: {},
        dependencyValues: {},
      }),
    /unknown provider/,
  );
});

test("dependency change triggers autocomplete refetch with new dependency snapshot", async () => {
  const form: TestForm = {
    basicInfo: { tourType: "mountain_day", destinationId: "" },
    filters: { regionId: "region-a" },
  };

  const calls: Array<{ searchText: string; regionId: unknown }> = [];
  const registry = new LookupRegistry();
  const engine = createEngine(form, registry, async ({ searchText, dependencyValues }) => {
    calls.push({ searchText, regionId: dependencyValues[REGION_PATH] });
    return {
      items: [{ id: "d1", name: `dest-${String(dependencyValues[REGION_PATH])}` }],
    };
  });

  await engine.refetchLookup(DESTINATION_PATH, "teh");
  assert.equal(calls.length, 1);
  assert.equal(calls[0]?.regionId, "region-a");

  form.filters.regionId = "region-b";
  const refetched = await engine.handleFieldChange(REGION_PATH);
  assert.deepEqual(refetched, [DESTINATION_PATH]);

  assert.equal(calls.length, 2);
  assert.equal(calls[1]?.regionId, "region-b");
  assert.equal(calls[1]?.searchText, "teh");

  const state = engine.getLookupState(DESTINATION_PATH);
  assert.equal(state?.status, "success");
  assert.equal(state?.items[0]?.name, "dest-region-b");
});

test("dependency change with unchanged snapshot does not refetch", async () => {
  const form: TestForm = {
    basicInfo: { tourType: "mountain_day", destinationId: "" },
    filters: { regionId: "region-a" },
  };

  let calls = 0;
  const registry = new LookupRegistry();
  const engine = createEngine(form, registry, async () => {
    calls += 1;
    return { items: [] };
  });

  await engine.refetchLookup(DESTINATION_PATH, "");
  assert.equal(calls, 1);

  const refetched = await engine.handleFieldChange(TOUR_TYPE_PATH);
  assert.deepEqual(refetched, []);
  assert.equal(calls, 1);
});

test("lookup field searchText change refetches only that field", async () => {
  const form: TestForm = {
    basicInfo: { tourType: "mountain_day", destinationId: "" },
    filters: { regionId: "region-a" },
  };

  const searchTexts: string[] = [];
  const registry = new LookupRegistry();
  const engine = createEngine(form, registry, async ({ searchText }) => {
    searchTexts.push(searchText);
    return { items: [] };
  });

  await engine.handleFieldChange(DESTINATION_PATH, { searchText: "da" });
  await engine.handleFieldChange(DESTINATION_PATH, { searchText: "dam" });

  assert.deepEqual(searchTexts, ["da", "dam"]);
});

test("subscribeLookup receives loading and success states (UI-agnostic)", async () => {
  const form: TestForm = {
    basicInfo: { tourType: "mountain_day", destinationId: "" },
    filters: { regionId: "region-a" },
  };

  const registry = new LookupRegistry();
  const engine = createEngine(form, registry, async () => ({
    items: [{ id: "1", name: "Alborz" }],
  }));

  const statuses: string[] = [];
  engine.subscribeLookup(DESTINATION_PATH, (state) => {
    statuses.push(state.status);
  });

  await engine.refetchLookup(DESTINATION_PATH, "al");
  assert.deepEqual(statuses, ["idle", "loading", "success"]);
});

import { readFormPath, snapshotFormValues } from "./formPath";
import type { LookupRegistry } from "./lookupRegistry";
import type {
  EvaluatedFieldRule,
  LookupFieldState,
  LookupStateListener,
  RuleConfig,
  RulePredicate,
} from "./types";

export type FormRuleEngineOptions<TForm extends Record<string, unknown>> = {
  rules: readonly RuleConfig<TForm>[];
  registry: LookupRegistry;
  getFormValues: () => TForm;
  readPath?: (form: TForm, path: string) => unknown;
};

function resolveRuleFlag<TForm extends Record<string, unknown>>(
  value: boolean | RulePredicate<TForm> | undefined,
  form: TForm,
  readPath: (path: string) => unknown,
  defaultValue: boolean,
): boolean {
  if (value === undefined) return defaultValue;
  if (typeof value === "boolean") return value;
  return value({ form, readPath });
}

const IDLE_LOOKUP_STATE: LookupFieldState = {
  status: "idle",
  items: [],
  requestId: 0,
  dependencySnapshot: "{}",
  searchText: "",
};

/**
 * UI-agnostic form rule engine: visibility / required evaluation, lookup registry integration,
 * and dependency-driven autocomplete refetch.
 */
export class FormRuleEngine<TForm extends Record<string, unknown> = Record<string, unknown>> {
  private readonly rules: readonly RuleConfig<TForm>[];
  private readonly rulesByPath = new Map<string, RuleConfig<TForm>>();
  private readonly registry: LookupRegistry;
  private readonly getFormValues: () => TForm;
  private readonly readPath: (form: TForm, path: string) => unknown;

  /** dependency path → lookup field paths that must refetch when it changes */
  private readonly dependencyIndex = new Map<string, Set<string>>();
  private readonly lookupStates = new Map<string, LookupFieldState>();
  private readonly lookupListeners = new Map<string, Set<LookupStateListener>>();
  private readonly lastSearchText = new Map<string, string>();
  private readonly lastDependencySnapshots = new Map<string, string>();
  /** Latest in-flight / completed request id per lookup field (stale-response guard). */
  private readonly inflightRequestId = new Map<string, number>();
  private requestCounter = 0;

  constructor(options: FormRuleEngineOptions<TForm>) {
    this.rules = options.rules;
    this.registry = options.registry;
    this.getFormValues = options.getFormValues;
    this.readPath =
      options.readPath ?? ((form, path) => readFormPath(form, path));

    for (const rule of this.rules) {
      if (this.rulesByPath.has(rule.path)) {
        throw new Error(
          `FormRuleEngine: duplicate rule path "${rule.path}"`,
        );
      }
      this.rulesByPath.set(rule.path, rule);

      if (rule.lookupProvider != null && rule.dependencies != null) {
        for (const dep of rule.dependencies) {
          const bucket = this.dependencyIndex.get(dep) ?? new Set<string>();
          bucket.add(rule.path);
          this.dependencyIndex.set(dep, bucket);
        }
      }

      if (rule.lookupProvider != null) {
        this.lookupStates.set(rule.path, { ...IDLE_LOOKUP_STATE });
        this.lastDependencySnapshots.set(
          rule.path,
          this.buildDependencySnapshot(rule.path),
        );
      }
    }
  }

  getRule(path: string): RuleConfig<TForm> | undefined {
    return this.rulesByPath.get(path);
  }

  evaluateField(path: string): EvaluatedFieldRule {
    const rule = this.rulesByPath.get(path);
    const form = this.getFormValues();
    const read = (p: string) => this.readPath(form, p);

    if (rule == null) {
      return {
        path,
        visible: true,
        required: false,
        dependencies: [],
      };
    }

    return {
      path,
      visible: resolveRuleFlag(rule.visible, form, read, true),
      required: resolveRuleFlag(rule.required, form, read, false),
      lookupProvider: rule.lookupProvider,
      dependencies: rule.dependencies ?? [],
    };
  }

  evaluateAll(): EvaluatedFieldRule[] {
    return this.rules.map((rule) => this.evaluateField(rule.path));
  }

  getLookupState<TItem = unknown>(fieldPath: string): LookupFieldState<TItem> | undefined {
    return this.lookupStates.get(fieldPath) as LookupFieldState<TItem> | undefined;
  }

  subscribeLookup<TItem = unknown>(
    fieldPath: string,
    listener: LookupStateListener<TItem>,
  ): () => void {
    const bucket = this.lookupListeners.get(fieldPath) ?? new Set();
    bucket.add(listener as LookupStateListener);
    this.lookupListeners.set(fieldPath, bucket);

    const current = this.lookupStates.get(fieldPath);
    if (current != null) {
      listener(current as LookupFieldState<TItem>);
    }

    return () => {
      const set = this.lookupListeners.get(fieldPath);
      if (set == null) return;
      set.delete(listener as LookupStateListener);
      if (set.size === 0) {
        this.lookupListeners.delete(fieldPath);
      }
    };
  }

  /**
   * Notify the engine that a form path changed. Refetches lookups when:
   * - the changed path is a lookup field (optional new `searchText`), or
   * - the changed path appears in another field's `dependencies`.
   */
  async handleFieldChange(
    changedPath: string,
    options?: { searchText?: string },
  ): Promise<string[]> {
    const refetched: string[] = [];
    const pending: Array<Promise<unknown>> = [];

    const ownRule = this.rulesByPath.get(changedPath);
    if (ownRule?.lookupProvider != null) {
      const text =
        options?.searchText ?? this.lastSearchText.get(changedPath) ?? "";
      this.lastSearchText.set(changedPath, text);
      pending.push(this.refetchLookup(changedPath, text));
      refetched.push(changedPath);
    }

    const dependents = this.dependencyIndex.get(changedPath);
    if (dependents != null) {
      for (const fieldPath of dependents) {
        const scheduled = this.scheduleRefetchIfDependenciesChanged(fieldPath);
        if (scheduled != null) {
          pending.push(scheduled);
          refetched.push(fieldPath);
        }
      }
    }

    await Promise.all(pending);
    return refetched;
  }

  /** Field paths with lookups that list `dependencyPath` in `dependencies`. */
  getLookupFieldsAffectedByDependency(dependencyPath: string): readonly string[] {
    const set = this.dependencyIndex.get(dependencyPath);
    return set == null ? [] : [...set];
  }

  async refetchLookup<TItem = unknown>(
    fieldPath: string,
    searchText: string,
  ): Promise<LookupFieldState<TItem>> {
    const rule = this.rulesByPath.get(fieldPath);
    if (rule?.lookupProvider == null) {
      throw new Error(
        `FormRuleEngine.refetchLookup: field "${fieldPath}" has no lookupProvider`,
      );
    }
    if (!this.registry.has(rule.lookupProvider)) {
      throw new Error(
        `FormRuleEngine.refetchLookup: unknown lookupProvider "${rule.lookupProvider}"`,
      );
    }

    const requestId = ++this.requestCounter;
    this.inflightRequestId.set(fieldPath, requestId);
    const form = this.getFormValues();
    const dependencyValues = this.collectDependencyValues(rule);
    const dependencySnapshot = snapshotFormValues(form, rule.dependencies ?? []);

    this.lastSearchText.set(fieldPath, searchText);
    this.lastDependencySnapshots.set(fieldPath, dependencySnapshot);

    this.publishLookupState(fieldPath, {
      status: "loading",
      items: this.lookupStates.get(fieldPath)?.items ?? [],
      requestId,
      dependencySnapshot,
      searchText,
    });

    try {
      const result = await this.registry.search<TItem, TForm>(rule.lookupProvider, {
        providerId: rule.lookupProvider,
        fieldPath,
        searchText,
        form,
        dependencyValues,
      });

      if (this.inflightRequestId.get(fieldPath) !== requestId) {
        return this.lookupStates.get(fieldPath) as LookupFieldState<TItem>;
      }

      const next: LookupFieldState<TItem> = {
        status: "success",
        items: result.items,
        requestId,
        dependencySnapshot,
        searchText,
      };
      this.publishLookupState(fieldPath, next);
      return next;
    } catch (error) {
      if (this.inflightRequestId.get(fieldPath) !== requestId) {
        return this.lookupStates.get(fieldPath) as LookupFieldState<TItem>;
      }
      const message =
        error instanceof Error ? error.message : "Lookup failed";
      const next: LookupFieldState<TItem> = {
        status: "error",
        items: [],
        error: message,
        requestId,
        dependencySnapshot,
        searchText,
      };
      this.publishLookupState(fieldPath, next);
      return next;
    }
  }

  private scheduleRefetchIfDependenciesChanged(
    fieldPath: string,
  ): Promise<LookupFieldState> | null {
    const rule = this.rulesByPath.get(fieldPath);
    if (rule?.lookupProvider == null) return null;

    const nextSnapshot = this.buildDependencySnapshot(fieldPath);
    const prevSnapshot = this.lastDependencySnapshots.get(fieldPath);
    if (prevSnapshot === nextSnapshot) {
      return null;
    }

    const searchText = this.lastSearchText.get(fieldPath) ?? "";
    return this.refetchLookup(fieldPath, searchText);
  }

  private buildDependencySnapshot(fieldPath: string): string {
    const rule = this.rulesByPath.get(fieldPath);
    if (rule?.dependencies == null || rule.dependencies.length === 0) {
      return "{}";
    }
    return snapshotFormValues(this.getFormValues(), rule.dependencies);
  }

  private collectDependencyValues(
    rule: RuleConfig<TForm>,
  ): Record<string, unknown> {
    const form = this.getFormValues();
    const out: Record<string, unknown> = {};
    for (const path of rule.dependencies ?? []) {
      out[path] = this.readPath(form, path);
    }
    return out;
  }

  private publishLookupState(fieldPath: string, state: LookupFieldState): void {
    this.lookupStates.set(fieldPath, state);
    const listeners = this.lookupListeners.get(fieldPath);
    if (listeners == null) return;
    for (const listener of listeners) {
      listener(state);
    }
  }
}

/**
 * Registry of autocomplete / lookup providers (API services, in-memory catalogs, …).
 * UI layers register concrete fetchers; {@link FormRuleEngine} invokes them by id.
 */

export type LookupQuery<TForm extends Record<string, unknown> = Record<string, unknown>> = {
  providerId: string;
  fieldPath: string;
  searchText: string;
  form: TForm;
  /** Values for paths listed in the field rule's `dependencies`. */
  dependencyValues: Record<string, unknown>;
};

export type LookupResult<TItem = unknown> = {
  items: TItem[];
};

export type LookupProvider<TItem = unknown, TForm extends Record<string, unknown> = Record<string, unknown>> = (
  query: LookupQuery<TForm>,
) => Promise<LookupResult<TItem>>;

export class LookupRegistry {
  private readonly providers = new Map<string, LookupProvider>();

  register<TItem, TForm extends Record<string, unknown> = Record<string, unknown>>(
    providerId: string,
    provider: LookupProvider<TItem, TForm>,
  ): this {
    if (providerId.trim() === "") {
      throw new Error("LookupRegistry.register: providerId must be non-empty");
    }
    this.providers.set(providerId, provider as LookupProvider);
    return this;
  }

  has(providerId: string): boolean {
    return this.providers.has(providerId);
  }

  async search<TItem = unknown, TForm extends Record<string, unknown> = Record<string, unknown>>(
    providerId: string,
    query: LookupQuery<TForm>,
  ): Promise<LookupResult<TItem>> {
    const provider = this.providers.get(providerId);
    if (provider == null) {
      throw new Error(`LookupRegistry: unknown provider "${providerId}"`);
    }
    return (await provider(query)) as LookupResult<TItem>;
  }
}

/** Process-wide default registry (optional convenience for apps). */
export const defaultLookupRegistry = new LookupRegistry();

import type { LookupQuery, LookupResult } from "./lookupRegistry";

export type RulePredicate<TForm extends Record<string, unknown>> = (ctx: {
  form: TForm;
  readPath: (path: string) => unknown;
}) => boolean;

/**
 * Declarative field rule: visibility, required, autocomplete lookup, and dependency wiring.
 * Consumed by {@link FormRuleEngine} — no React or DOM assumptions.
 */
export type RuleConfig<TForm extends Record<string, unknown> = Record<string, unknown>> = {
  /** Dot path on the form model (`basicInfo.destinationId`, …). */
  path: string;
  visible?: boolean | RulePredicate<TForm>;
  required?: boolean | RulePredicate<TForm>;
  /**
   * Key registered on {@link LookupRegistry} (e.g. `destination.search`).
   * When set, the engine can run autocomplete queries for this field.
   */
  lookupProvider?: string;
  /**
   * Other form paths whose value changes should invalidate / refetch this field's lookup.
   */
  dependencies?: readonly string[];
};

export type EvaluatedFieldRule = {
  path: string;
  visible: boolean;
  required: boolean;
  lookupProvider?: string;
  dependencies: readonly string[];
};

export type LookupFetchStatus = "idle" | "loading" | "success" | "error";

export type LookupFieldState<TItem = unknown> = {
  status: LookupFetchStatus;
  items: TItem[];
  error?: string;
  /** Monotonic id so async callers can ignore stale responses. */
  requestId: number;
  /** Serialized dependency values used for the in-flight / last successful fetch. */
  dependencySnapshot: string;
  searchText: string;
};

export type LookupStateListener<TItem = unknown> = (state: LookupFieldState<TItem>) => void;

export type { LookupQuery, LookupResult };

export enum WorkspaceRole {
  Owner = "owner",
  Leader = "leader",
  Admin = "admin",
  Member = "member",
  Viewer = "viewer"
}

/** Higher number = higher privilege. */
export const ROLE_RANK: Readonly<Record<WorkspaceRole, number>> = Object.freeze({
  [WorkspaceRole.Viewer]: 1,
  [WorkspaceRole.Member]: 2,
  [WorkspaceRole.Admin]: 3,
  [WorkspaceRole.Leader]: 4,
  [WorkspaceRole.Owner]: 5
});

/**
 * Parses persisted JWT / DB / invite role strings into {@link WorkspaceRole}.
 * Unknown values return `undefined` (no loose string casting).
 */
export function tryParseWorkspaceRole(raw: string | undefined | null): WorkspaceRole | undefined {
  if (raw === undefined || raw === null) {
    return undefined;
  }
  const key = raw.trim().toLowerCase();
  if (key === "") {
    return undefined;
  }
  if (key === "operator") {
    return WorkspaceRole.Member;
  }
  for (const value of Object.values(WorkspaceRole)) {
    if (value === key) {
      return value;
    }
  }
  return undefined;
}

