        "http://127.0.0.1:3001/api/v2/auth/web/phone/preflight",
        "-H", "Host: probe-rate-phase7.localhost:3001",
        "-H", "Content-Type: application/json",
        "-d", '{"phone":"+15550000001"}'],
      { encoding: "utf8" },
